"use strict";(self.webpackChunkbcsd_blog=self.webpackChunkbcsd_blog||[]).push([[2309],{4201:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"/posts/introduce-FE-2025","metadata":{"permalink":"/front-end/posts/introduce-FE-2025","source":"@site/@frontEnd/posts/introduce-FE-2025.mdx","title":"BCSD \uac00\uc774\ub4dc: \ud504\ub860\ud2b8\uc5d4\ub4dc","description":"\ud504\ub860\ud2b8\uc5d4\ub4dc \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!","date":"2025-05-05T00:00:00.000Z","tags":[{"label":"FE","permalink":"/front-end/tags/fe"},{"label":"\ud2b8\ub799 \uc18c\uac1c","permalink":"/front-end/tags/\ud2b8\ub799-\uc18c\uac1c"}],"readingTime":5.105,"hasTruncateMarker":true,"authors":[{"name":"hyejun0228","url":"https://github.com/hyejun0228","email":"hyejunkkim228@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/114041848?s=400&u=89ca185a98f74df94eccbcb8c28e16bc97ed0fc4&v=4","key":"hyejun0228"}],"frontMatter":{"date":"2025-05-05T00:00:00.000Z","authors":"hyejun0228","title":"BCSD \uac00\uc774\ub4dc: \ud504\ub860\ud2b8\uc5d4\ub4dc","description":"\ud504\ub860\ud2b8\uc5d4\ub4dc \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!","keywords":["FE","\ud2b8\ub799 \uc18c\uac1c"],"tags":["FE","\ud2b8\ub799 \uc18c\uac1c"]},"unlisted":false,"nextItem":{"title":"AB \ud14c\uc2a4\ud2b8 \uc5b4\ub5bb\uac8c \uc0dd\uc131\ud574\uc694?","permalink":"/front-end/posts/abTest-guide"}},"content":"\ud504\ub860\ud2b8\uc5d4\ub4dc \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!\\n\\n{/* truncate */}\\n\\n# **BCSD FrontEnd Track Introduce**\\n\\n\ud504\ub860\ud2b8\uc5d4\ub4dc \ud2b8\ub799\uc5d0 \uc9c0\uc6d0\ud574\uc8fc\uc2e0 \uc5ec\ub7ec\ubd84, \uc9c4\uc2ec\uc73c\ub85c \ud658\uc601\ud569\ub2c8\ub2e4! \ud83c\udf89\\n\\n\uc774 \ubb38\uc11c\ub294 \ud504\ub860\ud2b8\uc5d4\ub4dc \ud2b8\ub799\uc758 \uc804\ubc18\uc801\uc778 \uc18c\uac1c\uc640 \uc55e\uc73c\ub85c \ubc30\uc6b0\uac8c \ub420 \ub0b4\uc6a9, \uadf8\ub9ac\uace0 \uc5ec\ub7ec\ubd84\uc774 \uc5b4\ub5a4 \uacbd\ud5d8\uc744 \ud558\uac8c \ub420\uc9c0 \uc548\ub0b4\ud574 \ub4dc\ub9bd\ub2c8\ub2e4. \ud55c \ubc88 \ucb49 \uc77d\uc5b4\ubcf4\uc2dc\uba74 \ub9ce\uc740 \ub3c4\uc6c0\uc774 \ub420 \uac70\uc608\uc694!\\n\\n---\\n\\n## **Q. \ud504\ub860\ud2b8\uc5d4\ub4dc\ub780 \ubb34\uc5c7\uc778\uac00\uc694?**\\n\\n\ud504\ub860\ud2b8\uc5d4\ub4dc\ub294 \uc6f9\uc0ac\uc774\ud2b8\ub098 \uc571\uc5d0\uc11c **\uc0ac\uc6a9\uc790\uac00 \uc9c1\uc811 \ubcf4\uace0, \ud074\ub9ad\ud558\uace0, \uc785\ub825\ud558\ub294 \ubaa8\ub4e0 \ud654\uba74**\uc744 \ub9cc\ub4dc\ub294 \ubd84\uc57c\uc785\ub2c8\ub2e4.\\n\\n\uc27d\uac8c \ub9d0\ud574, \uc5ec\ub7ec\ubd84\uc774 \uc6f9 \ube0c\ub77c\uc6b0\uc800\uc5d0\uc11c \ubcf4\ub294 \uba4b\uc9c4 \uc0ac\uc774\ud2b8\uc640 \uc778\ud130\ub799\uc158\ub4e4\uc774 \ubaa8\ub450 \ud504\ub860\ud2b8\uc5d4\ub4dc \uac1c\ubc1c\uc790\uc758 \uc190\uc744 \uac70\uccd0 \ub9cc\ub4e4\uc5b4\uc9d1\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \uc5b4\ub5a4 \uc5b8\uc5b4\uc640 \ub3c4\uad6c\ub97c \uc0ac\uc6a9\ud558\ub098\uc694?**\\n\\n\ud504\ub860\ud2b8\uc5d4\ub4dc \ud2b8\ub799\uc5d0\uc11c\ub294 \uc8fc\ub85c **HTML, CSS, JavaScript, TypeScript** \ub97c \uae30\ubcf8\uc73c\ub85c \ubc30\uc6b0\uac8c \ub429\ub2c8\ub2e4.\\n\\n\uadf8\ub9ac\uace0, \uc2e4\uc81c \uc11c\ube44\uc2a4 \uac1c\ubc1c\uc5d0\uc11c\ub294 **React, Tanstack query**\uc640 \uac19\uc740 \ub77c\uc774\ube0c\ub7ec\ub9ac\ub3c4 \ud65c\uc6a9\ud569\ub2c8\ub2e4.\\n\\n- **HTML/CSS**: \uc6f9\ud398\uc774\uc9c0\uc758 \uad6c\uc870\uc640 \ub514\uc790\uc778\uc744 \ub2f4\ub2f9\ud569\ub2c8\ub2e4.\\n- **JavaScript, TypeScript**: \uc6f9\ud398\uc774\uc9c0\uc5d0 \uc0dd\ub3d9\uac10\uacfc \uae30\ub2a5\uc744 \ub354\ud569\ub2c8\ub2e4.\\n- **React**: \ubcf5\uc7a1\ud55c \uc6f9\uc571\uc744 \ud6a8\uc728\uc801\uc73c\ub85c \ub9cc\ub4e4 \uc218 \uc788\ub294 \ub77c\uc774\ube0c\ub7ec\ub9ac\uc785\ub2c8\ub2e4.\\n- **TanStack Query** : \uc11c\ubc84\uc5d0\uc11c \ub370\uc774\ud130\ub97c \uac00\uc838\uc624\uace0 \uce90\uc2f1\ud558\uba70, \ub85c\ub529/\uc5d0\ub7ec \uc0c1\ud0dc\ub97c \uc790\ub3d9\uc73c\ub85c \uad00\ub9ac\ud574\uc8fc\ub294 \ub370\uc774\ud130 \ub3d9\uae30\ud654 \ub77c\uc774\ube0c\ub7ec\ub9ac\uc785\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ubb34\uc5c7\uc744 \ubc30\uc6b0\uace0, \uc5b4\ub5a4 \ud504\ub85c\uc81d\ud2b8\ub97c \ud558\ub098\uc694?**\\n\\n\ube44\uae30\ub108 \uacfc\uc815\uc5d0\uc11c\ub294\\n\\n- \uc6f9\uc758 \uae30\ubcf8 \uad6c\uc870\uc640 \ub3d9\uc791 \uc6d0\ub9ac\\n- HTML/CSS\ub97c \uc774\uc6a9\ud55c \ud654\uba74 \uad6c\ud604\\n- JavaScript, TypeScript\ub85c \ub3d9\uc801\uc778 \uae30\ub2a5 \ub9cc\ub4e4\uae30\\n- React\ub85c \uc2e4\uc81c \uc11c\ube44\uc2a4\ud615 \uc6f9\uc571 \uac1c\ubc1c \ub4f1\uc744 \ub2e8\uacc4\uc801\uc73c\ub85c \ubc30\uc6c1\ub2c8\ub2e4.\\n\\n\ub9c8\uc9c0\ub9c9 \ud68c\uace0\uc5d0\uc11c\ub294 \uc5ec\ub7ec\ubd84\ub9cc\uc758 **\uc791\uc740 \uc6f9 \ud504\ub85c\uc81d\ud2b8**\ub97c \uc9c1\uc811 \uae30\ud68d\ud558\uace0 \ub9cc\ub4e4\uc5b4\ubcf4\ub294 \uacbd\ud5d8\ub3c4 \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ud611\uc5c5\uc740 \uc5b4\ub5bb\uac8c \uc774\ub8e8\uc5b4\uc9c0\ub098\uc694?**\\n\\n\ud504\ub860\ud2b8\uc5d4\ub4dc \uac1c\ubc1c\uc790\ub294 \ubc31\uc5d4\ub4dc, \ub514\uc790\uc774\ub108, PM \ub4f1 \ub2e4\uc591\ud55c \uc5ed\ud560\uc758 \ud300\uc6d0\ub4e4\uacfc \ud568\uaed8 \uc77c\ud569\ub2c8\ub2e4.\\n\\n\ud504\ub85c\uc81d\ud2b8\ub97c \uc9c4\ud589\ud558\uba70 **API \uc5f0\ub3d9, \ub514\uc790\uc778 \ubc18\uc601, \uc77c\uc815 \uad00\ub9ac** \ub4f1 \uc2e4\ubb34\uc5d0 \uac00\uae4c\uc6b4 \ud611\uc5c5 \uacbd\ud5d8\uc744 \uc313\uac8c \ub429\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ube44\uc804\uacf5\uc790\ub098 \ucc98\uc74c \ubc30\uc6b0\ub294 \uc0ac\ub78c\ub3c4 \ub530\ub77c\uac08 \uc218 \uc788\ub098\uc694?**\\n\\n\ub124!\\n\\n\ud504\ub860\ud2b8\uc5d4\ub4dc \ud2b8\ub799\uc740 **\ucc98\uc74c \uc2dc\uc791\ud558\ub294 \ubd84\ub4e4\ub3c4 \ucda9\ubd84\ud788 \ub530\ub77c\uc62c \uc218 \uc788\ub3c4\ub85d** \ucee4\ub9ac\ud058\ub7fc\uc774 \uad6c\uc131\ub418\uc5b4 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc911\uc694\ud55c \uac74, \uc0c8\ub85c\uc6b4 \uac83\uc5d0 \ub3c4\uc804\ud558\ub824\ub294 \ub9c8\uc74c\uacfc \uc5f4\uc815\uc785\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ub808\uade4\ub7ec\uac00 \ub418\uba74 \ubb34\uc5c7\uc744 \ud558\ub098\uc694?**\\n\\n\ube44\uae30\ub108 \uacfc\uc815\uc744 \uc131\uacf5\uc801\uc73c\ub85c \ub9c8\uce58\uace0 \ud68c\uace0 \uc2ec\uc0ac\uae4c\uc9c0 \uc644\uc218\ud558\uba74,\\n\\nBCSD\uc758 \uc2e4\uc81c \ud504\ub85c\uc81d\ud2b8(\uc608: \ucf54\uc778 \ud504\ub85c\uc81d\ud2b8)\uc5d0 \ud22c\uc785\ub418\uc5b4 \uc2e4\uc804 \uacbd\ud5d8\uc744 \uc313\uac8c \ub429\ub2c8\ub2e4.\\n\\n\ud300\uc6d0\ub4e4\uacfc \ud568\uaed8 \uc11c\ube44\uc2a4\uc758 \uc8fc\uc694 \uae30\ub2a5\uc744 \uc9c1\uc811 \uac1c\ubc1c\ud558\uace0, \uc6b4\uc601 \uacbd\ud5d8\uae4c\uc9c0 \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \uc55e\uc73c\ub85c\uc758 \uc9c4\ub85c\ub294?**\\n\\n\ud504\ub860\ud2b8\uc5d4\ub4dc \uac1c\ubc1c\uc790\ub294 IT \uc5c5\uacc4\uc5d0\uc11c \ub9e4\uc6b0 \ud070 \uc218\uc694\ub97c \uc790\ub791\ud558\ub294 \uc9c1\uad70\uc785\ub2c8\ub2e4.\\n\\n\ud2b8\ub799\uc744 \uc131\uc2e4\ud788 \uc774\uc218\ud55c\ub2e4\uba74,\\n\\n- \uc2e4\ubb34\ud615 \ud3ec\ud2b8\ud3f4\ub9ac\uc624\\n- \ud611\uc5c5 \uacbd\ud5d8\\n- \ucd5c\uc2e0 \uae30\uc220 \ud2b8\ub80c\ub4dc \uc2b5\ub4dd \ub4f1\uc744 \ubc14\ud0d5\uc73c\ub85c \ucde8\uc5c5\uc774\ub098 \ub2e4\uc591\ud55c \uc9c4\ub85c\ub85c \ud655\uc7a5\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n**\ub9c8\ubb34\ub9ac**\\n\\n\ud504\ub860\ud2b8\uc5d4\ub4dc \ud2b8\ub799\uc744 \ub530\ub77c\uac00\ub2e4 \ubcf4\uba74 \ucc98\uc74c \ud654\uba74\uc744 \ub9cc\ub4e4\uc5c8\uc744 \ub54c\uc758 \u201c\ub0b4\uac00 \uc9c1\uc811 \ub9cc\ub4e4\uc5c8\ub2e4\u201d\ub294 \ubfcc\ub4ef\ud568\uacfc \uc131\ucde8\uac10\uc744 \ub290\ub07c\uc2e4 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uadf8 \ucc98\uc74c\uc758 \uc124\ub818\uc744 \uae30\uc5b5\ud558\uba70, \ub54c\ub54c\ub85c \uc5b4\ub824\uc6b4 \uc21c\uac04\uc774 \uc624\ub354\ub77c\ub3c4 \ub05d\uae4c\uc9c0 \uc2a4\uc2a4\ub85c\ub97c \ubbff\uace0 \ub098\uc544\uac00\uc168\uc73c\uba74 \ud569\ub2c8\ub2e4.\\n\\n\uc5ec\ub7ec\ubd84\uc774 \uc9c0\uae08 \ud558\ub294 \uc77c\uc5d0 \ud655\uc2e0\uc774 \uc5c6\ub354\ub77c\ub3c4, \ubd84\uba85\ud788 \uc131\uc7a5\ud558\uace0 \uc788\ub2e4\ub294 \uac83\uc744 \uc790\uc2e0 \uc788\uac8c \ub9d0\uc500\ub4dc\ub9b4 \uc218 \uc788\uc2b5\ub2c8\ub2e4."},{"id":"/posts/abTest-guide","metadata":{"permalink":"/front-end/posts/abTest-guide","source":"@site/@frontEnd/posts/abTest-guide.mdx","title":"AB \ud14c\uc2a4\ud2b8 \uc5b4\ub5bb\uac8c \uc0dd\uc131\ud574\uc694?","description":"AB \ud14c\uc2a4\ud2b8 \uc0dd\uc131, \uc218\uc815, \uc0ad\uc81c \ub4f1 \uc0ac\uc6a9\ubc95 \uc815\ub9ac \ubb38\uc11c\uc785\ub2c8\ub2e4.","date":"2024-10-01T00:00:00.000Z","tags":[{"label":"AB \ud14c\uc2a4\ud2b8","permalink":"/front-end/tags/ab-\ud14c\uc2a4\ud2b8"},{"label":"\uc0ac\uc6a9\ubc95","permalink":"/front-end/tags/\uc0ac\uc6a9\ubc95"}],"readingTime":5.29,"hasTruncateMarker":true,"authors":[{"name":"jeonhoon choi","url":"https://github.com/hoooooony","email":"cjh41820@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/112807899?s=400&u=6212abbc408247f540b8096772553123fd74fdb5&v=4","key":"hoooooony"}],"frontMatter":{"date":"2024-10-01T00:00:00.000Z","authors":"hoooooony","title":"AB \ud14c\uc2a4\ud2b8 \uc5b4\ub5bb\uac8c \uc0dd\uc131\ud574\uc694?","description":"AB \ud14c\uc2a4\ud2b8 \uc0dd\uc131, \uc218\uc815, \uc0ad\uc81c \ub4f1 \uc0ac\uc6a9\ubc95 \uc815\ub9ac \ubb38\uc11c\uc785\ub2c8\ub2e4.","keywords":["AB \ud14c\uc2a4\ud2b8","\uc0ac\uc6a9\ubc95"],"tags":["AB \ud14c\uc2a4\ud2b8","\uc0ac\uc6a9\ubc95"]},"unlisted":false,"prevItem":{"title":"BCSD \uac00\uc774\ub4dc: \ud504\ub860\ud2b8\uc5d4\ub4dc","permalink":"/front-end/posts/introduce-FE-2025"},"nextItem":{"title":"QA\ub97c \ubcf4\ub2e4 \ud6a8\uacfc\uc801\uc73c\ub85c?","permalink":"/front-end/haejinyun/august-retrospect_haejin"}},"content":"\uc774\ubc88\uc5d0 \uc120\uad8c\uc774\uac00 \uc5f4\uc2ec\ud788 \uad6c\ud604\ud55c \ub3d9\uc544\ub9ac \uc790\uccb4 AB \ud14c\uc2a4\ud2b8 \ub3c4\uad6c\uc758 \uc0ac\uc6a9\ubc29\ubc95\uc785\ub2c8\ub2e4.\\n\\n{/* truncate */}\\n\\n\\n\\n\\n## AB \ud14c\uc2a4\ud2b8 \uc0dd\uc131\ubc95([\uc5b4\ub4dc\ubbfc](https://admin.koreatech.in/abtest))\\n### \uc0dd\uc131\ud558\uae30\\n- **\uc88c\uce21\uc758 \ud0ed\uc5d0\uc11c \ud14c\uc2a4\ud2b8 \ud0ed\uc758 AB \ud14c\uc2a4\ud2b8 \ud074\ub9ad**\\n <img src=\\"/img/@frontEnd/abTest-guide/01.png\\" width=\\"300px\\" alt=\\"\uc774\ubbf8\uc9c0\\" />\\n<br/><br/>\\n- **\ud398\uc774\uc9c0 \uc88c\uce21\uc0c1\ub2e8\uc758 \uc0dd\uc131 \ubc84\ud2bc\uc744 \ud074\ub9ad\ud55c\ub2e4.**\\n <img src=\\"/img/@frontEnd/abTest-guide/02.png\\" width=\\"700px\\" alt=\\"\uc774\ubbf8\uc9c0\\" />\\n<br/><br/>\\n- **\ubaa8\ub2ec\uc5d0\uc11c \ud544\uc694\ud55c \uc815\ubcf4\ub97c \uc785\ub825\ud569\ub2c8\ub2e4.**\\n1. AB \ud14c\uc2a4\ud2b8\uc758 \uc81c\ubaa9\uc740 \ud574\ub2f9 \ud14c\uc2a4\ud2b8\ub97c \uc758\ubbf8\ud558\ub294 \uc81c\ubaa9\uc744 \uc801\uc5b4\uc8fc\uc2dc\uba74 \ub429\ub2c8\ub2e4.\\n1. \ubcc0\uc218\ub294 \ud574\ub2f9 \ud14c\uc2a4\ud2b8\ub97c \uc2dd\ubcc4\ud558\ub294 \uc720\uc77c\ud55c \uac12\uc73c\ub85c \ub2e4\ub978 \ud14c\uc2a4\ud2b8\uc640 \uac19\uc73c\uba74 \uc548\ub418\uba70 \uc601\uc5b4\ub85c \uc791\uc131\ud574 \uc8fc\uc138\uc694.\\n1. \uc124\uba85\uc740 \ud574\ub2f9 \ud14c\uc2a4\ud2b8\uac00 \uc5b4\ub5a4 \ud14c\uc2a4\ud2b8\uc778\uc9c0 \uc54c \uc218 \uc788\ub3c4\ub85d \ub0b4\uc6a9\uc744 \uc801\uc5b4\uc8fc\uc138\uc694.\\n1. \ubaa8\ub4e0 \ub0b4\uc6a9\uc744 \uc804\ubd80 \uae30\uc785\ud55c \ud6c4 \ub2e4\uc74c\uc744 \ud074\ub9ad\ud574 \uc8fc\uc138\uc694.\\n <img src=\\"/img/@frontEnd/abTest-guide/03.png\\" width=\\"600px\\" alt=\\"\uc774\ubbf8\uc9c0\\" /> \\n<br/><br/>\\n- **\ub2e4\uc74c \ub2e8\uacc4\uc5d0\uc11c\ub294 \ud574\ub2f9 \ud14c\uc2a4\ud2b8\uc758 \uc2e4\ud5d8\uad70 \uc815\ubcf4\ub97c \uc785\ub825\ud569\ub2c8\ub2e4.**\\n1. \uac01 \uc2e4\ud5d8\uad70\uc758 \uc81c\ubaa9\uc740 \ud574\ub2f9 \uc2e4\ud5d8\uad70\uc744 \uc758\ubbf8\ud558\ub294 \uc81c\ubaa9\uc744 \uc801\uc5b4\uc8fc\uc138\uc694.\\n1. \uc2e4\ud5d8 \ubcc0\uc218\uba85\uc740 \ud574\ub2f9 \uc2e4\ud5d8\uad70\uc744 \uc2dd\ubcc4\ud558\ub294 \uac12\uc73c\ub85c \uac1c\ubc1c\uc790\ub4e4\uc774 \uac1c\ubc1c\uc2dc\uc5d0 \uc0ac\uc6a9\ud558\uac8c \ub429\ub2c8\ub2e4.\\n<br/> A,B \ub610\ub294 \uc758\ubbf8\ub97c \uac00\uc9c4 \uc601\uc5b4 \ub2e8\uc5b4\ub97c \uc0ac\uc6a9\ud574\uc8fc\uc138\uc694.\\n1. \uc2e4\ud5d8\uad70\uc744 \ucd94\uac00\ud558\uace0 \uc2f6\uc73c\uba74 \uc2e4\ud5d8 \ucd94\uac00\ubc84\ud2bc\uc744 \uc0ad\uc81c\ud558\uace0 \uc2f6\ub2e4\uba74 \uc0ad\uc81c\ub97c \ud074\ub9ad\ud574\uc8fc\uc138\uc694.\\n1. \uc0ad\uc81c \ubc84\ud2bc \ud074\ub9ad\uc2dc \ubb34\uc870\uac74 \uc624\ub978\ucabd \uc2e4\ud5d8\uad70\ubd80\ud130 \uc0ad\uc81c\ub429\ub2c8\ub2e4.\\n1. \uac01 \uc2e4\ud5d8\uad70\uc5d0 \ub4e4\uc5b4\uac08 \uc0ac\uc6a9\uc790\uc758 \ube44\uc728\uc740 \uc544\ub798\uc758 **\uc2ac\ub77c\uc774\ub4dc \ubc14**\ub97c \ud1b5\ud574\uc11c \uc870\uc808\ud574\uc8fc\uc138\uc694!\\n<img src=\\"/img/@frontEnd/abTest-guide/04.png\\" width=\\"600px\\" alt=\\"\uc774\ubbf8\uc9c0\\" />\\n<br/><br/>\\n- **\uc644\ub8cc\ub97c \ud074\ub9ad\ud558\uba74 \uc815\uc0c1\uc801\uc73c\ub85c \ud14c\uc2a4\ud2b8 \ub4f1\ub85d\uc2dc \uc774\ub7f0 \ud1a0\uc2a4\ud2b8\uac00 \ub728\uac8c \ub429\ub2c8\ub2e4.**\\n <img src=\\"/img/@frontEnd/abTest-guide/05.png\\" width=\\"300px\\" alt=\\"\uc774\ubbf8\uc9c0\\" /> \\n\\n### \uc218\uc815\ud558\uae30\\n- **\ud574\ub2f9 \ud14c\uc2a4\ud2b8\uc758 \uc790\uc138\ud55c \ub0b4\uc6a9 \ud655\uc778\ud558\uae30**\\n1. \ud14c\uc774\ube14\uc5d0\uc11c \ud2b9\uc815 \ud14c\uc2a4\ud2b8\ub97c \ud074\ub9ad\ud558\uac8c \ub418\uba74 \ub2e4\uc74c\uacfc \uac19\uc740 \uc0c1\uc138 \ud398\uc774\uc9c0\ub85c \uc774\ub3d9\ud569\ub2c8\ub2e4.\\n1. \ubcc0\uc218\ub4e4\uc740 \uc218\uc815\uc774 \ubd88\uac00\ud558\uba70 \ud654\uba74\uc0c1\uc5d0 \ud770\uc0c9 \ubc30\uacbd \uac12\ub9cc \uc218\uc815 \uac00\ub2a5\ud569\ub2c8\ub2e4.\\n1. \ube44\uc728\uc740 \uc2ac\ub77c\uc774\ub4dc\ubc14\ub97c \ud1b5\ud574\uc11c\ub9cc \uc870\uc808\ud574\uc8fc\uc138\uc694.\\n1. \ubcc0\uacbd\ub418\ub294 \ube44\uc728\uc740 \uae30\uc874\uc758 \uc0ac\uc6a9\uc790\ub4e4\uc5d0\uac8c \uc801\uc6a9\ub418\ub294\uac83\uc774 \uc544\ub2cc \uc55e\uc73c\ub85c \ud3b8\uc785\ub418\ub294 \uc0ac\uc6a9\uc790\ub4e4\uc774 \ud574\ub2f9 \ube44\uc728\uc5d0 \ub530\ub77c \ud3b8\uc785\ub429\ub2c8\ub2e4.\\n <img src=\\"/img/@frontEnd/abTest-guide/06.png\\" width=\\"600px\\" alt=\\"\uc774\ubbf8\uc9c0\\" /> \\n- **\uc218\uc815 \ubc84\ud2bc\uc73c\ub85c \uc218\uc815\ud558\uae30**\\n1. \uc544\ub798\uc758 \ud30c\ub780 \ubc84\ud2bc\uc744 \ud074\ub9ad\ud558\uba74 \uc218\uc815\uc774 \uc644\ub8cc\ub429\ub2c8\ub2e4.\\n1. \uc2e4\ud5d8\uc744 \uc798 \ubabb \uc0dd\uc131\ud558\uc600\ub2e4\uba74 \uc0ad\uc81c \ubc84\ud2bc\uc744 \uc774\uc6a9\ud574\uc8fc\uc138\uc694.\\n <img src=\\"/img/@frontEnd/abTest-guide/07.png\\" width=\\"600px\\" alt=\\"\uc774\ubbf8\uc9c0\\" /> \\n\\n### \uc2b9\uc790 \uc815\ud558\uae30\\n- **\uc2e4\ud5d8\uad70 \ubcc0\uc218 \uc785\ub825\uc73c\ub85c \uc2b9\uc790 \uc815\ud558\uae30**\\n1. \uc2b9\uc790\ub85c \uc815\ud558\uace0\uc790 \ud558\ub294 \uc2e4\ud5d8\uad70\uc758 \ubcc0\uc218\ub97c \uc785\ub825\uce78\uc5d0 \uc785\ub825\ud574\uc8fc\uc138\uc694.\\n1. \uc2b9\uc790 \uc815\ud558\uae30 \ubc84\ud2bc\uc744 \ud074\ub9ad\ud574\uc8fc\uc138\uc694.\\n <img src=\\"/img/@frontEnd/abTest-guide/08.png\\" width=\\"600px\\" alt=\\"\uc774\ubbf8\uc9c0\\" /> \\n- **\uacbd\uace0 \ubaa8\ub2ec\uc5d0\uc11c \ud655\uc815\ud558\uae30**\\n <img src=\\"/img/@frontEnd/abTest-guide/09.png\\" width=\\"600px\\" alt=\\"\uc774\ubbf8\uc9c0\\" /> \\n\\n### \ud504\ub860\ud2b8\uc5d0\uc11c \uc0ac\uc6a9\ud558\uae30(KOIN_WEB_RECODE \uae30\uc900)\\n\\n\uc804 \uc544\ub798\uc640 \uac19\uc774 \uc0ac\uc6a9\ud558\uc600\uc2b5\ub2c8\ub2e4.\\n```\uc5b8\uc5b4\uba85(ts) title=\\"\uac04\ub2e8 \uc0ac\uc6a9\ubc95\\"\\n\\n// highlight-start\\nconst ABView = useABTestView(\'\ud14c\uc2a4\ud2b8\uc758 \ubcc0\uc218\uba85\', token);\\n// highlight-end\\n\\nABView === \\"\uc124\uc815\ud55c \uc2e4\ud5d8\uad70\uc758 \ubcc0\uc218\uba85\\" ? \uac01 UI : \uac01 UI;\\n\\n```\\n\\n`useABTestView()`\ub0b4\ubd80\uc5d0\uc11c `access_history_id`\ub97c \ucc98\ub9ac\ud558\uae30 \ub54c\ubb38\uc5d0 \uc0ac\uc6a9\ud558\uc2e4 \ub54c \ub530\ub85c \uc8fc\uc2e4 \ud544\uc694\ub294 \uc5c6\uc2b5\ub2c8\ub2e4.\\n\\n### access_history_id\uac00 \ubb34\uc5c7\uc778\uac00?\\naccess_history_id\ub294 \uc720\uc800\ub97c \uad6c\ubd84\ud558\uae30 \uc704\ud55c \uace0\uc720\ud55c \uac12\uc785\ub2c8\ub2e4. <br/>\\nAB\ud14c\uc2a4\ud2b8 \uac1c\ubc1c \uacfc\uc815\uc5d0\uc11c \uc9c8 \uc88b\uc740 \ud1b5\uacc4\ub97c \uc704\ud574\uc11c\ub294 **\ube44\ub85c\uadf8\uc778 \uc720\uc800** \ub97c \uad6c\ubcc4\ud574\uc57c\ud568\uc744 \uc54c\uac8c \ub418\uc5b4 \uad6c\ud604\ud558\uac8c \ub41c \uac12\uc785\ub2c8\ub2e4. <br/>\\n\uc0ac\uc6a9\uae30\uae30\ub9c8\ub2e4 \ubc1b\uac8c \ub418\ub294 \uac12\uc73c\ub85c **\ubc18\uc601\uad6c\uc801**\uc73c\ub85c \uc800\uc7a5\ud558\uae30 \uc704\ud574\uc11c KOIN_WEB_RECODE\uc5d0\uc11c\ub294 \ub85c\uceec \uc2a4\ud1a0\ub9ac\uc9c0\uc5d0 \ud604\uc7ac \uc800\uc7a5\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n[\uc790\uc138\ud55c \uad6c\ud604 \uace0\ubbfc \uacfc\uc815\uc774 \uc54c\uace0 \uc2f6\ub2e4\uba74?](http://localhost:3000/back-end/songsunkook/abtest)\\n\\n**\uc0ac\uc6a9\ud558\ub2e4\uac00 \ubd88\ud3b8\ud55c \uacbd\ud5d8\uc774 \uc788\ub2e4\uba74 \uc5b8\uc81c\ub4e0 DM \uc8fc\uc138\uc694!!**"},{"id":"/haejinyun/august-retrospect_haejin","metadata":{"permalink":"/front-end/haejinyun/august-retrospect_haejin","source":"@site/@frontEnd/haejinyun/august-retrospect_haejin.mdx","title":"QA\ub97c \ubcf4\ub2e4 \ud6a8\uacfc\uc801\uc73c\ub85c?","description":"8\uc6d4 \uc6d4\uac04 \ud68c\uace0 - QA\uc758 \ub2e4\uc591\ud55c \ubc29\uc2dd\uc744 \uc0b4\ud3b4\ubcf4\uace0 \uc801\uc808\ud55c \ubc29\uc2dd\uc744 \uace0\ubbfc\ud574\ubd05\uc2dc\ub2e4.","date":"2024-09-03T00:00:00.000Z","tags":[{"label":"\uc6d4\uac04 \ud68c\uace0","permalink":"/front-end/tags/\uc6d4\uac04-\ud68c\uace0"},{"label":"QA","permalink":"/front-end/tags/qa"}],"readingTime":17.855,"hasTruncateMarker":true,"authors":[{"name":"haejinyun","url":"https://github.com/haejinyun","email":"dbshaejin@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/86779590?v=4","key":"haejinyun"}],"frontMatter":{"date":"2024-09-03T00:00:00.000Z","authors":"haejinyun","title":"QA\ub97c \ubcf4\ub2e4 \ud6a8\uacfc\uc801\uc73c\ub85c?","description":"8\uc6d4 \uc6d4\uac04 \ud68c\uace0 - QA\uc758 \ub2e4\uc591\ud55c \ubc29\uc2dd\uc744 \uc0b4\ud3b4\ubcf4\uace0 \uc801\uc808\ud55c \ubc29\uc2dd\uc744 \uace0\ubbfc\ud574\ubd05\uc2dc\ub2e4.","keywords":["QA"],"tags":["\uc6d4\uac04 \ud68c\uace0","QA"]},"unlisted":false,"prevItem":{"title":"AB \ud14c\uc2a4\ud2b8 \uc5b4\ub5bb\uac8c \uc0dd\uc131\ud574\uc694?","permalink":"/front-end/posts/abTest-guide"},"nextItem":{"title":"staleTime\uacfc gcTime\uc774 \ubb54\uac00\uc694?","permalink":"/front-end/posts/react-query"}},"content":"QA\ub97c \ubcf4\ub2e4 \ud6a8\uc728\uc801\uc73c\ub85c?\\n\\n{/* truncate */}\\n\\nimport gifOne from \\"../../static/img/@frontEnd/august-retrospect_haejin/1.gif\\";\\nimport gifTwo from \\"../../static/img/@frontEnd/august-retrospect_haejin/2.gif\\";\\nimport gifThree from \\"../../static/img/@frontEnd/august-retrospect_haejin/3.gif\\";\\nimport gifFour from \\"../../static/img/@frontEnd/august-retrospect_haejin/4.gif\\";\\nimport gifFive from \\"../../static/img/@frontEnd/august-retrospect_haejin/5.gif\\";\\nimport gifSix from \\"../../static/img/@frontEnd/august-retrospect_haejin/6.gif\\";\\nimport gifSeven from \\"../../static/img/@frontEnd/august-retrospect_haejin/7.png\\";\\n\\n\\n\\n## \ub4e4\uc5b4\uac00\ub294 \ub9d0\\n<br/>\\nQA\ub780 \uc11c\ube44\uc2a4\uac00 \ubc30\ud3ec\ub418\uae30 \uc804 \uc0ac\uc6a9\uc790\uac00 \ub290\ub084 \uc218 \uc788\ub294 \ubd88\ud3b8\ud568 \ud639\uc740 \uc11c\ube44\uc2a4 \uc790\uccb4\uc5d0 \uae30\ub2a5\uc801 \uacb0\ud568\ub4f1\uc744 \ud655\uc778 \ud560 \uc218 \uc788\ub294 \ub9c8\uc9c0\ub9c9 \uad00\ubb38\uacfc \uac19\uc740 \uc5ed\ud560\uc744 \ud569\ub2c8\ub2e4. \uc774\ub294 \uc11c\ube44\uc2a4\uc758 \ud488\uc9c8\uc744 \ubcf4\uc7a5\ud558\uace0, \uc0ac\uc6a9\uc790\uac00 \uc548\uc815\uc801\uc774\uace0 \ub9cc\uc871\uc2a4\ub7ec\uc6b4 \uacbd\ud5d8\uc744 \ud560 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uc911\uc694\ud55c \ub2e8\uacc4\uc785\ub2c8\ub2e4. \ub9cc\uc57d QA\uac00 \uc628\uc804\ud788 \uc9c4\ud589\ub418\uc9c0 \uc54a\uace0 \uc0ac\uc6a9\uc790\uac00 \uc11c\ube44\uc2a4\ub97c \ub9c8\uc8fc\ud558\uac8c \ub41c\ub2e4\uba74, \uc11c\ube44\uc2a4\uc5d0 \ub300\ud55c \uc2e0\ub8b0\uac00 \ubb34\ub108\uc9c0\ub294 \ucd5c\uc545\uc744 \ub9de\uc774\ud560\uc9c0\ub3c4 \ubaa8\ub985\ub2c8\ub2e4. \uadf8\ub807\uae30 \ub54c\ubb38\uc5d0 QA\ub294 \uaf3c\uaf3c\ud558\uac8c, \uadf8\ub9ac\uace0 \uccb4\uacc4\uc801\uc73c\ub85c \uc9c4\ud589\ub418\uc5b4\uc57c \ud569\ub2c8\ub2e4. \uc774\uc5d0 \ub300\ud55c \uace0\ubbfc\uc758 \uacb0\uacfc\ub85c, QA \ud504\ub85c\uc138\uc2a4\ub97c \uac1c\uc120\ud558\uae30 \uc704\ud55c \uba87 \uac00\uc9c0 \ubc29\uc548\uc744 \uc0dd\uac01\ud558\uac8c \ub418\uc5c8\uc2b5\ub2c8\ub2e4.\\n<br/>\\n\\n<div style={{display: \'flex\', justifyContent: \'center\'}}>\\n<img src={gifOne} />\\n</div>\\n\\n<br/>\\n<br/>\\n\\n## \ud604\uc7ac BCSD\uc758 QA \ubc29\uc2dd\uc740?\\n<br/>\\n\uac01 \ud300(User, Campus, Business)\ubcc4 QA \ubc29\uc2dd\uc774 \uc870\uae08\uc529\uc740 \ubaa8\ub450 \ub2e4\ub974\uc9c0\ub9cc \uadf8 \uacb0\uc740 \uac19\ub2e4\uace0 \ub290\uaef4\uc84c\uc2b5\ub2c8\ub2e4.\\n\\n\uac01 \ud300\uc6d0\ub4e4\uc774 \ud2b9\uc815 \ud639\uc740 \uc5ec\ub7ec \uae30\ub2a5\uc5d0 \ub300\ud55c \ubaa8\ub4e0 \uacbd\uc6b0\uc758 \uc218\ub97c \uccb4\ud06c\ud558\uace0 \uc2e4\ud589\uc2dc\ucf1c \ubcf4\ub294 \ubc29\uc2dd\uc73c\ub85c \uc9c4\ud589\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4. \uc774\ub807\uac8c \ubc1c\uacac\ud55c \uc774\uc288\ub4e4\uc740 \ubaa8\ub450 \ubb38\uc11c\ud654\ub97c \ud1b5\ud574 \uacf5\uc720\ud558\uace0 \ud56b\ud53d\uc2a4\ub85c \uc989\uac01\uc801\uc73c\ub85c \ud574\uacb0\ud558\uac70\ub098, \ud544\uc694\uc5d0 \ub530\ub77c \ud6c4\uc18d \uc791\uc5c5\uc73c\ub85c \ucc98\ub9ac\ud558\uac8c \ub429\ub2c8\ub2e4.\\n<br/>\\n<div style={{display: \'flex\', justifyContent: \'center\'}}>\\n<img src={gifTwo} />\\n</div>\\n\\n<br/>\\n<br/>\\n\\n\uc774\ub7ec\ud55c \ubc29\uc2dd\uc740 \uac1c\ubcc4 \uae30\ub2a5\uc5d0 \ub300\ud55c \uc9d1\uc911\uc801\uc778 \ud14c\uc2a4\ud2b8\ub97c \uac00\ub2a5\ud558\uac8c \ud55c\ub2e4\ub294 \uc810\uc5d0\uc11c \uc774\uc810\uc774 \uc788\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uadf8\ub7ec\ub098 \ub3d9\uc2dc\uc5d0 \uc544\uc26c\uc6b4 \uc810\ub3c4 \uc874\uc7ac\ud569\ub2c8\ub2e4.\\n\\n- \uc758\ub3c4\uc640 \uc2e4\uc218\uc758 \uacbd\uacc4\uac00 \ubaa8\ud638\ud574 \uc9c8 \uc218 \uc788\ub2e4.\\n- \ubd88\ud544\uc694\ud55c \ub9ac\uc18c\uc2a4 \uc18c\ubaa8\\n- \uacbd\uc6b0\uc758 \uc218 \ud30c\uc545 \ubc0f \ubb38\uc11c\ud654 \uacfc\uc815\uc758 \uc2e4\uc218 \ubc1c\uc0dd\\n\\n\uc704 \ubb38\uc7a5\uc744 \uc870\uae08 \ud480\uc5b4\uc11c \uc608\uc2dc\uc640 \ud568\uaed8 \uc774\uc57c\uae30\ud574\ubcf4\ub824\uace0 \ud569\ub2c8\ub2e4.\\n\\n1. \uc758\ub3c4\ub41c \uae30\ub2a5\uc778\uc9c0 \uac1c\ubc1c \uacfc\uc815\uc5d0\uc11c\uc758 \uc2e4\uc218\uc778\uc9c0 \ud30c\uc545\ud558\uae30 \uc5b4\ub835\uc2b5\ub2c8\ub2e4.\\n    \\n    \uae30\ub2a5\uc758 \ub3d9\uc791\uc774 \uc0c1\uc0c1 \ud639\uc740 \uae30\ud68d(\uae30\ub2a5 \uba85\uc138)\uacfc \ub2e4\ub978 \uacbd\uc6b0, \uc774\uac83\uc774 \ucd94\ud6c4\uc5d0 \uc218\uc815\uc774 \ub41c \ubd80\ubd84\uc778\uc9c0 \uc624\ub958\uc778\uc9c0\ub97c \ud30c\uc545\ud558\uae30 \uc704\ud574 \ubd88\ud544\uc694\ud55c \uc2dc\uac04\uc774 \ub4e4\uc5b4\uac08 \uac83\uc785\ub2c8\ub2e4. QA\uc5d0 \uac1c\ubc1c\uc5d0 \ucc38\uc5ec\ud55c \ubaa8\ub4e0 \uc778\uc6d0\uacfc \ud568\uaed8 \uc9c4\ud589\ud574\uc57c\ud558\uc9c0\ub9cc \uadf8\ub7ec\uc9c0 \ubabb\ud560 \ub54c\ub97c \uc0dd\uac01\ud55c\ub2e4\uba74, \ud574\ub2f9 \uae30\ub2a5\uc758 Issue, PR, \uad00\ub828 \uc18c\ud1b5 \uae30\ub85d \ub4f1\uc744 \ubcf4\uba70 \uc2e4\uc218\uc778\uc9c0 \uc218\uc815\ub41c \uae30\ud68d\uc778\uc9c0\ub97c \ud30c\uc545\ud574\uc57c \ud560 \uac83\uc785\ub2c8\ub2e4.\\n    \\n2. \ubd88\ud544\uc694\ud55c \ub9ac\uc18c\uc2a4 \uc18c\ubaa8\\n    \\n    1\ubc88\uc5d0\uc11c \ub9d0\ud55c \ubb38\uc81c\uc810\uc774 \ubc1c\uc0dd\ud588\uc744 \uacbd\uc6b0 \uc774\ub97c \ud574\uacb0\ud558\uae30 \uc704\ud574 \ub2f4\ub2f9\uc790\ub97c \ucc3e\uace0 \ucee4\ubba4\ub2c8\ucf00\uc774\uc158\ud558\ub294 \ube44\uc6a9\uc774 \ubc1c\uc0dd\ud560 \uac83\uc785\ub2c8\ub2e4. \uc774\ub294 \uc804\uccb4\uc801\uc778 \uc11c\ube44\uc2a4\uc758 \ubc30\ud3ec \uae30\uac04\uc744 \ub51c\ub808\uc774 \uc2dc\ud0ac\uc218\ub3c4 \uc788\uc73c\uba70, \ubd88\ud544\uc694\ud55c \uc218\uc815\ub4f1\uc744 \uc57c\uae30\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n3. \uacbd\uc6b0\uc758 \uc218 \ud30c\uc545 \ubc0f \ubb38\uc11c\ud654 \uacfc\uc815\uc758 \uc2e4\uc218 \ubc1c\uc0dd\\n    \\n    \ubaa8\ub4e0 \uacbd\uc6b0\uc758 \uc218\ub97c \ud30c\uc545\ud55c\ub2e4\ub294 \uac83\uc740 \uc0dd\uac01\ubcf4\ub2e4 \ub9e4\uc6b0 \uc5b4\ub824\uc6b4 \uc77c\uc77c \uac83\uc785\ub2c8\ub2e4. \ube7c\uba39\ub294 \uacbd\uc6b0\ub3c4 \uc788\uc744 \uac83\uc774\uba70, \ubb38\uc11c\ud654 \uacfc\uc815\uc5d0\uc11c \ub204\ub77d\ub418\ub294 \ubd80\ubd84\ub3c4 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4. \uc5ec\ub7ec\uba85\uc5d0\uc11c \ubaa8\ub4e0 \uc0ac\ud56d\uc744 \ubb38\uc11c\ud654 \ud55c\ub2e4 \ud558\ub354\ub77c\ub3c4 \uc774\uac83\uc744 \uac80\ud1a0\ud558\uace0 \uad00\ub9ac\ud558\ub294 \uc5b4\ub5a4 \ucd94\uac00\uc801\uc778 \ub9ac\uc18c\uc2a4\uac00 \ud544\uc694\ud560 \uac83\uc785\ub2c8\ub2e4.\\n    \\n\\n\uc704\uc640 \uac19\uc740 \ubb38\uc81c\uc810\uc744 \uc0b4\ud3b4\ubcf4\uba74, \ud604\uc7ac\uc758 QA \ubc29\uc2dd\uc774 \uc644\uc804\ud788 \ud6a8\uacfc\uc801\uc774\uc9c0\ub9cc\uc740 \uc54a\ub2e4\ub294 \uac83\uc744 \ub290\ub084 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ub4e4\uc5b4\uac00\ub294 \ub9d0\uc5d0\uc11c \uc774\uc57c\uae30 \ud588\ub358 \uac83 \ucc98\ub7fc QA\ub294 \uc11c\ube44\uc2a4\uac00 \ubc30\ud3ec \ub418\uae30 \uc804 \ub9c8\uc9c0\ub9c9 \ub2e8\uacc4\ub85c \uc791\uc740 \ube48\ud2c8\uc774 \uc11c\ube44\uc2a4\uc758 \uc2e0\ub8b0\ub3c4\uc640 \uc9c1\uacb0\ub418\uc5b4 \uc788\uc2b5\ub2c8\ub2e4. \uadf8\ub807\uae30\uc5d0 \ubaa8\ub450\uac00 \ub354 \uc2e0\uacbd\uc744 \uace4\ub450\uc138\uc6b0\uace0 \uc9c4\ud589\ub420 \uac83\uc785\ub2c8\ub2e4. \uc774\ub7f0 \uc2a4\ud2b8\ub808\uc2a4 \uac15\ub3c4\uac00 \ub192\uc740 \uc791\uc5c5\uc744 \ub2e4\ub978 \ubc29\ud5a5\uc73c\ub85c \uc811\uadfc\ud558\uc5ec \uc704\uc640 \uac19\uc740 \ubb38\uc81c\uc810\uc744 \ud574\uacb0\ud560 \uc218 \uc788\ub294 \ubc29\uc2dd\uc744 \ubaa8\uc0c9\ud560 \ud544\uc694\uac00 \uc788\ub2e4\uace0 \ub290\uaf08\uc2b5\ub2c8\ub2e4.\\n<br/>\\n<div style={{display: \'flex\', justifyContent: \'center\'}}>\\n<img src={gifThree} />\\n</div>\\n\\n<br/>\\n<br/>\\n## \uc778\uc218 \ud14c\uc2a4\ud2b8\ub780?\\n<br/>\\n\uc55e\uc120 \ubb38\uc81c\ub97c \uac1c\uc120\ud558\uae30 \uc704\ud574 \uc800\ub294 \u201c\uc778\uc218 \ud14c\uc2a4\ud2b8\u201d\ub77c\ub294 \uc811\uadfc \ubc29\uc2dd\uc744 \uc0dd\uac01\ud574\ubcf4\uc558\uc2b5\ub2c8\ub2e4. \\n\\n\uc778\uc218 \ud14c\uc2a4\ud2b8\\n\\n: \uc0ac\uc6a9\uc790\uac00 \uc2e4\uc81c \uc11c\ube44\uc2a4\ub97c \uc0ac\uc6a9\ud558\ub294 \uac83 \ucc98\ub7fc \uc2e4\uc81c \uc0ac\uc6a9 \uc2dc\ub098\ub9ac\uc624\ub97c \uae30\ubc18\uc73c\ub85c \uae30\ub2a5\uc744 \ud14c\uc2a4\ud2b8\ud558\ub294 \ubc29\ubc95\\n\\n\ub2e8\uc21c\ud788 \uac1c\ubcc4 \uae30\ub2a5\uc758 \ub3d9\uc791\uc744 \ud655\uc778\ud558\ub294 \uac83\uc744 \ub118\uc5b4, \uc11c\ube44\uc2a4\uac00 \uc804\uccb4\uc801\uc73c\ub85c \uc608\uc0c1\ub300\ub85c \ub3d9\uc791 \ud558\ub294\uc9c0 \uac80\uc99d\ud558\ub294\ub370 \uc911\uc810\uc744 \ub461\ub2c8\ub2e4. \uc778\uc218\ud14c\uc2a4\ud2b8\ub294 \ub098\uc544\uac00 \uc11c\ube44\uc2a4 \uc720\uc800 \uc800\ub2c8\ub9f5\uc744 \uadf8\ub9b4 \uc218 \uc788\ub294 \uae30\ud68c\ub3c4\ub85c \uc791\uc6a9\ud569\ub2c8\ub2e4. \uc774\ub97c \ud1b5\ud574 \uc0ac\uc6a9\uc790\uc758 \ud750\ub984\uc744 \uc608\uce21\ud558\uace0 \uadf8 \ud750\ub984\uc5d0 \uc774\uc0c1\uc774 \uc5c6\ub294\uc9c0 \ud655\uc778\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \\n\\n\uc608\ub97c \ub4e4\uc5b4 \\n\\n1. \uc720\uc800\uac00 \ud68c\uc6d0\uac00\uc785\uc744 \ud569\ub2c8\ub2e4.\\n    1. \uc544\uc774\ub514 \uc785\ub825\\n    2. \ube44\ubc00\ubc88\ud638\uc785\ub825\\n    3. \ube44\ubc00\ubc88\ud638 \uc7ac \uc785\ub825\\n        \\n        \u2026\\n        \\n2. \uc720\uc800\uac00 \ub85c\uadf8\uc778\uc744 \ud569\ub2c8\ub2e4.\\n3. \uba54\uc778 \ud398\uc774\uc9c0\uc5d0 \ub3c4\ucc29\ud569\ub2c8\ub2e4.\\n4. \ubcf5\ub354\ubc29\uc5d0 \ub4e4\uc5b4\uac11\ub2c8\ub2e4.\\n    \\n    \u2026\\n    \\n\\n\uc774\ub807\uac8c \uc2dc\ub098\ub9ac\uc624\ub97c \uae30\ubc18\uc73c\ub85c \ud558\uba74, 1\ucc28\uc801\uc778 \uae30\ub2a5 \ud14c\uc2a4\ud2b8\uac00 \ubcf4\ub2e4 \uccb4\uacc4\uc801\uc774\uace0 \uc21c\uc870\ub86d\uac8c \uc9c4\ud589 \ub420 \uac83\uc785\ub2c8\ub2e4.\\n\\n(\ub9c8\uce58 \ucc38\uad50 \uad50\uc7ac\ucc98\ub7fc \ubcf4\uace0 \ub530\ub77c\uac08 \uc694\uc18c\uac00 \uc0dd\uae34\ub2e4!)\\n<br/>\\n<div style={{display: \'flex\', justifyContent: \'center\'}}>\\n<img src={gifFour} />\\n</div>\\n\\n<br/>\\n<br/>\\n\ub2e8\uc21c\ud788 \ucf54\ub4dc\uc758 \uc624\ub958\ub97c \ucc3e\ub294 \uac83\uc5d0\uc11c \ub098\uc544\uac00, \uc2dc\uc2a4\ud15c\uc774 \uc2e4\uc81c \uc0ac\uc6a9\uc790\uc5d0\uac8c \uc81c\uacf5\ub418\ub294 \uc21c\uac04\ub4e4\uc744 \uc810\uac80\ud560 \uc218 \uc788\ub294 \uac83\uc774 \uc778\uc218 \ud14c\uc2a4\ud2b8\uc758 \uac15\uc810\uc785\ub2c8\ub2e4. \ub610\ud55c, \uc5ec\uae30\uc11c \uc57d\uac04\uc758 \ubc14\ub9ac\uc5d0\uc774\uc158\uc744 \uc900\ub2e4\uba74, \uc0ac\uc6a9\uc790\uac00 \uac11\uc791\uc2a4\ub7fd\uac8c \ud589\ud558\ub294 \uac1c\ubc1c\uc790\uac00 \uc608\uc0c1\ud558\uc9c0 \ubabb\ud55c \ub3d9\uc791\uc744 \uc2dc\ub098\ub9ac\uc624 \ucd08\uae30 \ub2e8\uacc4\uc5d0\uc11c \ud070 \ubd80\ub2f4 \uc5c6\uc774 \uc608\uce21\ud558\uace0 \ud14c\uc2a4\ud2b8\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc774\ub85c\uc368 \ub2e4\uc591\ud55c \uc0c1\ud669\uc5d0 \ub300\ud55c \ub300\ube44\ub3c4 \uac00\ub2a5\ud574\uc9c0\uba70, \ubcf4\ub2e4 \uc548\uc815\uc801\uc778 \uc11c\ube44\uc2a4 \uc81c\uacf5\uc774 \uac00\ub2a5\ud574\uc9c8 \uac83\uc785\ub2c8\ub2e4.\\n<br/>\\n<br/>\\n## \uc778\uc218 \ud14c\uc2a4\ud2b8\ub97c BCSD\uc5d0 \ub179\uc778\ub2e4\uba74?\\n<br/>\\n\ud55c\ud3b8\uc73c\ub85c\ub294 \\"\uc774\ubbf8 \uae30\ud68d\uc774 \uc9dc\uc5ec \uc788\ub294\ub370 \uc2dc\ub098\ub9ac\uc624\uac00 \uc65c \ud544\uc694\ud558\uc9c0? \uc2dc\ub098\ub9ac\uc624\uac00 \ud604\uc7ac \uae30\ud68d\uacfc \ubb34\uc5c7\uc774 \ub2e4\ub978 \uac70\uc9c0?\\"\ub77c\ub294 \uc0dd\uac01\uc774 \ub4e4 \uc218\ub3c4 \uc788\uc2b5\ub2c8\ub2e4.\\n<br/>\\n<div style={{display: \'flex\', justifyContent: \'center\'}}>\\n<img src={gifFive} />\\n</div>\\n<br/>\\n<br/>\\n\uadf8\ub7ec\ub098 \uc2dc\ub098\ub9ac\uc624\ub780 \ucd08\uae30 \uae30\ud68d\uc774 \uc218\uc815\ub418\uac70\ub098, \uac1c\ubc1c\uc744 \uc9c4\ud589\ud558\uba74\uc11c \\"\uc774\uac74 \ub2e4\uc74c PR\uc5d0\uc11c \ud574\uc57c\uc9c0~\\"\ud558\uba74\uc11c \ub193\uce58\ub294 \ubd80\ubd84\ub4e4\uc744 \ubcf4\uc644\ud560 \uc218 \uc788\ub294 \uc911\uc694\ud55c \ub3c4\uad6c\uc785\ub2c8\ub2e4. \uc774\ub7ec\ud55c \uc694\uc18c\ub4e4\uc744 \ub530\ub85c \uc544\uce74\uc774\ube59\ud558\uace0, \uae30\ud68d \ubb38\uc11c\uc5d0 \uc989\uc2dc \ubc18\uc601\ud560 \uc218 \uc788\ub2e4\uba74, \uadf8 \uae30\ud68d \ubb38\uc11c \ucc28\uc81c\uac00 \uc2dc\ub098\ub9ac\uc624\ub85c\uc11c \uc644\uc131\ub420 \uc218 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4. \uadf8\ub7ec\ub098 \uc6b0\ub9ac\uc758 \uac1c\ubc1c \uc0c1\ud669 \uc18d\uc5d0\uc11c \uc774\ub97c \uccb4\uacc4\uc801\uc73c\ub85c \uad00\ub9ac\ud558\ub294 \uac83\uc740 \uc27d\uc9c0 \uc54a\uc744 \uac83\uc785\ub2c8\ub2e4.\\n\\n\uadf8\ub807\ub2e4\uba74, \uacc4\uc18d \uc5b8\uae09\ud558\uace0 \uc788\ub294 \uc2dc\ub098\ub9ac\uc624\ub294 \u201c\ub204\uac00 \uc5b4\ub290 \uc2dc\uc810\uc5d0 \uc368\uc57c\ud558\ub294 \uac83\uc774\ub0d0!\u201d\ub77c\uace0 \uc0dd\uac01\uc774 \ub4e4 \uac83\uc785\ub2c8\ub2e4.\\n\\n\uc81c\uac00 \uc0dd\uac01\ud558\ub294 \ucd5c\uc801\uc758 \uc2dc\uc810\uc744 PR\uc744 \uc791\uc131\ud560 \ub54c\ub77c\uace0 \uc0dd\uac01\ud569\ub2c8\ub2e4. \uc2e4\uc81c\ub85c \uac1c\ubc1c\ud55c \ub0b4\uc6a9\uc744 \uac00\uc7a5 \uc0dd\uc0dd\ud558\uac8c \uae30\uc5b5\ud558\ub294 \uc2dc\uc810\uc774\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4.(\ubb38\uc11c\ud654\uc5d0\uc11c \uac00\uc7a5 \uc911\uc694\ud55c \uac83\uc740 \ubbf8\ub8e8\uc9c0 \uc54a\uae30\u2026) \\n\\n\uae30\ud68d\ub41c \ubd80\ubd84\uc5d0\uc11c \uc5b4\ub514\ub97c \uc5b4\ub5bb\uac8c \uac1c\ubc1c\ud588\ub294\uc9c0, \ud2b9\uc774\uc0ac\ud56d\uc774 \uc788\ub2e4\uba74 \uadf8\uac83\uc744 \uc2dc\ub098\ub9ac\uc624 \ubb38\uc11c\uc5d0 \ubc14\ub85c \uae30\ub85d\ud569\ub2c8\ub2e4. \uc774\ub807\uac8c \ub2e4\uc591\ud55c \uae30\ub2a5\ub4e4\uc758 \uac1c\ubc1c \uacfc\uc815\uc774 \uc2dc\ub098\ub9ac\uc624 \ubb38\uc11c\uc5d0 \ucd94\uac00\ub418\uba74, \uc2e4\uc81c \uc791\uc5c5 \ub0b4\uc6a9\uc744 \ubc18\uc601\ud55c \uc2e4\uc9c8\uc801\uc778 \ubb38\uc11c\uac00 \uc644\uc131\ub429\ub2c8\ub2e4. \uc774 \ubb38\uc11c\uc5d0\ub294 \ubc14\ub010 \uae30\ud68d \ubc0f \ud2b9\uc774\uc0ac\ud56d\uc774 \ubaa8\ub450 \ub179\uc544\ub4e4\uc5b4 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4. \uacb0\uacfc\uc801\uc73c\ub85c, \uc774 \ubb38\uc11c\ub294 \uc2e4\uc81c\uc801\uc778 \uc720\uc800 \uc800\ub2c8\ub9f5\uc774 \ub420 \uac83\uc774\uace0, \uc774\ub294 \uae30\ud68d\uacfc \uac1c\ubc1c\uc758 \ubb34\uacb0\uc131\uc744 \uc720\uc9c0\uc2dc\ud0ac \uc218 \uc788\ub294 \uc694\uc18c\uc77c \uac83\uc785\ub2c8\ub2e4. \\n\\n(\uc774\ud6c4 \ub9c8\ucf00\ud305 \uc6a9 \ud639\uc740 \ub2e4\uc591\ud55c \ub85c\uae45\uc744 \ucc0d\uc744 \ub54c\ub098 DA \ud30c\ud2b8\uc5d0\uc11c\ub3c4 \ud65c\uc6a9 \uac00\ub2a5 \uc608\uc0c1)\\n\\nQA\ub97c \uc9c4\ud589\ud560 \ub54c\ub294 \uc774 \uc2dc\ub098\ub9ac\uc624 \ubb38\uc11c\ub97c \ud65c\uc6a9\ud558\uc5ec \uc2a4\ud1a0\ub9ac\ub77c\uc778\uc744 \ub530\ub77c\uac00\uba70, \uc0ac\uc6a9\uc790\uac00 \uc758\ub3c4\ub41c \ud750\ub984\ub300\ub85c \uc11c\ube44\uc2a4\ub97c \uc774\uc6a9\ud558\ub294 \ub370 \ubb38\uc81c\uac00 \uc5c6\ub294\uc9c0 \ud655\uc778\ud560 \uc218 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4. \uc774\ud6c4\uc5d0\ub294 \ub2e4\uc591\ud55c \uc0ac\uc6a9\uc790\uc758 \ud589\ub3d9\uc744 \ud1b5\ud574 \uc5e3\uc9c0 \ucf00\uc774\uc2a4\ub97c \ud655\uc778\ud558\uace0, \uc11c\ube44\uc2a4\uc758 \uacac\uace0\ud568\uc744 \ud655\ubcf4\ud558\ub294 \uc791\uc5c5\uc744 \uc9c4\ud589\ud560 \uc218 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4.\\n\\n<br/>\\n<div style={{display: \'flex\', justifyContent: \'center\'}}>\\n<img src={gifSix} />\\n</div>\\n\\n<br/>\\n<br/>\\n## \uc131\uacf5\uc801\uc778 \ud14c\uc2a4\ud2b8\ub97c \uc704\ud574\uc11c \ub178\ub825\ud574\uc57c \ud558\ub294 \uc810?\\n<br/>\\n\uacbd\uc6b0\uc758 \uc218\ub97c \ud30c\uc545\ud558\uace0 \uc2dc\ub098\ub9ac\uc624\ub97c \uc791\uc131\ud558\ub294 \uacfc\uc815\uc774 \uac1c\ubc1c \uae30\uac04\uc744 \uc9c0\uc5f0\uc2dc\ud0a8\ub2e4\uba74, \uc774\ub294 \uc624\ud788\ub824 \ud14c\uc2a4\ud2b8\ub97c \ud558\uc9c0 \uc54a\ub294 \uac83\ub9cc \ubabb\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ub610\ud55c, \uac1c\ubc1c\uc790\uac00 \uace0\ub824\ud558\ub294 \uacbd\uc6b0\uc758 \uc218\uac00 \ub108\ubb34 \ub2e8\uc870\ub85c\uc6cc\uc11c \ud14c\uc2a4\ud2b8\uac00 \ucda9\ubd84\ud788 \ud6a8\uacfc\uc801\uc774\uc9c0 \uc54a\uc744 \uc218\ub3c4 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uadf8\ub7ec\ub098 \uc870\uae08 \ub354 \uae4a\uc774 \uc0dd\uac01\ud574\ubcf4\uba74, PR\uc5d0 \ubcc0\uacbd \uc0ac\ud56d\uc744 \uac78\uc5b4 \ucf54\ub4dc \ub9ac\ubdf0 \uc2dc \ub0b4\uac00 \uc911\uc810\uc801\uc73c\ub85c \ud655\uc778\ud574\uc57c \ud560 \uac83\ub4e4\uc744 \uc801\ub294 \uac83\uc774 \uc911\uc694\ud569\ub2c8\ub2e4. \uac1c\ubc1c\uc790\ub294 \uae30\ub2a5 \uba85\uc138\ub97c \uae30\ubc18\uc73c\ub85c \uc791\uc5c5\uc744 \uc9c4\ud589\ud558\ubbc0\ub85c, \uc774 \uba85\uc138\ub97c \ubc14\ud0d5\uc73c\ub85c \uc2e4\uc81c\ub85c \uac1c\ubc1c\ud55c \ub0b4\uc6a9\uacfc \uac1c\ubc1c \uc911 \ubc1c\uc0dd\ud55c \ubcc0\uacbd \uc0ac\ud56d\uc744 \uae30\ub85d\ud558\uba74 \ub429\ub2c8\ub2e4. \uc774\ub97c \ud1b5\ud574 \uc2dc\ub098\ub9ac\uc624\uc5d0 \ub300\ud55c \ubd80\ub2f4\uc744 \uc904\uc774\uba70 \uc2e4\uc81c \uac1c\ubc1c \ub0b4\uc6a9\ub9cc\uc744 \uc815\uc81c\ud574 \ub098\uac08 \uc218 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4.\\n\\n\ud558\uc9c0\ub9cc \ubaa8\ub4e0 \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c \uc774\ub7ec\ud55c \uc811\uadfc \ubc29\uc2dd\uc774 \uc801\ud569\ud558\uc9c0\ub294 \uc54a\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc608\ub97c \ub4e4\uc5b4:\\n\\n- **\uc218\uc815\uc774 \uc7a6\uc9c0 \uc54a\uc740 \uc5b4\ub4dc\ubbfc**: \uc5b4\ub4dc\ubbfc \ud398\uc774\uc9c0\ub294 \uc77c\ubc18\uc801\uc73c\ub85c \uc548\uc815\ub41c \uae30\ub2a5\uc744 \uc81c\uacf5\ud558\uba70, \uc0ac\uc6a9\uc790 \uc778\ud130\ud398\uc774\uc2a4\uc640 \uc0c1\ud638\uc791\uc6a9\uc774 \ubcf5\uc7a1\ud558\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4. \uc774\ub7ec\ud55c \uacbd\uc6b0, **E2E(End-to-End) \ud14c\uc2a4\ud2b8**\uac00 \uc801\ud569\ud569\ub2c8\ub2e4. E2E \ud14c\uc2a4\ud2b8\ub294 \uc0ac\uc6a9\uc790\uac00 \uc2e4\uc81c\ub85c \uc2dc\uc2a4\ud15c\uc744 \uc0ac\uc6a9\ud558\ub294 \uac83\ucc98\ub7fc \uc804\uccb4 \ud750\ub984\uc744 \uc2dc\ubbac\ub808\uc774\uc158\ud558\uc5ec, \uc2dc\uc2a4\ud15c\uc774 \ucc98\uc74c\ubd80\ud130 \ub05d\uae4c\uc9c0 \uc608\uc0c1\ub300\ub85c \ub3d9\uc791\ud558\ub294\uc9c0 \ud655\uc778\ud569\ub2c8\ub2e4. \uc5b4\ub4dc\ubbfc \ud398\uc774\uc9c0\uc640 \uac19\uc774 \ud070 \ubcc0\ud654\uac00 \uc790\uc8fc \uc77c\uc5b4\ub098\uc9c0 \uc54a\ub294 \uacbd\uc6b0, E2E \ud14c\uc2a4\ud2b8\ub97c \ud1b5\ud574 \uc8fc\uc694 \uae30\ub2a5\ub4e4\uc774 \uc608\uc0c1\ub300\ub85c \uc791\ub3d9\ud558\ub294\uc9c0 \uac80\uc99d\ud558\uba74 \ud6a8\uc728\uc801\uc785\ub2c8\ub2e4.\\n- **\uc218\uc815\uc774 \ub9ce\uc740 \uacf5\uc6a9 \ud328\ud0a4\uc9c0\ub098 \uc720\ud2f8**: \uacf5\uc6a9 \ud328\ud0a4\uc9c0\ub098 \uc720\ud2f8\ub9ac\ud2f0\ub294 \uc790\uc8fc \uc218\uc815\ub418\uba70, \uc5ec\ub7ec \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c \uc7ac\uc0ac\uc6a9\ub418\uae30 \ub54c\ubb38\uc5d0 \uc548\uc815\uc131\uc774 \ub9e4\uc6b0 \uc911\uc694\ud569\ub2c8\ub2e4. \uc774\ub7ec\ud55c \uacbd\uc6b0, **\uc778\uc218 \ud14c\uc2a4\ud2b8**\ub97c \ud1b5\ud574 \uac01 \uae30\ub2a5\uc774 \uba85\uc138\ub300\ub85c \ub3d9\uc791\ud558\ub294\uc9c0 \uaf3c\uaf3c\ud788 \ud655\uc778\ud574\uc57c \ud569\ub2c8\ub2e4. \uc778\uc218 \ud14c\uc2a4\ud2b8\ub294 \uae30\ub2a5\uc758 \uc138\ubd80\uc801\uc778 \ub3d9\uc791\uc744 \uac80\uc99d\ud558\ub294 \ub370 \uc911\uc810\uc744 \ub450\ubbc0\ub85c, \uc790\uc8fc \ubcc0\uacbd\ub418\uba74\uc11c\ub3c4 \uc2e0\ub8b0\uc131\uc774 \ud544\uc694\ud55c \ucf54\ub4dc\uc5d0 \uc801\ud569\ud569\ub2c8\ub2e4.\\n- **\uc720\uc800\uc758 \ud750\ub984\uacfc \uc11c\ube44\uc2a4\uc758 \ub3d9\uc791 \uacfc\uc815\uc774 \uc911\uc694\ud55c \uacbd\uc6b0**: \uc0ac\uc6a9\uc790\uac00 \uc11c\ube44\uc2a4\ub97c \uc774\uc6a9\ud558\ub294 \uc804\uccb4\uc801\uc778 \ud750\ub984\uc774 \uc911\uc694\ud55c \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc5d0\uc11c\ub294, E2E \ud14c\uc2a4\ud2b8\uc640 \uc778\uc218 \ud14c\uc2a4\ud2b8\ub97c \uc801\uc808\ud788 \ubcd1\ud589\ud558\uc5ec \uc0ac\uc6a9\ud569\ub2c8\ub2e4. E2E \ud14c\uc2a4\ud2b8\ub85c \ud070 \uadf8\ub9bc\uc744 \uac80\uc99d\ud558\uba74\uc11c, \uc778\uc218 \ud14c\uc2a4\ud2b8\ub85c \uc138\ubd80\uc801\uc778 \uae30\ub2a5\uc744 \ud655\uc778\ud558\uc5ec \uc11c\ube44\uc2a4\uc758 \uacac\uace0\ud568\uc744 \ud655\ubcf4\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uac01 \ud504\ub85c\uc81d\ud2b8\ub9c8\ub2e4 \ud2b9\uc131\uc774 \uc870\uae08\uc529\uc740 \ub2e4\ub985\ub2c8\ub2e4. \ub530\ub77c\uc11c \uc801\uc808\ud55c QA\ubc0f \ud14c\uc2a4\ud2b8 \ubc29\ubc95\uc744 \uace0\ubbfc\ud558\uace0 \ub3c4\uc785\ud574\ubcf4\ub294 \uac83\uc774 \ubcf4\ub2e4 \uc548\uc815\uc801\uc778 \uc11c\ube44\uc2a4\ub97c \uc81c\uacf5\ud558\uae30 \uc704\ud574\uc11c \uc911\uc694\ud560 \uac83\uc785\ub2c8\ub2e4. \\n\\n## \ub9c8\ubb34\ub9ac \ub9d0\\n\\n\ud604\uc7ac \ubd80\ud2b8\ucea0\ud504\uc5d0\uc11c \ud504\ub85c\uc81d\ud2b8\ub97c \uc9c4\ud589\ud558\uba70, QA\ub97c \uc9c4\ud589\ud574\uc57c\ud558\ub294 \uc21c\uac04\uc774 \uc788\uc5c8\uc2b5\ub2c8\ub2e4. \uadf8\ub7ec\ub098 BCSD \uac1c\ubc1c\ubcf4\ub2e4 \ud6e8\uc52c \ube60\ub974\uac8c \uc9c4\ud589\ub418\ub294 \uc77c\uc815 \uc18d\uc5d0\uc11c \ud504\ub85c\uc81d\ud2b8 \uba58\ud1a0\ub2d8\uaed8 \uc801\uc808\ud55c QA \uae30\uac04\uc5d0 \ub300\ud574 \uc9c8\ubb38\ud55c \uc801\uc774 \uc788\uc5c8\uc2b5\ub2c8\ub2e4. \uadf8\ub54c \uba58\ud1a0\ub2d8\uc740 QA\ub97c \ud2b9\uc815 \uae30\uac04\uc5d0 \ubab0\uc544\uc11c \ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c, \uae30\ub2a5\ub9c8\ub2e4 QA\ub97c \uc9c4\ud589\ud55c\ub2e4\uace0 \uc9c4\ud589\ud574\uc57c \ud55c\ub2e4\uace0 \uc870\uc5b8\ud558\uc168\uc2b5\ub2c8\ub2e4. \uadf8\ub9ac\uace0 \uc774\uc640 \uad00\ub828\ud558\uc5ec \\"\uc778\uc218 \ud14c\uc2a4\ud2b8\\"\ub77c\ub294 \uac1c\ub150\uc744 \uc5b8\uae09\ud558\uc168\uc2b5\ub2c8\ub2e4. \\n\\n\uae30\ub2a5\ub9c8\ub2e4 \uc2dc\ub098\ub9ac\uc624\ub97c \uc791\uc131\ud574 \uc544\uce74\uc774\ube59\ud574\ub450\uace0, \ub9c8\uc9c0\ub9c9 QA \ub54c\uc5d0\ub294 \ud574\ub2f9 \uc2dc\ub098\ub9ac\uc624\ub97c \ud65c\uc6a9\ud558\uc5ec \ubbf8\ub9ac \uc900\ube44\ub41c\ub300\ub85c \ud14c\uc2a4\ud2b8\ub97c \uc9c4\ud589\ud558\ub294 \ubc29\ud5a5\uc744 \ucd94\ucc9c\ud558\uc168\uc2b5\ub2c8\ub2e4. \ucc98\uc74c\uc5d0\ub294 \u201c\uc2dc\ub098\ub9ac\uc624\uac00 \uae30\ud68d\uc774\ub791 \ubb34\uc5c7\uc774 \ub2e4\ub974\uc9c0?\u201c\ub77c\ub294 \uc0dd\uac01\uc774\uc5c8\uc9c0\ub9cc, \ud574\ub2f9 \ubb38\uc7a5\uc744 \uacf1\uc539\uc73c\uba70 \uc2e4\uc81c \uac1c\ubc1c \uc0c1\ud669\uc774\ub791 \ube44\uad50\ud574 \ubcf4\ub2c8 \uc2dc\ub098\ub9ac\uc624\uc758 \ud544\uc694\uc131\uc744 \ub290\ub07c\uac8c \ub418\uc5c8\uc2b5\ub2c8\ub2e4. \\n\\n\uae30\ud68d\ub300\ub85c \uc774\ub8e8\uc5b4\uc9c0\ub294 \uac1c\ubc1c\uc740 \uc874\uc7ac\ud558\uc9c0 \uc54a\uc744 \uac83\uc785\ub2c8\ub2e4. (\ub2e4\uc591\ud55c \uc6d0\uc778\uc73c\ub85c \uae30\ud68d\uc774 \ub2e4\uc774\uc5b4\ud2b8\ub97c \ud558\uae30\ub3c4 \uc0b4\uc774 \ucc0c\uae30\ub3c4 \ud558\uc8e0..^^)\\n<br/>\\n<div style={{display: \'flex\', justifyContent: \'center\'}}>\\n<img src={gifSeven} />\\n</div>\\n<br/>\\n<br/>\\n\ub2e4\uc591\ud55c \uac1c\ubc1c \ud658\uacbd\uc5d0\uc11c \uc801\uc808\ud55c \ubb38\uc11c\ud654\uc640 \ud2b9\uc131\uc5d0 \uc54c\ub9de\ub294 \ud14c\uc2a4\ud2b8 \ubc29\ubc95\uc774 \uc774\ud6c4 QA\uc758 \ubd80\ub2f4\uc744 \uc904\uc5ec\uc904 \uc218 \uc788\ub294 \ud55c\uc904\uae30\uc758 \ube5b\uc77c \uc218\ub3c4 \uc788\uaca0\ub2e4!\ub77c\ub294 \uc0dd\uac01\uc774 \ub418\uc5b4 \uae00\uc744 \uc791\uc131\ud574\ubcf4\uc558\uc2b5\ub2c8\ub2e4. \\n\\n\uc774\ubc88 \uae30\ud68c\ub85c \uc9c0\uae08 \ud558\uace0 \uc788\ub294 \ud504\ub85c\uc81d\ud2b8\uc5d0\ub294 \uc5b4\ub5a4 \ubc29\uc2dd\uc774 \ub354 \uc5b4\uc6b8\ub9ac\uace0 \ud6a8\uc728\uc801\uc77c\uc9c0 \uace0\ubbfc\ud574\ubcf4\uba74 \uc88b\uaca0\uc2b5\ub2c8\ub2e4!"},{"id":"/posts/react-query","metadata":{"permalink":"/front-end/posts/react-query","source":"@site/@frontEnd/posts/react-query.mdx","title":"staleTime\uacfc gcTime\uc774 \ubb54\uac00\uc694?","description":"@tanstack/react-query\uc758 swr\ubc29\uc2dd\uc5d0 \ub300\ud55c \uc124\uba85\uc785\ub2c8\ub2e4.","date":"2024-08-31T00:00:00.000Z","tags":[{"label":"react-query","permalink":"/front-end/tags/react-query"}],"readingTime":7.715,"hasTruncateMarker":true,"authors":[{"name":"WonBeen Choi","url":"https://github.com/ChoiWonBeen","email":"chldnjsqls1264@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/50780281?v=4","key":"ChoiWonBeen"}],"frontMatter":{"date":"2024-8-31","authors":"ChoiWonBeen","title":"staleTime\uacfc gcTime\uc774 \ubb54\uac00\uc694?","description":"@tanstack/react-query\uc758 swr\ubc29\uc2dd\uc5d0 \ub300\ud55c \uc124\uba85\uc785\ub2c8\ub2e4.","keywords":["react-query"],"tags":["react-query"]},"unlisted":false,"prevItem":{"title":"QA\ub97c \ubcf4\ub2e4 \ud6a8\uacfc\uc801\uc73c\ub85c?","permalink":"/front-end/haejinyun/august-retrospect_haejin"},"nextItem":{"title":"BCSDLab\uc740 \ubb50\ud558\ub294 \ub3d9\uc544\ub9ac\uc77c\uae4c?","permalink":"/front-end/posts/july-retrospect_daepan"}},"content":"@tanstack/react-query\uc758 stale-while-revalidate\ubc29\uc2dd\uc5d0 \ub300\ud55c \uc124\uba85\uc785\ub2c8\ub2e4.\\n\\n{/* truncate */}\\n\\n## \uc65c React Query\ub97c?\\n\\n\uc5ec\ub7ec\ubd84\ub4e4\uc740 `@tanstack/react-query`\ub97c \uc65c \uc120\ud0dd\ud588\ub098\uc694?<br/>\\n\uae30\uc220 \uc2a4\ud0dd\uc758 \uc120\ud0dd\uc5d0\ub294 \uc5b8\uc81c\ub098 \uadf8 \uc774\uc720\uac00 \uc911\uc694\ud569\ub2c8\ub2e4. react-query\uc758 \uc0ac\uc6a9\uc73c\ub85c \uc5b4\ub5a4 \uc774\uc810\uc744 \uc5bb\uace0 \uc2f6\uc5c8\ub098\uc694?\\n\\n\uacfc\uac70\uc758 \uc800\ub294 \uc774\ub807\uac8c \uc0dd\uac01\ud588\uc5b4\uc694.\\n- \uc798\uc740 \ubaa8\ub974\uc9c0\ub9cc, \uac19\uc740 \ucffc\ub9ac\ud0a4\uc5d0 \ub300\ud574 \uc11c\ubc84\ub85c \ubcf4\ub0b4\ub294 \uc694\uccad\uc744 \uce90\uc2f1\ud574 \uc8fc\uc5b4\uc11c\\n- \uce90\uc2f1\uc774 \ub418\ub2c8\uae50, \uc11c\ubc84\ub85c \ubcf4\ub0b4\ub294 \uc694\uccad\uc758 \uc218\ub97c \uc904\uc77c \uc218 \uc788\uc5b4\uc11c\\n- `data, isLoading, isError`\uc640 \uac19\uc774 \uc0c1\ud0dc\ub97c \ud3b8\ud558\uac8c \uc4f8 \uc218 \uc788\ub294 \uc778\ud130\ud398\uc774\uc2a4\ub97c \uc81c\uacf5\ud574\uc11c\\n- suspense\ub97c \uc9c0\uc6d0\ud574\uc11c\\n\\n\ub370\uc774\ud130\ub97c \ud56d\uc0c1 \ub2e4\uc2dc \uac00\uc838\uc624\ub294\uac74 \ube44\uc6a9\uc774 \ub9ce\uc774 \ub4dc\ub2c8\uae50, \uce90\uc2f1\uc744 \ud65c\uc6a9\ud574 \ub124\ud2b8\uc6cc\ud06c \uc694\uccad\uc758 \uc218\ub97c \ucd5c\uc18c\ud654\ud558\uace0 \uc2f6\uc5c8\uc5c8\uc8e0.\\n\\n\uadf8\ub7f0\ub370 \uc0ac\uc6a9\ud574\ubcf4\ub2c8 \uadf8\ub807\uc9c0 \uc54a\uc558\uc5b4\uc694.\\n\\n```tsx\\nexport const useCategoryList = () => {\\n  return useQuery(\\n    {\\n      queryKey: QueryKey.GetCategoryList,\\n      queryFn: fetchCategoryList,\\n    },\\n  );\\n};\\n\\nexport function HomePage(){\\n    const { data } = useCategoryList();\\n\\n    return <div>{data.map((category) => <div>{category.name}</div>)}</div>\\n}\\n\\nexport function StorePage(){\\n    const { data } = useCategoryList();\\n\\n    return <div>{data.map((category) => <div>{category.name}</div>)}</div>\\n}\\n\\n```\\n\\n\ub450 \ud398\uc774\uc9c0\ub97c \uc774\ub3d9\ud558\ub2c8, \ub450 \ubc88\uc758 \ub124\ud2b8\uc6cc\ud06c \uc694\uccad\uc774 \ubc1c\uc0dd\ud588\uc5b4\uc694. \uc774\uac8c \uce90\uc2f1\uc774\ub77c\uace0\uc694?<br/>\\n\uadf8\ub798\uc11c \uc800\ub294 \uc5b4\ub5bb\uac8c\ud558\uba74 \uc694\uccad\uc744 \ub9c9\uc744 \uc218 \uc788\uc744\uae4c \ucc3e\uc544\ubd24\uc8e0.\\n\\n\uacf5\uc2dd\ubb38\uc11c\uc5d0\uc11c\ub294, staleTime\uac12\uc744 \ub354 \uae38\uac8c \uc124\uc815\ud558\ub77c\uace0 \ud588\uc5b4\uc694.(\ucd08\uae30\uac12\uc774 0\uc774\ub77c\uc11c, 5\ubd84\uc815\ub3c4\ub85c \uc124\uc815\ud588\uc5b4\uc694)<br/>\\n```tsx\\nconst queryClient = new QueryClient({\\n  defaultOptions: {\\n    queries: {\\n      staleTime: 5 * 60 * 1000,\\n    },\\n  },\\n});\\n```\\nstaleTime\uc744 \uc804\uccb4\uc801\uc73c\ub85c \ub298\ub9ac\ub2c8 \uc2e4\uc81c\ub85c \ud398\uc774\uc9c0\ub97c \uc5ec\ub7ec\ubc88 \uc774\ub3d9\ud574\ub3c4, \ub3d9\uc77c\ud55c \ucffc\ub9ac\uc5d0 \ub300\ud574 \uc694\uccad\uc774 \ud55c\ubc88\ub9cc \uc9c4\ud589\ub410\uc5b4\uc694.\\n\\n\uadf8\ub7f0\ub370 \uc774\uc0c1\ud574\uc694. staleTime\uc744 \ub298\ub9ac\ub2c8\uae50, \uce90\uc2f1\uc774 \ub354 \uc798 \ub418\ub294\uac8c \ub9de\uc744\uae4c\uc694?<br/>\\n\uadf8\uac8c \ub9de\ub2e4\uba74 \uc65c \ucd08\uae30\uac12\uc774 0\uc73c\ub85c \uc124\uc815\ub418\uc5b4 \uc788\uc744\uae4c\uc694?\\n\\n## staleTime\uc774\ub780?\\nstaleTime\uc740, \ubc1b\uc544\uc628 \ub370\uc774\ud130\uac00 stale\ud558\ub2e4(\uc624\ub798\ub410\ub2e4)\uace0 \ud45c\uc2dc\ub420\ub54c\uae4c\uc9c0 \uac78\ub9ac\ub294 \uc2dc\uac04\uc744 \ub73b\ud574\uc694.<br/>\\n\ucd08\uae30\uac12\uc740 0\uc73c\ub85c, \uae30\ubcf8\uc801\uc73c\ub85c react-query\ub294 \ubaa8\ub4e0 \uc11c\ubc84 \uc694\uccad\uc5d0 \ub300\ud574\uc11c - \uc774 \ub370\uc774\ud130\ub294 \uc624\ub798\ub410\uc73c\ub2c8, \ub2e4\uc2dc \ubc1b\uc544\uc640\uc57c\ud560 \ud544\uc694\uac00 \uc788\ub2e4\uace0 \ud45c\uc2dc\ud558\ub294\uac70\uc8e0\\n\\n\uadf8\ub7fc \uce90\uc2f1\uc774 \ub418\ub294\uac8c \uc544\ub2c8\uc796\uc544\uc694!<br/>\\n\ub77c\uace0 \uc0dd\uac01\ud55c\ub2e4\uba74, `staleTime`\uacfc \ud568\uaed8 \uc9c0\uc815\ud560 \uc218 \uc788\ub294 `gcTime`(4\ubc84\uc804 \uc774\ud558\uc5d0\uc11c\ub294 `cacheTime`)\uc744 \ud568\uaed8 \uc774\ud574\ud574\uc57c\ud569\ub2c8\ub2e4.\\n\\ngcTime/cacheTime\uc740, \ub370\uc774\ud130\uac00 \uce90\uc2dc\uc5d0 \uc800\uc7a5\ub418\ub294 \uc2dc\uac04\uc744 \ub73b\ud574\uc694. (\ucd08\uae30\uac12\uc740 5\ubd84\uc785\ub2c8\ub2e4)<br/>\\n5\ubd84\ub3d9\uc548\uc740, \ub3d9\uc77c\ud55c \ucffc\ub9ac\uc5d0 \ub300\ud574\uc11c \uce90\uc2dc\ub97c \uc0ac\uc6a9\ud55c\ub2e4\ub294 \uc758\ubbf8\uc774\uc8e0.\\n\\n\uc74c? \uc544\uae4c \ub2e4\uc2dc \uc694\uccad\ud574\uc57c\ud55c\ub2e4, \uc624\ub798\ub410\ub2e4 \ud558\uc9c0 \uc54a\uc558\ub358\uac00\uc694?\\n\ub124. \uadf8\ub798\uc11c \uc6b0\ub9ac\ub294 react-query\uac00 \uce90\uc2dc\ub97c \ud65c\uc6a9\ud558\ub294 \ubc29\uc2dd\uc778, SWR(stale-while-revalidate) \ubc29\uc2dd\uc5d0 \ub300\ud574 \uc774\ud574\ud574\uc57c\ud569\ub2c8\ub2e4.\\n\\n## stale-while-revalidate\\n\\n\ubb38\uc7a5 \uadf8\ub300\ub85c \ud574\uc11d\ud558\uc790\uba74 \uc544\ub798\uc640 \uac19\uc544\uc694, \\n- \uae30\uc874\uc5d0 \uc788\ub358 \ub370\uc774\ud130\ub97c \uadf8\ub300\ub85c \ubcf4\uc5ec\uc8fc\uba74\uc11c (stale), \\n- \ub3d9\uc2dc\uc5d0 \ubc31\uadf8\ub77c\uc6b4\ub4dc\uc5d0\uc11c \uc0c8\ub85c\uc6b4 \ub370\uc774\ud130\ub97c \uac00\uc838\uc624\ub294 \ub3d9\uc548 (while), \\n- \uc774\ub97c \uac80\uc99d\ud558\uace0 \uac31\uc2e0\ud558\ub294 \uac83 (revalidate)\\n\\nreact-query\uc5d0 \ub9de\uac8c \uc774\ud574\ud558\uba74, staleTime\uc774 \uc9c0\ub09c \uc0c1\ud0dc\uc774\ub354\ub77c\ub3c4,<br/>\\n\uadf8 \ub370\uc774\ud130\ub97c **\uba3c\uc800 \ubcf4\uc5ec\uc8fc\uba74\uc11c** \uc0c8\ub85c\uc6b4 \ub370\uc774\ud130\ub85c \uac31\uc2e0\ud55c\ub2e4\ub294 \ub73b\uc774\uc8e0.\\n\\n\uc9c0\uae08\uae4c\uc9c0 staleTime\uc774 0\uc774\ub77c\uc11c \uc911\ubcf5\uc73c\ub85c \ud588\ub358 \uc694\uccad\uc740, \uc0ac\uc2e4 UX\uc801\uc73c\ub85c \uc544\ubb34\ub7f0 \ubb38\uc81c\uac00 \uc5c6\uc5c8\ub358\uac70\uc608\uc694.<br/>\\n\uce90\uc2dc\uc5d0 \ub370\uc774\ud130\uac00 \uc788\ub2e4\uba74 \uba3c\uc800 \uce90\uc2dc\ub41c \ub370\uc774\ud130\ub97c \ubcf4\uc5ec\uc8fc\uae30\uc5d0, \uadf8\ub3d9\uc548 \ub370\uc774\ud130\ub97c \uac00\uc838\uc624\uba74\uc11c \ucd5c\uc2e0\ud654\uae4c\uc9c0 \ub3d9\uc2dc\uc5d0 \uc9c4\ud589\ud55c\uac70\uc8e0.\\n\\n:::note\\n\uc774\ub7ec\ud55c \uce90\uc2f1\ud558\ub294 \ubc29\ubc95\uc740 react-query\ub9cc \uc0ac\uc6a9\ud558\ub294 \ubc29\uc2dd\uc740 \uc544\ub2d9\ub2c8\ub2e4.<br/>\\n\uc6d0\uc870\uaca9\uc778 `swr`\uc774\ub77c\ub294 \ub77c\uc774\ube0c\ub7ec\ub9ac\uac00 \uc874\uc7ac\ud558\ub294\ub370\ub2e4\uac00, \uc720\uba85\ud55c \uc6f9 \uce90\uc2f1 \uc804\ub7b5\uc758 \uba85\uce6d\uc77c \ubfd0\uc774\uc608\uc694.\\n:::\\n\\n\uc0ac\uc2e4 \uc608\uc804\uc5d0\ub294 \uc11c\ubc84 \uc694\uccad \ud55c\ubc88\ud55c\ubc88\uc774 \uc5c4\uccad \ud06c\ub9ac\ud2f0\uceec\ud558\ub2e4, \ud55c\ubc88\uc774\ub77c\ub3c4 \uc904\uc774\ub294\uac8c \ud070 \uc758\ubbf8\uac00 \uc788\ub2e4\uace0 \uc0dd\uac01\ud588\ub294\ub370,<br/>\\n\uc774\uc81c\uc640\uc11c \ub3cc\uc544\ubcf4\ub2c8 \uadf8\uc815\ub3c4 \uc694\uccad\uc758 \ucc28\uc774\ub294 \uc11c\ubc84\uc5d0 \uc544\ubb34\ub7f0 \uc601\ud5a5\uc744 \uc8fc\uc9c0 \uc54a\uc558\uc5c8\uc5b4\uc694.<br/>\\n\uc624\ud788\ub824 staleTime\uc744 \uc5b5\uc9c0\ub85c \ub298\ub838\ub354\ub2c8 \uc0c8\ub85c\uace0\uce68\uc744 \ud558\uc9c0 \uc54a\ub294 \uc774\uc0c1 \ud398\uc774\uc9c0 \ub370\uc774\ud130\uac00 \uac31\uc2e0\ub418\uc9c0 \uc54a\ub294\ub2e4\uac70\ub098 \ud558\ub294 \uc2dd\uc758 \ubb38\uc81c\ub4e4\uc774 \ubc1c\uc0dd\ud588\uc8e0\\n\\n## \uc774\ud574\ud558\uace0 \ub098\uba74,,\\n\\n\uc774\ub97c \uae68\ub2ec\uc740 \ub4a4\ub85c\ub294, \uae30\ubcf8\uc801\uc778 staleTime\uc744 \ub2e4\uc2dc 0\uc73c\ub85c \ub3cc\ub824\uc57c\uaca0\ub2e4 \uc0dd\uac01\ud588\uc5b4\uc694.<br/>\\n\ubb3c\ub860 \uc815\ub9d0 \uc798 \uc548\ubc14\ub00c\ub294 \ud2b9\uc815 \ucffc\ub9ac\uc5d0 \ub300\ud574\uc11c\ub294 \ub530\ub85c staleTime\uc744 `Infinity`\ub85c \uc9c0\uc815\ud55c\ub2e4\uac70\ub098 \ud560 \uc218 \uc788\uac8c \ub418\uc5c8\uc8e0.<br/>\\n\uc880 \ub354 \uc0c1\ud669\uc5d0 \ub9de\uac8c \uc635\uc158\uc744 \uc124\uc815\ud560 \uc218 \uc788\uac8c \ub41c \uac70\uc608\uc694.\\n\\n\ub610\ud55c react-query\uc758 \ub2e4\ub978 \uba54\uc18c\ub4dc\ub098, \uc0c1\ud0dc\ub4e4\uc5d0 \ub300\ud574\uc11c\ub3c4 \uc774\ud574\uac00 \ub298\uc5c8\uc5b4\uc694<br/>\\nuseQuery\ub294 `isLoading`\uacfc `isFetching` \ub450\uac00\uc9c0 \uc0c1\ud0dc\ub97c \ubd84\ub9ac\ud574\uc11c \uc804\ub2ec\ud574\uc918\uc694.<br/>\\n\uc774\uc804\uae4c\uc9c0\ub294 \ubb34\uc2a8 \ucc28\uc778\uc9c0 \uc798 \ubab0\ub790\ub294\ub370, \uc774\uc81c \uc27d\uac8c \ub9d0\ud560 \uc218 \uc788\uc8e0.<br/>\\n\\n- \uce90\uc2dc\ub41c \ub370\uc774\ud130\uac00 \uc5c6\ub2e4\uba74 **isLoading\uacfc isFetching\uc774 true**\uc77c \uac83\uc774\uace0,<br/>\\n- \uce90\uc2dc\ub41c \ub370\uc774\ud130\ub294 \uc788\uc9c0\ub9cc, staleTime\uc744 \uc9c0\ub0ac\ub2e4\uba74 isFetching\ub9cc true\uc77c \uac70\uc608\uc694.\\n- \uc5f0\uacb0\ud574\uc11c, Suspense\ub97c \ud2b8\ub9ac\uac70\ud558\ub294 \ubd80\ubd84\uc5d0\uc11c\ub3c4 - \uce90\uc2dc\uac00 \uc874\uc7ac\ud55c\ub2e4\uba74 \uc0c1\uc704 \ub9e5\ub77d\uc758 Suspense\ub97c \ud2b8\ub9ac\uac70\ud558\uc9c0\ub3c4 \uc54a\uc744\uac70\uad6c\uc694.\\n\\n\ub77c\uc774\ube0c\ub7ec\ub9ac \uc81c\uc791\ud300\uc5d0\uc11c \ucd08\uae30\uac12\uc744 \uac01\uac01 0\ucd08\uc640 5\ubd84\uc73c\ub85c \uc124\uc815\ud55c \ub370\uc5d0\ub294 \ub2e4 \uc774\uc720\uac00 \uc788\uc5c8\ub2e4\ub294\uac78 \uae68\ub2eb\uace0,<br/>\\n\ub354 \ub098\uc740 \uc0ac\uc6a9\uc790 \uacbd\ud5d8\uc744 \uc704\ud574 \uc5b4\ub5a4 \uc635\uc158\uc744 \uc0ac\uc6a9\ud574\uc57c \ud558\ub294\uc9c0 - \uc5b4\ub5a4 \uc0c1\ud669\uc5d0\uc11c staleTime\uacfc gcTime\uc744 \uc801\uc808\ud558\uac8c \ubcc0\uacbd\ud560 \uc218 \uc788\uc744\uc9c0 \uc774\ud574\ud558\uace0 \ubc14\uafd4\ubcf8 \uacbd\ud5d8\uc774 \uc0dd\uae34\ub2e4\uba74, \uc815\ub9d0 react-query\ub97c \uc798 \uc37c\uad6c\ub098, \uc774 \uae30\uc220\uc744 \uace0\ub978 \uc774\uc720\ub97c \uc798 \uc124\uba85\ud560 \uc218 \uc788\uac8c \ub420 \uac83 \uac19\uc544\uc694!\\n\\n\uc774 \uc804\ub7b5\uc744 \ud1a0\ub300\ub85c \uac04\ub2e8\ud55c \ucffc\ub9ac\ub354\ub77c\ub3c4 \uc18c\uc18c\ud788 \ub354 \ub9ce\uc740 \uace0\ubbfc\uc744 \ud558\uba74\uc11c \uc791\uc5c5\ud574\ubcf4\uc544\uc694."},{"id":"/posts/july-retrospect_daepan","metadata":{"permalink":"/front-end/posts/july-retrospect_daepan","source":"@site/@frontEnd/posts/july-retrospect_daepan.mdx","title":"BCSDLab\uc740 \ubb50\ud558\ub294 \ub3d9\uc544\ub9ac\uc77c\uae4c?","description":"7\uc6d4 \uc6d4\uac04 \ud68c\uace0 \uacb8 \ub3d9\uc544\ub9ac \ub808\uade4\ub7ec\uac00 \ub41c\ub2e4\uba74 \ubb34\uc2a8 \uc77c\uc744 \ud560\uae4c?","date":"2024-08-06T00:00:00.000Z","tags":[{"label":"\uc6d4\uac04 \ud68c\uace0","permalink":"/front-end/tags/\uc6d4\uac04-\ud68c\uace0"},{"label":"\ub808\uade4\ub7ec \uc804\ud658","permalink":"/front-end/tags/\ub808\uade4\ub7ec-\uc804\ud658"}],"readingTime":9.6,"hasTruncateMarker":true,"authors":[{"name":"daekwan Kim","url":"https://github.com/daepan","email":"qw04011@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/50792467?v=4","key":"daepan"}],"frontMatter":{"date":"2024-08-06T00:00:00.000Z","authors":"daepan","title":"BCSDLab\uc740 \ubb50\ud558\ub294 \ub3d9\uc544\ub9ac\uc77c\uae4c?","description":"7\uc6d4 \uc6d4\uac04 \ud68c\uace0 \uacb8 \ub3d9\uc544\ub9ac \ub808\uade4\ub7ec\uac00 \ub41c\ub2e4\uba74 \ubb34\uc2a8 \uc77c\uc744 \ud560\uae4c?","keywords":["\uc6d4\uac04 \ud68c\uace0","\ub808\uade4\ub7ec\uc758 \uc0b6"],"tags":["\uc6d4\uac04 \ud68c\uace0","\ub808\uade4\ub7ec \uc804\ud658"]},"unlisted":false,"prevItem":{"title":"staleTime\uacfc gcTime\uc774 \ubb54\uac00\uc694?","permalink":"/front-end/posts/react-query"},"nextItem":{"title":"\ucd08\ub85d\uc2a4\ud130\ub514 \ubc0b\uc5c5","permalink":"/front-end/junghaesung79/cholog-study-meetup"}},"content":"BCSDLab Regular\ub294 \uc5b4\ub5a4 \ud65c\ub3d9\uc744 \ud560\uae4c?\\n\\n{/* truncate */}\\n\\n## \ub4e4\uc5b4\uac00\uba70\\n\uc774\ubc88 Front-End \ud2b8\ub799\uc5d0\uc11c 7\uc6d4 \ud68c\uace0\ub97c \ub2f4\ub2f9\ud558\uac8c \ub41c Front-End \ud2b8\ub799 Regular \uae40\ub300\uad00\uc785\ub2c8\ub2e4. \uc774\ubc88 7\uc6d4 \ud68c\uace0\ub85d\uc744 \ub2f4\ub2f9\ud558\uba74\uc11c \\"\uc6b0\ub9ac \ub3d9\uc544\ub9ac\uc5d0 \ub4e4\uc5b4\uac00\ub294 \ud68c\uace0\ub85d\uc740 \uc5b4\ub5a4 \uc774\uc57c\uae30\ub97c \uc368\uc57c\ud560\uae4c?\\"\ub97c \uace0\ubbfc\ud588\uc2b5\ub2c8\ub2e4. \uc65c\ub0d0\ud558\uba74 \uc774 \uae00\uc740 \uc6b0\ub9ac \ub3d9\uc544\ub9ac\uc6d0\ub9cc\uc5d0\uac8c \uacf5\uc720\ub418\ub294 \uac83\uc774 \uc544\ub2cc \ub9ce\uc740 \uc0ac\ub78c\ub4e4\uc5d0\uac8c \uacf5\uc720\ub418\ub294 \uc774\uc57c\uae30\ub97c \uc801\uc5b4\uc57c\ud55c\ub2e4\uace0 \uc0dd\uac01\ud588\uc2b5\ub2c8\ub2e4. \uadf8\ub798\uc11c \uc81c\uac00 \uc774\ubc88 7\uc6d4\uc744 \uc624\uba74\uc11c \uc6b0\ub9ac \ub3d9\uc544\ub9ac\uc5d0\uc11c \ud65c\ub3d9\ud55c \uc8fc\uc694\ud55c \ud65c\ub3d9\ub0b4\uc5ed\uc744 \uc18c\uac1c\ud558\uace0 \uac1c\uc778\uc801\uc73c\ub85c \uc5b4\ub5a4 \uc77c\uc744 \ud558\uace0 \uc788\ub294\uc9c0\uc5d0 \ub300\ud574 \uc801\uc5b4\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n\\n## What is BCSD Lab\\n\\n\uba3c\uc800, BCSD Lab \ub3d9\uc544\ub9ac\ub294 \uc2a4\ud0c0\ud2b8\uc5c5\ud615 \ud559\uc220 \ub3d9\uc544\ub9ac\uc785\ub2c8\ub2e4. \uc6b0\ub9ac \ub3d9\uc544\ub9ac\uc5d0\uc11c \uc6b4\uc601\ud558\ub294 \uc11c\ube44\uc2a4\uc778 \\"\ucf54\uc778-\ud55c\uae30\ub300 \uc0ac\ub78c\ub4e4\\"\uc744 \uc9c1\uc811 \ud559\uc0dd\ub4e4\ub07c\ub9ac \uc6b4\uc601\ud558\uba74\uc11c IT \ubd84\uc57c\uc5d0\uc11c\ub294 FrontEnd, BackEnd, Android, iOS \ud2b8\ub799\uc774 \uc788\uace0, \ub514\uc790\uc778\uc5d0\uc11c\ub294 Design \ud2b8\ub799\uc774 \uc788\uc2b5\ub2c8\ub2e4. \uac01 \ud2b8\ub799\ub9c8\ub2e4 \ud559\uc0dd\ub4e4\uc774 \uc6b4\uc601\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ud604\uc7ac 24\ub144\ub3c4 7\uc6d4 \uae30\uc900\uc73c\ub85c \ub3d9\uc544\ub9ac \ub0b4\uc5d0\ub294 \uc57d 60\uba85 \uc778\uc6d0\ub4e4\uc774 \ud65c\ub3d9\ud558\uace0 \uc788\uc73c\uba70, \uaf64\ub098 \ub300\uaddc\ubaa8 \uc778\uc6d0\ub4e4\uc774 \ud574\ub2f9 \ud504\ub85c\uc81d\ud2b8\uc5d0 \ucc38\uc5ec\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4. \ubaa8\ub4e0 \uc778\uc6d0\ub4e4\uc744 \ud558\ub098\uc758 \uc11c\ube44\uc2a4\uc5d0 \uac1c\ubc1c\uc744 \ub2f4\ub2f9\ud558\uae30 \uc704\ud574 \uc800\ud76c\ub294 \ucf54\uc778\uc774\ub77c\ub294 \uc11c\ube44\uc2a4\ub97c \ucd1d 3\uac1c\ub97c \ubd84\ud560\ud558\uace0 \uac01 \ubd84\uc57c\ub97c \ub2f4\ub2f9\ud558\ub294 \ud300 \ub2e8\uc704 \uc791\uc5c5\uc73c\ub85c \uc9c4\ud589\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n* `Team. Business` : \uc8fc\ubcc0\uc0c1\uc810, \ubcf5\ub355\ubc29, \uc0ac\uc7a5\ub2d8 \ud50c\ub7ab\ud3fc \uad00\ub828\\n* `Team. User` : \uc2dc\uac04\ud45c, \uc720\uc800, \uc124\uc815&\uad00\ub9ac \uad00\ub828\\n* `Team. Campus` : \ud559\uad50\uc2dd\ub2e8, \ud559\uad50\ub0b4 \ubc84\uc2a4, \ucee4\ubba4\ub2c8\ud2f0 \uad00\ub828\\n\\n\uc774\ub807\uac8c \uac01 \ud300 \ub2e8\uc704\ub85c \uc791\uc5c5\ud568\uc73c\ub85c\uc368 \uc6b0\ub9ac\ub4e4\ub9cc\uc758 \ud611\uc5c5\uccb4\uc81c\ub97c \uad6c\uc131\ud558\uace0 \uac01 \ud2b8\ub799\ub9c8\ub2e4 \ubc30\uc815\ub41c \uae30\ud68d\uacfc \ub514\uc790\uc778\uc758 \ubc29\ud5a5\uc131\uc744 \ud1b5\ud574 \uc6b0\ub9ac\ub4e4\uc758 \uc11c\ube44\uc2a4 \ubc1c\uc804\uc5d0 \ub9ce\uc740 \ud798\uc744 \uc3df\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n## 7\uc6d4 \uac04 \uc9c4\ud589\ud55c \ud65c\ub3d9\\n\\n\uc800\ub294 7\uc6d4 \ub3d9\uc548 BCSDLab\uc5d0\uc11c Team.Business Front-End \ubd84\uc57c\ub97c \ub2f4\ub2f9\ud574\uc11c \uac1c\ubc1c\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4. \uadf8\uc640 \ub3d9\uc2dc\uc5d0 \uc6b0\ub9ac\uac00 \uc774\ub7f0 \uc11c\ube44\uc2a4 \uac1c\ubc1c\ub9cc \ud558\ub294\uac00? \uadf8\uac83\uc740 \ub610 \uc544\ub2d9\ub2c8\ub2e4. \uc6b0\ub9ac\ub4e4\uc758 \ubaa9\ud45c\ub294 \ucde8\uc5c5\uc774\uae30\ub3c4 \ud558\uc9c0\ub9cc, \uc911\uc694\ud55c \uac83\uc740 \uc6b0\ub9ac\uac00 \ud558\ub098\uc758 \uc5d4\uc9c0\ub2c8\uc5b4, \ub514\uc790\uc774\ub108\ub85c \uc131\uc7a5\ud558\ub294 \uac83\uc785\ub2c8\ub2e4. \uc774\ub7f0 \uc11c\ube44\uc2a4 \uac1c\ubc1c\uacfc \ubcd1\ud589\ud558\uc5ec \ud2b8\ub799\ub0b4\uc5d0\uc11c \ub2e4\uc591\ud55c \uc2a4\ud130\ub514 \ud65c\ub3d9\uc744 \uc9c4\ud589\ud569\ub2c8\ub2e4. 7\uc6d4\uac04 \uac01 \ud65c\ub3d9\uc5d0\uc11c \ubb34\uc5c7\uc744 \ud588\ub294\uc9c0\uc5d0 \ub300\ud55c \uc18c\uac1c\ud558\uba74\uc11c \ud68c\uace0\ub97c \uc9c4\ud589\ud574\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n### Business \ud300\uc5d0\uc11c\uc758 \ud65c\ub3d9\\n\\n\uba3c\uc800, \uc81c\uac00 \ud65c\ub3d9\ud558\ub294 Team.Business\uc5d0\uc11c\ub294 \uc8fc\uc694\ud55c \ud65c\ub3d9\uc73c\ub85c \ud604\uc7ac 7\uc6d4\uc5d0 \uc9d1\uc911\ud588\ub358 \uc791\uc5c5\uc73c\ub85c\ub294 \uc8fc\ubcc0 \uc0c1\uc810 \uc815\ubcf4\uc758 \ucd5c\uc2e0\ud654\uc640 \uc8fc\ubcc0 \uc0c1\uc810\uc5d0 \ub300\ud55c \uc0ac\uc6a9\uc131 \uc99d\ub300, \ucf54\uc778 \uc0ac\uc7a5\ub2d8 \uc5b4\ud50c \ucabd\uc744 \ub2f4\ub2f9\ud574\uc11c \uc9c4\ud589\ud588\uc2b5\ub2c8\ub2e4.\\n\\n<div style={{width: \'100%\', height: \'300px\', display:\'flex\', justifyContent: \'center\'}}> \\n<img src=\\"https://i.imgur.com/Tmpxvis.png\\" width=\\"60%\\" height=\\"75%\\"/> \\n<video src=\\"https://github.com/user-attachments/assets/7ca1904a-0087-4626-bdc0-08c63e40d521\\" width=\\"30%\\" height=\\"300px\\"/>\\n</div>\\n\uc6b0\ub9ac\uac00 \uae30\ub2a5\uacfc \uae30\ud68d\uc758 \ubc29\ud5a5\uc131\uc744 \uacb0\uc815\ud560 \ub54c \uc6b0\ub9ac\uac00 \uc0ac\uc6a9\ud558\ub294 \uc11c\ube44\uc2a4\uc5d0 \ub300\ud574\uc11c \ub9ce\uc740 \ucd94\uc801\uc744 \uc9c4\ud589\ud558\uace0 \uc788\uace0 \uc5b8\uc81c\ub098 \\"\uc720\uc800\ub4e4\uc774 \uc6d0\ud558\ub294 \uc11c\ube44\uc2a4\ub780 \ubb34\uc5c7\uc77c\uae4c?\\"\ub97c \uace0\ubbfc\ud558\uace0 \uadf8\uc5d0 \ub300\ud55c \uae30\ubc18\ud55c \ub370\uc774\ud130 \ub4f1\uc744 \uad6c\ucd95\ud558\uae30 \uc704\ud574 Google Analytics\ub97c \uc9c1\uc811 \uc124\uc815\ud558\uace0 \uc2e4\uc81c \uc720\uc800\ub4e4\uc774 \uc6b0\ub9ac \uc5b4\ud50c\uc744 \uc5b4\ub5bb\uac8c \ud65c\uc6a9\ud558\ub294\uc9c0\ub97c \ubd84\uc11d\ud558\uace0, \uc5b4\ub5a4 \uae30\ub2a5\uc774 \ud544\uc694\ud560\uc9c0\ub97c \uace0\ubbfc\ud569\ub2c8\ub2e4.\\n\\n\ubb3c\ub860 \uadf8 \uacfc\uc815\uc5d0\uc11c \uc704\uc5d0 \uac19\uc774 \uac04\ub2e8\ud55c \uc0ac\uc6a9\uc131 \uc99d\ub300\ub098 \ucd5c\uc2e0\ud654\ub97c \uc9c4\ud589\ud558\uac8c \ub418\ub294 \uac83\uc5d0\ub294 \ub9ce\uc740 \uadfc\uac70\ub97c \uae30\ubc18\ud569\ub2c8\ub2e4.\\n\\n1. GA\uc5d0\uc11c \ubd84\uc11d\ub41c \ub370\uc774\ud130\ub97c \uae30\ubc18\ud55c \uae30\ub2a5 \uae30\ud68d\uc758 \ubc29\ud5a5\uc131 \uc120\uc815\\n2. User Test\ub97c \ud1b5\ud55c \uc2e4\uc81c \uc0ac\uc6a9\uc790 \uc778\ud130\ubdf0\\n\\n<div style={{width: \'100%\', height: \'100%\'}}> \\n\\t<div style={{width: \'100%\', height:\'30%\', display: \'flex\'}}>\\n\\t\\t<img src=\\"https://i.imgur.com/5ECk719.png\\" width=\\"48%\\" height=\\"30%\\"/>\\n\\t\\t<img src=\\"https://i.imgur.com/InPsXah.png\\" width=\\"48%\\" height=\\"100%\\"/ >\\n\\t</div>\\n\\t<img src=\\"https://i.imgur.com/LhcXGgV.png\\" width=\\"100%\\" height=\\"70%\\"/>\\n\\t\\n</div>\\n// *\ub118\ub098 \uace0\uc0dd\ud558\ub294 \uc6b0\ub9ac DA, PM \ubd84\ub4e4!*\\n\\n\ud574\ub2f9 \ubd84\uc11d\uc774 \ub9c8\ubb34\ub9ac \ub418\uba74\uc740 \uac1c\ubc1c, DA, PM, \ub514\uc790\uc774\ub108 \ub4e4\uc774 \ubaa8\uc5ec\uc11c \uc55e\uc73c\ub85c \uc774\ub7f0 \ub370\uc774\ud130\ub97c \uae30\ubc18\uc73c\ub85c \uc5b4\ub5a4 \uae30\ub2a5\uc73c\ub85c \uc9c4\ud589\ud558\uba74 \uc88b\uc744\uc9c0\ub97c \uc11c\ub85c\uc758 \uc758\uacac\uc744 \uacf5\uc720\ud558\uace0 \ud568\uaed8 \ud611\uc5c5\ud558\ub294 \ud615\ud0dc\ub85c \uc9c4\ud589\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### \ud2b8\ub799\uc5d0\uc11c \ud558\ub294 \ud65c\ub3d9\\n\\n\uc55e\uc5d0\uc11c \ub9d0\ud55c \uac83 \ucc98\ub7fc \uc704\uc5d0\uc11c\uc758 \ud65c\ub3d9\uc740 Team \ub2e8\uc704\uc5d0\uc11c \ub9c8\ubb34\ub9ac\ud558\ub294 \uac83\uc774 \uc544\ub2cc \uc0c8\ub86d\uac8c \ud2b8\ub799 \ub0b4\ubd80\uc5d0\uc11c\ub3c4 \ub9ce\uc740 \ud65c\ub3d9\uc744 \uc9c4\ud589\ud569\ub2c8\ub2e4.\\n\\n#### \uc2a4\ud130\ub514 \ud65c\ub3d9\\n\\n\ub3d9\uc544\ub9ac\uc5d0\uc11c \uc2a4\ud130\ub514\ub294 \ub9e4\uc6b0 \ud754\ud558\uc9c0\ub9cc, \uc6b0\ub9ac\ub294 \uac1c\ubc1c\uc790\ub97c \ud76c\ub9dd\ud558\ub294 \uc0ac\ub78c\ub4e4\uc774 \ubaa8\uc778 \ub9cc\ud07c \uac1c\ubc1c\uacfc \uad00\ub828\ub41c \uc2a4\ud130\ub514\ub97c \uc8fc\ub85c \uc9c4\ud589\ud569\ub2c8\ub2e4. \uae30\uac04\uc740 \ubcf4\ud1b5 \ubc29\ud559\uae30\uac04 \ud639\uc740 \ud559\uae30 \uc911\uc5d0 \ud558\ub8e8 1~2\uc2dc\uac04\uc774\ub77c\ub3c4 \ub0b4\uc11c \uacf5\ubd80\ud560 \uc218 \uc788\ub3c4\ub85d \uc8fc\uac04 \uc2a4\ud130\ub514\ub97c \uc9c4\ud589\ud569\ub2c8\ub2e4.\\n\\n\uc800\ub294 \uc774\ubc88 7\uc6d4\uc5d0 \ubaa8\ub358 \uc6f9\uc5d0\uc11c \uac00\uc7a5 \uadfc\uac04\uc774 \ub418\uace0 \uc788\ub294 JavaScript\uc5d0 \ub300\ud574\uc11c \ub354 Deep \ud558\uac8c \uc54c\uae30 \uc704\ud574\uc11c ko.javascript \ub0b4\uc6a9\uc744 \uae30\ubc18\uc73c\ub85c \uc2a4\ud130\ub514\ub97c \uc9c4\ud589\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4. \ud63c\uc790\uc11c \uacf5\ubd80\ud558\ub294 \uac83\uc774 \uc544\ub2cc \ub2e4\ub978 \uc778\uc6d0\ub4e4\uacfc \ud568\uaed8\ud558\ub294 \uac83\uc73c\ub85c \ub3d9\uae30\ubd80\uc5ec\ub97c \ucd09\uc9c4\ud558\uace0 \uc11c\ub85c\uac00 \ub193\uce5c \ubd80\ubd84\uc744 \ubcf4\uc644\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n<div style={{display: \'flex\', justifyContent: \'center\'}}>\\n<img src=\\"https://i.imgur.com/HZ5RCga.png\\" width=\\"70%\\" height=\\"60%\\" />\\n</div>\\n\\n#### \uc18c\uadf8\ub8f9 \ud65c\ub3d9\\n\\n\ub610\ud55c FrontEnd \ud2b8\ub799\uc5d0\uc11c\ub294 \uc18c\uadf8\ub8f9 \ud65c\ub3d9\uc744 \uc9c4\ud589\ud569\ub2c8\ub2e4. \ub2e4\uc591\ud558\uac8c Slack \ub0b4\uc5d0 \uc788\ub294 Slack \ubd07\uc744 \uac1c\ubc1c\ud558\ub294 \uadf8\ub8f9\uc774\ub098 \ub530\ub85c \uc0ac\uc774\ub4dc \ud504\ub85c\uc81d\ud2b8\uc5d0 \ub300\ud55c \uc544\uc774\ub514\uc5b4\ub97c \uc5bb\uc5b4\uc11c \uc0ac\uc774\ub4dc \ud504\ub85c\uc81d\ud2b8\ub97c \uc9c4\ud589\ud558\ub294 \uadf8\ub8f9\ub3c4 \uc788\uc2b5\ub2c8\ub2e4. \uc800\ub294 \ub9ac\ud329\ud1a0\ub9c1 \uadf8\ub8f9\uc774\ub77c\ub294 \uc6b0\ub9ac\uac00 \uc791\uc131\ud55c \uae30\ub2a5 \uc911\uc5d0 \uc624\ub798\ub41c \ucf54\ub4dc\ub098 \uad6c\uc870\uc801\uc778 \ubcc0\ud654\uac00 \ud544\uc694\ud558\ub294 \uacf3\uc744 \uc791\uc5c5\ud558\ub294 \ub9ac\ud329\ud1a0\ub9c1 \uadf8\ub8f9\uc744 \uc9c4\ud589\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uadf8\ub8f9\uc758 \ud65c\ub3d9\uc73c\ub85c\ub294 \ubb38\uc81c\uc810\uc744 \ucc3e\uace0 \ubd84\uc11d\ud558\uace0 \uc6b0\ub9ac\uac00 \ubb34\uc5c7\uc744 \ud574\uc57c\ud560\uc9c0\ub97c \uc815\uc758\ud569\ub2c8\ub2e4.\\n\uadf8\ub9ac\uace0 \ud574\ub2f9 \ub0b4\uc6a9\uc5d0 \ub300\ud55c \uadfc\uac70\ub97c \ud655\uc2e4\ud558\uac8c \ud558\uae30 \uc704\ud574 \ubb38\uc11c\ud654\ub97c \ud558\uace0 \uc11c\ub85c\uc5d0\uac8c \ud53c\ub4dc\ubc31\uc744 \uc90d\ub2c8\ub2e4.\\n\uc2e4\uc81c \uae30\ub2a5\uc5d0 \uc801\uc6a9\ud558\ub294 \uac83\uc73c\ub85c \uc6b0\ub9ac \ub9ac\ud329\ud1a0\ub9c1 \uc18c\uadf8\ub8f9\uc740 \uc774\ub97c \ud1b5\ud574 \uc6b0\ub9ac\ub4e4\uc758 \ud504\ub85c\uc81d\ud2b8\uac00 \uc774\uc804 \ucf54\ub4dc\uc5d0 \ub300\ud55c \ub808\uac70\uc2dc\ub85c \uc815\uccb4\ub418\uc9c0 \uc54a\ub3c4\ub85d \ub178\ub825\ud569\ub2c8\ub2e4.\\n\\n7\uc6d4\uc5d0 \uc9c4\ud589\ud55c \ub0b4\uc6a9\uc73c\ub85c\ub294 \uc6b0\ub9ac \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c \uc8fc\ub85c \ud65c\uc6a9\ub418\ub294 `react-hook-form`\uacfc \ud504\ub85c\uc81d\ud2b8\uc5d0 \uc0c8\ub86d\uac8c \ucd94\uac00\ub41c `useFunnel`\uc5d0 \ub300\ud55c \uae30\ub2a5\uc774 \uc798 \ub3d9\uc791\ud558\ub294\uc9c0\uc640 \ucf54\ub4dc\uc801 \ubb38\uc81c\ub97c \uc9c0\uc801\ud558\uace0 \uc774\ub97c \uc218\uc815\ud558\ub294 \uc791\uc5c5\uc744 \uc9c4\ud589\ud588\uc2b5\ub2c8\ub2e4.\\n\\n<div style={{display: \'flex\', width: \'100%\', height: \'100%\'}}>\\n\\t\\t<img src=\\"https://i.imgur.com/rpXR4hw.png\\" width=\\"50%\\" height=\\"120%\\"/>\\n\\t<div style={{width: \'50%\'}}>\\n\\t\\t<img src=\\"https://i.imgur.com/aLmaIQu.png\\" width=\\"100%\\" height=\\"50%\\"/>\\n\\t\\t<img src=\\"https://i.imgur.com/A571lbQ.png\\" width=\\"100%\\" height=\\"50%\\"/>\\n\\t</div>\\n</div>\\n\\n\\n## \ub9c8\ubb34\ub9ac\ud558\uba70\\n\\n\ubb54\uac00 \ud68c\uace0\ub85d\uc774\uae30\ub3c4 \ud558\uc9c0\ub9cc \uc704\uc640 \uac19\uc740 \ud65c\ub3d9\ub4e4\uc744 \uc9c4\ud589\ud558\uace0 \uc788\ub2e4\uace0 \uc124\uba85\ud55c \ubd80\ubd84\ub9cc \ub9ce\uc558\ub358 \uac83 \uac19\uc2b5\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \uc774\ub807\uac8c \uc815\ub9ac\ud558\uba74\uc11c \\"\ub0b4\uac00 7\uc6d4 \ub3d9\uc548 \uc774\ub7f0 \uac83\uc744 \uc9c4\ud589\ud588\uad6c\ub098\\"\ub97c \uc0dd\uac01\ud569\ub2c8\ub2e4.  \\n\uc774\ub807\uac8c \ud68c\uace0\ub97c \ud1b5\ud574 \ub098\uc758 7\uc6d4 \ud65c\ub3d9\uc744 \uc815\ub9ac\ud574\ubcf4\uc558\uace0, \ud639\uc2dc \uc6b0\ub9ac BCSDLab\uc5d0 \uad00\uc2ec\uc774 \uc788\ub2e4\uba74, \uc774\ub7f0 \uccb4\uacc4\uc801\uc778 \uc9d1\ub2e8\uc784\uc744 \uc54c\uc544\uc8fc\uc168\uc73c\uba74 \ud558\ub294 \ub9c8\uc74c\uc785\ub2c8\ub2e4 ^^"},{"id":"/junghaesung79/cholog-study-meetup","metadata":{"permalink":"/front-end/junghaesung79/cholog-study-meetup","source":"@site/@frontEnd/junghaesung79/cholog-study-meetup.mdx","title":"\ucd08\ub85d\uc2a4\ud130\ub514 \ubc0b\uc5c5","description":"\ucd08\ub85d\uc2a4\ud130\ub514 \ubc0b\uc5c5\uc5d0\uc11c \ub290\ub080 \uc810\ub4e4\uc744 \uacf5\uc720\ud574\uc694","date":"2024-06-23T00:00:00.000Z","tags":[{"label":"\ucd08\ub85d\uc2a4\ud130\ub514","permalink":"/front-end/tags/\ucd08\ub85d\uc2a4\ud130\ub514"}],"readingTime":9.495,"hasTruncateMarker":true,"authors":[{"name":"Haesung Jung","url":"https://github.com/junghaesung79","email":"gotjd0230@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/96577250?v=4","key":"junghaesung79"}],"frontMatter":{"date":"2024-06-23T00:00:00.000Z","authors":"junghaesung79","title":"\ucd08\ub85d\uc2a4\ud130\ub514 \ubc0b\uc5c5","description":"\ucd08\ub85d\uc2a4\ud130\ub514 \ubc0b\uc5c5\uc5d0\uc11c \ub290\ub080 \uc810\ub4e4\uc744 \uacf5\uc720\ud574\uc694","keywords":["chologstudy","meetup"],"tags":["\ucd08\ub85d\uc2a4\ud130\ub514"]},"unlisted":false,"prevItem":{"title":"BCSDLab\uc740 \ubb50\ud558\ub294 \ub3d9\uc544\ub9ac\uc77c\uae4c?","permalink":"/front-end/posts/july-retrospect_daepan"},"nextItem":{"title":"\uc0dd\ud611 \ub808\ud3ec \ubd84\ub9ac \uc791\uc5c5 \ud68c\uace0","permalink":"/front-end/junghaesung79/koin-coop-web-separation"}},"content":"\ucd08\ub85d\uc2a4\ud130\ub514 \ubc0b\uc5c5\uc5d0\uc11c \ub290\ub080 \uc810\ub4e4\uc744 \uacf5\uc720\ud574\uc694!\\n\\n{/* truncate */}\\n\\n\uc548\ub155\ud558\uc138\uc694! \uc800\ub294 FE \ud2b8\ub799 \ub808\uade4\ub7ec \uc815\ud574\uc131\uc785\ub2c8\ub2e4!\\n\uc800\ub294 \uc9c0\uae08 \ucd08\ub85d\uc2a4\ud130\ub514\uc5d0\uc11c 4\uae30\ub85c \ud65c\ub3d9\ud558\uace0 \uc788\uc5b4\uc694. \uadf8\ub7f0\ub370 \uc774\ubc88\uc5d0 \ucd08\ub85d\uc2a4\ud130\ub514\uc5d0\uc11c 2024 \uc5ec\ub984 \ucd08\ub85d \ubc0b\uc5c5\uc744 \uac1c\ucd5c\ud574\uc11c \ubc14\ub85c \uc2e0\uccad\ud588\uc5b4\uc694! 6\uc6d4 30\uc77c\uc5d0 \uc11c\uc6b8\uc5d0\uc11c \ubaa8\uc600\ub294\ub370, \uc2e0\uae30\ud55c \uac74 \ubaa8\uc778 \ucd1d \ub9c8\ud754 \uba85 \uc815\ub3c4\uc758 \uc0ac\ub78c \uc911\uc5d0\uc11c 18\uba85\uc774 BCSD\uc5d0\uc11c \uc628 \uc0ac\ub78c\ub4e4\uc774\uc5c8\uc5b4\uc694.\\n\\n\ubc0b\uc5c5\uc758 \uc804\uccb4\uc801\uc778 \uc21c\uc11c\ub85c \uc18c\uac1c, \ubbf8\ub2c8\uac8c\uc784, \ubc1c\ud45c \uc138\uc158\uc744 \ub9c8\uce58\uace0 \ub124\ud2b8\uc6cc\ud0b9 \uc2dc\uac04\uc744 \uac00\uc84c\uc5b4\uc694. \uac04\ub2e8\ud55c \ub0b4\uc6a9\uacfc \uc81c\uac00 \ub290\ub080 \uc810\uc744 \ub9d0\uc500\ub4dc\ub9b4\uac8c\uc694!\\n\\n### \uc624\ud504\ub2dd \ub178\ud2b8\\n\uc81c\uc77c \ucc98\uc74c\uc5d0\ub294 \uc624\ud504\ub2dd \ub178\ud2b8\ub77c\uace0 \ud574\uc11c \ucd08\ub85d\uc2a4\ud130\ub514\uc5d0 \ub300\ud574 \uc124\uba85\ud574\uc8fc\uc168\uc5b4\uc694. \uc124\uba85\uc744 \ub4e3\uae30 \uc804\uae4c\uc9c0\ub294 \ub2e8\uc21c\ud558\uac8c \ubc31\uc5d4\ub4dc, \uadf8\uc911 \uc2a4\ud504\ub9c1\uc5d0 \ub300\ud574 \uc785\ubb38 \uac15\uc758\ub97c \uc81c\uacf5\ud558\uace0 \uad00\ub9ac \ud53c\ub4dc\ubc31 \ud574\uc8fc\ub294 \ucee4\ubba4\ub2c8\ud2f0 \uc815\ub3c4\ub85c \uc0dd\uac01\ud588\uc5b4\uc694. \ud558\uc9c0\ub9cc \uadf8 \uc548\uc5d0\ub294 \ucc38\uc5ec\uc790\uac00 \ub610\ub2e4\uc2dc \ucf58\ud150\uce20\ub97c \ub9cc\ub4e4\uc5b4\ub0b4\ub294, \ub9c8\uce58 \uc800\ud76c BCSD\uc640 \uac19\uc740 \uc120\uc21c\ud658 \uad6c\uc870\ub97c \ucc44\ud0dd\ud558\uace0 \ub610 \uc5ec\ub7ec \uac00\uc9c0 \uae30\ud68d\uc774 \uc9c4\ud589\ub418\uace0 \uc788\uc5c8\uc5b4\uc694. \uadf8\ub798\uc11c \uc624\ud504\ub2dd \ub178\ud2b8\ub97c \ub4e3\uace0 \ucd08\ub85d\uc2a4\ud130\ub514\uc5d0 \ub300\ud55c \uc560\uc815\ub3c4\uac00 \ub354\uc6b1 \ub192\uc544\uc9c4 \uac83 \uac19\uc544\uc694.\\n\\n### \ubbf8\ub2c8\uac8c\uc784\\n\ucd08\ub85d\uc2a4\ud130\ub514\uc5d0 \ub300\ud55c \uc18c\uac1c\uac00 \ub05d\ub098\uace0 \ub098\uc11c\ub294 \ud55c \uc2dc\uac04 \uc815\ub3c4 \ubbf8\ub2c8\uac8c\uc784\uc744 \uc9c4\ud589\ud588\uc5b4\uc694. \ubc31\uc5d4\ub4dc\uc5d0\uc11c \uc0ac\uc6a9\ud558\ub294 \uae30\uc220\uc744 \ud1b5\ud574 10\ubd84 \ub3d9\uc548 1\ubd84\ub9c8\ub2e4 \uc815\uac01\uc758 \ubd84(min)\uc5d0 \uc694\uccad\uc744 \ubcf4\ub0b4\uace0 \uc815\uac01 \ubd84\uacfc\uc758 \ucc28\uc774\uac00 \uac00\uc7a5 \uc801\uac8c \ub09c \uc0ac\ub78c\uc774 \uc6b0\uc2b9\ud558\ub294 \uac8c\uc784\uc774\uc5c8\uc5b4\uc694. \uac8c\uc784 \uc758\ub3c4\ub300\ub85c\ub77c\uba74 \ubc31\uc5d4\ub4dc\uc5d0\uc11c \uc5ec\ub7ec \uac00\uc9c0 \ubcc0\uc218\ub97c \uc608\uc0c1\ud574\uc11c \uc815\ud655\ud55c \ud0c0\uc774\ubc0d\uc5d0 \uc694\uccad\uc744 \ubcf4\ub0b4\ub294 \ucf54\ub4dc\ub97c \uc9dc\uc57c \ud558\uc9c0\ub9cc \ub9cc\uc57d \uc5b8\uc5b4\ub97c \ubab0\ub77c\ub3c4 \ub2e8\uc21c\ud788 swagger\uc5d0\uc11c \uc694\uccad\uc744 \uc218\ub3d9\uc73c\ub85c \ubcf4\ub0bc \uc218 \uc788\uc5b4\uc11c \uc800\ud76c \ud504\ub860\ud2b8\uc5d4\ub4dc\ub098 \uac8c\uc784, PM \ud2b8\ub799 \ubd84\ub4e4\ub3c4 \ucc38\uc5ec\ud560 \uc218 \uc788\ub2e4\ub294 \uc810\uc774 \uc88b\uc558\uc5b4\uc694! \uc800\ub294 \uc2a4\ud504\ub9c1 \uac15\uc758\uc758 1\uc8fc\ucc28\ub97c \uc5b4\ub290 \uc815\ub3c4 \uc9c4\ud589\ud588\uae30\uc5d0 \ubd80\ubd84\ubd80\ubd84 \ucf54\ub4dc\ub97c \uc774\ud574\ud560 \uc218\ub294 \uc788\uc5c8\uc9c0\ub9cc, \ub3c4\uc800\ud788 \ubb54\uac00\ub97c \ub9cc\ub4e4\uc5b4\ub0b4\uc9c0\ub294 \ubabb\ud558\uaca0\uace0 \uadf8\ub798\uc11c \ub9ac\uc561\ud2b8\ub97c \ud1b5\ud574\uc11c \uc9c4\ud589\ud558\ub824\uace0 \ud588\uc5b4\uc694. \ud558\uc9c0\ub9cc \uc2dc\uac04 \ub0b4\ub85c \ub9cc\ub4e4\uc9c0 \ubabb\ud574\uc11c \uc800\ub3c4 \uc218\ub3d9\uc73c\ub85c \ud588\uc8e0. \uadf8\ub798\ub3c4 \ub108\ubb34 \uc7ac\ubc0c\uac8c \ud55c \uac83 \uac19\uc544\uc694!\\n\\n\\n### \ubc1c\ud45c \uc138\uc158\\n\ub2e4\uc74c\uc740 \ubc1c\ud45c \uc138\uc158\uc774\uc5c8\ub294\ub370 \uc800\ud76c BCSD \ubc31\uc5d4\ub4dc \ud2b8\ub799 5\ubd84\uaed8\uc11c \ubc1c\ud45c\ub97c \uc900\ube44\ud574\uc8fc\uc168\uc5b4\uc694. \ub2e4\ub4e4 \uae34\uc7a5\ud55c\ub2e4\uace0 \ub9d0\ud558\uba74\uc11c \uc2e4\uc0c1 \uae34\uc7a5\ud55c \uae30\uc0c9\uc740 \ubcf4\uc774\uc9c0 \uc54a\uace0 \uc544\uc8fc \uc778\uc0c1\uae4a\uc5c8\ub358 \ubc1c\ud45c\ub97c \ud574\uc8fc\uc168\uc5b4\uc694. \ubaa8\ub450 \ud765\ubbf8\ub85c\uc6b4 \ubc1c\ud45c\uc600\uc9c0\ub9cc \uadf8\uc911\uc5d0\uc11c \ub450 \ubd84\uc758 \ubc1c\ud45c\uc5d0 \uc788\uc5c8\ub358 \ub0b4\uc6a9\uc774 \uac00\uc7a5 \uae30\uc5b5\uc5d0 \ub0a8\uc558\uc5b4\uc694.\\n\\n#### \ucd5c\uc900\ud638:\ucd08\ub85d\uc2a4\ud130\ub514 \uc6b4\uc601\uacbd\ud5d8 \uacf5\uc720\\n\ucc98\uc74c\uc740 \ucd5c\uc900\ud638\ud615\uc758 \ubc1c\ud45c\uc600\ub294\ub370 \uc9c0\uae08\uae4c\uc9c0 \ucd08\ub85d\uc2a4\ud130\ub514\ub97c 3\uae30\uae4c\uc9c0 \uc6b4\uc601\ud558\uba74\uc11c \ub290\ub080 \uac83\ub4e4\uc744 \uacf5\uc720\ud574\uc8fc\uc168\uc5b4\uc694. \uac01 \uae30\uc218\ub9c8\ub2e4\uc758 \ud2b9\uc9d5\uacfc \ub290\ub080 \uc810\ub4e4, \uadf8\ub9ac\uace0 \uc6b4\uc601\uc790/\ucc38\uc5ec\uc790\uc758 \ud301\ub3c4 \uc8fc\uc168\uc5b4\uc694. \uc800\ub3c4 \uc9c0\uae08 4\uae30\ub97c \ud558\uace0 \uc788\uae30 \ub54c\ubb38\uc5d0 \ub4e4\uc73c\uba74\uc11c \ub098\ub3c4 \uc774\ub807\uac8c \ud574\uc57c\uc9c0 \ud558\ub294 \uac8c \uba87\uba87 \uc788\uc5c8\uc5b4\uc694. \uc0ac\uc2e4 \uc800\ub294 1\uc8fc\ucc28\ub97c \ucc38\uc5ec\ud558\uba74\uc11c, \ubaa8\ub974\ub294 \uac83\uc744 \uc9c8\ubb38\ud558\uae30\uac00 \ub450\ub824\uc6e0\uc5b4\uc694. \uc81c\uac00 \uc0dd\uac01\ud558\uae30\uc5d0 \uc880 \uc0ac\uc18c\ud55c \uac83 \uac19\uc740 \uac83\ub4e4\uc744 \\"\uc774\uac83\ub3c4 \uc548 \ucc3e\uc544\ubcf4\uace0 \uc9c8\ubb38\ud558\ub098?\\"\ub77c\ub294 \ub9d0\uc744 \ub4e4\uc744 \uac83 \uac19\uc544\uc11c \uacc4\uc18d \uc9c8\ubb38\uc744 \uaebc\ub824 \uc654\uc5b4\uc694. \ud558\uc9c0\ub9cc \ubc1c\ud45c\uc5d0\uc11c \\"\uac81\uba39\uc9c0 \ub9c8\ub77c. \uc2e4\ud328\ud558\uba74 \uc5bb\ub294 \uac8c 2\ubc30. \ub2a5\ub3d9\uc801\uc778 \uc5b4\ub9b0\uc774\uac00 \uc131\uc7a5\uc774 \ube60\ub974\ub2e4.\\" \uc774\ub7f0 \ub9d0\ub4e4\uc744 \ub4e3\uace0 \uc9c0\uae08\uae4c\uc9c0 \uc5b4\ub9ac\uc11d\uc5c8\ub2e4\ub294 \uac83\uc744 \uae68\ub2ec\uc558\uc5b4\uc694. \ubaa8\ub974\ub294 \uac83\uc744 \uc804\ud600 \ubd80\ub044\ub7ec\uc6cc\ud560 \ud544\uc694\uac00 \uc5c6\ub294\ub370 \ub9d0\uc774\uc8e0.\\n\\n#### \ubc30\uc9c4\ud638:\ucd08\ub85d\uc2a4\ud130\ub514\ub97c \ud558\uac8c\ub418\uae30 \uae4c\uc9c0\uc640 \ubc30\uc6b4 \uac83\\n\ubc14\ub85c \ub2e4\uc74c \uc21c\uc11c\ub294 \uc9c4\ud638\uc600\ub294\ub370 \ucef4\ud4e8\ud130\uc5d0 \uad00\uc2ec\uc774 \uc0dd\uae30\uace0\ubd80\ud130 \uc9c0\uae08\uc758 \ucd08\ub85d\uc2a4\ud130\ub514\ub97c \ud558\uae30\uae4c\uc9c0 \uc0dd\uac01\ud55c \uac83\ub4e4\uc744 \uacf5\uc720\ud588\uc5b4\uc694. BCSD\uc5d0 \ub4e4\uc5b4\uc624\uae30 \uc804\uacfc \ud6c4, \uc18c\ud504\ud2b8\uc6e8\uc5b4 \ub9c8\uc5d0\uc2a4\ud2b8\ub85c \uacfc\uc815, \ucd08\ub85d\uc2a4\ud130\ub514\ub97c \ud558\uc9c0 \uc54a\uc558\ub354\ub77c\uba74 \uc774\ub7f0 \uc598\uae30\ub4e4\uc744 \ud574\uc92c\uc5b4\uc694. \ub9e8 \ucc98\uc74c\uc5d0 \uc2e0\uc785\uc0dd \ub54c\ubd80\ud130 BCSD \uc774\uc804\uae4c\uc9c0\ub294 \ubc31\uc900 \ubb38\uc81c\ub9cc \ud480\uc5c8\ub294\ub370 \uadf8\ub54c \ud478\ub294 \uc218\uc900\uc774 \ud558\ub8e8\uc5d0 5~10\ubb38\uc81c\ub97c \ud480\uc5c8\ub2e4\ub294 \uac8c \uc778\uc0c1 \uae4a\uc5c8\uc5b4\uc694. \uc800\ub294 \uc81c \uac00\uc7a5 \ud070 \ubb38\uc81c\uac00 \uc54c\uace0\ub9ac\uc998\uc774\ub77c\uace0 \uc0dd\uac01\ud558\uace0 \uc788\ub294 \uc0c1\ud669\uc5d0\uc11c \uc774 \uc774\uc57c\uae30\ub97c \ub4e3\uace0 \uc800\ub3c4 \uc800 \uc815\ub3c4\ub85c \ud480\uc5b4\uc57c\uaca0\ub2e4\uace0 \uc0dd\uac01\ud588\uc5b4\uc694. \ucde8\uc5c5\uc744 \uc704\ud55c \ub450 \uac00\uc9c0 \uc5f4\uc1e0\uac00 \uc788\ub2e4\uace0 \ud558\uba74 \ud558\ub098\ub294 \ud3ec\ud2b8\ud3f4\ub9ac\uc624\uace0 \ub098\uba38\uc9c0\ub294 \uc54c\uace0\ub9ac\uc998\uc774\ub77c\uace0 \uc0dd\uac01\ud574\uc694, \uc800\ub294 \uadf8\ub098\ub9c8 \ud3ec\ud2b8\ud3f4\ub9ac\uc624\uc5d0 \ub123\uc744 \ub0b4\uc6a9\uc774 \uc788\uc9c0\ub9cc \uc54c\uace0\ub9ac\uc998\uc740 \uc815\ub9d0 \ub300\ud559\uad50 \uc2e0\uc785\uc0dd \uc218\uc900\uc774\ub77c\uc11c \ucd5c\uadfc\uc5d0 \ucc9c\ucc9c\ud788 \uc2dc\uc791\ud558\uace0 \uc788\uc5c8\uc5b4\uc694. \uadf8\ub7f0\ub370 \ubaa9\ud45c\ub85c \ud558\ub294 \uc218\uc900\uc5d0 \ub3c4\ub2ec\ud558\ub824\uba74 \uc9c4\ud638\ucc98\ub7fc \uac01 \uc7a1\uace0 \ud558\ub8e8\uc5d0 5\ubb38\uc81c\ub97c \ud478\ub294 \uc218\uc900\uc758 \uc2dc\uac04\uc744 \uc368\uc57c \ud560 \uac83 \uac19\uc544\uc694. \\n\\n### \ub124\ud2b8\uc6cc\ud0b9\\n\ubc1c\ud45c \uc138\uc158\uc774 \ub05d\ub09c \ub2e4\uc74c\uc5d0\ub294 \uc784\uc758\ub85c \uc815\ud574\uc9c4 \uc870\ubcc4\ub85c \ub124\ud2b8\uc6cc\ud0b9 \uc2dc\uac04\uc744 \uac00\uc84c\uc5b4\uc694. \uc5b4\uca4c\uba74 \uc774\ubc88 \ubc0b\uc5c5\uc5d0 \ucc38\uc5ec\ud55c \uc0ac\ub78c\ub4e4\uc774 \uac00\uc7a5 \uae30\ub300\ud558\ub294 \uc2dc\uac04\uc778\ub370\uc694. \uc800\ub3c4 \uc774 \uc2dc\uac04\uc744 \uac00\uc7a5 \uae30\ub2e4\ub838\uc5c8\uc5b4\uc694. \uc815\ub9d0 \uc6b0\uc5f0\ud788 \uc800\ud76c \uc870 5\uba85 \ubaa8\ub450 \uc678\ud5a5\uc801\uc778 \uc0ac\ub78c\ub4e4\uc774\uc5c8\ub294\ub370 \uac1c\ubc1c\uc744 \uc804\uacf5\ud558\ub294 \uc0ac\ub78c\uc744 \ubaa8\uc544\uc11c \ubaa8\ub450 \uc678\ud5a5\uc801\uc774\uae30 \ud798\ub4e4\ub2e4\uace0 \uc0dd\uac01\ud574\uc11c \ub2e4\ub4e4 \uc2e0\uae30\ud574\ud588\uc5c8\uc5b4\uc694. \uac1c\ubc1c\uc790\ub97c \ubaa9\ud45c\ub85c \ud558\uac8c \ub41c \uacfc\uc815\uc774\ub098 \uc774\ubc88 \uc0c1\ubc18\uae30\uc5d0 \uc774\ub8ec \ubaa9\ud45c, \ud558\ubc18\uae30\uc5d0 \uc9d1\uc911\ud560 \ubaa9\ud45c \ub4f1 \uc5ec\ub7ec \uc774\uc57c\uae30\uac00 \ub098\uc654\uc5b4\uc694. \ucc98\uc74c \ubcf4\ub294 \uc0ac\ub78c\ub4e4\uacfc \ube44\uc2b7\ud558\uc9c0\ub9cc \uc11c\ub85c \ub2e4\ub978 \uacbd\uc704\ub97c \uac70\uccd0 \uac19\uc740 \uac1c\ubc1c\uc790\ub97c \ubaa9\ud45c\ub85c \ud558\ub294 \uac8c \uc870\uae08 \ubc85\ucc3c\ub358 \uac83 \uac19\uc544\uc694.\\n\\n\uc870\ubcc4 \ub124\ud2b8\uc6cc\ud0b9\uc774 \ub05d\ub098\uace0 \uac01\uc790\uc758 \uc870\uc5d0\uc11c \ub098\uc654\ub358 \uc598\uae30\ub97c \uacf5\uc720\ud558\ub294 \uc2dc\uac04\uc744 \uac00\uc84c\uc5b4\uc694. \uadf8\ub2e4\uc74c\uc5d0\ub294 \uc0ac\uc9c4\ub3c4 \ucc0d\uace0 \uc790\uc720\ub86d\uac8c \ub2e4\ub978 \uc0ac\ub78c\ub4e4\uacfc \ub300\ud654\ud588\uc5b4\uc694. \ubc0b\uc5c5 \ud504\ub85c\uadf8\ub7a8\uc5d0 \uc801\uadf9\uc801\uc774\uc5c8\ub358 \uba87\uba87 \uc0ac\ub78c\uc5d0\uac8c \ub9d0\uc744 \uac78\uace0 \uc2f6\uc5c8\uc5c8\ub294\ub370 \uc774\ub54c \uc774\uc57c\uae30\ud574 \ubcfc \uc218 \uc788\uc5c8\uc5b4\uc694. \\n\\n### \uc774\ubc88 \ubc0b\uc5c5\uc744 \ud1b5\ud574\\n\uc800\ub294 \uc774\ubc88 \ubc0b\uc5c5\uc744 \ub2e4\ub978 \ud559\uad50/\uc2a4\ud130\ub514\uc758 \uc0ac\ub78c\ub4e4\uacfc \uc5f0\uacb0\uc810\uc744 \uac16\uace0 \uc2f6\ub2e4\ub294 \ubaa9\uc801\uc73c\ub85c \uc9c0\uc6d0\ud588\uc5b4\uc694. BCSD\uc5d0 \ud55c\uc815\ub418\uc9c0 \ub9d0\uace0 \ub354 \ub113\uc740 \uacf3\uc5d0\uc11c \ub354 \ub9ce\uc740 \uc0ac\ub78c\ub4e4\uacfc \uad50\ub958\ud558\uace0 \uc2f6\uc740 \uc695\uad6c\ub97c \uc774\ubc88 \ubc0b\uc5c5\uc5d0\uc11c \uc5b4\ub290 \uc815\ub3c4 \ucda9\uc871\uc2dc\ud0ac \uc218 \uc788\uc5c8\uc5b4\uc694. \ub2e4\ub978 \ubd84\ub4e4\ub3c4 \ub108\ubb34 \uc990\uac70\uc6e0\ub358 \uc2dc\uac04\uc774\ub77c\uace0 \ub9d0\ud558\uba74\uc11c \ub098\uc911\uc5d0 \uba87 \ubc88 \ub354 \ub9cc\ub098\uc790\uace0 \ub9d0\ud588\uc5b4\uc694. \uc774\ubc88 \ubc0b\uc5c5\uc744 \uc2dc\uc791\uc73c\ub85c \uc885\uc885 \uc11c\uc6b8\uc5d0\uc11c \uc800\ub791 \ube44\uc2b7\ud55c \uac1c\ubc1c\uc790\ub97c \ubaa9\ud45c\ub85c \ud558\ub294 \uc0ac\ub78c\ub4e4\uacfc \ub354\uc6b1\ub354 \ub9ce\uc774 \uad50\ub958\ud558\uace0 \uc2f6\uc5b4\uc694!"},{"id":"/junghaesung79/koin-coop-web-separation","metadata":{"permalink":"/front-end/junghaesung79/koin-coop-web-separation","source":"@site/@frontEnd/junghaesung79/koin-coop-web-separation.mdx","title":"\uc0dd\ud611 \ub808\ud3ec \ubd84\ub9ac \uc791\uc5c5 \ud68c\uace0","description":"\uc0dd\ud611 \ub808\ud3ec \ubd84\ub9ac \uc791\uc5c5\uc744 \ud558\uba74\uc11c \ub290\ub080 \uc810\ub4e4\uc744 \uacf5\uc720\ud574\uc694","date":"2024-06-23T00:00:00.000Z","tags":[{"label":"\ucf54\uc778","permalink":"/front-end/tags/\ucf54\uc778"},{"label":"\uc0dd\ud611","permalink":"/front-end/tags/\uc0dd\ud611"}],"readingTime":8.605,"hasTruncateMarker":true,"authors":[{"name":"Haesung Jung","url":"https://github.com/junghaesung79","email":"gotjd0230@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/96577250?v=4","key":"junghaesung79"}],"frontMatter":{"date":"2024-06-23T00:00:00.000Z","authors":"junghaesung79","title":"\uc0dd\ud611 \ub808\ud3ec \ubd84\ub9ac \uc791\uc5c5 \ud68c\uace0","description":"\uc0dd\ud611 \ub808\ud3ec \ubd84\ub9ac \uc791\uc5c5\uc744 \ud558\uba74\uc11c \ub290\ub080 \uc810\ub4e4\uc744 \uacf5\uc720\ud574\uc694","keywords":["Koin","Coop"],"tags":["\ucf54\uc778","\uc0dd\ud611"]},"unlisted":false,"prevItem":{"title":"\ucd08\ub85d\uc2a4\ud130\ub514 \ubc0b\uc5c5","permalink":"/front-end/junghaesung79/cholog-study-meetup"},"nextItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 9\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654)","permalink":"/front-end/haejinyun/infomate-9week"}},"content":"\uc0dd\ud611 \ub808\ud3ec \ubd84\ub9ac \uc791\uc5c5\uc744 \ud558\uba74\uc11c \ub290\ub080 \uc810\ub4e4\uc744 \uacf5\uc720\ud574\uc694!\\n\\n{/* truncate */}\\n\\n\uc548\ub155\ud558\uc138\uc694! \uc800\ub294 FE \ud2b8\ub799 \ub808\uade4\ub7ec \uc815\ud574\uc131\uc785\ub2c8\ub2e4! \ucd5c\uadfc(\uc774\ub77c\uace0 \ub9d0\ud558\uae30\ub294 \ucc98\uc74c \uae30\ud68d \ub2f9\uc2dc \ucf54\ub4dc\uac00 \ubc8c\uc368 \uba87 \ub2ec \uc804\uc774\ub124\uc694\u314b\u314b..) \ucf54\uc778\uc5d0\uc11c \uc2dd\ub2e8\uc758 \uc0ac\uc9c4\uacfc \ud488\uc808\uc5d0 \uad00\ud55c \uc815\ubcf4\ub97c \uc8fc\uae30 \uc2dc\uc791\ud588\uc5b4\uc694! \uadf8\ub9ac\uace0 \uadf8\uac83\uc744 \uc704\ud55c \ubc31 \uc624\ud53c\uc2a4\uc778 \ucf54\uc778 \uc601\uc591\uc0ac \ud398\uc774\uc9c0\uac00 \ub9cc\ub4e4\uc5b4\uc84c\uc8e0. \uc774 \uc601\uc591\uc0ac \ud398\uc774\uc9c0\ub294 \uc544\uc9c1 \uc571\uc740 \uc5c6\uace0 \uc6f9\uc73c\ub85c\ub9cc \uc9c0\uc6d0\ud558\ub294\ub370 \uc9c0\uae08\uc740 [`KOIN_OWNER_WEB`](https://github.com/BCSDLab/KOIN_OWNER_WEB) \ub808\ud3ec\uc9c0\ud1a0\ub9ac(\uc774\ud558 \uc624\ub108 \ub808\ud3ec)\uc5d0 \uadf8 \ucf54\ub4dc\uac00 \uc788\uc5b4\uc694. \uadf8\ub798\uc11c \uc601\uc591\uc0ac\ub2d8\uc740 \uc6b0\uc120 [`owner.koreatech.in`](https://owner.koreatech.in/)\uc5d0 \uc811\uc18d\ud558\uace0 \uc800\ud76c\uac00 \ub530\ub85c \uc900\ube44\ud55c \uc601\uc591\uc0ac \uacc4\uc815\uc744 \ud1b5\ud574\uc11c \uc2dd\ub2e8\uc744 \uad00\ub9ac\ud558\uace0 \uc788\uc5b4\uc694. \uc804\ud600 \ub2e4\ub978 \uae30\ub2a5\uc744 \uc694\uad6c\ud558\ub294 \ub3c4\uba54\uc778\uc774\uc9c0\ub9cc \ucc98\uc74c \uae30\ud68d \ub2f9\uc2dc\uc5d0\ub294 \ub2e8\uc77c \ud398\uc774\uc9c0 \ud544\uc694 + \uc0dd\ud611\uacfc\uc758 \ud611\uc5c5\uc774 \uc2dc\ubc94\uc801\uc778 \uae30\ub2a5\uc774\ub77c\ub294 \uc774\uc720\ub85c \ub808\ud3ec\uc9c0\ud1a0\ub9ac\ub97c \ubd84\ub9ac\ud558\ub294 \uac83\ubcf4\ub2e4 \uae30\uc874 \ub808\ud3ec\uc5d0 \uc758\uc874\ud558\ub294 \uac8c \ub354 \uac04\ud3b8\ud574\uc11c \uadf8\ub807\uac8c \ud588\ub358 \uac83 \uac19\uc544\uc694. \ud558\uc9c0\ub9cc \ubd88\ud3b8\ud55c \uc810\ub3c4 \uc788\uc5c8\uc5b4\uc694.\ud83d\ude2d\\n\\n### \ub2e8\uc77c \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uc758 \ubb38\uc81c\uc810\\n1. \ub85c\uadf8\uc778 \uc2dc \uad8c\ud55c \uad6c\ubd84 \ud544\uc694\\n\uc0ac\uc7a5\ub2d8\uacfc \uc601\uc591\uc0ac\ub2d8\uc758 \uacc4\uc815\uc744 \uad6c\ubd84\ud574\uc57c \ud560 \ud544\uc694\uac00 \uc0dd\uae30\uace0 \uadf8\uc5d0 \ub530\ub77c \uc624\ub108 \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uc758 \ub85c\uadf8\uc778 \ub85c\uc9c1\uc744 \ub9ce\uc774 \uace0\uccd0\uc57c \ud588\uc5b4\uc694. \uc571\uc774 \uc544\ub2cc \uc6f9\ud398\uc774\uc9c0\ub77c\uc11c \ub204\uad70\uac00\uac00 url\ub85c \ub2e4\ub978 \ucabd \ud398\uc774\uc9c0\ub85c \uc811\uadfc\ud558\ub294 \uac00\ub2a5\uc131\ub3c4 \uc5c6\uc560\uc57c \ud558\uace0 \ubc84\uadf8\ub3c4 \ub9ce\uc774 \uc0dd\uae30\uace0... \uace0\uce58\ub294 \ub370 \uc2dc\uac04\uc774 \ub9ce\uc774 \ub4e4\uc5c8\uc8e0.\\n\\n2. \ubaa8\ub4c8 \uad6c\ubd84 \ud544\uc694\\n\uc0ac\uc7a5\ub2d8 \uae30\ub2a5\uacfc \uc601\uc591\uc0ac \uae30\ub2a5\uc5d0\uc11c \ube44\uc2b7\ud55c \ub3d9\uc791\uc744 \ud558\uc9c0\ub9cc \uad6c\ubd84\uc744 \ud574\uc11c \uc0ac\uc6a9\ud574\uc57c\ud558\ub294 \ubaa8\ub4c8\uc774 \uc788\uc5c8\uc5b4\uc694. \uc11c\ub85c \ub3c5\ub9bd\ub418\uc5b4 \uc788\uc9c0\ub9cc \ube44\uc2b7\ud55c \ubcc0\uc218\uba85\uc778 \uadf8\uac83\ub4e4\uc744 \uad6c\ubd84\ud574\uc57c \ud558\ub2c8 \uac1c\ubc1c\ud558\ub2e4\ubcf4\uba74 \uadf8\uac83\ub4e4\uc774 \ud5f7\uac08\ub9b4 \ub54c\uac00 \uc788\uc5c8\uc5b4\uc694. \\n\\n3. \ud655\uc7a5 \ud55c\uacc4\uc131\\n\uadf8\ub9ac\uace0 \ub9cc\uc57d\uc5d0 \uc774\ubc88 \uc601\uc591\uc0ac \ud398\uc774\uc9c0\ucc98\ub7fc \uc0dd\ud611\uc774\ub098 \ud559\uad50 \uce21\uacfc \uc5f0\uacc4\ud560 \ub9cc\ud55c \uae30\ud68d\uc774 \uc0dd\uacbc\uc744 \ub54c \ucf54\uc778 \uc0ac\uc7a5\ub2d8\uacfc \uac19\uc740 \ub3c4\uba54\uc778\uc744 \uc4f0\uae30 \ub54c\ubb38\uc5d0 \ud504\ub860\ud2b8\uc5d4\ub4dc \uc785\uc7a5\uc5d0\uc11c\ub294 \uc18c\uadf9\uc801\uc774\uac8c \ub420 \uc218 \uc788\ub2e4\uace0 \uc0dd\uac01\ud574\uc694. \uc800\ub294 \uac1c\uc778\uc801\uc73c\ub85c \uc774\ubc88 \uc601\uc591\uc0ac \ud398\uc774\uc9c0 \uac1c\ubc1c\ub85c \uc778\ud55c \uc2dd\ub2e8 \uc0ac\uc9c4 \uae30\ub2a5\uc758 \ud559\uc0dd\ub4e4\uacfc \ud559\uad50\uce21\uc758 \ubc18\uc751\uc774 \uc88b\uc740 \uac83 \uac19\uc544\uc11c \uc880 \ub354 \ub3c4\uc804\uc801\uc73c\ub85c \ud655\uc7a5\ud558\uace0 \uc2f6\uc5b4\uc694!\\n\\n\uadf8\ub798\uc11c \ub808\ud3ec\uc9c0\ud1a0\ub9ac\ub97c \ubd84\ub9ac\ud558\uae30\ub85c \ud588\uc2b5\ub2c8\ub2e4!!(\uc6b0\uc640) \uae30\uc655 \uc0c8\ub85c \ub9cc\ub4dc\ub294 \uac70 \ucc98\uc74c\uc73c\ub85c vite\ub97c \uc0ac\uc6a9\ud558\uae30\ub85c \ud588\uc5b4\uc694. \ud504\ub85c\uc81d\ud2b8 \ud3f4\ub354\uc640 [`KOIN_COOP_WEB`](https://github.com/BCSDLab/KOIN_COOP_WEB) \ub808\ud3ec\uc9c0\ud1a0\ub9ac(\uc774\ud558 \uc0dd\ud611 \ub808\ud3ec) \uc0dd\uc131\uc740 \uc6b0\ub9ac \ud2b8\ub799\uc7a5\ub2d8\uaed8\uc11c \ud574\uc8fc\uc168\uace0 \uc800\ub294 \uc0dd\uc131\uc744 \uc81c\uc678\ud55c, \uc5ec\ub7ec \uc124\uc815\uacfc \uc624\ub108 \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uc5d0\uc11c \uc601\uc591\uc0ac \ubd80\ubd84\ub9cc \ube7c\uc11c \uac00\uc838\uc624\ub294 \uc77c\uc744 \ud588\uc5b4\uc694. \ub808\ud3ec\uc9c0\ud1a0\ub9ac \ucd08\uae30\ub97c \uafb8\ubbf8\uac8c \ub41c  \uac83\uc774 \ucc98\uc74c\uc774\ub77c \ucd08\ubc18\uc5d0\ub294 \ub9c9\ub9c9\ud588\uc5c8\ub294\ub370 \ud558\ub098\ud558\ub098 \uac74\ub4dc\ub824\ubcf4\uba74\uc11c \uc990\uac81\uac8c \ucf54\ub529\ud55c \uac83 \uac19\uc544\uc694. \ub2e4\ub978 \uc0ac\ub78c \ub208\uce58 \uc548 \ubcf4\uace0 \ud558\uace0 \uc2f6\uc740 \uac83\uc744 \ub9ce\uc774 \ud588\uc5b4\uc694. \uc81c\uac00 \uc791\uc5c5\ud558\uba74\uc11c \uae30\uc5b5\uc5d0 \ub0a8\ub294 \ubd80\ubd84\uc744 \uc124\uba85\ud574\ub4dc\ub9b4\uac8c\uc694!\\n\\n### \ubd84\ub9ac \uc791\uc5c5 \uc911 \uae30\uc5b5\uc5d0 \ub0a8\ub294 \uc810\\n1. \ucf54\ub4dc \uc2a4\ud0c0\uc77c \uac00\uc774\ub4dc\ub77c\uc778 \uaddc\uce59 \ucd94\uac00\\n\uc774\uc804 \uca5d\uca5d\ubc15\uc0ac \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c \uc788\uc5c8\ub358, \uac1c\uc778\uc801\uc73c\ub85c \ub418\uac8c \ub9cc\uc871\ud558\uace0 \uc788\ub358 \uaddc\uce59\uc744 \ucd94\uac00\ud588\uc5b4\uc694! \uadf8\uac74 \ubc14\ub85c import \uadf8\ub8f9\uc5d0 \uad00\ud55c \uaddc\uce59\uc774\uc608\uc694. import \ud558\ub294 \ud6c5\uacfc \ucef4\ud3ec\ub10c\ud2b8\ub4e4\uc774 \ub9ce\uc544\uc9d0\uc5d0 \ub530\ub77c \uc911\uad6c\ub09c\ubc29\ud574\uc9c0\ub294 \ucf54\ub4dc\uac00 \ubd88\ub9cc\uc774\uc5c8\ub294\ub370 \uadf8\uac83\uc744 \ud574\uc18c\ud558\uace0 \uac00\ub3c5\uc131\uc744 \ub298\ub9ac\uace0 \uc2f6\uc5b4\uc11c \uc774 \uaddc\uce59\uc744 \ub123\uc5c8\uc5b4\uc694. \uadf8\ub9ac\uace0 \uc800\uc7a5 \uc2dc \uc790\ub3d9\uc73c\ub85c eslint \uaddc\uce59\uc5d0 \ub530\ub77c \ucf54\ub4dc\ub97c \uc815\ub82c\ud574\uc8fc\ub294 `source.fixAll.eslint` \ud3b8\uc9d1\uae30 \uc124\uc815\ub3c4 \ucd94\uac00\ud588\uc5b4\uc694. \uc774 \ub450 \uac00\uc9c0 \ub355\ubd84\uc5d0 intellisense + auto imoprt \uc2dc \uc800\uc7a5\uc744 \ub204\ub974\ub294 \uac83\ub9cc\uc73c\ub85c \uc62c\ubc14\ub978 import \uadf8\ub8f9 \uc704\uce58\uc5d0 \ub4e4\uc5b4\uac00\uac8c \ub3fc\uc694!!\\n\\n2. \uad6c\uc131 \ud30c\uc77c\uacfc \uc124\uc815 \ud30c\uc77c\\n\uadf8\ub3d9\uc548\uc740 \uc124\uc815 \ud30c\uc77c\uc744 \ub9cc\uc838\ubcf8 \uacbd\ud5d8\uc774 \ubcc4\ub85c \uc5c6\uc5c8\ub294\ub370 \uc774\ubc88 \uae30\ud68c\uc5d0 \ud558\ub098\ud558\ub098 \uc870\uc0ac\ud558\uba70 \uac01\uac01\uc758 \ud30c\uc77c\uc774 \uc5b4\ub5a4 \uc5ed\ud560\uc744 \ud558\ub294 \uc9c0 \uc54c \uc218 \uc788\uc5c8\uc5b4\uc694. config \ud30c\uc77c\uc774\ub098 manifest\uac00 \ubb34\uc5bc \uad00\ub9ac\ud558\ub294 \uc9c0 \uc54c\uac8c \ub418\uc5c8\uace0 `.github`\uc758 \uc5ec\ub7ec \ud15c\ud50c\ub9bf\uacfc workflows\ub97c \uc218\uc815\ud558\uc5ec \uae43\ud5c8\ube0c \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uc758 pr \uc2dc\uc758 \ud15c\ud50c\ub9bf\uacfc \ub3d9\uc791\uc744 \uc218\uc815\ud588\uc5b4\uc694. \ub610 `index.html`\uc758 \uba54\ud0c0\ub370\uc774\ud130\ub3c4 \ub9cc\uc838\ubcfc \uc218 \uc788\uc5c8\uc5b4\uc694.\\n\\n3. \ubcc0\uc218\uba85, \ub85c\uc9c1 \ub4f1\uc758 \ud1b5\uc77c\\n\uc800\ub294 \ud504\ub860\ud2b8\ub97c \ub9cc\ub4e4 \ub54c \ucf54\ub4dc\uc758 \uac00\ub3c5\uc131\uc774\ub098 \uc77c\uad00\uc131\uc744 \uc911\uc694\ud558\uac8c \uc0dd\uac01\ud574\uc694. \uadf8\ub798\uc11c \uc790\uc8fc \ub3d9\uc544\ub9ac \ucf54\ub4dc\ub4e4\uc744 \ub9ac\ud329\ud1a0\ub9c1 \ud558\uace4 \ud558\uc8e0. \uc774\ubc88 \ub808\ud3ec \ubd84\ub9ac \uc791\uc5c5\uc744 \ud558\uae30 \uc804\uc5d0 [`KOIN_WEB_RECODE`](https://github.com/BCSDLab/KOIN_WEB_RECODE) \ub808\ud3ec\uc9c0\ud1a0\ub9ac(\uc774\ud558 \ub9ac\ucf54\ub4dc \ub808\ud3ec)\uc5d0\uc11c \ud559\uc0dd\uc2dd\ub2f9 \ucabd\uc744 \ud06c\uac8c \ub9ac\ud329\ud1a0\ub9c1 \ud588\ub294\ub370 \uadf8\ub54c \uc81c\uac00 \uc138\uc6b4 \ub098\ub984\uc758 \uaddc\uce59\uc5d0 \ub530\ub77c \uc774\ubc88 \uc0dd\ud611 \ub808\ud3ec\uc9c0\ud1a0\ub9ac\ub3c4 \uc218\uc815\ud588\uc5b4\uc694. \ub9ac\ucf54\ub4dc\uc640 \uc0dd\ud611 \ucf54\ub4dc\uac00 \ub611\uac19\uc774 \uc2dd\ub2e8\uc744 \ub2e4\ub8e8\uc9c0\ub9cc \uba87\uba87 \uc11c\ub85c \ub2e4\ub978 \ud0a4\uc6cc\ub4dc\ub97c \uc0ac\uc6a9\ud558\uace0 \uc788\uc5b4\uc11c \ud5f7\uac08\ub9ac\ub294 \uacbd\uc6b0\uac00 \uc788\uc5c8\ub294\ub370 \uc774\ubc88 \uae30\ud68c\uc5d0 \ud1b5\uc77c\ud560 \uc218 \uc788\uc5c8\uc5b4\uc694. \uc608\ub97c \ub4e4\uc5b4 A\ucf54\ub108/\ub2a5\uc218\uad00 \ub4f1 \uc7a5\uc18c\ub294 place\ub85c, \uc544\uce68/\uc810\uc2ec/\uc800\ub141\uc740 response\uc758 \uc774\ub984\uc744 \ucc38\uace0\ud574\uc11c dining type\uc73c\ub85c \ud1b5\uc77c\ud588\uc5b4\uc694.\\n\\n    \ub85c\uc9c1\uc758 \uacbd\uc6b0\uc5d0\ub294 \ub808\ud3ec\uc9c0\ud1a0\ub9ac\ub97c \ubd84\ub9ac\ud560 \ub54c \ub9ac\ucf54\ub4dc\uc640 \uc624\ub108 \ub808\ud3ec\uc9c0\ud1a0\ub9ac \uc911\uc5d0\uc11c \ub354 \ub098\uc740 \ub85c\uc9c1\uc744 \uc774\uc6a9\ud574 \ub9ac\ud329\ud1a0\ub9c1 \ud558\uba74\uc11c \uac00\ub3c5\uc131/\uc720\uc9c0\ubcf4\uc218\uc131\uc744 \ub298\ub838\uc5b4\uc694. \ub098\uc911\uc5d0\ub294 \ub9ac\ucf54\ub4dc \ucabd\uc5d0 \ub0a0\uc9dc \uc120\ud0dd \ub85c\uc9c1\uacfc zod\uc758 response schema\ub97c \uc801\uc6a9\ud574\uc11c \uc77c\uad00\uc131\uc744 \uc720\uc9c0\ud558\ub824\uace0 \ud574\uc694.\\n\\n### \uc774\uc678\uc5d0\ub3c4..\\n\uc774\ub7f0 \ubcc0\uacbd\uc810\ub4e4 \uc678\uc5d0\ub3c4 svg\uc758 import \ubc29\uc2dd\uc758 \ubcc0\ud654\ub098 \ucffc\ub9ac \ud0a4 \ubb34\ud6a8\ud654, Suspense\uc758 \uc801\uc808\ud55c \uc704\uce58 \ub4f1\ub4f1 \uae30\uc5b5\uc5d0 \ub0a8\ub294 \ubb38\uc81c\uc640 \ud574\uacb0 \uacbd\ud5d8\uc774 \uae30\uc5b5\uc5d0 \ub0a8\uc544\uc694. \uc774\ubc88 \uc791\uc5c5\uc740 \uc0c8\ub85c \uc54c\uac8c \ub41c \uac83\ub3c4 \ub9ce\uace0 \uad6c\uc131\uacfc \uad6c\ud604\uc5d0 \ub300\ud55c \ub9cc\uc871\uac10\ub3c4 \ucef8\uc5b4\uc694. \ud2b9\ud788 \ud1a0\ud070\uacfc \ub85c\uadf8\uc778\uc5d0 \uad00\ub828\ub41c \ub85c\uc9c1\uc5d0 \ub300\ud55c \uc774\ud574\ub3c4\uac00 \ub9ce\uc774 \ub298\uc5c8\uc5b4\uc694! \uc124\uc815\ud30c\uc77c\uc5d0 \ub300\ud55c \ub450\ub824\uc6c0\ub3c4 \uc904\uc5b4\uc11c \uc0ac\uc774\ub4dc \ud504\ub85c\uc81d\ud2b8\ub97c \uc2dc\uc791\ud558\uace0\uc790 \ud558\ub294 \uc5f4\uc815\ub3c4 \uc0dd\uacbc\uc5b4\uc694. \uc544\ubb34\ucabc\ub85d \uac1c\uc778\uc801\uc73c\ub85c \uc544\uc8fc \ub9cc\uc871\uc2a4\ub7ec\uc6b4 \uc791\uc5c5\uc774\uc5c8\uc5b4\uc694!"},{"id":"/haejinyun/infomate-9week","metadata":{"permalink":"/front-end/haejinyun/infomate-9week","source":"@site/@frontEnd/haejinyun/infomate-9week.mdx","title":"\uc778\ud3ec\uba54\uc774\ud2b8 9\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 9\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","date":"2024-06-10T00:00:00.000Z","tags":[{"label":"\uc778\ud3ec\uba54\uc774\ud2b8","permalink":"/front-end/tags/\uc778\ud3ec\uba54\uc774\ud2b8"},{"label":"\ucd5c\uc801\ud654","permalink":"/front-end/tags/\ucd5c\uc801\ud654"}],"readingTime":11.375,"hasTruncateMarker":true,"authors":[{"name":"haejinyun","url":"https://github.com/haejinyun","email":"dbshaejin@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/86779590?v=4","key":"haejinyun"}],"frontMatter":{"date":"2024-06-10T00:00:00.000Z","authors":"haejinyun","title":"\uc778\ud3ec\uba54\uc774\ud2b8 9\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 9\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","keywords":["\uc778\ud3ec\uba54\uc774\ud2b8","\ucd5c\uc801\ud654"],"tags":["\uc778\ud3ec\uba54\uc774\ud2b8","\ucd5c\uc801\ud654"]},"unlisted":false,"prevItem":{"title":"\uc0dd\ud611 \ub808\ud3ec \ubd84\ub9ac \uc791\uc5c5 \ud68c\uace0","permalink":"/front-end/junghaesung79/koin-coop-web-separation"},"nextItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 8\uc8fc\ucc28 \uacf5\uc720(\ud504\ub808\uc784\uc6cc\ud06c & \ub77c\uc774\ube0c\ub7ec\ub9ac)","permalink":"/front-end/haejinyun/infomate-8week"}},"content":"\uc778\ud3ec\uba54\uc774\ud2b8 9\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654) \ubaa8\uc74c\uc785\ub2c8\ub2e4.\\n\\n\uc6f9 \uc131\ub2a5 \ucd5c\uc801\ud654\uac00 \ud544\uc694\ud55c\uac00\uc694? - \uc724\ud574\uc9c4  \\n\\n{/* truncate */}\\n\\n## \uc6f9 \uc131\ub2a5 \ucd5c\uc801\ud654\uac00 \ud544\uc694\ud55c\uac00\uc694? - \uc724\ud574\uc9c4\\n\\n### \ub4e4\uc5b4\uac00\ub294 \ub9d0)\\n\\n\uc6f9 \uc131\ub2a5 \ucd5c\uc801\ud654\ub77c\ub294 \ub9d0\uc740 \ub9ce\uc774 \ub4e4\uc5b4\ubcf4\uc168\uc744 \uac83\uc785\ub2c8\ub2e4. \\n\\n\ucd5c\uc801\ud654\ub97c \uc65c \ud558\uc2dc\ub098\uc694? \ub77c\ub294 \uc9c8\ubb38\uc5d0 \uc800\ub294 \ube60\ub978 \uc6f9 \uc0ac\uc774\ud2b8\uac00 \uc0ac\uc6a9\ud558\uae30 \uc88b\uc73c\ub2c8\uae4c\uc694.\ub77c\ub294 \ub2f5\uc774 \uc804\ubd80\uc600\uc2b5\ub2c8\ub2e4. \\n\\n\uc774\ubc88 \uae00\uc744 \uc77d\uc73c\uba70 \uc880\ub354 \uad6c\uccb4\uc801\uc778 \uc6f9 \uc131\ub2a5 \ucd5c\uc801\ud654\uc758 \uc774\uc720\uc640 \uce21\uc131 \uae30\uc900\uc5d0 \ub300\ud574\uc11c \uc54c\uc544\ubcf4\uace0\uc790 \ud569\ub2c8\ub2e4.\\n\\n## 1. \uc131\ub2a5 \uce21\uc815\uc774 \ud544\uc694\ud55c \uc774\uc720?\\n\\n### \ube44\uc988\ub2c8\uc2a4 \uad00\uc810\\n\\n\ub9cc\uc57d \uc0ac\uc6a9\uc790\uac00 koin\uc5d0 \uc811\uc18d\ud558\uc5ec \uc2dd\ub2e8 \uc815\ubcf4\ub97c \ud655\uc778\ud558\ub824 \ud569\ub2c8\ub2e4. \uc774\ub54c \uc0ac\uc774\ud2b8\uc5d0 \uc811\uc18d\ud574\ub3c4 5\ucd08 \uc774\uc0c1 \ud654\uba74 \ub85c\ub4dc\uac00 \ub418\uc9c0 \uc54a\ub294\ub2e4\uace0 \ud55c\ub2e4\uba74 \uc0ac\uc6a9\uc790\ub294 \uacc4\uc18d\ud574\uc11c \uc0ac\uc774\ud2b8\uc5d0 \uc811\uc18d\ud560\uae4c\uc694?\\n\\n\uc800\ub9cc\ud558\uc5ec\ub3c4 \ubc14\ub85c \uc0ac\uc774\ud2b8\ub97c \uc774\ud0c8\ud558\uc5ec \ub2e4\ub978 \ubc29\uc2dd\uc73c\ub85c \uc815\ubcf4\ub97c \uc5bb\uc73c\ub824 \ud560 \uac83\uc785\ub2c8\ub2e4.\\n\\n\uc6f9 \uc0ac\uc774\ud2b8\uac00 \uc0ac\uc6a9\uc790\uc5d0\uac8c \ube68\ub9ac \ub85c\ub529\ub418\uba74 \uc88b\uc740 \uc0ac\uc6a9\uc790 \uacbd\ud5d8(UX, User Experince)\uc744 \uc81c\uacf5\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc0ac\uc6a9\uc790\uac00 \uc6f9 \uc0ac\uc774\ud2b8\uc5d0 \ub4e4\uc5b4\uac14\uc744 \ub54c, \ud558\uc580 \ud654\uba74\uc744 \ub178\ucd9c\uc2dc\ud0a4\uac70\ub098 \uc6f9 \uc0ac\uc774\ud2b8 \ub85c\ub529 \ubc0f \ub80c\ub354\ub9c1\uc5d0 \uc9c0\uc5f0\uc774 \ubc1c\uc0dd\ud558\uba74 \uc0ac\uc6a9\uc790\ub294 \uc790\uc5f0\uc2a4\ub808 \uc774\ud0c8\ud558\uac8c \ub418\uace0, \uc774 \ub54c \ud574\ub2f9 \uc6f9 \uc11c\ube44\uc2a4\ub294 \ubc29\ubb38 \uc0ac\uc6a9\uc790\uc5d0 \ub300\ud55c \uacb0\uc81c, \uad11\uace0 \ub4f1\uc758 \ube44\uc988\ub2c8\uc2a4 \uae30\ud68c\ub97c \uc783\uc5b4\ubc84\ub9ac\uac8c \ub429\ub2c8\ub2e4.\\n\\nThink with Google\uc758 \uae30\uc0ac\uc5d0\uc11c \ubc1c\ucdcc\ud55c \ub0b4\uc6a9\uc73c\ub85c\ub294 \uc6f9 \ud398\uc774\uc9c0 \ub85c\ub529 \uc2dc\uac04\uacfc \uc0ac\uc6a9\uc790 \uc774\ud0c8\ub960\uc5d0 \ub300\ud574 \uc774\uc57c\uae30 \ud588\uc2b5\ub2c8\ub2e4. \uae30\uc0ac\uc5d0 \ub530\ub974\uba74 `\ud398\uc774\uc9c0 \ub85c\ub529 \uc2dc\uac04\uc774 1\ucd08\uc5d0\uc11c 3\ucd08\ub85c \uc99d\uac00\ud558\uba74 \ud398\uc774\uc9c0 \uc774\ud0c8\ub960\uc774 32%\ub85c \uc99d\uac00`\ud55c\ub2e4\uace0 \ud558\uace0, `1\ucd08\uc5d0\uc11c 10\ucd08\uac00 \ub418\uba74 \ubb34\ub824 \ud398\uc774\uc9c0 \uc774\ud0c8\ub960\uc774 123%`\ub098 \ub41c\ub2e4\uace0 \ud569\ub2c8\ub2e4.\\n\\n### \uac80\uc0c9 \uc5d4\uc9c4 \uad00\uc810(SEO)\\n\\n2021\ub144 5\uc6d4\ubd80\ud130 Google\uc5d0\uc11c\ub294 \uc6f9 \uc131\ub2a5 \uc9c0\ud45c(\uc6f9 \uc131\ub2a5 \ucd5c\uc801\ud654\uac00 \uc5b4\ub290\uc815\ub3c4 \ub418\uc5c8\ub294\uac00)\ub294 \uac80\uc0c9\uc5d4\uc9c4 \uc21c\uc704\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce5c\ub2e4\uace0 \ubc1c\ud45c\ud588\uc2b5\ub2c8\ub2e4.\\n\\n\uc544\ub798 Google\uc774 \uc18c\uac1c\ud55c \ud45c\uc5d0\uc11c \ubcf4\uba74 Core Web Vitas\uc5d0 \uc788\ub294 LCP, FID(First Input Delay, \ucd5c\ucd08 \uc785\ub825 \uc9c0\uc5f0 \uc2dc\uac04), CLS(Cumulative Layout Shift, \ud398\uc774\uc9c0 \ub85c\ub4dc\uc2dc \ucd95\ucc99\ub41c \ud654\uba74\uc758 \uc6c0\uc9c1\uc784)\ub97c \ub9d0\ud569\ub2c8\ub2e4. (\uc774\ub294 \ud558\uc704 \ub2e8\ub77d\uc5d0\uc11c \uc790\uc138\ud788 \ub2e4\ub8f9\ub2c8\ub2e4.)\\n\\n## 2. FE\uc5d0\uc11c \uce21\uc815\ud574\uc57c \ud560 \uc131\ub2a5\uc740?\\n\\n### \ub85c\ub529\\n\\n\ub85c\ub529 \uc131\ub2a5\uc740 \uc11c\ubc84\uc5d0\uc11c \uc6f9 \ud398\uc774\uc9c0\uc5d0 \ud544\uc694\ud55c HTML, CSS, Javascript, \ubbf8\ub514\uc5b4 \uc18c\uc2a4(Image, Video) \ub4f1\uc758 \ub9ac\uc18c\uc2a4\ub97c \ub2e4\uc6b4\ub85c\ub4dc\ud560 \ub54c\uc758 \uc131\ub2a5\uc744 \ub9d0\ud569\ub2c8\ub2e4.\\n\\n- **FCP (First Contentful Paint)**\\n    \\n    FCP\ub294 \ud398\uc774\uc9c0\uac00 \ub85c\ub4dc\ub418\uae30 \uc2dc\uc791\ud558\uace0 \ucee8\ud150\uce20\uc758 \uc77c\ubd80\uac00 \ud654\uba74\uc5d0 \ub80c\ub354\ub9c1 \ub420 \ub54c \uae4c\uc9c0\uc758 \uc2dc\uac04\uc744 \uc758\ubbf8\ud569\ub2c8\ub2e4.\\n    \\n    \uc989, \uccab \uc694\uc18c\uac00 \ub85c\ub4dc \ub420 \ub54c\uae4c\uc9c0 \uac78\ub9ac\ub294 \uc2dc\uac04\uc744 \uc758\ubbf8\ud569\ub2c8\ub2e4.\\n    \\n- **FMP** **(First Meaningful Paint)**\\n    \\n    \ube0c\ub77c\uc6b0\uc800\uac00 \ud398\uc774\uc9c0\uc758 \uc8fc\uc694 \ucee8\ud150\uce20\ub4e4\uc744 \ud654\uba74\uc5d0 \ub80c\ub354\ub9c1\ud558\uae30 \uc2dc\uc791\ud558\ub294 \uc21c\uac04\uc744 \uc758\ubbf8\ud569\ub2c8\ub2e4.\\n    \\n    \uc989, \uc0ac\uc6a9\uc790\uc5d0\uac8c \uc758\ubbf8\uc788\ub294 \uccab \uc694\uc18c\uac00 \ub9ac\ub4dc\ub418\ub294 \uc21c\uac04\uc785\ub2c8\ub2e4.\\n    \\n- **LCP** **(Largest Contentful Paint)**\\n    \\n    \ud398\uc774\uc9c0\uc5d0\uc11c \uac00\uc7a5 \uc6a9\ub7c9\uc774 \ud070 \ucee8\ud150\uce20\uac00 \ud45c\uc2dc\ub418\ub294 \uc2dc\uc810\uc744 \ub098\ud0c0\ub0c5\ub2c8\ub2e4.\\n    \\n    \uc989, \uc8fc\uc694 \ucee8\ud150\uce20\uac00 \ub85c\ub4dc \ub420 \ub54c \uac78\ub9ac\ub294 \uc2dc\uac04\uc744 \ub9d0\ud569\ub2c8\ub2e4.\\n    \\n    \uad6c\uae00 \uc81c\uc2dc \uae30\uc900.\\n    \\n    - 2.5 \ubbf8\ub9cc: \uc88b\uc74c\\n    - 2.5 ~ 4.0: \uac1c\uc120 \ud544\uc694\\n    - 4.0 \uc774\uc0c1: \ud615\ud3b8 \uc5c6\uc74c\\n    \\n    \uc73c\ub85c \uad6c\ubd84\ud569\ub2c8\ub2e4.\\n    \\n\\n\ucf54\uc778\uc758 \uc2dd\ub2e8\uc73c\ub85c \uc608\ub97c \ub4e4\uc790\uba74, \ucc98\uc74c \ud5e4\ub354\uc640 \ub808\uc774\uc544\uc6c3\uc778 \uccab \uc694\uc18c\uac00 \ub728\ub294 \uac83\uc774 LCP\\n\\n\uc0ac\uc6a9\uc790\uc5d0\uac8c \uc758\ubbf8 \uc788\ub294 \uc694\uc18c\uc640 \ud398\uc774\uc9c0\uc5d0\uc11c \uac00\uc7a5 \ud070 \ucee8\ud150\uce20\ub97c \ucc28\uc9c0\ud558\ub294 \uac83\uc774 \ub3d9\uc77c\ud558\uae30\uc5d0 \uc2dd\ub2e8 \uc694\uc18c\ub4e4\uc774 FMP\uacfc LCP\uac00 \ub3d9\uc77c\ud55c \uc2dc\uc810\uc774 \ub420 \uac83\uc785\ub2c8\ub2e4.\\n\\n+\ucd5c\uadfc FCP\uc758 \uacbd\uc6b0 \ub85c\ub529\ubc14\uc640 \uac19\uc740 \ub300\uae30\ub97c \ub098\ud0c0\ub0b4\ub294 \uc694\uc18c\uac00 \uc788\ub294 \uacbd\uc6b0\uac00 \ub9ce\uc544, \uc2e4\uc81c \ucee8\ud150\uce20\uc640 \uad00\ub828 \uc5c6\ub294 \ub85c\ub529 \uc0c1\ud669\uc744 \uc0ac\uc6a9\uc790\uac00 \ubcf4\ub294 \uac83\uc740 \uc9c0\uc5f0 \uc2dc\uac04\uc73c\ub85c \ub290\ub084 \uc218 \uc788\uc5b4 FMP\ub77c\ub294 \uc0ac\uc6a9\uc790\uc5d0\uac8c \uc758\ubbf8\uc788\ub294 \ucee8\ud150\uce20\ub97c \uce21\uc815 \uae30\uc900\uc73c\ub85c \uc0ac\uc6a9\ud558\uc600\uc9c0\ub9cc, \ud604\uc7ac \uc57d 20%\uc758 \ud56d\ubaa9\uc5d0\uc11c \uc815\ud655\ud558\uc9c0 \uc54a\ub2e4\ub294 \uc5f0\uad6c \uacb0\uacfc\uac00 \ubc1c\ud45c\ub418\uc5b4 `LCP\ub97c \uae30\uc900\uc73c\ub85c \ub85c\ub529 \uc18d\ub3c4\ub97c \uce21\uc815\ud55c\ub2e4\uace0 \ud569\ub2c8\ub2e4.`\\n\\n### \ub80c\ub354\ub9c1\\n\\n\ub80c\ub354\ub9c1 \uc131\ub2a5\uc740 \ud398\uc774\uc9c0 \ud654\uba74\uc5d0 \uc8fc\uc694 \ub9ac\uc18c\uc2a4\uac00 \ud398\uc774\uc9c0\uc5d0 \uadf8\ub824\uc9c8 \ub54c\uc758 \uc131\ub2a5\uc744 \ub9d0\ud569\ub2c8\ub2e4.\\n\\n60\uc740 \uc0ac\ub78c\uc774 \uc790\uc5f0\uc2a4\ub7fd\ub2e4\uace0 \ub290\ub07c\ub294 \ucd08\ub2f9 \ud504\ub808\uc784 \uc218\ub77c\uace0 \ud569\ub2c8\ub2e4. \\n\\n\ub530\ub77c\uc11c 1s/60\ub294 \uc57d 16ms\ub85c \ube0c\ub77c\uc6b0\uc800 \ub80c\ub354\ub9c1 \uacfc\uc815\uc774 0.16\ucd08\ub97c \ucd08\uacfc\ud558\uac8c \ub41c\ub2e4\uba74  \ucd08\ub2f9 \ud504\ub808\uc784 \uc218\uac00 \uc904\uc5b4\ub4e4\uace0 \uc774\ub294 \uc0ac\uc6a9\uc790\uac00 \ud398\uc774\uc9c0\uac00 \ubc84\ubc85\uc778\ub2e4\uace0 \ub290\ub07c\uac8c \ub420 \uac83\uc785\ub2c8\ub2e4.\\n\\n\u21d2 \ub530\ub77c\uc11c \ube0c\ub77c\uc6b0\uc800 \ub80c\ub354\ub9c1 \uacfc\uc815\uc774 \uc5bc\ub9c8\ub098 \uac78\ub9ac\ub294\uc9c0 \uce21\uc815\uc744 \ud1b5\ud574 \ub80c\ub354\ub9c1 \uc131\ub2a5\uc744 \uce21\uc815\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### \uba54\ubaa8\ub9ac\\n\\n\uc9c0\ub09c\ubc88\uc5d0 \ub2e4\ub8e8\uc5c8\ub358 \uac00\ube44\uc9c0 \uceec\ub809\ud130\uc640 \uc5f0\uad00\ub41c \ud30c\ud2b8\uc785\ub2c8\ub2e4.\\n\\n\uba54\ubaa8\ub9ac\uc640 \uad00\ub828\ud574\uc11c\ub294 \uba54\ubaa8\ub9ac \ub204\uc218\uac00 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ud560\ub2f9 \ub418\uc5c8\ub358 \ub370\uc774\ud130\uc758 \ud574\uc81c\uac00 \uc7ac\ub54c \uc77c\uc5b4\ub098\uc9c0 \uc54a\uc544 \uc9c0\uc18d\uc801\uc73c\ub85c \uba54\ubaa8\ub9ac\uc5d0 \ub0a8\uc544\uc788\ub294 \uacbd\uc6b0\ub97c \ub9d0\ud569\ub2c8\ub2e4.\\n\\n\ub300\ubd80\ubd84\uc758 \uacbd\uc6b0\uc5d0\ub294 GC\uc5d0 \uc758\ud574 \ud574\uc81c\ub418\uc9c0\ub9cc \\n\\n- \uc804\uc5ed\ubcc0\uc218\\n- \ud574\uc81c\ub418\uc9c0 \uc54a\uc740 \ud0c0\uc774\uba38, \ucf5c\ubc31\\n- \ub3d4 \uc678\ubd80\uc5d0\uc11c\uc758 \ucc38\uc870\\n\\n\ub4f1\uc758 \uc6d0\uc778\uc73c\ub85c GC\uac00 \ub3d9\uc791\ud558\uc9c0 \uc54a\ub294\ub2e4\uace0 \ud569\ub2c8\ub2e4.\\n\\n\ub530\ub77c\uc11c \uba54\ubaa8\ub9ac \uc0ac\uc6a9\uc774 \uac10\uc18c\ud558\uc9c0 \uc54a\uc73c\uba74, \ud799\uacfc \ub178\ub4dc\uc0ac\uc6a9\uc591\uc774 \uc99d\uac00\ub9cc \ud558\uace0, \uc904\uc5b4\ub4e4\uc9c0 \uc54a\uac8c \ub429\ub2c8\ub2e4. \\n\\n### Web Vitals?\\n\\nGoogle\uc740 \ud544\uc218\uc801\uc778 \uc6f9 \uc131\ub2a5 \uc9c0\ud45c\uc778 Core Web Vital\uc744 \ub9cc\ub4e4\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n\ub110\ub9ac \uc0ac\uc6a9\ub418\ub294 \uc131\ub2a5 \uce21\uc815 \ub3c4\uad6c \uc911 \ud558\ub098\uc778 Google\uc758 Lighthouse\ub97c \uc774\uc6a9\ud558\uba74 Core Web Vital\uc5d0\uc11c \uc774\uc57c\uae30\ud558\ub294 \uc9c0\ud45c\ub4e4\uc744 \ud655\uc778\ud558\uace0 \uac1c\uc120\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n- LCP (\uc55e\uc11c \uc124\uba85)\\n- FID (First Input Delay)\\n    \\n    \uc0ac\uc6a9\uc790 \ud589\ub3d9\uc5d0 \ub300\ud55c \uc2e4\uc81c\uc801\uc778 \uc774\ubca4\ud2b8 \ud578\ub4e4\ub7ec\uc758 \ubc18\uc751\ud558\uae30 \uae4c\uc9c0\uc758 \uc2dc\uac04\uc744 \uc758\ubbf8\ud569\ub2c8\ub2e4.\\n    \\n    \uc0ac\uc6a9\uc790\uac00 \uc774\ubca4\ud2b8\ub97c \ubc1c\uc0dd\uc2dc\ucf30\uc744\ub54c \uba54\uc778 \uc2a4\ub808\ub4dc\uc5d0\uc11c \ub2e4\ub978 \ub3d9\uc791\uc744 \ud558\uace0 \uc788\ub2e4\uba74, \ud574\ub2f9 \uc774\ubca4\ud2b8\ub294 \ud604\uc7ac \uc9c4\ud589\uc911\uc778 \ub3d9\uc791\uc774 \ub05d\ub09c \ub4a4 \uc2dc\uc791\ub418\uac8c \ub420 \uac83\uc785\ub2c8\ub2e4.\\n    \\n    \u21d2 \uc0ac\uc6a9\uc790\uc758 \uc774\ubca4\ud2b8\ub97c \ubc1b\uace0 \uc2e4\uc81c\uc801\uc778 \ub3d9\uc791\uc744 \ucc98\ub9ac\ud560 \ub54c \uae4c\uc9c0 \uac78\ub9ac\ub294 \uc2dc\uac04\\n    \\n    - \uc774 \uc2dc\uac04\uc774 \uc9e7\uc744 \uc218\ub85d \uc0ac\uc6a9\uc790\ub294 \uc785\ub825\uc5d0 \ub300\ud55c \ube60\ub978 \ub3d9\uc791\uc774 \uac00\ub2a5\ud55c \uc0ac\uc774\ud2b8\ub77c\uace0 \ud310\ub2e8\ud558 \uac83\uc785\ub2c8\ub2e4.\\n    \\n    \uad6c\uae00 \uc81c\uc2dc \uae30\uc900.\\n    \\n    - 100ms \ubbf8\ub9cc: \uc88b\uc74c\\n    - 100ms ~ 300ms: \uac1c\uc120 \ud544\uc694\\n    - 300ms \uc774\uc0c1: \ud615\ud3b8 \uc5c6\uc74c\\n    \\n    \uc73c\ub85c \uad6c\ubd84\ud569\ub2c8\ub2e4.\\n    \\n- CLS (Cumulative Layout Shift)\\n    \\n    \uc2dc\uac01\uc801\uc778 \uc548\uc815\uc131\uc744 \uce21\uc815\ud560 \ub54c \uc0ac\uc6a9\ud569\ub2c8\ub2e4.\\n    \\n    \uc774\ub294 \uc2dc\uc791 \uc704\uce58\uc5d0\uc11c \ub808\uc774\uc544\uc6c3\uc774 \uc5bc\ub9c8\ub098 \ubcc0\ud654 \ud558\ub294\uc9c0\ub97c \uce21\uc815\ud569\ub2c8\ub2e4.\\n    \\n    \ud654\uba74\uc774 \ucc98\uc74c \ub80c\ub354\ub9c1 \ub41c \uc0c1\ud669\uc5d0\uc11c \ub35c\ucef9\uac70\ub9ac\uba70 \uc694\uc18c\uac00 \ucd94\uac00\ub418\ub294 \uac83\uc744 \uce21\uc815\ud569\ub2c8\ub2e4.\\n    \\n    \ubcc0\uacbd\ub3c4\ub97c \uacc4\uc0b0\ud558\uc5ec \uad6c\uae00 \uc81c\uc2dc \uae30\uc900.\\n    \\n    - 0.1 \ubbf8\ub9cc: \uc88b\uc74c\\n    - 0.1 ~ 0.25: \uac1c\uc120 \ud544\uc694\\n    - 0.25 \uc774\uc0c1: \ud615\ud3b8 \uc5c6\uc74c\\n    \\n    \uc73c\ub85c \uad6c\ubd84\ud569\ub2c8\ub2e4.\\n    \\n\\n## 3. \uc5b4\ub5a4 \uac83\uc73c\ub85c \uc131\ub2a5\uc744 \uce21\uc815\ud558\uc9c0?\\n\\n### Lighthouse\\n\\n\ud06c\ub86c \uac1c\ubc1c\uc790 \ub3c4\uad6c\uc5d0\uc11c \uc81c\uacf5\ud558\ub294 lighthouse\ub294 \ub9ce\uc774 \ub4e4\uc5b4\ubcf4\uc168\uc744 \uac83 \uac19\uc2b5\ub2c8\ub2e4.\\n\\nlighthouse\ub294 \uad6c\uae00\uc774 \uc81c\uc2dc\ud55c web vital\ub97c \uc774\uc6a9\ud558\uc5ec \uc131\ub2a5\uc744 \uce21\uc815\ud558\uace0 \uacb0\uacfc\ub97c \uc81c\uacf5\ud569\ub2c8\ub2e4.\\n\\n### \uac1c\ubc1c\uc790 \ub3c4\uad6c \ud0ed \ud65c\uc6a9\\n\\n- \ud37c\ud3ec\uba3c\uc2a4 \ud0ed: \uc9c1\uc811 \uc6d0\ud558\ub294 \uad6c\uac04\uc744 \ub179\ud654\ud558\uc5ec \ub124\ud2b8\uc6cc\ud06c, \uba54\ubaa8\ub9ac, \ub80c\ub354\ub9c1 \uc804\ubc18\uc801\uc778 \uc0ac\ud56d \uccb4\ud06c \uac00\ub2a5\\n- \ub124\ud2b8\uc6cc\ud06c \ud0ed: \uc9c1\uc811 \ub124\ud2b8\uc6cc\ud06c \ud658\uacbd \uc18d\ub3c4\ub97c \uc870\uc808\ud558\uc5ec \uc2dc\ubbac\ub808\uc774\uc158 \uac00\ub2a5 \ubc0f \ub124\ud2b8\uc6cc\ud06c \ucc98\ub9ac \uc694\uccad \uc2dc\uac04 \ud655\uc778 \uac00\ub2a5\\n- \uba54\ubaa8\ub9ac \ud0ed: \ud604\uc7ac \uba54\ubaa8\ub9ac \uc0ac\uc6a9\ub7c9\uc5d0 \ub300\ud574 \ud655\uc778 \uac00\ub2a5 \u21d2 \uac01 \uc2a4\ub0c5\uc0f7\uc744 \ucd2c\uc601\ud558\uc5ec \uc5b4\ub290 \ud56d\ubaa9\uc5d0\uc11c \uba54\ubaa8\ub9ac \ub204\uc218\uac00 \ubc1c\uc0dd\ud558\ub294\uc9c0 \uccb4\ud06c \uac00\ub2a5\\n\\n\ub4f1 \ub2e4\uc591\ud55c \ubaa8\ub2c8\ud130\ub9c1 \ub3c4\uad6c\uac00 \uc874\uc7ac\ud569\ub2c8\ub2e4.\\n\\n## 4. \ub9c8\ubb34\ub9ac\\n\\n\uc6f9 \uc0ac\uc774\ud2b8\uc758 \uc131\ub2a5\uc744 \uce21\uc815\ud558\ub294 \ub2e4\uc591\ud55c \uae30\uc900\ub3c4 \uce21\uc815\uc744 \ud558\ub294 \ub3c4\uad6c\ub4e4\ub3c4 \ub9ce\uc774 \uc788\ub294 \uac83\uc744 \ud655\uc778\ud560 \uc218 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n\uadf8\ub7ec\uba74 \uc5b4\ub5a4 \uac83\uc744 \uc0ac\uc6a9\ud558\uba74 \uc88b\uc740 \uac83\uc774\uc9c0?\ub77c\ub294 \uc9c8\ubb38\uc5d0 \uc5b4\ub5a4 \uc601\uc0c1\uc5d0\uc11c\ub294 \uc790\uc2e0\uc758 \uc11c\ube44\uc2a4\uc758 \uc6b0\uc120\uc21c\uc704\ub97c \ub450\uace0 \uadf8\uc5d0 \ub9de\ub294 \uc131\ub2a5 \uac1c\uc120\uc694\uc18c\uc5d0 \uc9d1\uc911\ud558\ub294 \uac83\uc774 \uc911\uc694\ud558\ub2e4\ud558\ub294 \uac83\uc744 \ubcf4\uc558\uc2b5\ub2c8\ub2e4.\\n\\n\ubcf8\uc778\uc758 \uc0ac\uc774\ud2b8\uc5d0\uc11c \uc911\uc694\ud55c \uc694\uc18c\ub97c \ud310\ub2e8\ud558\uc5ec \uc801\uc808\ud55c \uc131\ub2a5 \uc694\uc18c\ub97c \ud30c\uc545\ud558\ub294 \uac83\uc774 \uc131\ub2a5 \uac1c\uc120 \uc804 \uac00\uc7a5 \uc911\uc694\ud55c \uc694\uc18c\ub77c\uace0 \uc0dd\uac01\ub418\uc5c8\uc2b5\ub2c8\ub2e4. \\n\\n\ucc38\uace0:\\n[https://devocean.sk.com/blog/techBoardDetail.do?page=&boardType=undefined&query=&ID=164863&searchData=&subIndex=#none](https://devocean.sk.com/blog/techBoardDetail.do?page=&boardType=undefined&query=&ID=164863&searchData=&subIndex=#none)   \\nhttps://www.youtube.com/watch?v=A6J74xLWqYg&t=186s"},{"id":"/haejinyun/infomate-8week","metadata":{"permalink":"/front-end/haejinyun/infomate-8week","source":"@site/@frontEnd/haejinyun/infomate-8week.mdx","title":"\uc778\ud3ec\uba54\uc774\ud2b8 8\uc8fc\ucc28 \uacf5\uc720(\ud504\ub808\uc784\uc6cc\ud06c & \ub77c\uc774\ube0c\ub7ec\ub9ac)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 8\uc8fc\ucc28 \uacf5\uc720(\ud504\ub808\uc784\uc6cc\ud06c & \ub77c\uc774\ube0c\ub7ec\ub9ac) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","date":"2024-05-27T00:00:00.000Z","tags":[{"label":"\uc778\ud3ec\uba54\uc774\ud2b8","permalink":"/front-end/tags/\uc778\ud3ec\uba54\uc774\ud2b8"},{"label":"\ud504\ub808\uc784\uc6cc\ud06c","permalink":"/front-end/tags/\ud504\ub808\uc784\uc6cc\ud06c"},{"label":"\ub77c\uc774\ube0c\ub7ec\ub9ac","permalink":"/front-end/tags/\ub77c\uc774\ube0c\ub7ec\ub9ac"}],"readingTime":28.51,"hasTruncateMarker":true,"authors":[{"name":"haejinyun","url":"https://github.com/haejinyun","email":"dbshaejin@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/86779590?v=4","key":"haejinyun"}],"frontMatter":{"date":"2024-05-27T00:00:00.000Z","authors":"haejinyun","title":"\uc778\ud3ec\uba54\uc774\ud2b8 8\uc8fc\ucc28 \uacf5\uc720(\ud504\ub808\uc784\uc6cc\ud06c & \ub77c\uc774\ube0c\ub7ec\ub9ac)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 8\uc8fc\ucc28 \uacf5\uc720(\ud504\ub808\uc784\uc6cc\ud06c & \ub77c\uc774\ube0c\ub7ec\ub9ac) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","keywords":["\uc778\ud3ec\uba54\uc774\ud2b8","\ud504\ub808\uc784\uc6cc\ud06c","\ub77c\uc774\ube0c\ub7ec\ub9ac"],"tags":["\uc778\ud3ec\uba54\uc774\ud2b8","\ud504\ub808\uc784\uc6cc\ud06c","\ub77c\uc774\ube0c\ub7ec\ub9ac"]},"unlisted":false,"prevItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 9\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654)","permalink":"/front-end/haejinyun/infomate-9week"},"nextItem":{"title":"\ub808\uade4\ub7ec\ub85c \uc804\ud658\ub418\uace0...","permalink":"/front-end/GwakSeungJu/april-retrospect_GwakSeungju"}},"content":"\uc778\ud3ec\uba54\uc774\ud2b8 8\uc8fc\ucc28 \uacf5\uc720(\ud504\ub808\uc784\uc6cc\ud06c & \ub77c\uc774\ube0c\ub7ec\ub9ac) \ubaa8\uc74c\uc785\ub2c8\ub2e4.\\n\\nCSS \uc804\ucc98\ub9ac\uae30 \ubc0f \ub77c\uc774\ube0c\ub7ec\ub9ac - \uc724\ud574\uc9c4  \\n\uc2a4\ud0c0\uc77c\ub9c1 \uc2dc\uac04 \ub2e8\ucd95\ud558\ub824\uba74 Tailwind\ub97c \uc4f0\uc138\uc694 - \uae40\ud558\ub098  \\n\ud55c\uae00 \ucd08\uc131 \uac80\uc0c9 \uad6c\ud604 \uc5b4\ub835\uc9c0 \uc54a\uc544\uc694 - \uacfd\uc2b9\uc8fc  \\nstyle-dictionary\ub85c \ub514\uc790\uc778 \ud1a0\ud070 \ud65c\uc6a9\ud558\uae30 - \uae40\ubbfc\uc7ac\\n\\n{/* truncate */}\\n\\n## CSS \uc804\ucc98\ub9ac\uae30 \ubc0f \ub77c\uc774\ube0c\ub7ec\ub9ac - \uc724\ud574\uc9c4\\n\\n\ub4e4\uc5b4\uac00\ub294 \ub9d0)\\n\\n\uac1c\ubc1c\uc744 \ud558\uba70 \ub2e4\uc591\ud55c css \uc804\ucc98\ub9ac\uae30 \ubc0f \ub77c\uc774\ube0c\ub7ec\ub9ac\ub97c \uc0ac\uc6a9\ud55c \uacbd\ud5d8\uc774 \uc788\uc2b5\ub2c8\ub2e4. \uadf8\ub7ec\ub098 \uac01\uac01\uc758 \ud2b9\uc9d5\uc5d0 \ub300\ud574\uc11c\ub294 \uae4a\uac8c \uc0dd\uac01\ud574 \ubcf8 \uc801\uc774 \uc5c6\uc5c8\uc2b5\ub2c8\ub2e4. \uc774\ubc88 \uae00\uc5d0\uc11c\ub294 \ub300\ud45c\uc801\uc778 CSS \ubc29\uc2dd\uc778 Sass, SCSS, \uadf8\ub9ac\uace0 CSS-in-JS\uc5d0 \ub300\ud574 \uc124\uba85\ud558\uace0, \uac01 \ubc29\uc2dd\uc5d0 \ud574\ub2f9\ud558\ub294 \ub77c\uc774\ube0c\ub7ec\ub9ac\ub97c \uc18c\uac1c\ud558\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n## [ Sass ]\\n\\nCSS\ub294 \uaddc\ubaa8\uac00 \ucee4\uc9c8\uc218\ub85d \ucf54\ub4dc\uac00 \ubcf5\uc7a1\ud574\uc9c0\uace0, \uc720\uc9c0\ubcf4\uc218\uac00 \ubd88\ud3b8\ud574\uc9d1\ub2c8\ub2e4.\xa0CSS \ucf54\ub4dc \ub0b4\uc5d0\uc11c \ub3d9\uc77c\ud55c \ud639\uc740 \uc720\uc0ac\ud55c \ucf54\ub4dc\ub97c \uc7ac\uc0ac\uc6a9\ud558\uae30 \uc704\ud574\uc11c \'\ubcf5\uc0ac & \ubd99\uc5ec\ub123\uae30\'\uac00 \uc810\uc810 \ub9ce\uc544\uc9d1\ub2c8\ub2e4. \uc774\ub294 \ubb34\ucc99 \uadc0\ucc2e\uace0 \ub610 \uc2e4\uc218\ub97c \uc720\ubc1c\ud558\ub294 \uc791\uc5c5\uc785\ub2c8\ub2e4.\\n\\nSass\ub294 \ucef4\ud30c\uc77c \uacfc\uc815\uc744 \ud1b5\ud574 CSS \ud30c\uc77c\uc744 \uc0dd\uc131\ud574 \uc8fc\ub294 CSS\uc758 \ud655\uc7a5 \uc5b8\uc5b4\uc774\uc790 \uc804\ucc98\ub9ac\uae30(preprocessor)\ub85c\uc368, CSS\uc5d0\ub294 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294 \ub2e4\uc591\ud55c \uae30\ub2a5\ub4e4\uc744 \uac00\uc9c0\uace0 \uc788\uc2b5\ub2c8\ub2e4. \uadf8\ub9ac\uace0 \uc774 \uae30\ub2a5\ub4e4\uc740 \ucf54\ub4dc \uc791\uc131\uc5d0 \ub4dc\ub294 \uc2dc\uac04\uc744 \uc904\uc5ec\uc8fc\uace0, \ucf54\ub4dc\ub97c \uc720\uc9c0 \uad00\ub9ac\ud558\ub294 \ub370 \ub3c4\uc6c0\uc774 \ub429\ub2c8\ub2e4.\\n\\n\uadf8\ub7ec\ub098 Sass\ub294 CSS\uc758 \ub300\uccb4 \uc5b8\uc5b4\uac00 \uc544\ub2d9\ub2c8\ub2e4! Sass\ub294 CSS\uc758 \ud655\uc7a5 \uc5b8\uc5b4\uc785\ub2c8\ub2e4. Sass\uac00 \uc81c\uacf5\ud558\ub294 \ubb38\ubc95\uc744 \uae30\ubc18\uc73c\ub85c \ucf54\ub4dc\ub97c \uc791\uc131\ud55c \ub2e4\uc74c, \uc774\ub97c \ucef4\ud30c\uc77c\ud574 CSS \ud30c\uc77c\uc744 \ube4c\ub4dc\ud558\ub294 \uac83\uc774 Sass\ub97c \ud1b5\ud574 \uc2a4\ud0c0\uc77c\uc2dc\ud2b8\ub97c \uc0dd\uc0b0\ud558\ub294 \uc808\ucc28\uc785\ub2c8\ub2e4.\\n\\nSass\ub294 \ub2e4\uc74c\uacfc \uac19\uc740 \ucd94\uac00 \uae30\ub2a5\uacfc \uc720\uc6a9\ud55c \ub3c4\uad6c\ub4e4\uc744 \uc81c\uacf5\ud569\ub2c8\ub2e4.\\n\\n- \ubcc0\uc218\uc758 \uc0ac\uc6a9: Sass\uc5d0\uc11c \ubcc0\uc218\ub294 **`$`** \uae30\ud638\ub97c \uc0ac\uc6a9\ud558\uc5ec \uc815\uc758\ud569\ub2c8\ub2e4. \ubcc0\uc218\ub97c \uc0ac\uc6a9\ud558\uba74 \uc0c9\uc0c1, \ud3f0\ud2b8 \ud06c\uae30, \uac04\uaca9 \ub4f1\uc744 \uc911\uc559\uc5d0\uc11c \uad00\ub9ac\ud560 \uc218 \uc788\uc5b4 \uc77c\uad00\uc131\uc744 \uc720\uc9c0\ud558\uae30 \uc27d\uc2b5\ub2c8\ub2e4.\\n- \uc870\uac74\ubb38\uacfc \ubc18\ubcf5\ubb38: Sass\uc5d0\uc11c\ub294 \uc870\uac74\ubb38(**`@if`**, **`@else if`**, **`@else`**)\uacfc \ubc18\ubcf5\ubb38(**`@for`**, **`@each`**, **`@while`**)\uc744 \uc0ac\uc6a9\ud560 \uc218 \uc788\uc5b4, \ubcf5\uc7a1\ud55c \uc2a4\ud0c0\uc77c\ub9c1 \ub85c\uc9c1\uc744 \ucc98\ub9ac\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- Import: Sass\uc5d0\uc11c\ub294 **`@import`**\ub97c \uc0ac\uc6a9\ud558\uc5ec \uc5ec\ub7ec \ud30c\uc77c\ub85c \ub098\ub220\uc9c4 \uc2a4\ud0c0\uc77c\uc744 \ud558\ub098\ub85c \uacb0\ud569\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc774\ub97c \ud1b5\ud574 \ucf54\ub4dc\uc758 \ubaa8\ub4c8\ud654\uc640 \uc7ac\uc0ac\uc6a9\uc131\uc744 \ub192\uc77c \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- Nesting: Sass\ub294 \uc911\ucca9\uc744 \ud1b5\ud574 \uc2a4\ud0c0\uc77c\uc744 \uad6c\uc870\ud654\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- Mixin: Mixin\uc740 \uc7ac\uc0ac\uc6a9 \uac00\ub2a5\ud55c \uc2a4\ud0c0\uc77c \ube14\ub85d\uc744 \uc815\uc758\ud558\uace0, \uc774\ub97c \ud544\uc694\ud560 \ub54c\ub9c8\ub2e4 \ud638\ucd9c\ud558\uc5ec \uc0ac\uc6a9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc778\uc790\ub97c \ubc1b\uc544 \ub3d9\uc801\uc778 \uc2a4\ud0c0\uc77c\ub9c1\ub3c4 \uac00\ub2a5\ud569\ub2c8\ub2e4.\\n- Extend/Inheritance: **`@extend`**\ub97c \uc0ac\uc6a9\ud558\uba74 \uae30\uc874\uc758 CSS \ud074\ub798\uc2a4\uc758 \uc2a4\ud0c0\uc77c\uc744 \ub2e4\ub978 \ud074\ub798\uc2a4\uc5d0 \uc0c1\uc18d\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc774\ub294 \uc911\ubcf5 \uc2a4\ud0c0\uc77c\uc744 \ud53c\ud558\uace0, \ucf54\ub4dc\ub97c \uac04\uacb0\ud558\uac8c \uc720\uc9c0\ud558\ub294 \ub370 \uc720\uc6a9\ud569\ub2c8\ub2e4.\\n\\nCSS\uc640 \ube44\uad50\ud558\uc5ec Sass\ub294 \uc544\ub798\uc640 \uac19\uc740 \uc7a5\uc810\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n- CSS\ubcf4\ub2e4 \uc2ec\ud50c\ud55c \ud45c\uae30\ubc95\uc73c\ub85c CSS\ub97c \uad6c\uc870\ud654\ud558\uc5ec \ud45c\ud604\ud560 \uc218 \uc788\ub2e4.\\n- \uc2a4\ud0ac \ub808\ubca8\uc774 \ub2e4\ub978 \ud300\uc6d0\ub4e4\uacfc\uc758 \uc791\uc5c5 \uc2dc \ubc1c\uc0dd\ud560 \uc218 \uc788\ub294 \uad6c\ubb38\uc758 \uc218\uc900 \ucc28\uc774\ub97c \ud3c9\uc900\ud654\ud560 \uc218 \uc788\ub2e4.\\n- CSS\uc5d0\ub294 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294 Mixin \ub4f1\uc758 \uac15\ub825\ud55c \uae30\ub2a5\uc744 \ud65c\uc6a9\ud558\uc5ec CSS \uc720\uc9c0\ubcf4\uc218 \ud3b8\uc758\uc131\uc744 \ud070 \ud3ed\uc73c\ub85c \ud5a5\uc0c1\uc2dc\ud0ac \uc218 \uc788\ub2e4.\\n\\n## [ SCSS ]\\n\\nSass\ub97c \ub4e4\uc5b4\ubcf4\uc168\ub2e4\uba74 Scss \ub610\ud55c \uc775\uc219\ud560 \uc774\ub984\uc774\ub77c\uace0 \uc0dd\uac01\ud569\ub2c8\ub2e4. \uadf8\ub7ec\ub098 \ub458\uc758 \ucc28\uc774\ub294 \ubb34\uc5c7\uc77c\uae4c\uc694?\\n\\n\uc5ec\uae30\uc11c \uba3c\uc800 \uc54c\uc544\ubcf4\uba74 \uc88b\uc740 \uac83\uc740 Sass\ub77c\ub294 \uc774\ub984\uc5d0\ub294 \ub450 \uac00\uc9c0 \uc758\ubbf8\uac00 \ub2f4\uaca8 \uc788\uc2b5\ub2c8\ub2e4. \ud558\ub098\ub294 \ucf54\ub4dc\ub97c CSS\ub85c \ud574\uc11d\ud558\ub294 \uc5ed\ud560\uc744 \ud558\ub294 \uc804\ucc98\ub9ac\uae30\ub85c\uc11c\uc758 \uc758\ubbf8, \ub610 \ub2e4\ub978 \ud558\ub098\ub294 \ubb38\ubc95(\uad6c\ubb38)\uc73c\ub85c\uc368\uc758 \uc758\ubbf8\uc785\ub2c8\ub2e4. Sass \ubb38\ubc95\uc744 \uae30\ubc18\uc73c\ub85c \ucf54\ub4dc\ub97c \uc791\uc131\ud558\uba74, Sass \uc804\ucc98\ub9ac\uae30\uc758 \ub3c4\uc6c0\uc744 \ubc1b\uc544 CSS \ud30c\uc77c\uc744 \ub9cc\ub4e4\uc5b4\ub0bc \uc218 \uc788\uc2b5\ub2c8\ub2e4\\n\\n\uadf8\ub807\ub2e4\uba74 SCSS\ub294 SCSS \ubb38\ubc95\uc744 \uae30\ubc18\uc73c\ub85c \ucf54\ub4dc\ub97c \uc791\uc131\ud558\uba74, Sass \uc804\ucc98\ub9ac\uae30\uc758 \ub3c4\uc6c0\uc744 \ubc1b\uc544 \ucef4\ud30c\uc77c\ub7ec\uac00 \uc774\ub97c CSS\ub85c \ube4c\ub4dc \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ub2e4\uc2dc\ub9d0\ud574 Sass\uc640 SCSS\uc758 \ucc28\uc774\ub294 \ud45c\ud604\ud558\ub294 \ubb38\ubc95\uc5d0 \ucc28\uc774\ub9cc \uc788\uc744 \ubfd0 \uae30\ub2a5\uc740 \ub3d9\uc77c\ud569\ub2c8\ub2e4. (\ud30c\uc77c \ud655\uc7a5\uc790\ub85c \ubd84\ub9ac)\\n\\n- Sass\ub294 \ub4e4\uc5ec \uc4f0\uae30+\uc904 \ubc14\uafc8 \ud615\uc2dd\\n- SCSS\ub294 \uc911\uad04\ud638+\uc138\ubbf8\ucf5c\ub860 \ud615\uc2dd\\n\\n## [ CSS in JS ]\\n\\nCSS-in-JS\ub294 JavaScript \ucf54\ub4dc \ub0b4\uc5d0\uc11c CSS\ub97c \uc791\uc131\ud558\ub294 \ubc29\uc2dd\uc744 \uac00\uc9d1\ub2c8\ub2e4.\\n\\n\uc2a4\ud0c0\uc77c\uc744 \ucef4\ud3ec\ub10c\ud2b8 \ub2e8\uc704\ub85c \uad00\ub9ac\ud560 \uc218 \uc788\uc5b4 \uc720\uc9c0\ubcf4\uc218\uc131\uacfc \ubaa8\ub4c8\ud654\uac00 \ub6f0\uc5b4\ub098\ub2e4\ub294 \ud2b9\uc9d5\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\nReact\uc640 \uac19\uc740 \ucef4\ud3ec\ub10c\ud2b8 \uae30\ubc18 \ub77c\uc774\ube0c\ub7ec\ub9ac\uc640 \ud568\uaed8 \uc0ac\uc6a9\ub418\ub294 \uacbd\uc6b0\uac00 \ub9ce\uc2b5\ub2c8\ub2e4.\\n\\n- JS \ud30c\uc77c \uc548\uc5d0\uc11c CSS \ucf54\ub4dc\ub97c \uc791\uc131\ud558\uae30 \ub54c\ubb38\uc5d0 CSS\uc758 \ubcc0\uc218\uc640 \ud568\uc218\ub97c \uadf8\ub300\ub85c \uc0ac\uc6a9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- \ud074\ub798\uc2a4 \uba85\uc774 \ud574\uc2dc \uac12\uc73c\ub85c \uce58\ud658\ub418\uae30 \ub54c\ubb38\uc5d0 \ud074\ub798\uc2a4 \uc774\ub984\uc758 \uc911\ubcf5 \ubc0f \uc791\uba85\uc5d0 \ub300\ud55c \uac71\uc815\uc744 \ub35c \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- \ud604\ub300 \uc6f9\uc740 \ucef4\ud3ec\ub10c\ud2b8\ub97c \uae30\ubc18\uc73c\ub85c \ubc1c\uc804\ud558\uace0 \uc788\uc73c\ubbc0\ub85c, \ucef4\ud3ec\ub10c\ud2b8\uc640 \uc2a4\ud0c0\uc77c\uc744 \ud558\ub098\uc758 \ud30c\uc77c\uc5d0\uc11c \uc791\uc131\ud558\ub294 CSS-in-JS\ub294 \ubaa8\ub4c8\ud654\uac00 \uc218\uc6d4\ud574\uc9d1\ub2c8\ub2e4.\\n\\ncss in js\uc758 \ub300\ud45c\uc801\uc778 \ub450 \uac00\uc9c0 \ub77c\uc774\ube0c\ub7ec\ub9ac\ub97c \uac04\ub2e8\ud558\uac8c \uc0b4\ud3b4\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n### Styled components\\n\\n[https://styled-components.com/](https://styled-components.com/)\\n\\n\uc790\ub3d9\ud654\ub41c \uace0\uc720 \ud074\ub798\uc2a4\uba85, \ub3d9\uc801 \uc2a4\ud0c0\uc77c\ub9c1 \uc9c0\uc6d0, \uc11c\ubc84 \uc0ac\uc774\ub4dc \ub80c\ub354\ub9c1\uacfc\uc758 \ud638\ud658\uc131 \ub4f1\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ub610\ud55c CSS\ub97c \ucef4\ud3ec\ub10c\ud2b8\uc5d0 \uc9c1\uc811 \uc801\uc6a9\ud558\uae30 \ub54c\ubb38\uc5d0, \ucef4\ud3ec\ub10c\ud2b8 \ub2e8\uc704\ub85c \uc2a4\ud0c0\uc77c\uc744 \uad00\ub9ac\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc774\ub807\uac8c \ud558\uba74 \uc2a4\ud0c0\uc77c \ucda9\ub3cc \ubb38\uc81c\ub97c \ubc29\uc9c0\ud558\uace0, \uc720\uc9c0 \ubcf4\uc218 \ubc0f \ud655\uc7a5\uc131\uc744 \ud5a5\uc0c1\uc2dc\ud0ac \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n```jsx\\nimport React, { Component } from \'react\';\\nimport styled from \'styled-components\';\\n\\nconst Title = styled.h1`\\n  color: white;\\n`;\\n\\nconst Wrapper = styled.div`\\n    background: black\\n`\\n\\nclass App extends Component {\\n  render() {\\n    return (\\n        <Wrapper>\\n            <Title>Hello World!</Title>\\n        </Wrapper>\\n    );\\n  }\\n}\\n\\nexport default App;\\n\\n----\\n\\n// \uc0ac\uc6a9\ubc95\\nconst \ucef4\ud3ec\ub10c\ud2b8\uc774\ub984 = styled.\ud0dc\uadf8\uc774\ub984`\\n\\t// css \uc791\uc131\\n`;\\n\\n```\\n\\n### **Emotion**\\n\\n[https://emotion.sh/docs/introduction](https://emotion.sh/docs/introduction)\\n\\nstyped-components\uc640 \ube44\uc2b7\ud55c \ubc29\uc2dd\uc73c\ub85c \uc0ac\uc6a9 \uac00\ub2a5\ud569\ub2c8\ub2e4.\\n\\n- **css crop**: Emotion\uc744 \uc0ac\uc6a9\ud558\uc5ec React \ucef4\ud3ec\ub10c\ud2b8\ub97c \uc2a4\ud0c0\uc77c\ub9c1\ud560 \ub54c, css prop\uc744 \uc9c1\uc811 \ucef4\ud3ec\ub10c\ud2b8\uc5d0 \uc804\ub2ec\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc774\ub294 \ub3d9\uc801 \uc2a4\ud0c0\uc77c\ub9c1, \uc5ec\ub7ec \uc2a4\ud0c0\uc77c\uc758 \uc870\ud569\uc774 \ud544\uc694\ud560 \ub54c \ud070 \uc7a5\uc810\uc73c\ub85c \ud65c\uc6a9\ub429\ub2c8\ub2e4.\\n\\n```jsx\\n/** @jsxImportSource @emotion/react */\\nEmotion\uc744 \uc0ac\uc6a9\ud558\uc5ec React \ucef4\ud3ec\ub10c\ud2b8\ub97c \uc2a4\ud0c0\uc77c\ub9c1\ud560 \ub54c, css prop\uc744 \uc9c1\uc811 \ucef4\ud3ec\ub10c\ud2b8\uc5d0 \uc804\ub2ec \uac00\ub2a5\\n\\nimport { css } from \'@emotion/react\';\\n\\nfunction App() {\\n  return (\\n    <div\\n      css={css`\\n        background-color: palevioletred;\\n        color: white;\\n      `}\\n    >\\n      \uc548\ub155\ud558\uc138\uc694, Emotion!\\n    </div>\\n  )\\n}\\n```\\n\\n```jsx\\n/** @jsxImportSource @emotion/react */\\ncss prop\uc740 \ub3d9\uc801\uc73c\ub85c \uc2a4\ud0c0\uc77c\uc744 \uc801\uc6a9\ud558\ub294 \uac83\uc5d0 \uc720\uc6a9\\n\\nimport { css } from \'@emotion/react\';\\n\\nfunction Button({ primary }) {\\n  return (\\n    <button\\n      css={css`\\n        background-color: ${primary ? \'palevioletred\' : \'white\'};\\n        color: ${primary ? \'white\' : \'palevioletred\'};\\n      `}\\n    >\\n      \ubc84\ud2bc\\n    </button>\\n  )\\n}\\n```\\n\\n```jsx\\n/** @jsxImportSource @emotion/react */\\ncss prop\uc744 \uc5ec\ub7ec \uc2a4\ud0c0\uc77c\uacfc \uacb0\ud569\ud558\uae30\\n\\nimport { css } from \'@emotion/react\';\\n\\ninterface ButtonProps {\\n  children: React.ReactNode;\\n  theme?: \'primary\' | \'secondary\';\\n  onClick?: () => void;\\n}\\nconst Button = ({ children, theme = \'primary\', onClick }: ButtonProps) => {\\n  return (\\n    <button css={[style, themes[theme]]} onClick={onClick}>\\n      {children}\\n    </button>\\n  );\\n};\\n\\nconst style = css`\\n  padding: 10px 20px;\\n  border: none;\\n  border-radius: 4px;\\n  font-size: 16px;\\n  cursor: pointer;\\n  outline: none;\\n  transition: background-color 0.3s;\\n`;\\n\\nconst themes = {\\n  primary: css`\\n    background-color: palevioletred;\\n    color: white;\\n\\n    &:hover {\\n      background-color: darkviolet;\\n    }\\n  `,\\n  secondary: css`\\n    background-color: white;\\n    color: palevioletred;\\n    border: 1px solid palevioletred;\\n\\n    &:hover {\\n      background-color: palevioletred;\\n      color: white;\\n    }\\n  `,\\n};\\n\\nexport default Button;\\n```\\n\\n\ucc38\uace0\\n\\n[https://poiemaweb.com/sass-basics](https://poiemaweb.com/sass-basics)\\n\\n[https://inpa.tistory.com/entry/SCSS-\ud83d\udc8e-SassSCSS-\ub780-\uc124\uce58-\ubc0f-\ucef4\ud30c\uc77c#sassscss\uc758\\\\_\ub4f1\uc7a5](https://inpa.tistory.com/entry/SCSS-%F0%9F%92%8E-SassSCSS-%EB%9E%80-%EC%84%A4%EC%B9%98-%EB%B0%8F-%EC%BB%B4%ED%8C%8C%EC%9D%BC#sassscss%EC%9D%98_%EB%93%B1%EC%9E%A5)\\n\\n[https://velog.io/@lgs03042/Styled-components\uc640-Emotion-CSS-in-JS\uc758-\ube44\uad50-\ubc0f-\uc7a5\ub2e8\uc810#4-emotion](https://velog.io/@lgs03042/Styled-components%EC%99%80-Emotion-CSS-in-JS%EC%9D%98-%EB%B9%84%EA%B5%90-%EB%B0%8F-%EC%9E%A5%EB%8B%A8%EC%A0%90#4-emotion)\\n\\n## \uc2a4\ud0c0\uc77c\ub9c1 \uc2dc\uac04 \ub2e8\ucd95\ud558\ub824\uba74 Tailwind\ub97c \uc4f0\uc138\uc694 - \uae40\ud558\ub098\\n\\nTailwind\ub294 \ucd5c\uadfc \uc6f9 \ubd84\uc57c\uc5d0\uc11c \uc778\uae30\ub97c \ub04c\uace0\uc788\ub294 CSS \ud504\ub808\uc784\uc6cc\ud06c\uc785\ub2c8\ub2e4.\\n\\n\ud558\uc9c0\ub9cc \uac1c\ubc1c\uc790\ub4e4 \uc0ac\uc774\uc5d0\uc11c\ub3c4 \ud638\ubd88\ud638\uac00 \ub9ce\uc774 \uac08\ub9ac\ub294 \ud3b8\uc774\uba70, \uc5ec\ub7ec \ub17c\uc7c1\uc774 \uc624\uac00\ub294 \ud56b\ud3ec\ud14c\uc774\ud1a0\ub85c \uc5ec\uaca8\uc9d1\ub2c8\ub2e4.\\n\\nTailwind\uac00 \uc65c \ucc28\uc138\ub300 css \ud504\ub808\uc784\uc6cc\ud06c\ub85c \ub5b4\ub294\uc9c0 \uc54c\uc544\ubcf4\uace0, \uc800\uc758 \uc9c0\uadf9\ud788 \uc8fc\uad00\uc801\uc778 \ub9ac\ubdf0\ub3c4 \uac04\ub2e8\ud788 \uc801\uc5b4\ubcf4\ub824\ud569\ub2c8\ub2e4.\\n\\n## Tailwind?\\n\\nTailwind\ub294 \ub9ce\uc740 \uc720\ud2f8\ub9ac\ud2f0(utility) \ud074\ub798\uc2a4\ub85c \uc774\ub8e8\uc5b4\uc9c4 CSS \ud504\ub808\uc784\uc6cc\ud06c\uc785\ub2c8\ub2e4.\\n\\n\uc720\ud2f8\ub9ac\ud2f0 \ud074\ub798\uc2a4\ub780 \ud55c\uac00\uc9c0 \uc77c\ub9cc \ud558\ub294 \ub9e4\uc6b0 \uc801\uc740 \uc591\uc758 css \ucf54\ub4dc\ub97c \ub2f4\uace0 \uc788\ub294 \ud074\ub798\uc2a4\ub77c\uace0 \uc0dd\uac01\ud558\uba74 \ub418\ub294\ub370, \uc2e4\uc81c tailwind \ub85c \ucf54\ub4dc\ub97c \uc791\uc131\ud558\uace0 \ud06c\ub86c inspector\ub85c \uc120\ud0dd\ud574\ubcf4\uba74, \uac01 \uc2a4\ud0c0\uc77c\uc5d0 \ud55c \ud074\ub798\uc2a4\uac00 \ud560\ub2f9\ub418\uc5b4 \uc788\ub294 \uac83\uc744 \ud655\uc778\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ubcf4\ud1b5\uc758 css \ucf54\ub4dc\ub97c \uc791\uc131\ud558\ub824\uba74 css \ud30c\uc77c\uc744 \ubd84\ub9ac\ud558\uac70\ub098 \uc778\ub77c\uc778 \uc694\uc18c\ub85c \uc9c1\uc811 \uc791\uc131\ud558\uac8c \ub429\ub2c8\ub2e4.\\n\\n\ub7ec\ub098 Tailwind\ub97c \uc0ac\uc6a9\ud558\uba74 HTML \uc694\uc18c\uc758 **`class`** \uc18d\uc131\uc5d0 \uc720\ud2f8\ub9ac\ud2f0 \ud074\ub798\uc2a4\ub97c \ucd94\uac00\ud558\ub294 \uac83\ub9cc\uc73c\ub85c \uc2a4\ud0c0\uc77c\ub9c1\uc774 \uac00\ub2a5\ud569\ub2c8\ub2e4. (Tailwind\uc758 PostCSS \ud50c\ub7ec\uadf8\uc778\uc73c\ub85c \ub3d9\uc791\ud55c\ub2e4\uace0 \ud569\ub2c8\ub2e4)\\n\\n\ub530\ub77c\uc11c \ub2e4\uc74c\uacfc \uac19\uc774 Tailwind \ucf54\ub4dc\ub97c \uc791\uc131\ud55c\ub2e4\uace0 \uac00\uc815\ud558\uba74,\\n\\n```tsx\\n<button class=\\"rounded bg-blue-500 px-4 py-2 font-bold text-white hover:bg-blue-600\\">\\n  Primary\\n</button>\\n```\\n\\n\ub2e4\uc74c\uacfc \uac19\uc740 css \ud074\ub798\uc2a4\ub4e4\uc774 \ud569\uccd0\uc9c0\uac8c \ub429\ub2c8\ub2e4.\\n\\n```tsx\\n.rounded {\\n  border-radius: 0.25rem;\\n}\\n\\n.bg-blue-500 {\\n  background-color: rgb(59 130 246);\\n}\\n\\n.px-4 {\\n  padding-left: 1rem;\\n  padding-right: 1rem;\\n}\\n\\n...\\n```\\n\\n## \ub2e4\ub978 CSS \ud504\ub808\uc784\uc6cc\ud06c\uc640\uc758 \ube44\uad50\\n\\n\ub300\ud45c\uc801\uc778 Bootstrap \uc774\ub098 Mererial UI \ub4f1\uacfc\ub294 \ub2e4\ub974\uac8c Tailwind\uac00 \uac00\uc9c4 \uac15\uc810\uc740 \ubb34\uc5c7\uc77c\uae4c\uc694?\\n\\nBootstrap\uac19\uc740 \ud504\ub808\uc784\uc6cc\ud06c\ub294 `<button class=\\"btn btn-primary\\">` \ud55c\uc904\uc774\uba74 \uc704\uc758 UI \uc640 \ub3d9\uc77c\ud558\uac8c \uad6c\ud604\ud574\ub0bc \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uadf8\ub7ec\ub098, \uc138\ubd80\uc801\uc778 CSS \uc218\uc815\uc774 \ubd88\uac00\ud558\uac70\ub098 \ubd88\ud3b8\ud574\uc9d1\ub2c8\ub2e4.\\n\\n\ub530\ub77c\uc11c Tailwind\ub294 \ub354 \ub9ce\uc740 \ud074\ub798\uc2a4\ub97c \uc0ac\uc6a9\ud558\uace0 \ubc30\uc6cc\uc57c \ud55c\ub2e4\ub294 \ub2e8\uc810\uc774 \uc788\uc9c0\ub9cc, \ub2e4\ub978 \uce21\uba74\uc73c\ub85c \ubcf4\uba74 \uc5c4\uccad\ub09c \uc720\uc5f0\uc131\uacfc \ud655\uc7a5\uc131\uc744 \uc81c\uacf5\ud55c\ub2e4\uace0 \ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ub2e4\uc591\ud55c CSS \ub77c\uc774\ube0c\ub7ec\ub9ac\ub97c \uc368\ubcf8 \uc800\ub85c\uc11c\ub294 \uc774 \ubd80\ubd84\uc774 \ub9ce\uc774 \uacf5\uac10\ub418\ub294 \ubd80\ubd84\uc785\ub2c8\ub2e4.\\n\\n## Tailwind\ub97c \ub458\ub7ec\uc2fc \uce58\uc5f4\ud55c \ub17c\uc7c1\\n\\n\ud2b8\uc704\ud130\uac19\uc740\uacf3\uc5d0\uc11c\ub294 Tailwind\ub97c \uc88b\uc544\ud558\ub294 \ubd80\ub958\uc640 \uc2eb\uc5b4\ud558\ub294 \ubd80\ub958\uac00 \ub05d\uc5c6\ub294 \ub17c\uc7c1\uc744.. \ud55c\ub2e4\uace0 \ud569\ub2c8\ub2e4.\\n\\nTailwind\ub97c \uc88b\uc544\ud558\ub294 \uac1c\ubc1c\uc790\ub4e4\uc740 \uc0dd\uc0b0\uc131 \uce21\uba74, \ube60\ub974\uac8c \ub514\uc790\uc778\uc744 \uad6c\ud604\ud558\uac8c \ub3c4\uc640\uc900\ub2e4\ub294 \uc810\uc744 \uac15\uc870\ud569\ub2c8\ub2e4. \ub610\ud55c \ubcc0\uacbd\uc774\ub098 \uc218\uc815\uc774 \uc26c\uc6cc\uc11c \uc720\uc9c0\ubcf4\uc218\uac00 \uc798 \ub41c\ub2e4\uace0 \ub9d0\ud569\ub2c8\ub2e4. \ud55c \ubc88 Tailwind\ub97c \uc368\ubcf4\uba74 \ub2e4\uc2dc\ub294 \uae30\uc874\uc73c\ub85c \ub3cc\uc544\uac00\uc9c0 \ubabb\ud55c\ub2e4\ub294 \uac15\ub825\ud55c \ucc2c\uc131\uc758 \uc758\uacac\ub3c4 \ubcf4\uc600\uc2b5\ub2c8\ub2e4.\\n\\n\ubc18\uba74, Tailwind\ub97c \uc2eb\uc5b4\ud558\ub294 \uac1c\ubc1c\uc790\ub4e4\uc740 \uc720\ud2f8\ub9ac\ud2f0 \ud074\ub798\uc2a4\ub97c \uacfc\ub3c4\ud558\uac8c \uc0ac\uc6a9\ud558\ub294\uac83\uc774 \uac00\ub3c5\uc131\uc774 \ub5a8\uc5b4\uc9c0\uba70 \uc624\ud788\ub824 \uc720\uc9c0 \ubcf4\uc218\uc131\uc774 \ub0ae\uc544\uc9c4\ub2e4\uace0 \uc8fc\uc7a5\ud569\ub2c8\ub2e4. \ub610\ud55c \uacfc\ub3c4\ud558\uac8c Tailwind\ub97c \ud559\uc2b5\ud560 \uacbd\uc6b0, css \ubc14\ubcf4\uac00 \ub420\uac70\ub77c\ub294 \uacbd\uace0\ub3c4 \uc874\uc7ac\ud588\uc2b5\ub2c8\ub2e4. (\ud558\uc9c0\ub9cc, Tailwind\ub97c \uc0ac\uc6a9\ud574\ubcf4\uc9c0 \uc54a\uc740 \uc0ac\ub78c\ub4e4\uc774 \uc774\ub7f0 \ub9d0\uc744 \ud55c\ub2e4\ub294 \uc18d\uc124\ub3c4 \uc788\uc2b5\ub2c8\ub2e4.)\\n\\n## \ub098\uc758 \uc8fc\uad00\uc801\uc778 \ub9ac\ubdf0\\n\\n\ucd5c\uadfc \uc9c4\ud589\ud55c \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c Tailwind\ub97c \ucc98\uc74c\ubd80\ud130 \ub3c4\uc785\ud574 \uc0ac\uc6a9\ud574\ubcf4\uc558\ub294\ub370, \uc800\uc758 \uc8fc\uad00\uc801\uc778 \uc7a5\ub2e8\uc810\uc744 \ub9ac\ubdf0\ud574\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n### \uc7a5\uc810\\n\\n- \ub9e4\uc6b0 \ube60\ub978 CSS \uc791\uc131\uc774 \uac00\ub2a5\ud558\ub2e4 (\uae30\uc874 UI \uc791\uc5c5 \uc2dc\uac04\uc758 \ud6a8\uc728\uc744 \uc57d 70% \uc815\ub3c4 \uc62c\ub838\ub2e4\uace0 \uc0dd\uac01).\\n- \ub2e4\ub978 CSS \ud504\ub808\uc784\uc6cc\ud06c\ubcf4\ub2e4 \uc790\uc720\ub3c4\uac00 \ub192\uace0, \uc218\uc815\uc774 \uc6a9\uc774\ud558\ub2e4.\\n- \ucef4\ud3ec\ub10c\ud2b8\uc758 CSS \ud30c\uc77c\uc744 \ub530\ub85c \ucc3e\uc9c0 \uc54a\uc544\ub3c4 \ub418\uc5b4 \uac04\ud3b8\ud558\ub2e4.\\n- \ubaa8\ubc14\uc77c \ubc18\uc751\ud615 \uc801\uc6a9\uc774 \ud3b8\ub9ac\ud558\ub2e4 (**`sm:flex`**\uc640 \uac19\uc774 \uc791\uc131\ud558\uba74 \uc791\uc740 \ud654\uba74\uc5d0\uc11c flex\uac00 \uc801\uc6a9\ub428).\\n\\n### \ub2e8\uc810\\n\\n- \uc801\uc6a9\ud560 CSS \uc694\uc18c\uac00 \ub9ce\uc744 \uacbd\uc6b0, \uc778\ub77c\uc778 \ucf54\ub4dc\uac00 \uc5c4\uccad \uae38\uc5b4\uc9c4\ub2e4.\\n- \ub9ce\uc740 \uc591\uc758 HTML \uc694\uc18c\uc640 CSS\ub97c \ud55c\uaebc\ubc88\uc5d0 \ubcf4\uba74 \uac00\ub3c5\uc131\uc774 \ub5a8\uc5b4\uc9c4\ub2e4.\\n- [\\\\*\\\\*Vendor Prefixes](https://tailwindcss.com/docs/browser-support#vendor-prefixes)\\\\*\\\\* \ub97c \uc0ac\uc6a9\ud558\ub824\uba74 \ucd94\uac00\uc801\uc778 \ub77c\uc774\ube0c\ub7ec\ub9ac\ub97c install \ud574\uc57c\ud55c\ub2e4.\\n\\n## \ub9c8\uce58\uba70\\n\\n\uc0ac\uc2e4 \uc5b4\ub5a4 \ub77c\uc774\ube0c\ub7ec\ub9ac\ub97c \ub3c4\uc785\ud560\uc9c0 \uacb0\uc815\ud560 \ub54c\uc5d0\ub294 \ub9ce\uc740 \uace0\ub824\uc0ac\ud56d\uc744 \ub530\uc838\ubd10\uc57c \ud569\ub2c8\ub2e4. \uadf8\ub7fc\uc5d0\ub3c4 \uac00\uc7a5 \uc911\uc694\ud55c \uac83\uc740 \uc678\ubd80\uc801\uc778 \uc694\uc778(\uc778\uc9c0\ub3c4, \ucee4\ubba4\ub2c8\ud2f0 \uc758\uacac)\uc5d0 \ud729\uc4f8\ub9ac\uc9c0 \ub9d0\uace0 \uc790\uc2e0\uc758 \ud504\ub85c\uc81d\ud2b8\uc5d0 \uc801\ud569\ud55c \ub3c4\uad6c\uc778\uc9c0 \ud310\ub2e8\ud558\ub294 \uac83\uc774\ub77c\uace0 \uc0dd\uac01\uc774 \ub4ed\ub2c8\ub2e4.\\n\\nreference\\n\\n[https://tailwindcss.com/](https://tailwindcss.com/)\\n\\n[https://tailwindcss.com/docs/browser-support#vendor-prefixes](https://tailwindcss.com/docs/browser-support#vendor-prefixes)\\n\\n[https://kulkarniankita.com/newsletter/tailwind-vs-css-the-twitter-drama-](https://kulkarniankita.com/newsletter/tailwind-vs-css-the-twitter-drama-)\\n\\n[https://www.daleseo.com/tailwind/](https://www.daleseo.com/tailwind/)\\n\\n## \ud55c\uae00 \ucd08\uc131 \uac80\uc0c9 \uad6c\ud604 \uc5b4\ub835\uc9c0 \uc54a\uc544\uc694 - \uacfd\uc2b9\uc8fc\\n\\n## Intro\\n\\n\uac80\uc0c9 \uc2dc \ud55c\uae00 \ucd08\uc131\ub9cc\uc73c\ub85c \uc6d0\ud558\ub294 \ubb38\uc790\uc5f4\uc744 \ud0d0\uc0c9\ud560 \uc218 \uc788\ub2e4\uba74 \ud55c\uae00\uc758 \uc911\uc131, \uc885\uc131\uae4c\uc9c0 \uc785\ub825\ud560 \ud544\uc694\uc5c6\uc774 \uc815\ub9d0 \ube60\ub974\uac8c \uc785\ub825\uc774 \uac00\ub2a5\ud574\uc9d1\ub2c8\ub2e4. \ud544\uc790\ub294 \ub178\ub798\ubc29\uc5d0\uc11c \ub178\ub798 \uac80\uc0c9 \uc2dc \uc815\ub9d0 \ub9ce\uc774 \uc0ac\uc6a9\ud558\ub294\ub370 \uc774\ub97c \uad6c\ud604\ud574\uc57c \ud55c\ub2e4\uba74 \uc5b4\ub5bb\uac8c \ud574\uc57c \ud560\uae4c\uc694? \uc601\uc5b4\ub294 \ubb38\uc790\uc5f4\uc774 \ud55c \uae00\uc790 \ud55c \uae00\uc790 \uac00\uc7a5 \uc791\uc740 \ub2e8\uc704\ub85c \uc774\ub8e8\uc5b4\uc838 \uc788\uae30 \ub54c\ubb38\uc5d0 \ucd08\uc131\uc774\ub77c \ud560 \uac8c \uc5c6\ub294\ub370, \ud55c\uae00\uc740 \ud55c \uae00\uc790\uac00 \ucd08\uc131, \uc911\uc131, (\uc885\uc131)\uc73c\ub85c \uc774\ub8e8\uc5b4\uc838 \uc788\uae30 \ub54c\ubb38\uc5d0 \uae00\uc790 \ubd84\ub9ac\uac00 \ud544\uc694\ud569\ub2c8\ub2e4. \uadf8 \ubd84\ub9ac\ub294 \uc5b4\ub5bb\uac8c \ud560\uae4c\uc694? \uc774\ub97c \uc9c0\uc6d0\ud558\uace0 \ud55c\uae00 \ucd08\uc131\uc73c\ub85c \ubb38\uc790\uc5f4 \uac80\uc0c9\uc744 \uc9c0\uc6d0\ud558\ub294 \ub77c\uc774\ube0c\ub7ec\ub9ac\uac00 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n## **KLED: \ud55c\uae00\uc744 \uc9c0\uc6d0\ud558\ub294 \ud37c\uc9c0 \uac80\uc0c9 \ub77c\uc774\ube0c\ub7ec\ub9ac**\\n\\n### 1. \uc18c\uac1c\\n\\n[**kled**](https://github.com/taggon/kled-js)\ub294 \ub9ac\ubca4\uc288\ud0c0\uc778 \ud3b8\uc9d1 \uac70\ub9ac(Levenshtein Edit Distance) \uc54c\uace0\ub9ac\uc998\uc744 \uae30\ubc18\uc73c\ub85c \uc791\uc131\ub418\uc5c8\uc2b5\ub2c8\ub2e4. \uac04\ub2e8\ud788 **\ub9ac\ubca4\uc288\ud0c0\uc778 \ud3b8\uc9d1 \uac70\ub9ac**\ub780 A\ub77c\ub294 \ubb38\uc790\uc5f4\uc744 B\ub77c\ub294 \ubb38\uc790\uc5f4\ub85c \ubc14\uafb8\uae30 \uc704\ud574 \uba87 \ubc88\uc758 \ud3b8\uc9d1\uc774 \uc77c\uc5b4\ub098\uc57c \ud558\ub294\uc9c0 \ud655\uc778\ud558\ub294 \uc54c\uace0\ub9ac\uc998\uc785\ub2c8\ub2e4.(\u201cabd\u201d -> \u201cabc\u201d : 1)\\n\\n\ud558\uc9c0\ub9cc \ub9ac\ubca4\uc288\ud0c0\uc778 \ud3b8\uc9d1 \uac70\ub9ac\ub294 \ub2e4\ub978 \uc54c\uace0\ub9ac\uc998\uacfc \ub9c8\ucc2c\uac00\uc9c0\ub85c \ud55c\uad6d\uc5b4 \uac80\uc0c9\uc740 \uace0\ub824\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4. \ub2e8\uc21c\ud558\uac8c \u2018\u3131\u2019\uacfc \u2018\uac15\u2019\uc744 \uc644\uc804\ud788 \ub2e4\ub978 \ubb38\uc790\ub85c \ucde8\uae09\ud558\uc5ec \ub9c8\uce58 a\ub97c b\ub85c \ubc14\uafb8\ub294 \uac83\ucc98\ub7fc \ud3b8\uc9d1 \uac70\ub9ac\uac00 \uacc4\uc0b0\ub429\ub2c8\ub2e4. \uc774 \ubb38\uc81c\ub97c \ubc29\uc9c0\ud558\uae30 \uc704\ud574 kled\ub294 \u2018\u3131\u2019\uacfc \ucd08\uc131\uc774 \u2018\u3131\u2019\uc778 \ubaa8\ub4e0 \uae00\uc790\ub294 \ubaa8\ub450 \ub3d9\uc77c\ud558\ub2e4\uace0 \ubcf4\uace0 \ub9ac\ubca4\uc288\ud0c0\uc778 \ud3b8\uc9d1 \uac70\ub9ac\ub97c \uacc4\uc0b0\ud569\ub2c8\ub2e4.\\n\\n\uc774\ub7ec\ud55c \ubb38\uc81c\ub97c \ud574\uacb0\ud574\uc11c \ucd08\uc131 \u2018\u3131\u3134\u2019\uc744 \uc785\ub825\ud558\uba74 \uac80\uc0c9 \ub300\uc0c1 \ubb38\uc790\uc5f4 \uc911 \u2018\u3131\u2019\uacfc \u2018\u3134\u2019\uc774 \uc21c\uc11c\ub300\ub85c \uc788\ub294 \ubb38\uc790\uc5f4\uc744 \ubcf4\uc5ec\uc90d\ub2c8\ub2e4. \uc608\ub97c \ub4e4\uc5b4, \u2018\uacbd\uae30\ub3c4 \uc131\ub0a8\uc2dc\u2019, \u2018\uacbd\uc0c1\ub0a8\ub3c4 \ucc3d\uc6d0\uc2dc\u2019 \ub4f1\uc774 \ub098\ud0c0\ub0a0 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ud558\uc9c0\ub9cc, \uc774 \ub77c\uc774\ube0c\ub7ec\ub9ac\uc5d0\ub294 \uc57d\uac04\uc758 \ubd88\ud3b8\ud55c \uc810\uacfc \ubb38\uc81c\uc810\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### 2. \ubd88\ud3b8\ud55c \uc810\\n\\n\ubd88\ud3b8\ud55c \uc810\uc740 **\uc720\uc0ac\ub3c4 \uc810\uc218\ub97c \ubc18\ud658**\ud558\ub294 \ud568\uc218\uac00 \uac80\uc0c9 \ub300\uc0c1 \ubb38\uc790\uc5f4\uc758 \uae38\uc774\uc5d0 \ub530\ub77c \ub2ec\ub77c\uc9c0\uae30 \ub54c\ubb38\uc5d0 \uc790\uc2e0\uc774 \uc0dd\uac01\ud55c \ubb38\uc790\uc5f4\uc744 \uc785\ub825\ud588\uc744 \ub54c \uc720\uc0ac\ub3c4\uac00 \ub0ae\uc544 \ubc11\uc5d0\uc11c \ucc3e\uc544\uc57c \ud558\ub294 \uacbd\uc6b0\uac00 \uc788\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n<img\\n  src=\\"/img/@frontEnd/infomate-8week/infomate-8week-gwakseungjs1.jpg\\"\\n  style={{ marginBottom: \'20px\' }}\\n/>\\n\\n\uc704 \uadf8\ub9bc\uacfc \uac19\uc774 \uc790\uc2e0\uc740 \u2018\uc218\uc6d0\uc2dc\u2019\ub97c \uc0dd\uac01\ud558\uace0 \u2018\u3145\u3147\u3145\u2019\ub77c\uace0 \uc785\ub825\ud588\uc9c0\ub9cc \ubb38\uc790\uc5f4 \uae38\uc774\uac00 \uc9e7\uace0 \u2018\u3145\u2019, \u2018\u3147\u2019, \u2018\u3145\u2019\uc774 \ub4e4\uc5b4\uac04 \u2018\uc11c\uc6b8\ud2b9\ubcc4\uc2dc\u2019, \u2018\ubd80\uc0b0\uad11\uc5ed\uc2dc\u2019 \ub4f1\uc774 \uba3c\uc800 \ub098\uc624\uac8c \ub429\ub2c8\ub2e4. \ucc38\uace0\ub85c, \ub3c4\uc2dc \uc774\ub984 \uc606\uc758 \uc22b\uc790\uac00 \uc720\uc0ac\ub3c4\uc774\uace0, 0\ubd80\ud130 1 \uc774\ud558\uc758 \uc2e4\uc218\ub85c \ub098\ud0c0\ub0a9\ub2c8\ub2e4.\\n\\n### 3. \ubb38\uc81c\uc810\\n\\n\ub610, \uc774 \ub77c\uc774\ube0c\ub7ec\ub9ac\uc758 \ubb38\uc81c\uc810\uc740 \uac80\uc0c9 \uacb0\uacfc \uae00\uc790 \uc218\uc5d0 \uc81c\ud55c\uc774 \uac78\ub9b4 \uc218 \uc788\ub2e4\ub294 \uc810\uc785\ub2c8\ub2e4. \uc774\uac8c \ubb34\uc2a8 \ub9d0\uc774\ub0d0\uba74, \uc544\ub798 \uadf8\ub9bc\uc744 \ubd05\uc2dc\ub2e4.\\n\\n<img\\n  src=\\"/img/@frontEnd/infomate-8week/infomate-8week-gwakseungjs2.jpg\\"\\n  style={{ marginBottom: \'20px\' }}\\n/>\\n\\n\uc6d0\ub798\ub294 \uac80\uc0c9 \uacb0\uacfc\uc5d0 \u2018\ucda9\uccad\ub0a8\ub3c4 \ucc9c\uc548\uc2dc\u2019\ub9cc \ub098\uc640\uc57c \ud558\uace0 \uc720\uc0ac\ub3c4\ub294 1\uc774 \ub418\uc5b4\uc57c \ud560 \ud150\ub370, \u2018\ucda9\uccad\ub0a8\ub3c4 \ucc9c\uc548\uc2dc\u2019\uc758 \uc720\uc0ac\ub3c4\uac00 1\uc774 \uc544\ub2cc \uac83\ub3c4 \uadf8\ub807\uace0, \ub2e4\ub978 \uc9c0\uc5ed \uc774\ub984\uae4c\uc9c0 \uc720\uc0ac\ub3c4\uac00 \u2018\ucda9\uccad\ub0a8\ub3c4 \ucc9c\uc548\uc2dc\u2019\uc640 \uac19\ub2e4\ub294 \uc810\uc785\ub2c8\ub2e4.\\n\\n\uc774 \uc774\uc720\ub294 \uac80\uc0c9 \ub300\uc0c1\uc758 \ub370\uc774\ud130\uc14b\uc758 \uac00\uc7a5 \uc9e7\uc740 \ubb38\uc790\uc5f4\uc758 \uae38\uc774\uae4c\uc9c0\ub9cc \uacc4\uc0b0\ud558\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4. \uc704 \uc608\uc2dc\uc758 \ub370\uc774\ud130\uc14b \uc911 \uac00\uc7a5 \uc9e7\uc740 \uae38\uc774\uc758 \ubb38\uc790\uc5f4\uc740 \u2018\uc11c\uc6b8\ud2b9\ubcc4\uc2dc\u2019, \u2018\ubd80\uc0b0\uad11\uc5ed\uc2dc\u2019 \ub4f1 \uae38\uc774\uac00 5\uc785\ub2c8\ub2e4. \ub530\ub77c\uc11c \u2018**\ucda9\uccad\ub0a8\ub3c4** \u2019\uae4c\uc9c0\ub9cc \ube44\uad50\ud558\uc5ec \uacc4\uc0b0\ud558\ub294 \uac83\uc785\ub2c8\ub2e4.\\n\\n\ud574\uacb0 \ubc29\ubc95\uc740 \uc544\uc9c1 \ucc3e\uc9c0 \ubabb \ud588\uc9c0\ub9cc, \uc774\ub7ec\ud55c \ubb38\uc81c\uc810\uc744 \uac1c\uc120\ud558\uba74 \uc815\ub9d0 \uc720\uc6a9\ud558\uac8c \uc4f0\uc77c \ub77c\uc774\ube0c\ub7ec\ub9ac\uac00 \ub420 \uac83\uc785\ub2c8\ub2e4.\\n\\n## Hangul.js\\n\\n\ucd08\uc131 \uac80\uc0c9 \uae30\ub2a5\uc744 \uc704\ud574 \uc704 \ub77c\uc774\ube0c\ub7ec\ub9ac \ub300\uc2e0 \u2018[Hangul.js](https://github.com/e-/Hangul.js#hanguljs)\u2019\ub77c\ub294 \ub77c\uc774\ube0c\ub7ec\ub9ac\ub97c \uc0ac\uc6a9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc774 \ub77c\uc774\ube0c\ub7ec\ub9ac\ub294 \uc790\uc74c\uacfc \ubaa8\uc74c\uc744 \ubd84\ub9ac\ud558\ub294 \uae30\ub2a5\uc744 \uc81c\uacf5\ud558\uc5ec \ucd08\uc131 \uac80\uc0c9\uc5d0 \uc0ac\uc6a9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc774 \ub77c\uc774\ube0c\ub7ec\ub9ac\ub294 \ucd08\uc131 \uac80\uc0c9 \uae30\ub2a5\uc744 \uc81c\uacf5\ud558\ub294 \uac83\uc774 \uc544\ub2cc \uc790\uc74c\uacfc \ubaa8\uc74c\uc73c\ub85c \ubd84\ub9ac\ud558\uace0 \uc774 \ubb38\uc790\uac00 \uc790\uc74c\uc778\uc9c0, \ubaa8\uc74c\uc778\uc9c0, \uc790\uc74c\uc73c\ub85c \ub05d\ub098\ub294\uc9c0 \ub4f1\uc758 \uae30\ub2a5\uc744 \uc81c\uacf5\ud569\ub2c8\ub2e4. \uc774\ub97c \uc801\uc808\ud788 \uc774\uc6a9\ud558\uc5ec \ucd08\uc131 \uac80\uc0c9 \uae30\ub2a5\uc744 \uad6c\ud604\ud560 \uc218 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4.\\n\\n## \uacb0\ub860\\n\\n\uc704 \ub450 \ub77c\uc774\ube0c\ub7ec\ub9ac\ub294 \uac01\uc790 \uc7a5\ub2e8\uc810\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n`kled`\ub294 \ucd08\uc131\uc73c\ub85c \uac80\uc0c9\uc744 \ud560 \uc218 \uc788\ub294 \uae30\ub2a5\uc744 \uc81c\uacf5\ud558\uc5ec \uc27d\uac8c \uc0ac\uc6a9\uc774 \uac00\ub2a5\ud558\uc9c0\ub9cc, \uc704\uc5d0\uc11c \ubcf8 \uba87 \uac00\uc9c0 \ubb38\uc81c\uc810\uc774 \uc874\uc7ac\ud55c\ub2e4\ub294 \uc810\uc785\ub2c8\ub2e4.\\n\\n`Hangul.js`\ub294 `kled`\uc758 \ubb38\uc81c\uc810\uc744 \ubcf4\uc644\ud560 \uc218 \uc788\uace0 \ud65c\uc6a9 \ubc94\uc704\uac00 \ub113\ub2e4\ub294 \uc7a5\uc810\uc774 \uc788\uc9c0\ub9cc, \uadf8\ub97c \uc704\ud574 \uad6c\ud604\uc744 \uc9c1\uc811\ud574\uc57c \ud55c\ub2e4\ub294 \ub2e8\uc810\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n[\uc815\uaddc\ud45c\ud604\uc2dd\uc744 \uc774\uc6a9\ud574 \ucd08\uc131 \uac80\uc0c9\uc744 \uad6c\ud604\ud55c \ubc29\ubc95\uc744 \uc18c\uac1c\ud558\ub294 \uae00](https://taegon.kim/archives/9919)\ub3c4 \uc788\uc2b5\ub2c8\ub2e4. \uc774 \ubc29\ubc95\uc774 \u2018\uacb0\uacfc\u2019\uc801\uc73c\ub85c\ub294 \uac00\uc7a5 \uc88b\uc740 \ubaa8\uc2b5\uc744 \ubcf4\uc774\uc9c0\ub9cc, \uc131\ub2a5 \ud6a8\uc728\uc801\uc778 \uba74\uc5d0\uc11c \uadf8\ub807\uac8c \uc88b\uc9c0\ub294 \uc54a\uc2b5\ub2c8\ub2e4. \ub2e4\ub9cc, \ud06c\uc9c0 \uc54a\uc740 \ub370\uc774\ud130\uc14b\uc744 \uac80\uc0c9\ud55c\ub2e4\uace0 \ud558\uba74 \uc815\uaddc\ud45c\ud604\uc2dd\uc744 \uc774\uc6a9\ud558\ub294 \ubc29\ubc95\uc774 \uac00\uc7a5 \uc88b\ub2e4\uace0 \uc0dd\uac01\ud569\ub2c8\ub2e4.\\n\\n## \ucc38\uace0\uc790\ub8cc\\n\\n[KLED: \ud55c\uad6d\uc5b4\ub97c \uc9c0\uc6d0\ud558\ub294 \ud37c\uc9c0 \uac80\uc0c9 \ub77c\uc774\ube0c\ub7ec\ub9ac](https://taegon.kim/archives/10671)\\n\\n[NestJS\uc5d0\uc11c \ucd08\uc131 \uac80\uc0c9 \uae30\ub2a5 \uad6c\ud604\ud558\uae30](https://velog.io/@odahyun/NestJS\uc5d0\uc11c-\ucd08\uc131-\uac80\uc0c9-\uae30\ub2a5-\uad6c\ud604\ud558\uae30)\\n\\n## style-dictionary\ub85c \ub514\uc790\uc778 \ud1a0\ud070 \ud65c\uc6a9\ud558\uae30 - \uae40\ubbfc\uc7ac\\n\\nui/ux design\uc744 \uc704\ud574 \uc774\uc81c figma\ub97c \uc815\ub9d0 \ub9ce\uc774 \uc774\uc6a9\ud558\ub294 \uac83 \uac19\uc544\uc694. \uc9c0\uae08 \ub2e4\ub2c8\uace0 \uc788\ub294 \ud68c\uc0ac\uc5d0\uc11c\ub3c4 figma\ub97c \uc0ac\uc6a9\ud558\uace0 \uc788\uace0 \uc5ec\ub7ec\ubd84\ub4e4\ub3c4 figma\ub294 \uc774\ubbf8 \uce5c\uc219\ud55c \ud234\uc77c\uac81\ub2c8\ub2e4. figma\ub3c4 \ub9ce\uc740 \ubc1c\uc804\uc744 \uac70\uccd0 \uc9c0\uae08\uc5d0 \uc774\ub974\uace0 \uc788\uc8e0!\\n\\n\uadf8\ub798\uc11c \uac11\uc790\uae30 figma \uc774\uc57c\uae30\ub97c \uc65c \ud558\ub0d0\uad6c\uc694? \uc774\ubc88 \uae00\uc5d0\uc11c \uc18c\uac1c\ud558\ub824\ub294 \uc8fc\uc81c\uc640 figma\uac00 \uc57d\uac04\uc758 \uc5f0\uad00\uc131\uc774 \uc788\uac70\ub4e0\uc694.\\n\\n\ud504\ub860\ud2b8\uc5d0\uc11c \ucef4\ud3ec\ub10c\ud2b8 \ub2e8\uc704\uc758 \uac1c\ubc1c\uc774 \ub4e4\uc5b4\uc628 \uac83 \uacfc \uac19\uc774 \ub514\uc790\uc778\uc5d0\uc11c\ub3c4 \ucef4\ud3ec\ub10c\ud2b8 \uac1c\ub150\uc774 \uc0dd\uaca8\ub098\uac8c \ub429\ub2c8\ub2e4.\\n\\n\uadf8\ub9ac\uace0 \uc880 \ub354 \uccb4\uacc4\uc801\uc73c\ub85c \ub514\uc790\uc778\uc5d0 \uad00\ub828\ud55c \uac12\ub4e4\uc744 \uad00\ub9ac\ud558\uace0\uc790 \uc2dc\uc2a4\ud15c\uc744 \uad6c\ucd95\ud558\uae30 \uc704\ud55c \ub514\uc790\uc778 \ud1a0\ud070\uc744 \ud65c\uc6a9\ud569\ub2c8\ub2e4.\\n\\n\ucd5c\uadfc figma\uc5d0\ub3c4 \ub514\uc790\uc778 \ud1a0\ud070\uc744 \uc880 \ub354 \uc720\ub3d9\uc801\uc774\uace0 \uccb4\uacc4\uc801\uc73c\ub85c \uc4f8 \uc218 \uc788\uac8c local variables \ub77c\ub294 \uae30\ub2a5\uc774 \uc0dd\uaca8\ub0ac\uc5b4\uc694! \ub9c8\uce58 \uac1d\uccb4\uc758 \uc0c1\uc18d\ucc98\ub7fc \uc774\uc81c \ub514\uc790\uc778 \ud1a0\ud070\uc744 \uc0c1\uc18d\ud55c \uc0c8\ub85c\uc6b4 \ud1a0\ud070\uc744 \ub9cc\ub4e4 \uc218 \uc788\uac8c \ub418\uc5c8\uc8e0.\\n\\n\uc774 \ub514\uc790\uc778 \ud1a0\ud070\ub4e4\uc740 \uac1c\ubc1c\uc790\uc5d0\uac8c\ub3c4 \uc720\uc6a9\ud574\uc694. \ub514\uc790\uc774\ub108\uac00 \ub9cc\ub4e0 figma\uc758 \ud1a0\ud070\ub4e4\uc744 \ucf54\ub4dc\uc640 \uc5f0\ub3d9\uc2dc\ud0ac \uc218 \uc788\ub2e4\uba74 \uc5b4\ub5a8\uae4c\uc694? \uc5ec\ub7ec \ubd80\ubd84\uc5d0 \ub514\uc790\uc778\uc758 \ubcc0\ud654\uac00 \uc0dd\uaca8\ub3c4 \uc774\uc81c \ub514\uc790\uc774\ub108\uac00 \ud1a0\ud070\uc744 \ubcc0\uacbd\ud558\ub294 \uac83 \ub9cc\uc73c\ub85c\ub3c4 \ubc14\ub85c \ub514\uc790\uc778\uc744 \uc2e4\uc81c \uc6f9 \ud398\uc774\uc9c0\uc5d0 \uc801\uc6a9\uc2dc\ud0ac \uc218 \uc788\uac8c \ub429\ub2c8\ub2e4!\\n\\nfigma\uc758 token studio\ub97c \uc0ac\uc6a9\ud558\uba74 variables\ub85c \uc120\uc5b8\ud55c local token\ub4e4\uc744 json \ud615\uc2dd\uc73c\ub85c \ubf51\uc544\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n```jsx\\n{\\n  \\"blue\\": {\\n    \\"0\\": {\\n      \\"value\\": \\"#f5f5ff\\",\\n      \\"type\\": \\"color\\",\\n      \\"parent\\": \\"palette/Mode 1\\",\\n      \\"description\\": \\"\\"\\n    },\\n    \\"5\\": {\\n      \\"value\\": \\"#ebebff\\",\\n      \\"type\\": \\"color\\",\\n      \\"parent\\": \\"palette/Mode 1\\",\\n      \\"description\\": \\"\\"\\n    }\\n    ...\\n}\\n```\\n\\n\uc774 \uc0c9\uc744 \uc0c1\uc18d\ubc1b\uc740 variables \ub3c4 \uc798 \ubf51\uc544\uc8fc\uc8e0.\\n\\n```jsx\\n{\\n  \\"primary\\": {\\n    \\"400\\": {\\n      \\"value\\": \\"{dots-blue.400}\\", // \uc774\ub807\uac8c\\n      \\"type\\": \\"color\\",\\n      \\"parent\\": \\"semantic/Mode 1\\",\\n      \\"description\\": \\"\\"\\n    },\\n}\\n```\\n\\n\uc774\ub807\uac8c \uc120\uc5b8\ud55c \ud1a0\ud070\uc744 \uac1c\ubc1c\uc790\uc5d0\uac8c \uc775\uc219\ud55c css variables \ub85c \ubc14\uafd4\uc8fc\uae30 \uc704\ud574 style-dictionary\uac00 \ud544\uc694\ud569\ub2c8\ub2e4.\\n\\n```jsx\\nnpm i style-dictionary\\n```\\n\\ncss, scss, css in js, css custom \ub4f1 \ub2e4\uc591\ud55c \ud615\ud0dc\ub85c \ud1a0\ud070\uc744 \ubc14\uafb8\uc5b4 \uc904 \uc218 \uc788\uc5b4\uc694.\\n\\n\uac04\ub2e8\ud558\uac8c css \ud615\ud0dc\ub85c \ubc14\uafb8\uc5b4\ubcfc\uae4c\uc694? \uc6b0\uc120 config \ud30c\uc77c\uc744 \ub9cc\ub4e4\uc5b4 \ubd05\uc2dc\ub2e4!\\n\\n\uadf8\ub9ac\uace0 `extend` \ub97c \ud65c\uc6a9\ud574 \ud544\uc694\ud55c \uc815\ubcf4\ub4e4\uc744 \ub123\uc5b4\ubcfc\uac8c\uc694.\\n\\n```jsx\\n// style-dictionary.config.cjs\\n\\nconst styleDictionary = require(\'style-dictionary\');\\n\\nconst StyleDictionary = styleDictionary.extend({\\n  source: [\'./tokens/**.json\'], // \ud1a0\ud070\uc744 \uc800\uc7a5\ud560 \uc704\uce58\\n  platforms: {\\n    css: {\\n      transformGroup: \'css\', // \uadf8\ub8f9\uc774\ub984\\n      buildPath: \'src/\', // \ub9cc\ub4e4\uc5b4\uc9c4 \uacb0\uacfc\ubb3c\uc744 \ub193\uc744 \uc704\uce58\\n      files: [\\n        {\\n          destination: \'variables.css\', // \ud30c\uc77c\uc774\ub984\\n          format: \'css/variables\', // \ud3ec\ub9f7\ud615\ud0dc\\n        },\\n      ],\\n    },\\n  },\\n});\\n\\nStyleDictionary.cleanAllPlatforms(); // \uae30\uc874 \uaebc \uc0ad\uc81c\\nStyleDictionary.buildAllPlatforms(); // \ub2e4\uc2dc \ub9cc\ub4e4\uae30\\n```\\n\\n\uc9c0\uae08\uc740 \ud558\ub098\uc758 \ud50c\ub7ab\ud3fc\uc744 \ub2e4\ub8e8\uc5c8\uc9c0\ub9cc, ios, android \ub4f1 \ub2e4\uc591\ud55c \ud50c\ub7ab\ud3fc\uc744 \ub530\ub85c \ub2e4\ub8f0 \uc218\ub3c4 \uc788\uc5b4\uc694.\\n\\n\ub178\ub4dc \uba85\ub839\uc5b4\ub85c \uc2e4\ud589\uc744 \uc2dc\ucf1c\uc8fc\uba74\\n\\n```jsx\\nnode style-dictionary.config.cjs\\n```\\n\\n\ud574\ub2f9 \uc704\uce58\uc5d0 css variables \ud30c\uc77c\uc774 \ub098\uc628\uac78 \ud655\uc778 \ud560 \uc218 \uc788\uc5b4\uc694!\\n\\n```jsx\\n:root {\\n\\t--dots-blue-0: #f5f5ff;\\n  --dots-blue-5: #ebebff;\\n  --primary-400: #4046fd;\\n}\\n```\\n\\n\ub9cc\uc57d react vite \ud658\uacbd\uc5d0\uc11c \ub514\uc790\uc778 \ud1a0\ud070\uc744 \ud65c\uc6a9\ud574 css variables\ub97c \ud65c\uc6a9\ud558\uace0 \uc2f6\ub2e4\uba74 \uc544\ub798\uc640 \uac19\uc774 \ube4c\ub4dc\ub97c \ud574\uc8fc\uba74 \ub429\ub2c8\ub2e4!\\n\\n```jsx\\n\\"build\\": \\"node style-dictionary.config.cjs && vite build\\",\\n```\\n\\nfigma \uc758 token studio \ub97c \ud65c\uc6a9\ud574 github\uc640 \uc5f0\ub3d9\uc2dc\ud0a8\ub2e4\uba74 \uc790\ub3d9\uc73c\ub85c PR\uc744 \ub9cc\ub4e4\uc5b4\uc11c token\uc744 \ubc14\uafb8\uc5b4\uc904 \uc218 \uc788\uc8e0. \uadf8\ub807\ub2e4\uba74 \ube4c\ub4dc\ub420 \ub54c \ubc14\ub010 \ud1a0\ud070\uc774 \ubc18\uc601\ub418\uae30 \ub54c\ubb38\uc5d0 \uac1c\ubc1c\uc758 \uc190\uc744 \uac70\uce58\uc9c0 \uc54a\uace0 \uc2a4\ud0c0\uc77c\uc744 \ube60\ub974\uac8c \ubc18\uc601\ud560 \uc218 \uc788\uac8c\ub429\ub2c8\ub2e4!\\n\\ndev mode\uc758 css \uc5d0\uc11c\ub3c4 \ud574\ub2f9 variables \uc5d0 \ub9de\uac8c css \ucf54\ub4dc\ub97c \uc8fc\uae30 \ub54c\ubb38\uc5d0 \uac1c\ubc1c \uc0dd\uc0b0\ub825\uc740 \ub364\uc774\ub78d\ub2c8\ub2e4~!\\n\\n\uc774\uc678\uc5d0 \uc880 \ub354 \uc804\ubb38\uc801\uc73c\ub85c \uc0ac\uc6a9\ud558\uae30 \uc704\ud55c [@tokens-studio/sd-transforms](https://www.npmjs.com/package/@tokens-studio/sd-transforms), [token-transformer](https://npmjs.com/package/token-transformer)\uc640 tailwind \uc804\uc6a9 transformer \ub4f1.. \ud1a0\ud070\uc744 \uc798 \ud65c\uc6a9\ud558\uae30 \uc704\ud55c \uc5ec\ub7ec \ub77c\uc774\ube0c\ub7ec\ub9ac\ub4e4\uc774 \uc874\uc7ac\ud574\uc694. \uc774 \uc8fc\uc81c\uc5d0 \ud765\ubbf8\uac00 \uc0dd\uacbc\ub2e4\uba74 \uc544\ub798\uc758 \ud0a4\uc6cc\ub4dc\ub97c \ucc3e\uc544 \uc775\ud600\ubcf4\uba74 \uc88b\uc544\uc694~!\\n\\n- \ub514\uc790\uc778 \uc2dc\uc2a4\ud15c, \ub514\uc790\uc778 \ud1a0\ud070, figma token studio, figma variable"},{"id":"/GwakSeungJu/april-retrospect_GwakSeungju","metadata":{"permalink":"/front-end/GwakSeungJu/april-retrospect_GwakSeungju","source":"@site/@frontEnd/GwakSeungJu/april-retrospect_GwakSeungju.mdx","title":"\ub808\uade4\ub7ec\ub85c \uc804\ud658\ub418\uace0...","description":"4\uc6d4 \uc6d4\uac04 \ud68c\uace0\uc785\ub2c8\ub2e4.","date":"2024-05-24T00:00:00.000Z","tags":[{"label":"\uc6d4\uac04 \ud68c\uace0","permalink":"/front-end/tags/\uc6d4\uac04-\ud68c\uace0"},{"label":"\ub808\uade4\ub7ec \uc804\ud658","permalink":"/front-end/tags/\ub808\uade4\ub7ec-\uc804\ud658"}],"readingTime":7.76,"hasTruncateMarker":true,"authors":[{"name":"GwakSeungJu","url":"https://github.com/Gwak-Seungju","email":"gwak1016@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/74342515?v=4","key":"GwakSeungJu"}],"frontMatter":{"date":"2024-05-24T00:00:00.000Z","authors":"GwakSeungJu","title":"\ub808\uade4\ub7ec\ub85c \uc804\ud658\ub418\uace0...","description":"4\uc6d4 \uc6d4\uac04 \ud68c\uace0\uc785\ub2c8\ub2e4.","keywords":["\uc6d4\uac04 \ud68c\uace0","\ub808\uade4\ub7ec \uc804\ud658"],"tags":["\uc6d4\uac04 \ud68c\uace0","\ub808\uade4\ub7ec \uc804\ud658"]},"unlisted":false,"prevItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 8\uc8fc\ucc28 \uacf5\uc720(\ud504\ub808\uc784\uc6cc\ud06c & \ub77c\uc774\ube0c\ub7ec\ub9ac)","permalink":"/front-end/haejinyun/infomate-8week"},"nextItem":{"title":"BCSD FrontEnd \ud2b8\ub799 \uc18c\uac1c!!","permalink":"/front-end/junghaesung79/introduce-FE"}},"content":"23\ub144\ub3c4 \ud558\ubc18\uae30 Regular\ub85c \uc804\ud658\ub418\uace0 \ub09c \ub4a4 \uc57d 3\uac1c\uc6d4\uac04\uc758 \uc774\uc57c\uae30\ub97c \ub9d0\uc500\ub4dc\ub9ac\ub824\uace0 \ud569\ub2c8\ub2e4.\\n\\n{/* truncate */}\\n\\n### 4\uc6d4 \uc6d4\uac04 \ud68c\uace0\\n\\n\uc548\ub155\ud558\uc138\uc694! FE \ud2b8\ub799 \ub808\uade4\ub7ec \uacfd\uc2b9\uc8fc\uc785\ub2c8\ub2e4. \uc800\ub294 23\ub144\ub3c4 \ud558\ubc18\uae30 FE Beginner \uad50\uc721 \ucee4\ub9ac\ud058\ub7fc\uc744 \ub9c8\uce58\uace0 24\ub144 2\uc6d4\uc5d0 Regular\ub85c \uc804\ud658\uc774 \ub418\uc5c8\uc5b4\uc694! Regular\ub85c \uc804\ud658\ud55c \ub4a4 \uc9c0\uae08\uae4c\uc9c0 3\uac1c\uc6d4\uac04\uc758 \ud65c\ub3d9\uacfc \ub290\ub080 \uc810\uc744 \ub9d0\uc500\ub4dc\ub9ac\ub824\uace0 \ud574\uc694~!  \ud604\uc7ac FE \ube44\uae30\ub108\ubd84\ub4e4\uc774 \ubcf4\uc154\ub3c4 \uc88b\uc744 \uac83 \uac19\uc544\uc694!!\\n<div style={{ display: \\"flex\\", flexDirection: \\"column\\", width: \\"45%\\", margin: \\"25px auto\\" }}>\\n  <img src=\\"/img/@frontEnd/april-retrospect_GwakSeungju/01.jpg\\" alt=\\"\uc774\ubbf8\uc9c0\\" />\\n</div>\\n\\nRegular\ub85c \uc804\ud658\ub41c \ub4a4 \uccab \ud65c\ub3d9\uc740 **\u2018KOIN \uc774\ubca4\ud2b8 \uc2a4\ud1a0\ubc0d\u2019** \ud65c\ub3d9\uc774\uc5c8\uc5b4\uc694. 24\ub144\ub3c4 \uc0c1\ubc18\uae30\ubd80\ud130 KOIN \uac1c\ubc1c\uc744 \ud2b8\ub799 \ub2e8\uc704\ub85c \uc9c4\ud589\ud558\ub294 \uac83\uc774 \uc544\ub2cc \ubaa8\ub4e0 \ud2b8\ub799\uc774 \ucc38\uc5ec\ud558\ub294 \ud300 \ub2e8\uc704\ub85c \uc9c4\ud589\ud558\ub294 \uac83\uc73c\ub85c \uac1c\ud3b8\ud558\uc600\uc5b4\uc694. \uadf8\ub798\uc11c KOIN \uc11c\ube44\uc2a4\uc5d0 \uc788\uc744 \ub9cc\ud55c \ub610\ub294 \uc788\uc73c\uba74 \uc88b\uc744 \uac83 \uac19\uc740 \uae30\ub2a5\ub4e4\uc744 \uc0dd\uac01\ud558\uace0 \ubaa8\ub450\uac00 \ub611\uac19\uc774 \uc774\ud574\ud558\ub294 \uc2dc\uac04\uc744 \uac00\uc9c4 \uac83\uc774\uc8e0.\\n\ucc98\uc74c\ubd80\ud130 KOIN\uc5d0 \ub300\ud574 \uc0dd\uac01\ud574 \ubcf8\ub2e4\ub294 \uc810\uc5d0\uc11c \uc544\uc9c1 \ubcd1\uc544\ub9ac\uc778 \uc800\uc5d0\uac90 \uc815\ub9d0 \uc88b\uc740 \uc2dc\uac04\uc774\uc5c8\uc5b4\uc694.\\n<div style={{ display: \\"flex\\", flexDirection: \\"column\\", width: \\"45%\\", margin: \\"25px auto\\" }}>\\n  <img src=\\"/img/@frontEnd/april-retrospect_GwakSeungju/04.jpg\\" alt=\\"\uc774\ubbf8\uc9c0\\" />\\n</div>\\n\\nBeginner\uc5d0\uc11c Regular\ub85c \uc804\ud658\ub418\uba74 \uae30\ubcf8\uc801\uc73c\ub85c **\uc628\ubcf4\ub529 \uad50\uc721**\uc744 \ubc1b\uc544\uc57c \ud574\uc694. KOIN \ud504\ub85c\uc81d\ud2b8 \uac1c\ubc1c\uc744 \uc9c4\ud589\ud558\uae30 \uc704\ud574 \uc5b4\ub5a4 \uac83\ub4e4\uc744 \uc54c\uc544\uc57c \ud558\ub294\uac00\ub97c \ubc30\uc6b0\ub294\ub370 \ub300\ub7b5\uc801\uc778 \ucf54\ub4dc \uad6c\uc870, \ud3f4\ub354 \uad6c\uc870 \uadf8\ub9ac\uace0 Git \uc0ac\uc6a9 \ubc29\ubc95\uc744 \ubc30\uc6e0\uc5b4\uc694. \ub610\ud55c, Beginner \uacfc\uc815\uc5d0\uc11c \uc368 \ubcf4\uc9c0 \uc54a\uc558\ub358 TypeScript, react-query\uc758 \ucd94\uac00 \uacf5\ubd80\uac00 \ud544\uc694\ud588\uc5b4\uc694. \uc2e4\uc81c KOIN\uc5d0\uc11c \uc0ac\uc6a9\ud558\ub294 \ucf54\ub4dc\ub97c \ubcf4\uba70 \uacf5\ubd80\ud558\ub824\uace0 \ud588\uc9c0\ub9cc, \uc544\ubb34\uac83\ub3c4 \ubaa8\ub974\ub294 \uc0c1\ud0dc\uc5d0\uc11c \ubcf4\ub2c8\uae4c \uc798 \uc77d\ud788\uc9c0\ub3c4 \uc54a\uace0 \ubb58 \ubcf4\uace0 \uc2dc\uc791\ud574\uc57c \ud558\ub294\uc9c0 \uac10\uc774 \uc624\uc9c8 \uc54a\uc558\uc5b4\uc694. \uadf8\ub798\uc11c TypeScript\uc758 \uae30\ubcf8 \uac1c\ub150\ubd80\ud130 \uad50\uc7ac\ub97c \ubcf4\uba70 \uacf5\ubd80\ud588\uc5b4\uc694. \uadf8\ub807\uac8c \uacc4\uc18d \uacf5\ubd80\ub9cc \ud558\ub2e4\uac00 \uccab \uae30\ub2a5 \uac1c\ubc1c\uc744 \ud558\uac8c \ub418\uc5c8\ub294\ub370 \uc815\ub9d0 \uac04\ub2e8\ud55c \uac83\uc774\uc5c8\uc5b4\uc694! \ud558\uc9c0\ub9cc, \uc774\ub860\ub9cc \uc54c\uace0 \uc788\ub294 \uc0c1\ud0dc\uc5d0\uc11c \ubcf5\uc7a1\ud55c \ub85c\uc9c1\uc774 \uc5bd\ud600\uc788\ub294 \ucf54\ub4dc\ub97c \ub9cc\uc9c0\uc790\ub2c8 \ub2e4\uc2dc \ubcbd\uc5d0 \ubd80\ub52a\ud788\ub294 \ub290\ub08c\uc774 \ub4e4\uc5c8\uc5b4\uc694. \\n<div style={{ display: \\"flex\\", flexDirection: \\"column\\", width: \\"45%\\", margin: \\"25px auto\\" }}>\\n  <img src=\\"/img/@frontEnd/april-retrospect_GwakSeungju/02.jpg\\" alt=\\"\uc774\ubbf8\uc9c0\\" />\\n</div>\\n\\n\ub108\ubb34 \uac10\uc0ac\ud558\uac8c\ub3c4 \uc606\uc5d0\uc11c \ud558\ub098\uac00 API \ud638\ucd9c \ubc29\uc2dd, \ucf54\ub4dc \ub3d9\uc791 \ubc29\uc2dd \ub4f1\uc744 \uc54c\ub824\uc918 \uc774\ud574\ud560 \uc218 \uc788\uac8c \ub418\uc5c8\uc5b4\uc694. \uae30\ub2a5 \uad6c\ud604\uc744 \uc644\ub8cc\ud558\uace0 \uc774\uc81c PR\uc744 \ub0a0\ub824\uc57c \ud558\ub294\ub370, \ucc98\uc74c \ud558\ub294 \uac70\ub2e4 \ubcf4\ub2c8 \uc5c4\uccad \uc798 \uc368\uc57c \ud560 \uac83 \uac19\uace0, \ubb50 \ud558\ub098\ub77c\ub3c4 \uc798\ubabb \uc791\uc131\ud558\uba74 \uc548 \ub420 \uac83 \uac19\uc544\uc11c \ud574\uc131\uc774\uc5d0\uac8c \ub3c4\uc6c0\uc744 \uc694\uccad\ud588\uc5b4\uc694..! \u314e\u314e \ud574\uc131\uc774\uac00 \uc606\uc5d0\uc11c \uae30\ubcf8\uc801\uc778 PR \uc791\uc131\ubc95, \ud615\uc2dd \ub4f1\uc744 \uc54c\ub824\uc918\uc11c \ubb34\uc0ac\ud788 PR\uc744 \ub0a0\ub9b4 \uc218 \uc788\uc5c8\uc5b4\uc694. \uadf8\ub9ac\uace0 \ubb34\uc218\ud55c \ub9ac\ubdf0\ub4e4\uc774 \ub2ec\ub838\uc8e0. \ucf54\ub4dc \ucee8\ubca4\uc158\uc774\ub098 \ub9ac\ud329\ud1a0\ub9c1\ud560 \uc218 \uc788\ub294 \ubd80\ubd84\ub4e4\uc744 \ub9ac\ubdf0\ud574 \uc8fc\uc154\uc11c \uadf8\uac83\uc5d0 \ub300\ud574 \ud559\uc2b5\uc774 \ub418\uc5c8\ub358 \uac83 \uac19\uc544\uc694. \uadf8\ub807\uac8c \uccab PR\uc774 \ud719 \uc9c0\ub098\uac14\uc5b4\uc694. \uadf8 \uc774\ud6c4\uc5d0\ub294 \uc774\uc288 \ud574\uacb0 \ubd80\ubd84\ub4e4\uc744 \uc8fc\ub85c \ud574\uacb0\ud558\uba70 PR\uc744 \ub9ce\uc774 \uc62c\ub9ac\ub2e4 \ubcf4\ub2c8 \ubc14\ub85c \uc775\uc219\ud574\uc9c0\ub354\ub77c\uace0\uc694. \uadf8\ub798\uc11c \uc9c0\uae08\uc740 \ubcc4\ubb38\uc81c \uc5c6\uc774, \uac71\uc815 \uc5c6\uc774 PR\uc744 \uc62c\ub9ac\uace0 \uc788\ub2f5\ub2c8\ub2e4! \ud558\ud558..!\\n<div style={{ display: \\"flex\\", flexDirection: \\"column\\", width: \\"45%\\", margin: \\"25px auto\\" }}>\\n  <img src=\\"/img/@frontEnd/april-retrospect_GwakSeungju/03.jpg\\" alt=\\"\uc774\ubbf8\uc9c0\\" />\\n</div>\\n\\n\ud604\uc7ac \ud558\uace0 \uc788\ub294 \ud65c\ub3d9\uc73c\ub85c\ub294 **\u2018\uc778\ud3ec\uba54\uc774\ud2b8\u2019** \ub77c\ub294 FE \ud2b8\ub799 \ub0b4 \uc18c\uadf8\ub8f9 \ud65c\ub3d9\uacfc KOIN\uc5d0\uc11c 3\uac1c\uc758 \ub3c4\uba54\uc778\uc73c\ub85c \ub098\ub208 \ud300 \uc911 **\u2018USER\ud300\u2019** \ud65c\ub3d9\uc774 \uc788\uc5b4\uc694. \u2018\uc778\ud3ec\uba54\uc774\ud2b8\u2019\ub77c\ub294 \ud65c\ub3d9\uc740 2\uc8fc\ub9c8\ub2e4 \ud558\ub098\uc758 \ub300\uc8fc\uc81c\ub97c \uc7a1\uc544 \ud300\uc6d0\ub4e4\uc774 \uadf8 \uc8fc\uc81c\uc5d0 \ub300\ud55c \uc18c\uc8fc\uc81c\ub97c \uc815\ud558\uace0 \uadf8\uac83\uc5d0 \uad00\ub828\ud574 \ube14\ub85c\uae45\uc744 \ud558\uace0 \uc790\uc2e0\uc758 \uc8fc\uc7a5\uacfc \ud568\uaed8 \ud14c\ud06c\ub97c \uacf5\uc720\ud558\ub294 \uc18c\uadf8\ub8f9\uc774\uc5d0\uc694. \uc774 \uc18c\uadf8\ub8f9 \ud65c\ub3d9\uc744 \ud558\uba70 \uac00\uc7a5 \ud06c\uac8c \ub290\ub080 \uac83\uc740 \uc0c8\ub86d\uace0 \ud765\ubbf8\ub85c\uc6b4 \uc9c0\uc2dd\uc774 \uc313\uc778\ub2e4\ub294 \uc810\uc774\uc5d0\uc694! \uc81c\uac00 \uc791\uc131\ud558\ub294 \uc8fc\uc81c\uc5d0 \uad00\ud55c \uac83\uc740 \ubb3c\ub860\uc774\uace0 \ud300\uc6d0\ub4e4\uc774 \uc791\uc131\ud558\ub294 \uae00\uc744 \ubcf4\uba70 \u201c\uc774\ub7f0\uc800\ub7f0 \uac83\ub3c4 \uc788\uad6c\ub098. \uc7ac\ubc0c\ub124~\u201d\ub97c \ub9e4 \ucc28\uc2dc \ub290\uaf08\uc5b4\uc694!<br />\\n\uadf8\ub9ac\uace0 \u2018USER\ud300\u2019\uc740 \ud68c\uc6d0 \uad00\ub9ac\uc640 \uc2dc\uac04\ud45c \ubd80\ubd84\uc744 \ub2f4\ub2f9\ud558\ub294 \ud300\uc778\ub370, \uccab \uc2a4\ud504\ub9b0\ud2b8 \ub54c \ubc84\uadf8\uac00 \uc5c4\uccad \ub9ce\uc544\uc11c \uc2a4\ud504\ub9b0\ud2b8 \ubaa9\ud45c\ub97c \uc774\uc288 100% \ud574\uacb0\ub85c \uc7a1\uc558\uc5c8\uc5b4\uc694. \uc790\uc798\ud55c \ubc84\uadf8\ub4e4\uc744 \uc218\uc815\ud558\uba74\uc11c \uc774\uc804\uc5d4 \uc798 \uc548 \ubcf4\uc774\ub358 \ucf54\ub4dc\uac00 \ub208\uc5d0 \ub4e4\uc5b4\uc624\ub294 \uac83 \uac19\uc558\uc5b4\uc694. \uadf8\ub798\uc11c \uc800\uc5d0\uac90 1\ucc28 \uc2a4\ud504\ub9b0\ud2b8\uac00 \ub9e4\uc6b0 \uc758\ubbf8 \uc788\ub358 \uc2dc\uac04\uc774\uc5c8\uc5b4\uc694! \\n\\n\uc9c0\uae08\uae4c\uc9c0 \ub808\uade4\ub7ec\uac00 \ub418\uace0 \ub09c \ub4a4 \uc81c\uac00 \ud55c \ud65c\ub3d9\uacfc \ub290\ub080 \uc810\uc744 \ub9d0\uc500\ub4dc\ub824\ubd24\uc5b4\uc694. \uc55e\uc73c\ub85c \uc800\ub294 \uc544\uc9c1\ub3c4 \ubc30\uc6b0\ub294 \ub2e8\uacc4\ub77c \uc0dd\uac01\ud558\uace0 \uc788\uace0, \ubaa8\ub974\ub294 \uac83\ub3c4 \uc5c4\uccad \ub9ce\uae30 \ub54c\ubb38\uc5d0 \uacc4\uc18d\ud574\uc11c \uacf5\ubd80\ud558\uace0 \uc788\uc5b4\uc694. \ub2e4\uc74c\uc5d0 \ub9cc\ub4e4 \uc0c8\ub85c\uc6b4 \uae30\ub2a5\uc778 \ucee4\uc2a4\ud140 \uc2dc\uac04\ud45c \uc791\uc5c5\uc774 \uc788\ub294\ub370 \uc815\ub9d0 \uc7ac\ubc0c\uc744 \uac83 \uac19\uc544\uc694! \ud558\ub098\uc529 \ubc30\uc6cc\uac00\uba74\uc11c \ud654\uba74\uc5d0 \ub744\uc6b0\ub294 \uac83\ub9cc\ud07c \uc7ac\ubc0c\ub294 \uac8c \uc5c6\ub294 \uac83 \uac19\uc544\uc694. \ub2e4\ub9cc, \uadf8 \uacfc\uc815\uc774 \uc0b4\uc9dd \uc5b4\ub835\uace0 \uc624\ub798 \uac78\ub9b4 \uc218\ub3c4 \uc788\uc9c0\ub9cc..! \uadf8\ub7f4 \ub550! \ud63c\uc790 \ud574\uacb0\ud558\ub824\uace0 \ud558\uc9c0 \ub9d0\uace0, \ub098\ubcf4\ub2e4 \ub354 \uc798 \uc54c\uace0, \ub6f0\uc5b4\ub09c \ubd84\ub4e4\uaed8 \uc5ec\ucb64\ubcf4\uae30\ub85c \uc800 \uc2a4\uc2a4\ub85c \ub9c8\uc74c\uba39\uc5c8\uc2b5\ub2c8\ub2e4! \ud63c\uc790 \ud574\uacb0\ud588\ub2e4\uba74 \uc815\ub9d0 \ubfcc\ub4ef\ud558\uc9c0\ub9cc, \uc624\ub7ab\ub3d9\uc548 \ud574\uacb0 \ubabb \ud558\uace0 \uc788\uc73c\uba74 \uc2a4\ud2b8\ub808\uc2a4\ub9cc \uc313\uc774\ub354\ub77c\uace0\uc694..(\uc800\ub3c4 \uc5b8\uc820\uac00 \ub204\uad70\uac00\uc5d0\uac8c \uc9c8\ubb38\uc744 \ubc1b\uc544 \ub3c4\uc6c0\uc744 \uc904 \uc218 \uc788\uc744 \ub54c\uac00 \uc654\uc73c\uba74 \uc88b\uaca0\ub124\uc694..) 3\uac1c\uc6d4\uc774 \ub3fc\uc11c\uc57c \uc9c8\ubb38\uc774 \uc815\ub9d0 \uc911\uc694\ud558\ub2e4\ub294 \uac83\uc744 \uae68\ub2ec\uc558\ub124\uc694 \u314e\u314e..!\\n<div style={{ display: \\"flex\\", flexDirection: \\"column\\", width: \\"45%\\", margin: \\"25px auto\\" }}>\\n  <img src=\\"/img/@frontEnd/april-retrospect_GwakSeungju/05.jpg\\" alt=\\"\uc774\ubbf8\uc9c0\\" />\\n</div>"},{"id":"/junghaesung79/introduce-FE","metadata":{"permalink":"/front-end/junghaesung79/introduce-FE","source":"@site/@frontEnd/junghaesung79/introduce-FE.mdx","title":"BCSD FrontEnd \ud2b8\ub799 \uc18c\uac1c!!","description":"\uc6b0\ub9ac \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!","date":"2024-05-24T00:00:00.000Z","tags":[{"label":"FE","permalink":"/front-end/tags/fe"},{"label":"\ud2b8\ub799 \uc18c\uac1c","permalink":"/front-end/tags/\ud2b8\ub799-\uc18c\uac1c"}],"readingTime":6.28,"hasTruncateMarker":true,"authors":[{"name":"Haesung Jung","url":"https://github.com/junghaesung79","email":"gotjd0230@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/96577250?v=4","key":"junghaesung79"}],"frontMatter":{"date":"2024-05-24T00:00:00.000Z","authors":"junghaesung79","title":"BCSD FrontEnd \ud2b8\ub799 \uc18c\uac1c!!","description":"\uc6b0\ub9ac \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!","keywords":["FE","\ud2b8\ub799 \uc18c\uac1c"],"tags":["FE","\ud2b8\ub799 \uc18c\uac1c"]},"unlisted":false,"prevItem":{"title":"\ub808\uade4\ub7ec\ub85c \uc804\ud658\ub418\uace0...","permalink":"/front-end/GwakSeungJu/april-retrospect_GwakSeungju"},"nextItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 7\uc8fc\ucc28 \uacf5\uc720(\uc54c\uace0\ub9ac\uc998)","permalink":"/front-end/GwakSeungJu/infomate-7week"}},"content":"BCSD\uc5d0 \ub4e4\uc5b4\uc624\ub294 \uac83\uc744 \uace0\ubbfc\ud558\uace0 \uc788\uac70\ub098 FE \ud2b8\ub799\uc774 \ubb34\uc5c7\uc744 \ud558\ub294\uc9c0 \uad81\uae08\ud55c \ubd84\ub4e4\uc774 \uc77d\uc73c\uc2dc\uba74 \uc88b\uc744 \uac70\uc608\uc694!\\n\\n{/* truncate */}\\n\\n\uc548\ub155\ud558\uc138\uc694! \uc800\ub294 FE \ud2b8\ub799 \ub808\uade4\ub7ec \uc815\ud574\uc131\uc785\ub2c8\ub2e4! \ube14\ub85c\uadf8\uac00 \uc0dd\uae30\uace0 \ub098\uc11c \uc4f0\uace0 \uc2f6\uc5c8\ub358 \uae00\ub4e4\uc774 \uc870\uae08 \uc788\ub294\ub370 \uadf8\uc911 \ud558\ub098\ub97c \uc368\ubcf4\ub824\uace0 \ud574\uc694 \ubc14\ub85c BCSD\uc758 FE \ud2b8\ub799\uc5d0 \uad00\ud55c \uc18c\uac1c\uc785\ub2c8\ub2e4! \\n\\n### \uc6b0\ub9ac\ub294..\\n\ud575\uc2ec \uba3c\uc800 \ub9d0\ud558\uba74 \uc800\ud76c BCSD FE \ud2b8\ub799\uc740 \ud06c\uac8c \uad6c\ubd84\ud588\uc744 \ub54c \ub2e4\uc74c \ud65c\ub3d9\ub4e4\uc744 \ud574\uc694.\\n\\n1. \ucf54\uc778, \ucf54\uc778 for Business \ub4f1\uc758 \uc11c\ube44\uc2a4 \uac1c\ubc1c\\n2. \uba87 \uac1c\uc758 \uc18c\uadf8\ub8f9\uc5d0\uc11c \uc815\ud55c \uc8fc\uc81c\uc5d0 \ub300\ud574 \ud0d0\uad6c\\n3. \uc815\ud574\uc9c4 \uae30\uac04 \ub3d9\uc548 \ud2b9\uc815 \ucc45\uc774\ub098 \uc8fc\uc81c\uc5d0 \ub300\ud574 \ud559\uc2b5\u2022\uacf5\uc720\\n\\n\uc774\uc678\uc5d0\ub3c4 FE \ud2b8\ub799 \ub0b4\uc5d0\uc11c \ub2e4\uc591\ud55c \uac83\ub4e4\uc744 \uc2dc\ub3c4\ud560 \uc218 \uc788\uc5b4\uc694. \uc800\ud76c\ub294 \uc774\ub7f0 \ud65c\ub3d9\uc744 \ud1b5\ud574 \uc9c0\uc18d\uc801\uc73c\ub85c \ud559\uc2b5\u2022\uc131\uc7a5\ud558\uba70, \uc2e4\ubb34 \uacbd\ud5d8\uc744 \uc313\ub294 \uac83\uc744 \ubaa9\ud45c\ub85c \ud558\uace0 \uc788\uc5b4\uc694.\\n\\n## \ud83d\udcd6 \uad50\uc721\\n\\n\ucc98\uc74c\uc5d0 \ub3d9\uc544\ub9ac\uc5d0 \uac00\uc785\ud558\uba74 \uc6b0\uc120 \ube44\uae30\ub108\ub85c\uc11c \ud55c \ud559\uae30 \ub3d9\uc548 \uad50\uc721\uc744 \ub4e3\uac8c \ub3fc\uc694. \ud2b8\ub799 \ub0b4\uc5d0\uc11c \uc0ac\uc6a9\ud558\ub294 \uc5b8\uc5b4\ub098 \ub3c4\uad6c\ub4e4\uc740 \ud559\uacfc\ubaa9\uc5d0\uc11c \uac00\ub974\uccd0\uc8fc\uc9c0 \uc54a\ub294 \ub0b4\uc6a9\uc774\uae30 \ub54c\ubb38\uc5d0 \uc800\ud76c\uac00 \uc9c1\uc811 \ub9cc\ub4e0 \ucee4\ub9ac\ud058\ub7fc\uc5d0 \ub530\ub77c \uad50\uc721\uc744 \ub4e4\uc73c\uba74\uc11c \ub098\uc640 \ub9de\ub294 \ubd84\uc57c\uc778\uc9c0 \ud655\uc778\ud560 \uc218 \uc788\uc5b4\uc694.\\n\ucee4\ub9ac\ud058\ub7fc\uc740 \uc5ec\uae30\uc11c(https://bcsdlab.com/track/frontend) \ud655\uc778\ud560 \uc218 \uc788\uc5b4\uc694.\\n\\n\uad50\uc721 \ub9c8\uc9c0\ub9c9\uc5d0 \uc788\ub294 \ud68c\uace0 \ud504\ub85c\uc81d\ud2b8\ub97c \ub9c8\uce58\uace0 \uacc4\uc18d BCSD\uc640 \uac19\uc774\ud558\uae30\ub97c \ud76c\ub9dd\ud560 \uacbd\uc6b0 \ub808\uade4\ub7ec \uc804\ud658 \uba74\uc811\uc744 \ubcf4\uac8c \ub3fc\uc694. \uadf8\ub3d9\uc548 \uacf5\ubd80\ud588\ub358 \uac83\ub4e4\uc774\ub098 \uc5bc\ub9c8\ub098 \uac19\uc774 \uc77c\ud558\uace0 \uc2f6\uc740\uc9c0\ub97c \uae30\uc900\uc73c\ub85c \ub808\uade4\ub7ec \uc804\ud658 \uc5ec\ubd80\uac00 \uacb0\uc815\ub3fc\uc694. \uadf8\ub54c \ube44\ub85c\uc18c \uc800\uc640 \uac19\uc740 \ub808\uade4\ub7ec\uac00 \ub418\ub294 \uac83\uc774\uc8e0.\\n\\n\ub808\uade4\ub7ec\uac00 \ub418\uba74 \uc9e7\uc740 \uc628\ubcf4\ub529\uc744 \uacfc\uc815\uc744 \uac70\uce58\uba74\uc11c \ubcf8\uaca9\uc801\uc73c\ub85c \ud65c\ub3d9\uc744 \uc2dc\uc791\ud558\uac8c \ub3fc\uc694. \uadf8\ub54c\ubd80\ud130\ub294 \uaca9\uc8fc\ub85c \uc9c4\ud589\ub418\ub294 \ud2b8\ub799 \ud68c\uc758\uc5d0 \ucc38\uc5ec\ud574\uc11c \ud2b8\ub799 \ub0b4\uc758 \uacf5\uc720 \uc0ac\ud56d\uc744 \ub4e3\uac70\ub098 \uc9c4\ud589\ub3c4\ub97c \uacf5\uc720\ud574\uc694.\\n\\n## \u2728 \uac1c\ubc1c\\n\\n\uac00\uc7a5 \uc911\uc694\ud55c \ud65c\ub3d9\uc778 \uac1c\ubc1c\uc740 \ud604\uc7ac \ud300 \ub2e8\uc704\ub85c \uc9c4\ud589\ud558\uace0 \uc788\uc5b4\uc694. \ud604\uc7ac\ub294 \ucea0\ud37c\uc2a4\ud300, \ube44\uc988\ub2c8\uc2a4\ud300, \uc720\uc800\ud300 \uc774\ub807\uac8c \ucd1d \uc138 \uac1c\uc758 \ud300\uc73c\ub85c \ub098\ub258\uc5b4\uc11c \uadf8 \uc548\uc5d0\uc11c \ub2e4\ub978 \ud2b8\ub799 \uc0ac\ub78c\ub4e4\uacfc \ubaa9\ud45c\ub97c \uacf5\uc720\ud558\uba70 \uac1c\ubc1c\uc744 \uc9c4\ud589\ud574\uc694. \uc77c\uc8fc\uc77c\uc5d0 \ud55c \ubc88 \ud300 \ud68c\uc758\ub97c \ud558\uace0 \uac70\uae30\uc5d0\uc11c \ub098\uc628 \uc758\uc0ac\uacb0\uc815\uc5d0 \ub530\ub77c \uc2a4\ud504\ub9b0\ud2b8\ub97c \uc9c4\ud589/\uad00\ub9ac\ud574\uc694. \uba87 \uc8fc\uc5d0 \uac78\uce5c \uc2a4\ud504\ub9b0\ud2b8\ub098 \uc2a4\ud06c\ub7fc\uc774 \ub05d\ub0ac\uc744 \ub54c\ub294 \uc218\uace0\ud588\ub2e4\ub294 \uc758\ubbf8\ub85c \ud68c\uc2dd \uac00\uc9c0\uae30\ub3c4 \ud574\uc694!\\n\\n\ud55c \ud300\uc5d0\ub294 FE, BE, \ubaa8\ubc14\uc77c, \ub514\uc790\uc778 \ub4f1 \ub2e4\uc591\ud55c \ud2b8\ub799 \uc778\uc6d0\ub4e4\uc774 \uc18d\ud574 \uc788\uc5b4\uc694. \ud300\uc7a5\uacfc PM\uc758 \uc8fc\ub3c4\ud558\uc5d0 \ud300\uc758 \uac1c\ubc1c \ubc29\ud5a5\uc131\uc774 \uacb0\uc815\ub418\uace0 \uac01\uc790 \uc2a4\ud504\ub9b0\ud2b8 \uae30\uac04 \ub3d9\uc548 \ub9e1\uc740 \uc77c\uc744 \ucc98\ub9ac\ud558\ub294 \uacbd\ud5d8\uc744 \uac00\uc838\uc694. \ud611\uc5c5\uc774\ub098 \ud504\ub85c\uc81d\ud2b8 \uad00\ub9ac\uc5d0 \uc788\uc5b4 \uc5b4\ub290 \uc815\ub3c4 \uc2e4\ubb34\uc640 \ube44\uc2b7\ud55c \ubaa8\uc2b5\uc73c\ub85c \uc9c4\ud589\ub418\uba70 \uba58\ud1a0\ubd84\ub4e4\uc758 \ud53c\ub4dc\ubc31\uc744 \ubc1b\uae30\ub3c4 \ud574\uc694. \\n\\n:::note \uc2a4\ud504\ub9b0\ud2b8? \uc2a4\ud06c\ub7fc?\\n-\\t\uc2a4\ud504\ub9b0\ud2b8: \uc77c\uc815\ud55c \uae30\uac04(\uc77c\ubc18\uc801\uc73c\ub85c 2-4\uc8fc) \ub3d9\uc548 \ud2b9\uc815 \ubaa9\ud45c\ub97c \ub2ec\uc131\ud558\uae30 \uc704\ud574 \uc218\ud589\ud558\ub294 \uac1c\ubc1c \uc8fc\uae30\uc785\ub2c8\ub2e4. \uc2a4\ud504\ub9b0\ud2b8 \ub3d9\uc548 \ud300\uc740 \ubaa9\ud45c \ub2ec\uc131\uc744 \uc704\ud574 \uc9d1\uc911\uc801\uc73c\ub85c \uc791\uc5c5\ud558\uace0, \uc2a4\ud504\ub9b0\ud2b8 \uc885\ub8cc \uc2dc \uacb0\uacfc\ubb3c\uc744 \ud3c9\uac00\ud569\ub2c8\ub2e4.\\n-\\t\uc2a4\ud06c\ub7fc: \uc560\uc790\uc77c \ubc29\ubc95\ub860\uc758 \uc77c\uc885\uc73c\ub85c, \ud300\uc774 \ubcf5\uc7a1\ud55c \ud504\ub85c\uc81d\ud2b8\ub97c \uad00\ub9ac\ud558\uace0 \ud6a8\uc728\uc801\uc73c\ub85c \ud611\ub825\ud560 \uc218 \uc788\ub3c4\ub85d \ub3d5\ub294 \ud504\ub808\uc784\uc6cc\ud06c\uc785\ub2c8\ub2e4. \uc2a4\ud06c\ub7fc\uc5d0\uc11c\ub294 \uc815\uae30\uc801\uc778 \ud68c\uc758(\ub370\uc77c\ub9ac \uc2a4\ud06c\ub7fc, \uc2a4\ud504\ub9b0\ud2b8 \ub9ac\ubdf0, \uc2a4\ud504\ub9b0\ud2b8 \ud68c\uace0)\ub97c \ud1b5\ud574 \uc9c4\ud589 \uc0c1\ud669\uc744 \uc810\uac80\ud558\uace0, \ud300\uc758 \uc791\uc5c5\uc744 \uc870\uc728\ud569\ub2c8\ub2e4.\\n:::\\n\\n## \ud83d\udcda \uc18c\uadf8\ub8f9, \uc2a4\ud130\ub514\\n\\n\ucf54\uc778 \uc11c\ube44\uc2a4\uc758 \uac1c\ubc1c \ub9d0\uace0\ub3c4 \uc5ec\ub7ec \ud0d0\uad6c\ud65c\ub3d9\uc744 \ud560 \uc218 \uc788\uc5b4\uc694. FE \ud2b8\ub799\uc5d0\ub294 \uc5ec\ub7ec \uc18c\uadf8\ub8f9\uacfc \uc2a4\ud130\ub514\uac00 \uc788\uc5b4\uc694. \ub9e4\uc8fc \uac1c\ubc1c\uc5d0 \uad00\ub828\ub41c \uac00\ubcbc\uc6b4 \uc8fc\uc81c\ub97c \uc815\ud574\uc11c \uacf5\ubd80\ud558\uace0 \uae00\uc744 \uc368\ubcf4\ub294 \uc778\ud3ec\uba54\uc774\ud2b8, BCSD\uc758 \uba54\uc2e0\uc800\uc778 \uc2ac\ub799\uc5d0\uc11c \uc0ac\uc6a9\ud560 \uc218 \uc788\ub294 \ud3b8\uc758 \uae30\ub2a5\uc744 \ub9cc\ub4dc\ub294 \uc090\ubd07\uadf8\ub8f9 \ub4f1 4\uac1c\uc758 \uc18c\uadf8\ub8f9, \uadf8\ub9ac\uace0 \uba58\ud1a0\ubd84\uc758 \ub3c4\uc6c0\uc744 \ubc1b\uc544 \ucde8\uc5c5\uc744 \uc900\ube44\ud558\ub294 \ucde8\uc5c5 \uc2a4\ud130\ub514\uac00 \uc788\uc5b4\uc694.\\n\\n\ub9cc\uc57d \uc774\ubbf8 \uc788\ub294 \uc18c\uadf8\ub8f9\uc774\ub098 \uc2a4\ud130\ub514 \ub9d0\uace0\ub3c4 \uacf5\ubd80\ud558\uace0 \uc2f6\uc740 \uc8fc\uc81c\uac00 \uc788\uc73c\uba74, \ub808\uade4\ub7ec\uc5d0\uc11c \ub9c8\uc74c\uc774 \uac19\uc740 \uc0ac\ub78c\uc744 \ubaa8\uc544\uc11c \uc0c8\ub85c\uc6b4 \uc18c\ubaa8\uc784\uc774\ub098 \uc2a4\ud130\ub514\ub97c \ub9cc\ub4e4 \uc218\ub3c4 \uc788\uc5b4\uc694!\\n\\n### \ub9c8\ubb34\ub9ac\\n\\n\uc5b4\ub5a4\uac00\uc694? \uc800\ud76c\uac00 \ubb34\uc5c7\uc744 \ud558\ub294 \uc9c0\uc5d0 \uad00\ud55c \uad81\uae08\uc99d\uc740 \ud480\ub838\ub098\uc694?\\n\\n\ub2e4\ub978 \ud2b8\ub799 \uc18c\uac1c \ubcf4\ub7ec\uac00\uae30 >>"},{"id":"/GwakSeungJu/infomate-7week","metadata":{"permalink":"/front-end/GwakSeungJu/infomate-7week","source":"@site/@frontEnd/GwakSeungJu/infomate-7week.mdx","title":"\uc778\ud3ec\uba54\uc774\ud2b8 7\uc8fc\ucc28 \uacf5\uc720(\uc54c\uace0\ub9ac\uc998)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 7\uc8fc\ucc28 \uacf5\uc720(\uc54c\uace0\ub9ac\uc998) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","date":"2024-05-13T00:00:00.000Z","tags":[{"label":"\uc778\ud3ec\uba54\uc774\ud2b8","permalink":"/front-end/tags/\uc778\ud3ec\uba54\uc774\ud2b8"},{"label":"\uc54c\uace0\ub9ac\uc998","permalink":"/front-end/tags/\uc54c\uace0\ub9ac\uc998"}],"readingTime":21.385,"hasTruncateMarker":true,"authors":[{"name":"GwakSeungJu","url":"https://github.com/Gwak-Seungju","email":"gwak1016@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/74342515?v=4","key":"GwakSeungJu"}],"frontMatter":{"date":"2024-05-13T00:00:00.000Z","authors":"GwakSeungJu","title":"\uc778\ud3ec\uba54\uc774\ud2b8 7\uc8fc\ucc28 \uacf5\uc720(\uc54c\uace0\ub9ac\uc998)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 7\uc8fc\ucc28 \uacf5\uc720(\uc54c\uace0\ub9ac\uc998) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","keywords":["\uc778\ud3ec\uba54\uc774\ud2b8","\uc54c\uace0\ub9ac\uc998"],"tags":["\uc778\ud3ec\uba54\uc774\ud2b8","\uc54c\uace0\ub9ac\uc998"]},"unlisted":false,"prevItem":{"title":"BCSD FrontEnd \ud2b8\ub799 \uc18c\uac1c!!","permalink":"/front-end/junghaesung79/introduce-FE"},"nextItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 6\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654)","permalink":"/front-end/GwakSeungJu/infomate-6week"}},"content":"\uc778\ud3ec\uba54\uc774\ud2b8 7\uc8fc\ucc28 \uacf5\uc720(\uc54c\uace0\ub9ac\uc998) \ubaa8\uc74c\uc785\ub2c8\ub2e4.\\n\\nCSS \ud504\ub85c\ud37c\ud2f0\uc5d0 \uc228\uaca8\uc9c4 \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998 - \uacfd\uc2b9\uc8fc  \\nHeap \uba54\ubaa8\ub9ac\uc640 GC \uc54c\uace0\ub9ac\uc998 - \uc724\ud574\uc9c4  \\nReact reconciliation \uc54c\uace0\ub9ac\uc998\uc744 \ucd08\uac04\ub2e8\ud558\uac8c \uc54c\uc544\ubcf4\uc790! - \uae40\ubbfc\uc7ac  \\n\uc7ac\ubbf8\uc640 \uc774\uc775\uc744 \uc704\ud55c \uc790\ubc14\uc2a4\ud06c\ub9bd\ud2b8 \uc804\ubb38\ud654 - \uae40\ud558\ub098  \\n\\n{/* truncate */}    \\n\\n## CSS \ud504\ub85c\ud37c\ud2f0\uc5d0 \uc228\uaca8\uc9c4 \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998 - \uacfd\uc2b9\uc8fc\\n\\n### Intro\\n\\n\uc790\uc8fc \uc0ac\uc6a9\ud588\uc5c8\ub358 CSS \ucf54\ub4dc\uac00 \uc608\uc0c1\uce58 \ubabb\ud55c \ub2e4\ub978 \uacb0\uacfc\ub97c \ub0b3\uc740 \uc801\uc774 \uc788\uc5c8\uc744 \uac83\uc785\ub2c8\ub2e4. \uadf8 \uc774\uc720\ub294 \ud504\ub85c\ud37c\ud2f0\uac00 \ubcf5\uc7a1\ud55c \uc2dc\uc2a4\ud15c\uc5d0\uc11c \uc791\ub3d9\ud558\uace0, \ud504\ub85c\ud37c\ud2f0\uc758 \uc791\ub3d9 \ubc29\uc2dd\uc744 \ubcc0\uacbd\uc2dc\ud0a4\ub294 \ubbf8\ubb18\ud55c \ucee8\ud14d\uc2a4\ud2b8\uac00 \uc788\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4. \uc774\ub294 `\ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998`\uacfc \uc5f0\uad00\ub418\uc5b4 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998\\n\\n`\ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998`\uc774 \ubb58\uae4c\uc694? \ube0c\ub77c\uc6b0\uc800\uac00 HTML\uc744 \ub80c\ub354\ub9c1\ud560 \ub54c, \ubaa8\ub4e0 \uc694\uc18c\ub294 \uae30\ubcf8 \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998\uc744 \uc0ac\uc6a9\ud558\uc5ec \uacc4\uc0b0\ub41c \ub808\uc774\uc544\uc6c3\uc744 \uac16\uc2b5\ub2c8\ub2e4. \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998\uc5d0\ub294 \uc544\ub798\uc640 \uac19\uc740 \uac83\ub4e4\uc774 \ud3ec\ud568\ub429\ub2c8\ub2e4.\\n\\n- Flexbox\\n- Positioned\\n- Grid\\n- Table\\n- Flow\\n\\n`z-index`\ub97c \uc608\ub85c \uc124\uba85\ub4dc\ub9ac\uaca0\uc2b5\ub2c8\ub2e4. `z-index`\ub294 \ubcf4\ud1b5 `position`\uacfc \ud568\uaed8 \uc911\ucca9 \uc21c\uc11c\ub97c \uc81c\uc5b4\ud558\ub294 \ub370 \uc0ac\uc6a9\ub418\uba70, \uacb9\uccd0\uc84c\uc744 \ub54c \uc5b4\ub290 \uc694\uc18c\uac00 \uc704\uc5d0 \ud45c\uc2dc\ub420\uc9c0 \uacb0\uc815\ud558\ub294 \uc18d\uc131\uc785\ub2c8\ub2e4. \uc774\ub97c `position`\uc5c6\uc774 \uc0ac\uc6a9\ud558\uba74 \ub2f9\uc5f0\ud788 \uc81c\ub300\ub85c\ub41c \ub3d9\uc791\uc744 \ud558\uc9c0 \uc54a\uaca0\uc8e0? \uc774\ub294 **\ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998** \uc911 `Flow \ub808\uc774\uc544\uc6c3`\uc744 \uc0ac\uc6a9\ud588\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4. `Flow \ub808\uc774\uc544\uc6c3`\uc740 \ub2e4\ub978 \ub808\uc774\uc544\uc6c3\uc73c\ub85c \ud2b9\uc815\uc9d3\uc9c0 \uc54a\ub294 \uc774\uc0c1 default\ub85c \uc0ac\uc6a9\ub429\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@frontEnd/infomate-7week/image01.jpg\\"  alt=\\"\uc774\ubbf8\uc9c0\\" style={{ width : \\"80%\\" }} />\\n\\n\ud558\uc9c0\ub9cc, \uc704 \uc608\uc2dc\ub97c \ubcf4\uba74 `position`\uc744 \uc0ac\uc6a9\ud558\uc9c0 \uc54a\uace0, `flex`\ub97c \uc0ac\uc6a9\ud558\ub294 \uac83\uc73c\ub85c\ub3c4 `z-index`\uac00 \ub3d9\uc791\ud558\ub294 \uac83\uc744 \ud655\uc778\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc774\uac83\uc740 \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998 \uc911 `Flexbox \uc54c\uace0\ub9ac\uc998`\uc774 `z-index`\ub97c \uad6c\ud604\ud558\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4. \uc774\ucc98\ub7fc \uac01 \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998\uc5d0 \uc5b4\ub5a0\ud55c \ud504\ub85c\ud37c\ud2f0\ub97c \uad6c\ud604\ud560 \uc218 \uc788\uac8c \uc815\uc758\ud560 \uc218 \uc788\uace0, \ub610\ud55c \uc77c\ubc18\uc801\uc778 \uae30\ubcf8 \ub3d9\uc791\uc744 \uc7ac\uc815\uc758\ud560 \uc218\ub3c4 \uc788\uc2b5\ub2c8\ub2e4. `width`\ub85c \uadf8 \uc608\ub97c \uc124\uba85\ud558\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@frontEnd/infomate-7week/image02.jpg\\"  alt=\\"\uc774\ubbf8\uc9c0\\" style={{ width : \\"80%\\" }} />\\n\\n\uccab `div \ud0dc\uadf8`\ub294 **Flow \ub808\uc774\uc544\uc6c3**\uc744 \uc0ac\uc6a9\ud558\uc5ec \ub80c\ub354\ub9c1\ub418\uba70, \uc2e4\uc81c\ub85c `2000px`\uc758 \ub108\ube44\ub97c \uac16\uc9c0\ub9cc, \uac19\uc740 \uc18d\uc131\uc744 \uac16\ub294 `flex-wrapper \ub0b4\ubd80\uc758 div \ud0dc\uadf8`\ub294 **Flexbox \ub808\uc774\uc544\uc6c3**\uc744 \uc0ac\uc6a9\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4. \uc774\ucc98\ub7fc \uac19\uc740 \uc18d\uc131\uc744 \uac00\uc9c8\uc9c0\ub77c\ub3c4 \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998\uc5d0 \uc758\ud574 \ub2e4\ub978 \uacb0\uacfc\ub97c \ub0b3\uc744 \uc218 \uc788\uac8c \ub429\ub2c8\ub2e4.\\n\\n### \ucda9\ub3cc\\n\\n\ub9cc\uc57d \ud558\ub098\uc758 \uc694\uc18c\uc5d0 \uc5ec\ub7ec \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998\uc774 \uc801\uc6a9\ub418\uba74 \uc5b4\ub5bb\uac8c \ub420\uae4c\uc694?\\n\\n```html\\n<style>\\n  .row {\\n    display: flex;\\n  }\\n  .primary.item {\\n    position: absolute;\\n  }\\n</style>\\n<ul class=\\"row\\">\\n  <li class=\\"item\\"></li>\\n  <li class=\\"primary item\\"></li>\\n  <li class=\\"item\\"></li>\\n</ul>\\n```\\n\\n\uc138 \ub9ac\uc2a4\ud2b8 \ud56d\ubaa9\uc740 \ubaa8\ub450 Flex \ucee8\ud14c\uc774\ub108\uc5d0 \ud3ec\ud568\ub41c \uc790\uc2dd\uc774\ubbc0\ub85c, **Flexbox \ub808\uc774\uc544\uc6c3**\uc5d0 \ub530\ub77c \ubc30\uce58\ub418\uc5b4\uc57c \ud569\ub2c8\ub2e4. \uadf8\ub7ec\ub098 \ub450 \ubc88\uc9f8 \uc790\uc2dd \uc694\uc18c\ub294 `position: absolute`\ub85c \ud2b9\uc815\uc2dc\ucf30\uae30 \ub54c\ubb38\uc5d0 `Positioned \ub808\uc774\uc544\uc6c3` \ub3d9\uc791\uc744 \ub530\ub985\ub2c8\ub2e4.\\n\\n\uc774\ub807\uac8c \ub450 \ub808\uc774\uc544\uc6c3\uc774 \ucda9\ub3cc \uc2dc \uc694\uc18c\ub294 **\uc81c\uc77c \uc8fc\ub41c \ub808\uc774\uc544\uc6c3 \ubaa8\ub4dc\ub97c \uc0ac\uc6a9**\ud558\uc5ec \ub80c\ub354\ub9c1\ub429\ub2c8\ub2e4. \uc815\ud655\ud55c \uacc4\uce35 \uad6c\uc870\ub294 \ubaa8\ub974\uc9c0\ub9cc, `Positioned \ub808\uc774\uc544\uc6c3`\uc774 **\ub192\uc740 \uc6b0\uc120\uc21c\uc704**\ub97c \uac16\ub294 \uacbd\ud5a5\uc774 \uc788\uc2b5\ub2c8\ub2e4. \ub530\ub77c\uc11c \ub450 \ubc88\uc9f8 \uc790\uc2dd \uc694\uc18c\ub294 Flexbox\uac00 \uc544\ub2cc Positioned \ub808\uc774\uc544\uc6c3\uc744 \uc0ac\uc6a9\ud569\ub2c8\ub2e4.\\n\\n\uc77c\ubc18\uc801\uc73c\ub85c \uc758\ub3c4\uc801\uc778 \ucda9\ub3cc\uc744 \ubc1c\uc0dd\uc2dc\ud0a4\ub294 \uacbd\uc6b0\uac00 \ub300\ubd80\ubd84\uc785\ub2c8\ub2e4. \uadf8\ub7ec\ub098 \uc694\uc18c\uac00 \uc608\uc0c1\ub300\ub85c \uc791\ub3d9\ud558\uc9c0 \uc54a\ub294 \uac83\uc744 \ud655\uc778\ud55c\ub2e4\uba74 \uc0ac\uc6a9 \uc911\uc778 \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998\uc744 \ud655\uc778\ud574\ubcfc \ud544\uc694\uac00 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### \uc778\ub77c\uc778 \ub9c8\ubc95 \uacf5\uac04(inline magic space)\\n\\n<img src=\\"/img/@frontEnd/infomate-7week/image03.jpg\\"  alt=\\"\uc774\ubbf8\uc9c0\\" style={{ width : \\"80%\\" }} />\\n\\n\uc704 \ubc15\uc2a4 \uc548\uc5d0 \uace0\uc591\uc774 \uc774\ubbf8\uc9c0\uac00 \uc788\uc2b5\ub2c8\ub2e4. \ub2e8\uc21c \ucf54\ub4dc\uc774\uba70 padding\uc774\ub098 margin\uc744 \uc8fc\uc9c0 \uc54a\uc558\ub294\ub370 \uc774\ubbf8\uc9c0 \uc544\ub798\uc5d0 \uc57d\uac04\uc758 \uc5ec\ubc31\uc774 \uc788\ub294 \uac83\uc744 \ud655\uc778\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc5b4\ub5a0\ud55c \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998\uc744 \uc9c0\uc815\ud558\uc9c0 \uc54a\uc558\uae30 \ub54c\ubb38\uc5d0 Flow \ub808\uc774\uc544\uc6c3\uc774\ub77c\ub294 \uac83\uc744 \uc720\ucd94\ud560 \uc218 \uc788\uace0, \uadf8 Flow \ub808\uc774\uc544\uc6c3 \ub54c\ubb38\uc5d0 \uc544\ub798 \uc5ec\ubc31\uc774 \uc0dd\uae34\ub2e4\ub77c\uace0 \uc0dd\uac01\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. Flow \ub808\uc774\uc544\uc6c3\uc740 `\uc778\ub77c\uc778(inline)` \ub610\ub294 `\ube14\ub85d(block)` \uad6c\uc870\ub97c \uae30\ubc18\uc73c\ub85c \ud569\ub2c8\ub2e4.\\n\\n\uadf8\ub9ac\uace0 \uc778\ub77c\uc778 \uc694\uc18c\ub294 \ub808\uc774\uc544\uc6c3\uc758 \uc77c\ubd80\uac00 \uc544\ub2c8\ub77c \ub2e8\ub77d \uc911\uac04\uc5d0 \uc0ac\uc6a9\ub418\ub294 \uacbd\uc6b0\uac00 \ub9ce\uc2b5\ub2c8\ub2e4. \uadf8\ub807\uae30 \ub54c\ubb38\uc5d0 \uc778\ub77c\uc778 \uc694\uc18c\uac00 \uc8fc\ubcc0 \ud14d\uc2a4\ud2b8\uc758 \uac00\ub3c5\uc131\uc5d0 \ubd80\uc815\uc801\uc778 \uc601\ud5a5\uc744 \uc8fc\uc9c0 \uc54a\ub3c4\ub85d \uc57d\uac04\uc758 **\uc218\uc9c1 \uacf5\uac04(\uc904 \uac04\uaca9)\uc774 \ucd94\uac00**\ub429\ub2c8\ub2e4.\\n\\n\uc774\ub7ec\ud55c \uc774\uc720\ub85c \uc704 \uace0\uc591\uc774 \uc774\ubbf8\uc9c0 \ubc11\uc5d0 \uc5ec\ubc31\uc774 \uc0dd\uae34 \uac83\ub3c4 \uc774\ud574\uac00 \ub420 \uac83\uc785\ub2c8\ub2e4. \uc774\ubbf8\uc9c0\ub294 \uae30\ubcf8\uc801\uc73c\ub85c \uc778\ub77c\uc778 \uc694\uc18c\uc774\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4!\\n\\n\uc774\ub97c \ud574\uacb0\ud558\uae30 \uc704\ud55c \uac00\uc7a5 \uac04\ub2e8\ud55c \ubc29\ubc95\uc73c\ub85c\ub294 \uc778\ub77c\uc778 \ubd80\ubd84\uc744 \ube14\ub85d\uc73c\ub85c \ucc98\ub9ac\ud558\ub294 \uac83\uc785\ub2c8\ub2e4. \\n\\n\ub610\ud55c, \uc774 \ub3d9\uc791\uc740 Flow \ub808\uc774\uc544\uc6c3\uc5d0\uc11c\ub9cc \ud574\ub2f9\ud558\ubbc0\ub85c, \ub2e4\ub978 \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998\uc73c\ub85c \uc804\ud658\ud574 \ubb38\uc81c\ub97c \ud574\uacb0\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4 ex) display: flex;\\n\\n\ub9c8\uc9c0\ub9c9\uc73c\ub85c, `line-height`\ub97c \ud1b5\ud574 \ucd94\uac00 \uacf5\uac04\uc744 0\uc73c\ub85c \ucd95\uc18c\uc2dc\ucf1c \ubb38\uc81c\ub97c \ud574\uacb0\ud560 \uc218\ub3c4 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### \uacb0\ub860\\n\\n`CSS`\ub294 \ub9ce\uc740 `\ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998`\uc774 \uc788\uc73c\uba70 \ubaa8\ub450 \uace0\uc720\ud55c \uae30\ubc95\uacfc \uc228\uaca8\uc9c4 \uba54\ucee4\ub2c8\uc998\uc774 \uc788\uc2b5\ub2c8\ub2e4. CSS \ud504\ub85c\ud37c\ud2f0\uc5d0\ub9cc \uc9d1\uc911\ud55c\ub2e4\uba74, \uc6d0\ud558\ub294 \uacb0\uacfc\ub97c \uc5bb\uc9c0 \ubabb\ud588\uc744 \ub54c \uadf8 \uc6d0\uc778\uc744 \uc81c\ub300\ub85c \ud30c\uc545\ud558\uc9c0 \ubabb\ud560 \uac83\uc785\ub2c8\ub2e4. \ub610\ud55c, \uc6d0\ud558\ub294 \uacb0\uacfc\ub97c \ub9cc\ub4e4\uae30 \uc704\ud574 \ubd80\uac00\uc801\uc778 \uc18d\uc131\uc744 \ucd94\uac00\ud558\ub294 \ubc29\ubc95\uc73c\ub85c \ud574\uacb0\ud560 \uac83\uc785\ub2c8\ub2e4. \ud558\uc9c0\ub9cc, \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998\uc744 \uc774\ud574\ud55c\ub2e4\uba74, \uc801\uc808\ud55c \ub808\uc774\uc544\uc6c3 \uc54c\uace0\ub9ac\uc998\uc744 \uc120\ud0dd\ud574 \uadfc\ubcf8\uc801\uc778 \ubb38\uc81c\ub97c \ud574\uacb0\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### \ucc38\uace0\uc790\ub8cc\\n\\n[https://junghan92.medium.com/\ubc88\uc5ed-\ub808\uc774\uc544\uc6c3-\uc54c\uace0\ub9ac\uc998-\uc774\ud574\ud558\uae30-baed8b1eca5f](https://junghan92.medium.com/%EB%B2%88%EC%97%AD-%EB%A0%88%EC%9D%B4%EC%95%84%EC%9B%83-%EC%95%8C%EA%B3%A0%EB%A6%AC%EC%A6%98-%EC%9D%B4%ED%95%B4%ED%95%98%EA%B8%B0-baed8b1eca5f)\\n\\n<br />\\n## Heap \uba54\ubaa8\ub9ac\uc640 GC \uc54c\uace0\ub9ac\uc998 - \uc724\ud574\uc9c4\\n\\n### \ub4e4\uc5b4\uac00\uba70)\\n\\nHeap. \uc790\ub8cc\uad6c\uc870, \uc54c\uace0\ub9ac\uc998 \uc801\uc73c\ub85c\ub294 \uaf64\ub098 \uc775\uc219\ud558\uc2e4 \uac83\uc785\ub2c8\ub2e4. \uadf8\ub7ec\ub098 \uc774\ubc88 \uc8fc\uc81c\ub85c\ub294 \ud799 \uba54\ubaa8\ub9ac\ub77c\ub294 \uc601\uc5ed\uacfc \uadf8\ub97c \uad00\ub9ac\ud558\ub294 \uac00\ube44\uc9c0 \uceec\ub9ad\ud130\uc5d0 \ub300\ud574\uc11c \uc774\uc57c\uae30\ud574 \ubcf4\ub824 \ud569\ub2c8\ub2e4.\\n\\n### Heap \uba54\ubaa8\ub9ac\ub780\\n\\n\ud799 \uba54\ubaa8\ub9ac\ub780 \uc790\ubc14\uc2a4\ud06c\ub9bd\ud2b8\uc5d0\uc11c \ucc38\uc870 \ud0c0\uc785(\uac1d\uccb4 \ub4f1) \ub370\uc774\ud130\ub97c \uc800\uc7a5\ud558\uae30 \uc704\ud55c, \uba54\ubaa8\ub9ac \ud560\ub2f9\uc744 \ud558\ub294 \uc601\uc5ed\uc73c\ub85c js\uc5d0\uc11c \ub3d9\uc801\uc73c\ub85c \ud560\ub2f9\ub418\ub294 \ub370\uc774\ud130\ub97c \uc800\uc7a5\ud558\ub294 \uacf5\uac04\uc785\ub2c8\ub2e4.\\n\\n\ud799 \uba54\ubaa8\ub9ac\uc758 \uacbd\uc6b0 \ubcc0\uc218\uac00 \uc0dd\uc131\ub418\uace0 \ud574\uc81c\ub420 \ub54c\uae4c\uc9c0 \ub370\uc774\ud130\ub97c \uc720\uc9c0\ud558\uba70, \ud560\ub2f9 \ubc0f \ud574\uc81c\ub294 \ud504\ub85c\uadf8\ub7a8 \uc2e4\ud589 \uc911 \uc790\ub3d9\uc73c\ub85c \uc774\ub8e8\uc5b4\uc9d1\ub2c8\ub2e4. \ud799\uc740 \uc2a4\ud0dd\uacfc \ub2ec\ub9ac \uad6c\uc870\ud654\ub418\uc9c0 \uc54a\uc740 \uc790\uc720 \ud615\uc2dd\uc758 \uba54\ubaa8\ub9ac \uacf5\uac04\uc73c\ub85c \ud544\uc694\uc5d0 \ub530\ub77c \ub3d9\uc801 \ud655\uc7a5 \ubc0f \ucd95\uc18c \uac00\ub2a5\ud569\ub2c8\ub2e4.\\n\\n\ud799\uc758 \ub3d9\uc801 \uba54\ubaa8\ub9ac \ud560\ub2f9\\n\\n- \uac1d\uccb4 \ubc0f \ud568\uc218\\n- \ub7f0\ud0c0\uc784\uc5d0 \ud06c\uae30\ub97c \uc54c \uc218 \uc788\uc74c\\n- \uac1d\uccb4\ub2f9 \uc81c\ud55c \uc5c6\uc74c\\n\\n### JS\uc5d0\uc11c \ud799 \uba54\ubaa8\ub9ac\uc758 \uc911\uc694\uc131\\n\\njs \uc5d4\uc9c4\uc740 \uac00\ube44\uc9c0 \uceec\ub809\uc158\uc744 \ud1b5\ud574 \ud799 \uba54\ubaa8\ub9ac\ub97c \uc790\ub3d9 \uad00\ub9ac\ud569\ub2c8\ub2e4. \\n\\n\ud799 \uba54\ubaa8\ub9ac\ub294 \ucc38\uc870 \ud0c0\uc785 \ub370\uc774\ud130(\uc608: \uac1d\uccb4, \ud568\uc218)\ub97c \uc800\uc7a5\ud558\ub294 \ub370 \uc0ac\uc6a9\ub418\uba70, \ud504\ub85c\uadf8\ub7a8\uc758 \ub3d9\uc801 \ub370\uc774\ud130\uac00 \uc800\uc7a5\ub418\ub294 \uc8fc\uc694 \uacf5\uac04\uc785\ub2c8\ub2e4. \uc774 \uba54\ubaa8\ub9ac \uc601\uc5ed\uc740 \ub370\uc774\ud130\uac00 \ud544\uc694\ud55c \ub3d9\uc548 \uc720\uc9c0\ub418\uba70, \ub354 \uc774\uc0c1 \ud544\uc694\ud558\uc9c0 \uc54a\uc744 \ub54c \uc790\ub3d9\uc73c\ub85c \ud574\uc81c\ub429\ub2c8\ub2e4.\\n\\n\ud799 \uba54\ubaa8\ub9ac \uad00\ub9ac\uc758 \ud6a8\uc728\uc131\uc740 \ud504\ub85c\uadf8\ub7a8\uc758 \uc131\ub2a5\uacfc \uc9c1\uacb0\ub429\ub2c8\ub2e4. \ud6a8\uc728\uc801\uc778 \uba54\ubaa8\ub9ac \uad00\ub9ac\ub294 \uba54\ubaa8\ub9ac \ub204\uc218\ub97c \ubc29\uc9c0\ud558\uace0, \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc758 \ubc18\uc751\uc131\uacfc \uc548\uc815\uc131\uc744 \uc720\uc9c0\ud558\ub294 \ub370 \uc911\uc694\ud569\ub2c8\ub2e4. \uba54\ubaa8\ub9ac \ub204\uc218\ub294 \ubbf8\uc0ac\uc6a9 \uba54\ubaa8\ub9ac\uac00 \uc801\uc808\ud788 \ud574\uc81c\ub418\uc9c0 \uc54a\uc544 \uacc4\uc18d\ud574\uc11c \uba54\ubaa8\ub9ac \uc0ac\uc6a9\ub7c9\uc774 \uc99d\uac00\ud558\ub294 \ud604\uc0c1\uc744 \ub9d0\ud558\uba70, \uc774\ub294 \uacb0\uad6d \uc131\ub2a5 \uc800\ud558\ub098 \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc758 \uc2e4\ud328\ub97c \ucd08\ub798\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### GC: Garbage Collector\\n\\n\uac00\ube44\uc9c0 \uceec\ub809\uc158\uc740 \uba54\ubaa8\ub9ac\uc5d0\uc11c \ub354 \uc774\uc0c1 \uc0ac\uc6a9\ud558\uc9c0 \uc54a\ub294 \uac1d\uccb4\ub97c \uc790\ub3d9\uc73c\ub85c \uac80\ucd9c\ud558\uace0 \ub354 \uc774\uc0c1 \uc4f0\uc9c0 \uc54a\ub294 \ubc84\ub9ac\ub294 \uac12\uc73c\ub85c \ud310\ub2e8\ud558\uc5ec \uadf8 \uba54\ubaa8\ub9ac \uacf5\uac04\uc744 \ud574\uc81c\ud569\ub2c8\ub2e4.\\n\\n\uc774\ub7f0 \uacfc\uc815\uc740 \ud504\ub85c\uadf8\ub7a8\uc758 \uba54\ubaa8\ub9ac \ud6a8\uc728\uc131\uc744 \ubcf4\uc7a5\ud558\uac8c \ub418\uba70, \uba54\ubaa8\ub9ac \ub204\uc218\ub97c \ubc29\uc9c0\ud569\ub2c8\ub2e4.\\n\\n\uadf8\ub7ec\uba74 **\uc5b4\ub5bb\uac8c \ub354 \uc774\uc0c1 \uc0ac\uc6a9\ud558\uc9c0 \uc54a\ub294 \uba54\ubaa8\ub9ac\ub77c\uace0 \ud310\ub2e8\ud558\ub294 \uac83\uc77c\uae4c\uc694?** \uadf8\ub9ac\uace0 **GC\uac00 \ub3d9\uc791\ud558\ub294 \ub3d9\uc548 \ud504\ub85c\uadf8\ub7a8\uc774 \uc911\ub2e8\ub418\ub294 \uc2dc\uac04\uc744 \uc904\uc77c \uc218 \uc788\uc744\uae4c\uc694?** \uc774\ub294 \uc77c\ubd80 \uc54c\uace0\ub9ac\uc998\uc744 \uc0ac\uc6a9\ud574 \ud574\uacb0\ud569\ub2c8\ub2e4.\\n\\n- Reference-counting garbage collection\\n    \\n    \uc774\ub294 \uac00\ub9ac\ud0a4\ub294 \ucc38\uc870\uac00 \uc5c6\ub294 \uac1d\uccb4\ub97c \uc218\uc9d1\ud569\ub2c8\ub2e4.\\n    \\n    \uac1d\uccb4\uac00 \uc0dd\uc131\ub420 \ub54c\ub9c8\ub2e4 \ud574\ub2f9 \uac1d\uccb4\ub97c \ucc38\uc870\ud558\ub294 \ubcc0\uc218, \uc18d\uc131, \ub610\ub294 \ub2e4\ub978 \uac1d\uccb4\ub4e4\uc5d0 \ub300\ud55c \ucc38\uc870 \uc218\uac00 \uc99d\uac00\ud558\uace0, \ucc38\uc870\uac00 \ud574\uc81c\ub420 \ub54c\ub9c8\ub2e4 \uac10\uc18c\ud569\ub2c8\ub2e4. \ucc38\uc870 \uc218\uac00 0\uc774 \ub418\uba74, \uc989 \uc5b4\ub5a4 \ub2e4\ub978 \uac1d\uccb4\ub098 \ubcc0\uc218\ub3c4 \ud574\ub2f9 \uac1d\uccb4\ub97c \ucc38\uc870\ud558\uace0 \uc788\uc9c0 \uc54a\uc744 \ub54c \ud574\ub2f9 \uac1d\uccb4\ub294 \uac00\ube44\uc9c0\ub85c \uac04\uc8fc\ub418\uc5b4 \uba54\ubaa8\ub9ac\uc5d0\uc11c \ud574\uc81c\ub429\ub2c8\ub2e4. \\n    \\n    \uadf8\ub7ec\ub098 \uc774 \uc54c\uace0\ub9ac\uc998\uc758 \uacbd\uc6b0 \uac1d\uccb4\ub4e4 \uc0ac\uc774\uc758 \uc21c\ud658 \ucc38\uc870\uac00 \ubc1c\uc0dd\ud558\ub294 \uacbd\uc6b0, \ucc38\uc870 \uc218\uac00 0\uc774 \ub418\uc9c0 \uc54a\ub294 \uacbd\uc6b0\uac00 \uc788\uc5b4 \uba54\ubaa8\ub9ac \ub204\uc218\uac00 \ubc1c\uc0dd\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n- Mark-and-Sweep\\n    \\n    \'mark\' \ub2e8\uacc4\uc5d0\uc11c\ub294 GC\uc758 Root\uc5d0\uc11c\ubd80\ud130 \ubaa8\ub4e0 \ubcc0\uc218\ub4e4\uc744 \uc2a4\uce94\ud558\uba70 \uac01\uac01 \uc5b4\ub5a4 \uac1d\uccb4\ub97c \ucc38\uc870\ud558\uace0 \uc788\ub294\uc9c0 \ucc3e\uc544 \ub9c8\ud0b9\ud799\ub2c8\ub2e4. \uc774\ub294 \ucc38\uc870\ub418\uace0 \uc788\ub294 \uac1d\uccb4\uc640 \ucc38\uc870\ub418\uc9c0 \uc54a\uc740 \uac1d\uccb4\ub4e4\uc744 \uc2dd\ubcc4\ud558\ub294 \uacfc\uc815\uc785\ub2c8\ub2e4.\\n    \\n    \u2018sweep\u2019\ub2e8\uacc4\uc5d0\uc11c\ub294 \ucc38\uc870\ub418\uc9c0 \uc54a\ub294 \uac1d\uccb4\ub4e4\uc744 Heap\uc5d0\uc11c \uc81c\uac70\ud569\ub2c8\ub2e4. \\n    \\n    +Compact: \uc774\ub294 \uc54c\uace0\ub9ac\uc998\uc5d0 \ub530\ub77c \ucd94\uac00\ub420\uc218\ub3c4 \uc788\ub294 \ubd80\ubd84\uc73c\ub85c, Sweep \ud6c4, \ubd84\uc0b0\ub41c \uac1d\uccb4\ub4e4\uc744 Heap\uc758 \uc2dc\uc791 \uc8fc\uc18c\ub85c \ubaa8\uc544 \uba54\ubaa8\ub9ac\uac00 \ud560\ub2f9\ub41c \ubd80\ubd84\uacfc \uadf8\ub807\uc9c0 \uc54a\uc740 \ubd80\ubd84\uc73c\ub85c \ub098\ub215\ub2c8\ub2e4. (\uba54\ubaa8\ub9ac \ub2e8\ud3b8\ud654 \ubc29\uc9c0)\\n    \\n    \uc704 \ubc29\ubc95\uc740 \uc21c\ud658 \ucc38\uc870\ub85c \uc778\ud55c \ubb38\uc81c\ub97c \ud574\uacb0\ud560 \uc218 \uc788\uc73c\uba70, \uc9c0\uae08\uc758 js \uc5d4\uc9c4\uc5d0\uc11c \ub9ce\uc774 \uc0ac\uc6a9\ub429\ub2c8\ub2e4.\\n    \\n\\n\ucc38\uace0 \uae00:\\n\\n[https://developer.mozilla.org/en-US/docs/Web/JavaScript/Memory_Management#garbage_collection](https://developer.mozilla.org/en-US/docs/Web/JavaScript/Memory_Management#garbage_collection)\\n\\n[https://velog.io/@sejinkim/\uc790\ubc14\uc2a4\ud06c\ub9bd\ud2b8\uc758-\uba54\ubaa8\ub9ac-\uad00\ub9ac-\uc124\uba85](https://velog.io/@sejinkim/%EC%9E%90%EB%B0%94%EC%8A%A4%ED%81%AC%EB%A6%BD%ED%8A%B8%EC%9D%98-%EB%A9%94%EB%AA%A8%EB%A6%AC-%EA%B4%80%EB%A6%AC-%EC%84%A4%EB%AA%85)\\n\\n[https://imasoftwareengineer.tistory.com/103](https://imasoftwareengineer.tistory.com/103)\\n\\n<br />\\n## React reconciliation \uc54c\uace0\ub9ac\uc998\uc744 \ucd08\uac04\ub2e8\ud558\uac8c \uc54c\uc544\ubcf4\uc790! - \uae40\ubbfc\uc7ac  \\nReact 18 \ubd80\ud130 reconciliation \uc54c\uace0\ub9ac\uc998\uc774 \ubc14\ub00c\uc5c8\ub2e4\ub294 \uc0ac\uc2e4 \uc54c\uace0 \uacc4\uc168\ub098\uc694?\\n\\n### React reconciliation?\\nReact Reconciliation\uc740 React\uac00 \uac00\uc0c1 DOM\uc5d0 \ub300\ud55c \ubcc0\uacbd \uc0ac\ud56d\uc744 \uacb0\uc815\ud558\uace0 \ud574\ub2f9 \ubcc0\uacbd \uc0ac\ud56d\uc744 \uc2e4\uc81c DOM\uc5d0 \uc801\uc6a9\ud558\ub294 \ud504\ub85c\uc138\uc2a4\uc5d0\uc694! ui\uac00 \uae30\ubcf8 \ub370\uc774\ud130\uc640 \ub3d9\uae30\ud654\ub41c \uc0c1\ud0dc\ub97c \uc720\uc9c0\ud558\uc5ec \ubd88\ud544\uc694\ud55c \uc5c5\ub370\uc774\ud2b8\ub97c \ucd5c\uc18c\ud654\ud558\uace0 \ud544\uc694\ud55c \uad6c\uc131 \uc694\uc18c\ub9cc \ub80c\ub354\ub9c1\ud558\ub3c4\ub85d \ubcf4\uc7a5\ud558\uc8e0.  \\n\uc608\uc804 \ubc84\uc804\uc758 React\uc5d0\uc11c\ub294 \\"diffing\\" \ub610\ub294 \\"tree diffing\\"\uc774\ub77c\uace0\ub3c4 \uc54c\ub824 \uc54c\uace0\ub9ac\uc998\uc744 \uc0ac\uc6a9\ud588\ub2f5\ub2c8\ub2e4! \uc774\uc804 \ubc0f \ud604\uc7ac \uac00\uc0c1 DOM \ud2b8\ub9ac\ub97c \ube44\uad50\ud558\uc5ec \ucc28\uc774\uc810\uc744 \uc2dd\ubcc4\ud558\uace0 \uadf8\uc5d0 \ub530\ub77c \uc601\ud5a5\uc744 \ubc1b\ub294 \uad6c\uc131 \uc694\uc18c\ub97c \uc5c5\ub370\uc774\ud2b8\ud558\ub294 \ubc29\uc2dd\uc774\uc5c8\uc8e0. \ud558\uc9c0\ub9cc \uc774 \uc811\uadfc \ubc29\uc2dd\uc5d0\ub294 \ud2b9\ud788 \ud06c\uace0 \ubcf5\uc7a1\ud55c \uad6c\uc131 \uc694\uc18c \uacc4\uce35\uc744 \ucc98\ub9ac\ud560 \ub54c \uc81c\ud55c\uc774 \uc788\uc5c8\uc5b4\uc694..\\n\\n### React 18\uc5d0\uc11c\ub294?\\nReact 18\uc5d0\uc11c\ub294 \ub354 \ud5a5\uc0c1\ub41c reconciliation \uc54c\uace0\ub9ac\uc998\uc744 \uc0ac\uc6a9\ud574\uc694! \ub4e4\uc5b4\ubcf4\uc168\ub098\uc694? \u2018Concurrent mode!\u2019  \\nConcurrent mode\ub97c \uc0ac\uc6a9\ud558\uba74 React\uac00 \uba54\uc778 \uc2a4\ub808\ub4dc\ub97c \ucc28\ub2e8\ud558\uc9c0 \uc54a\uace0 \ub3d9\uc2dc\uc5d0 \uc5ec\ub7ec \uc791\uc5c5\uc744 \uc218\ud589\ud560 \uc218 \uc788\uc73c\ubbc0\ub85c \uc751\ub2f5\uc131\uc774 \ud5a5\uc0c1\ub418\uace0 \uc0ac\uc6a9\uc790 \uacbd\ud5d8\uc774 \ub354 \uc6d0\ud65c\ud574\uc9c4\ub2f5\ub2c8\ub2e4.  \\n\\"Concurrent React\\"\ub85c \uc54c\ub824\uc9c4 React 18\uc758 \uc0c8\ub85c\uc6b4 \uc870\uc815 \uc54c\uace0\ub9ac\uc998\uc740 \uc870\uc815 \uc791\uc5c5\uc744 \\"fiber\\"\ub77c\uace0 \ud558\ub294 \ub354 \uc791\uc740 \ub2e8\uc704\ub85c \ub098\ub204\uace0 \uc911\uc694\ub3c4\uc5d0 \ub530\ub77c \uc6b0\uc120\uc21c\uc704\ub97c \uc9c0\uc815\ud574\uc694. \uc774 \uc811\uadfc \ubc29\uc2dd\uc744 \ud1b5\ud574 React\ub294 \uc870\uc815 \ud504\ub85c\uc138\uc2a4\ub97c \ud6a8\uc728\uc801\uc73c\ub85c \uc911\ub2e8\ud558\uace0 \uc7ac\uac1c\ud558\uc8e0. \ub2e4\ub974\uac8c \uc774\uc57c\uae30\ud558\uc790\uba74 \uc0ac\uc6a9\uc790 \uc0c1\ud638 \uc791\uc6a9 \ubc0f \uae30\ud0c0 \uc6b0\uc120 \uc21c\uc704\uac00 \ub192\uc740 \uc791\uc5c5\uc758 \uc6b0\uc120 \uc21c\uc704\ub97c \uc9c0\uc815\ud560 \uc218 \uc788\uc5b4\uc694!  \\n\\n### React reconciliation \uc8fc\uc694 \uac1c\ub150 \uc815\ub9ac\\n\\n**Fiber Reconciliation**\\n- React 18\uc758 reconciliation \ud504\ub85c\uc138\uc2a4\ub294 fiber \uc218\uc900\uc5d0\uc11c \uc791\ub3d9\ud55c\ub2e4\uace0 \ud588\uc5c8\uc8e0? fiber\ub294 \uc27d\uac8c \uc774\uc57c\uae30 \ud558\uc790\uba74 \uad6c\uc131 \uc694\uc18c\uc640 \ud574\ub2f9 \uc791\uc5c5\uc744 \ub098\ud0c0\ub0b4\uc694. \uc870\uc815 \uc791\uc5c5\uc744 \ub354 \uc791\uc740 fiber\ub85c \ubd84\ud560\ud568\uc73c\ub85c\uc368 React\ub294 \uc774\ub97c \ubcf4\ub2e4 \ud6a8\uc728\uc801\uc73c\ub85c \uad00\ub9ac\ud558\uace0 \uc6b0\uc120\uc21c\uc704\ub97c \uc9c0\uc815\ud560 \uc218 \uc788\uac8c \ub418\ub294\uac70\uc5d0\uc694.\\n\\n**Render Phase and Commit Phase**\\n- reconciliation \ud504\ub85c\uc138\uc2a4\ub294 rendering, commit \ub2e8\uacc4\ub77c\ub294 \ub450 \uac00\uc9c0 \uc8fc\uc694 \ub2e8\uacc4\ub85c \ub098\ub20c \uc218 \uc788\uc5b4\uc694. rendering \ub2e8\uacc4\uc5d0\uc11c React\ub294 \uad6c\uc131 \uc694\uc18c \ud2b8\ub9ac\ub97c \ud0d0\uc0c9\ud558\uc5ec Fiber\ub97c \uc0dd\uc131\ud558\uac70\ub098 \uc5c5\ub370\uc774\ud2b8\ud558\uc8e0. \ub80c\ub354\ub9c1\ud574\uc57c \ud558\ub294 \uad6c\uc131 \uc694\uc18c\ub97c \uacb0\uc815\ud558\uace0 \ube68\ub9ac \ud574\uacb0\ub418\uc5b4\uc57c \ud558\ub294 \uc5c5\ub370\uc774\ud2b8\ub97c \uba3c\uc800 \uc6b0\uc120 \uc21c\uc704 \ubaa9\ub85d\uc73c\ub85c \uc62c\ub824\uc694.\\n- commit \ub2e8\uacc4\ub294 React\ub294 \ubcc0\uacbd \uc0ac\ud56d\uc744 \uc2e4\uc81c DOM\uc5d0 \uc801\uc6a9\ud558\ub294 \ub2e8\uacc4\uc5d0\uc694. \uc774 \ub54c\ub3c4 \ub9c8\ucc2c\uac00\uc9c0\ub85c \uc5ec\ub7ec \uc6b0\uc120 \uc21c\uc704 \ub808\ubca8\ub85c \ub098\ub204\uc5b4\uc838 React\uac00 \uc131\ub2a5 \uc800\ud558 \uc5c6\uc774 \uc911\uc694\ud55c \uc5c5\ub370\uc774\ud2b8\uc758 \uc6b0\uc120 \uc21c\uc704\ub97c \uc9c0\uc815\ud558\uace0 ui\uc5d0 \uc751\ub2f5\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\uc9c0\uc694.\\n\uac04\ub2e8\ud558\uac8c react v18\uc758 reconciliation \uc54c\uace0\ub9ac\uc998\uc744 \uc54c\uc544\ubd24\uc5b4\uc694! \uc815\ub9d0 \uac04\ub2e8\ud558\uac8c \uc774\uc57c\uae30 \ud588\uae30\ub54c\ubb38\uc5d0 reconciliation \uc744 \ub354\uc790\uc138\ud788 \uc54c\uace0 \uc2f6\ub2e4\uba74 \uc544\ub798 \uae00\uc744 \uc644\ub3c5\ud574\ubcf4\ub294\uac83\ub3c4 \uc88b\uc544\uc694~!\\n\\n### react\uc758 Lane model\uacfc concurrent render \uc790\uc138\ud788 \uc54c\uc544\ubcf4\uae30\\nhttps://goidle.github.io/react/in-depth-react18-intro/  \\nhttps://goidle.github.io/react/in-depth-react18-lane/  \\nhttps://goidle.github.io/react/in-depth-react18-transition_1/  \\nhttps://goidle.github.io/react/in-depth-react18-transition_2 copy/  \\nhttps://goidle.github.io/react/in-depth-react18-concurrent_render/  \\n\\n<br />\\n## \uc7ac\ubbf8\uc640 \uc774\uc775\uc744 \uc704\ud55c \uc790\ubc14\uc2a4\ud06c\ub9bd\ud2b8 \uc804\ubb38\ud654? - \uae40\ud558\ub098\\n\\n[https://velog.io/@surim014/optimizing-javascript-for-fun-and-for-profit#9-\uc804\ubb38\ud654specialization-\uc0ac\uc6a9\ud558\uae30](https://velog.io/@surim014/optimizing-javascript-for-fun-and-for-profit#9-%EC%A0%84%EB%AC%B8%ED%99%94specialization-%EC%82%AC%EC%9A%A9%ED%95%98%EA%B8%B0)  \\n\uc774 \uae00\uc740 JavaScript \ucd5c\uc801\ud654 \ubc29\ubc95\uc5d0 \ub300\ud55c \ub0b4\uc6a9\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4.\\n\\n\uc774\uc911\uc5d0\uc11c 9\ubc88 \ucc55\ud130\uc778 \uc804\ubb38\ud654(specialization) \uc5d0 \uad00\ub828\ud574 \ud765\ubbf8\ub86d\uac8c \ub290\ub080 \ubd80\ubd84\uc744 \uc911\uc2ec\uc73c\ub85c \uc124\uba85\ud558\uaca0\uc2b5\ub2c8\ub2e4. \uc774\uc678\uc758 \ub0b4\uc6a9\uc774 \uad81\uae08\ud558\uc2e0 \ubd84\ub4e4\uc740 \uc704 \uae00\uc758 \ub098\uba38\uc9c0 \ucc55\ud130\ub4e4\uc744 \uc77d\uc5b4\ubcf4\uc2dc\uae30 \ubc14\ub78d\ub2c8\ub2e4.\\n\\n### \uc804\ubb38\ud654\\n\\n\uc804\ubb38\ud654\ub294 \ud2b9\uc815 \uc0ac\uc6a9 \uc0ac\ub840\uc758 \uc81c\uc57d \uc870\uac74\uc744 \ub85c\uc9c1\uc5d0 \ub9de\ucd94\ub294 \uac83\uc785\ub2c8\ub2e4.\\n\\n\uc77c\ubc18\uc801\uc73c\ub85c \ud55c \uc870\uac74\uc774 \ub2e4\ub978 \uc870\uac74\ubcf4\ub2e4 \ub354 \uc790\uc8fc \ubc1c\uc0dd\ud55c\ub2e4\uace0 \ud310\ub2e8\ub420 \ub54c, \uc774\ub97c \ud30c\uc545\ud558\uace0 \ud574\ub2f9 \uc870\uac74\uc5d0 \ub9de\uac8c \ucf54\ub4dc\ub97c \uc791\uc131\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc608\ub97c \ub4e4\uc5b4, \uc5b4\ub5a4 \uc81c\ud488 \ubaa9\ub85d\uc5d0 \ud0dc\uadf8\ub97c \ucd94\uac00\ud574\uc57c \ud558\ub294 \uc0c1\ud669\uc5d0\uc11c, \ud0dc\uadf8\uac00 \ub300\ubd80\ubd84 \ube44\uc5b4\uc788\ub2e4\ub294 \uac83\uc744 \uc54c\uac8c \ub418\uc5c8\ub2e4\uace0 \uac00\uc815\ud574\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n\ub530\ub77c\uc11c \uc774 \uc0c1\ud669\uc5d0 \ub9de\ucd94\uc5b4 \uc804\ubb38\ud654\ub97c \uc801\uc6a9\ud558\uace0 \uc774\uc5d0 \ub300\ud574 \uc124\uba85\ud558\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n\ub2e4\uc74c\uacfc \uac19\uc774 \uc608\uc2dc \ubb3c\ud488\uacfc \ud0dc\uadf8\ub97c \uc815\uc758\ud569\ub2c8\ub2e4.\\n\\n```tsx\\nconst descriptions = [\'apples\', \'oranges\', \'bananas\', \'seven\']\\nconst someTags = {\\n  apples: \'::promotion::\',\\n}\\nconst noTags = {}\\n```\\n\\n\uadf8\ub7f0 \ub2e4\uc74c, \uc804\ubb38\ud654\ub97c \uc801\uc6a9\ud558\uc9c0 \uc54a\uc740 \ubb38\uc790\uc5f4 \ubcc0\ud658 \ud568\uc218\ub97c \uc0b4\ud3b4\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n```tsx\\n// \ud574\ub2f9\ub418\ub294 \uacbd\uc6b0 \ud0dc\uadf8\uc640 \ud568\uaed8 \uc81c\ud488\uc744 \ubb38\uc790\uc5f4\ub85c \uc804\ud658\ud569\ub2c8\ub2e4.\\nfunction productsToString(description, tags) {\\n  let result = \'\'\\n  description.forEach(product => {\\n    result += product\\n    if (tags[product]) result += tags[product]\\n    result += \', \'\\n  })\\n  return result\\n}\\n```\\n\\n\uc774\uc640 \ub2e4\ub974\uac8c \ube48\ud0dc\uadf8\ub97c \uba3c\uc800 \uac78\ub7ec\uc8fc\ub294 \uc804\ubb38\ud654\uac00 \uc801\uc6a9\ub41c \ub3d9\uc77c\ud55c \uae30\ub2a5 \ud568\uc218\ub97c \ub9cc\ub4e4\uc5b4\uc90d\ub2c8\ub2e4.\\n\\n```tsx\\nfunction productsToStringSpecialized(description, tags) {\\n  // \uc6b0\ub9ac\ub294 `tags`\uac00 \ube44\uc5b4 \uc788\uc744 \uac00\ub2a5\uc131\uc774 \uc788\ub2e4\ub294 \uac83\uc744 \uc54c\uace0 \uc788\uc73c\ubbc0\ub85c \ubbf8\ub9ac \ud55c \ubc88 \ud655\uc778\ud55c \ub2e4\uc74c \ub0b4\ubd80 \ub8e8\ud504\uc5d0\uc11c `if` \uac80\uc0ac\ub97c \uc81c\uac70\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n  if (isEmpty(tags)) {\\n    let result = \'\'\\n    description.forEach(product => {\\n      result += product + \', \'\\n    })\\n    return result\\n  } else {\\n    // \ubb38\uc790\uc5f4 \uc804\ud658 \ub85c\uc9c1\uc740 \ub3d9\uc77c\\n  }\\n}\\nfunction isEmpty(o) { for (let _ in o) { return false } return true }\\n```\\n\\n\uc774 \ub450\uac1c\uc758 \ud568\uc218\ub97c \uac00\uc9c0\uace0 \uc2e4\uc81c \ube44\uad50\ud588\uc744 \ub54c\uc758 \uc218\uce58 \ube44\uad50\ub294 \ub2e4\uc74c\uacfc \uac19\uc774 \ub098\ud0c0\ub0a9\ub2c8\ub2e4.\\n\\n- non speciailized : 85.71 %\\n- specialized : 100 %\\n\\n\uc704\uc640 \uac19\uc740 \uc0c1\ud669\uc5d0\uc11c\ub294 \ub2e4\uc74c\uacfc \uac19\uc740 \uc54c\uace0\ub9ac\uc998 \uc801\uc6a9\uc744 \ud1b5\ud574 \uc131\ub2a5\uc774 \ub354 \ub192\uc544\uc9c8 \uc218\ub294 \uc788\uc9c0\ub9cc, \uc870\uac74\uc774 \ub2ec\ub77c\uc9c4\ub2e4\uba74 \ub2e4\ub974\uac8c \ud310\ub2e8\ud574\uc57c \ud560 \ud544\uc694\uac00 \uc788\uc744\uac83\uc785\ub2c8\ub2e4. \\n\\n(\ucf54\ub4dc\uc5d0\uc11c\uc758 \ubd84\uae30 \uce21\ubcc0\uc5d0\uc11c\ub3c4 \uc81c\uac70\ud558\ub294\uac8c \ub354 \ud6a8\uc728\uc801\uc774\ub2e4 \ub77c\ub294 \uc774\uba74\uc774 \uc788\uae30\uc5d0.. [\ub300\ud45c \uc608\uc2dc](https://stackoverflow.com/questions/11227809/why-is-processing-a-sorted-array-faster-than-processing-an-unsorted-array))\\n\\nreference : [https://velog.io/@surim014/optimizing-javascript-for-fun-and-for-profit#9-\uc804\ubb38\ud654specialization-\uc0ac\uc6a9\ud558\uae30](https://velog.io/@surim014/optimizing-javascript-for-fun-and-for-profit#9-%EC%A0%84%EB%AC%B8%ED%99%94specialization-%EC%82%AC%EC%9A%A9%ED%95%98%EA%B8%B0)  \\n[https://stackoverflow.com/questions/11227809/why-is-processing-a-sorted-array-faster-than-processing-an-unsorted-array](https://stackoverflow.com/questions/11227809/why-is-processing-a-sorted-array-faster-than-processing-an-unsorted-array)"},{"id":"/GwakSeungJu/infomate-6week","metadata":{"permalink":"/front-end/GwakSeungJu/infomate-6week","source":"@site/@frontEnd/GwakSeungJu/infomate-6week.mdx","title":"\uc778\ud3ec\uba54\uc774\ud2b8 6\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 6\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","date":"2024-04-29T00:00:00.000Z","tags":[{"label":"\uc778\ud3ec\uba54\uc774\ud2b8","permalink":"/front-end/tags/\uc778\ud3ec\uba54\uc774\ud2b8"},{"label":"\ucd5c\uc801\ud654","permalink":"/front-end/tags/\ucd5c\uc801\ud654"}],"readingTime":14.405,"hasTruncateMarker":true,"authors":[{"name":"GwakSeungJu","url":"https://github.com/Gwak-Seungju","email":"gwak1016@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/74342515?v=4","key":"GwakSeungJu"}],"frontMatter":{"date":"2024-04-29T00:00:00.000Z","authors":"GwakSeungJu","title":"\uc778\ud3ec\uba54\uc774\ud2b8 6\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 6\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","keywords":["\uc778\ud3ec\uba54\uc774\ud2b8","\ucd5c\uc801\ud654"],"tags":["\uc778\ud3ec\uba54\uc774\ud2b8","\ucd5c\uc801\ud654"]},"unlisted":false,"prevItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 7\uc8fc\ucc28 \uacf5\uc720(\uc54c\uace0\ub9ac\uc998)","permalink":"/front-end/GwakSeungJu/infomate-7week"},"nextItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 5\uc8fc\ucc28 \uacf5\uc720(UX)","permalink":"/front-end/hanagertrudeKim/infomate-5week"}},"content":"\uc778\ud3ec\uba54\uc774\ud2b8 6\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654) \ubaa8\uc74c\uc785\ub2c8\ub2e4.    \\n\\n\ub9ac\uc561\ud2b8 \ub9ac\ub80c\ub354\ub9c1 \ucd5c\uc18c\ud654 \ud558\uae30 - \uc724\ud574\uc9c4    \\nWeb Vitals \ucd5c\uc801\ud654\ub97c \uc704\ud55c Tip.. - \uae40\ud558\ub098    \\n{/* truncate */}\\n\\n## \ub9ac\uc561\ud2b8 \ub9ac\ub80c\ub354\ub9c1 \ucd5c\uc18c\ud654 \ud558\uae30 - \uc724\ud574\uc9c4\\n\\n### \ub4e4\uc5b4\uac00\ub294 \ub9d0\\n\\nreact developer tool\uc774\ub77c\ub294 \ud06c\ub86c \ud655\uc7a5 \ud504\ub85c\uadf8\ub7a8\uc744 \uc544\uc2dc\ub098\uc694?\\n\\n\ud574\ub2f9 \ud655\uc7a5\uc790\ub294 \ub9ac\uc561\ud2b8\ub85c \ub9cc\ub4e4\uc5b4\uc9c4 \ud398\uc774\uc9c0\uc758 \ub80c\ub354\ub9c1\uc744 \uc9c1\uc811 \ub208\uc5d0 \ubcf4\uc774\uac8c \ud45c\uc2dc\ud574 \uc8fc\ub294 \ud504\ub85c\uadf8\ub7a8\uc785\ub2c8\ub2e4.\\n\\n\ud574\ub2f9 \ud504\ub85c\uadf8\ub7a8\uc744 \ub2e4\uc6b4 \ubc1b\uace0 \uc791\uc5c5\ud558\ub358 \ud398\uc774\uc9c0\uc758 \ub80c\ub354\ub9c1 \uacfc\uc815\uc744 \uc0b4\ud3b4\ubcf4\ub2c8 \ubd88\ud544\uc694\ud55c \ub80c\ub354\ub9c1\uc774 \ub108\ubb34 \ub9ce\uc774 \uc77c\uc5b4\ub098\ub294 \uac83\uc744 \ud655\uc778\ud560 \uc218 \uc788\uc5c8\uc2b5\ub2c8\ub2e4. \\n\\n\ubcc0\ud654\uac00 \uc5c6\ub294 \ucef4\ud3ec\ub10c\ud2b8\uac00 \ub80c\ub354\ub9c1 \ub41c\ub2e4\uba74 \uc774\ub294 \ubd84\uba85 \ub0ad\ube44\uac00 \ubc1c\uc0dd\ud558\uac8c \ub420 \uac83\uc785\ub2c8\ub2e4. \\n\\n\ub530\ub77c\uc11c \uc704\uc640 \uac19\uc740 \ub0ad\ube44\ub97c \ucd5c\uc18c\ud654\ud558\uae30 \uc704\ud574 \ub80c\ub354\ub9c1 \ucd5c\uc801\ud654\uc640 \uad00\ub828\ub41c \uc8fc\uc81c\ub85c \uc815\ud574\ubcf4\uc558\uc2b5\ub2c8\ub2e4.\\n\\n### \ub80c\ub354\ub9c1\uc744 \uc2e4\ud589\ud558\ub294 \uacbd\uc6b0\\n\\n\ub9ac\uc561\ud2b8\uc758 \ub80c\ub354\ub9c1\uc774\ub780 \ud568\uc218\ub97c \uc2e4\ud589\ud558\ub294 \uac83\uc774\ub77c\uace0 \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n(app \ucef4\ud3ec\ub10c\ud2b8\uc758 \ub0b4\ubd80 \ub85c\uc9c1\uc744 \uc2e4\ud589)\\n\\n\ub80c\ub354\ub9c1\uc744 \uc2e4\ud589\ud558\ub294 \uacbd\uc6b0\ub294 \uc544\ub798\uc640 \uac19\uc2b5\ub2c8\ub2e4.\\n\\n- **`props`\uac00 \ubcc0\uacbd\ub418\uc5c8\uc744 \ub54c**\\n- **`state`\uac00 \ubcc0\uacbd\ub418\uc5c8\uc744 \ub54c**\\n\\n\ub610\ud55c, \ubd80\ubaa8 \ucef4\ud3ec\ub10c\ud2b8\uac00 \ub80c\ub354\ub9c1\uc774 \ub418\uc5c8\uc744 \uacbd\uc6b0 \uc790\uc2dd \ucef4\ud3ec\ub10c\ud2b8\ub3c4 \ub80c\ub354\ub9c1\uc774 \ub429\ub2c8\ub2e4.\\n\\n- **`parent \ucef4\ud3ec\ub10c\ud2b8`**\\n    - **`childA \ucef4\ud3ec\ub10c\ud2b8`**\\n    - **`childB \ucef4\ud3ec\ub10c\ud2b8`**\\n    \\n\\n\uc704\uc640 \uac19\uc740 \uad6c\uc870\ub85c \uad6c\uc131\uc774 \ub418\uc5b4\uc788\ub294 \ucef4\ud3ec\ub10c\ud2b8\ub77c \uac00\uc815\ud574 \ubd05\uc2dc\ub2e4.\\n\\n### \ubd88\ud544\uc694\ud55c \ub80c\ub354\ub9c1\uc774 \uc0dd\uae30\ub294 \uacbd\uc6b0\\n\\n- `parent \ucef4\ud3ec\ub10c\ud2b8 **(state \uc815\uc758, handle \ud568\uc218 \uc815\uc758)**`\\n    - `childA\ucef4\ud3ec\ub10c\ud2b8 **(props\ub85c state \uc804\ub2ec)**`\\n    - `childB\ucef4\ud3ec\ub10c\ud2b8 **(props\ub85c handle \ud568\uc218 \uc804\ub2ec)**`\\n\\n\uc704\uc640 \uac19\uc740 \uae30\uc900\uc73c\ub85c state\uc640 \ud568\uc218\ub97c \uc815\uc758\ud574 \ubcf4\uc558\uc2b5\ub2c8\ub2e4.\\n\\nparent\uc5d0\uc11c state\uc758 \uac12\uc774 \ubcc0\uacbd\ub418\uc5c8\uc744 \ub54c, \ub80c\ub354\ub9c1\uc774 \ub418\ub294 \uae30\uc900\uc73c\ub85c \uc0dd\uac01\ud574 \ubcf4\uba74\\n\\n`state \uc804\ub2ec\uc774 \ub41c childA\uc758 \ucef4\ud3ec\ub10c\ud2b8`\ub294 **\ub9ac\ub80c\ub354\ub9c1\uc774 \uc77c\uc5b4\ub098\ub294 \uac83\uc774 \ub9de\uc2b5\ub2c8\ub2e4.**\\n\\n\uadf8\ub7ec\ub098, `\uc0c8\ub85c \uadf8\ub824\uc9c8 \ud544\uc694\uac00 \uc5c6\ub294 childB`\uc758 \uacbd\uc6b0\uc5d0\ub3c4 **\ub9ac\ub80c\ub354\ub9c1\uc774 \uc77c\uc5b4\ub098\uac8c \ub429\ub2c8\ub2e4.(\ubd88\ud544\uc694 \ub9ac\ub80c\ub354\ub9c1 \ubc1c\uc0dd)**\\n\\nchildB\uac00 \ub9ac\ub80c\ub354\ub9c1\uc774 \uc77c\uc5b4\ub098\uac8c \ub420 \uacbd\uc6b0 childB \ud558\uc704\uc5d0 \uc788\ub294 \uc790\uc2dd \ucef4\ud3ec\ub10c\ud2b8\ub4e4 \ub610\ud55c \ub9ac\ub80c\ub354\ub9c1\uc774 \uc77c\uc5b4\ub098\uac8c \ub418\uc5b4 **\uba54\ubaa8\ub9ac \ubc0f \uc790\uc6d0 \ub0ad\ube44\uac00 \uc77c\uc5b4\ub0a0 \uac83\uc785\ub2c8\ub2e4.**\\n\\n\uadf8\ub807\ub2e4\uba74 \uc5b4\ub5bb\uac8c childB\uc5d0\uc11c \ub9ac\ub80c\ub354\ub9c1\uc744 \ub9c9\uc744 \uc218 \uc788\uc744\uae4c\uc694?\\n\\n### \ubd88\ud544\uc694\ud55c \ub9ac\ub80c\ub354\ub9c1 \ub9c9\uae30\\n\\n\uc0c8\ub85c \uadf8\ub824\uc9c8 \ud544\uc694\uac00 \uc5c6\ub294 childB\ub294 \uc65c \ub9ac\ub80c\ub354\ub9c1\uc774 \ub418\ub294 \uac83\uc77c\uae4c\uc694?\\n\\n\uac04\ub2e8\ud558\uac8c \uc124\uba85\uc744 \ud558\uc790\uba74, parent \ucef4\ud3ec\ub10c\ud2b8\uc5d0 \uc815\uc758\ub418\uc5b4 \uc788\ub294 state\uac00 \ubcc0\uacbd\uc774 \ub418\uba70 \uc0c8\ub85c \ub80c\ub354\ub9c1\uc774 \ub418\ub294 parent \ucef4\ud3ec\ub10c\ud2b8\uc5d0\uc11c hadle \ud568\uc218\uac00 \uc7ac\uc815\uc758 \ub418\uba70 \uc774\uc804\uc758 \ud568\uc218\uc640 \ub2e4\ub978 \ucc38\uc870\uac12\uc744 \uac00\uc9c0\uace0 \uc788\uae30\uc5d0 \ub2e4\ub978 \ud568\uc218\ub85c \uc778\uc2dd\ud558\uc5ec \uc0c8\ub86d\uac8c childB \ub610\ud55c \ub9ac\ub80c\ub354\ub9c1 \ub418\ub294 \uac83\uc785\ub2c8\ub2e4. (props\uc758 \uac12\uc774 \ubcc0\uacbd\ub418\uba74 \uc7ac\ub80c\ub354\ub9c1 \ub41c\ub2e4\ub294 \uac1c\ub150\uc5d0 \uc758\uac70)\\n\\n\uadf8\ub807\ub2e4\uba74 \ud568\uc218\uc758 \ucc38\uc870\uac12\uc774 \ubc14\ub00c\uc9c0 \uc54a\uac8c \ud55c\ub2e4\uba74 \ub9ac\ub80c\ub354\ub9c1\uc774 \uc77c\uc5b4\ub098\uc9c0 \uc54a\uac8c \ud560 \uc218 \uc788\uc9c0 \uc54a\uc744\uae4c\uc694?\\n\\n\u21d2 \uc774\ub294 react\uc5d0\uc11c \uc0ac\uc6a9\ud558\ub294 useCallback \ud6c5\uc744 \uc0ac\uc6a9\ud558\uc5ec \uad6c\ud604\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n**useCallback**\\n\\n- \ud568\uc218\ub97c \uba54\ubaa8\uc774\uc81c\uc774\uc158 \ud574\uc8fc\ub294 \ud6c5\\n- \uae30\uc874\uc5d0 \uc218\ud589\ud55c \uc5f0\uc0b0\uc758 \uacb0\uacfc\uac12\uc744 \uc5b4\ub518\uac00 \uc800\uc7a5\ud574\ub450\uace0 \ub098\uc911\uc5d0 \ud544\uc694\ud560 \ub54c \uc7ac\uc0ac\uc6a9\ud558\ub294 \uae30\ubc95\\n- \ud568\uc218\ub97c useCallback\uc73c\ub85c \uac10\uc2f8\uc8fc\uba74 \uc758\uc874\uc131 \ubc30\uc5f4\uc774 \ubcc0\ud558\uc9c0 \uc54a\ub294 \uc774\uc0c1, \ud568\uc218\ub97c \uc0c8\ub85c \uc0dd\uc131\ud558\uc9c0(\ub3d9\uc77c\ud55c \ucc38\uc870\uac12\uc744 \uac00\uc9d0) \uc54a\uc74c\\n- `const handleSample = useCallback( ( ) \u21d2 { }, [ ] );`\\n\\n\uadf8\ub807\ub2e4\uba74 \uc704\uc758 useCallback\uc744 \ud1b5\ud574\uc11c childB\uc758 \ubd88\ud544\uc694\ud55c \ub80c\ub354\ub9c1\uc740 \uc77c\uc5b4\ub098\uc9c0 \uc54a\uc744\uae4c\uc694?\\n\\n\uc544\uc27d\uac8c\ub3c4 \uadf8\ub807\uc9c0\ub294 \uc54a\uc2b5\ub2c8\ub2e4.\\n\\n\uc774\ub294 parent \ucef4\ud3ec\ub10c\ud2b8\uac00 \ucef4\ud30c\uc77c \ub418\ub294 \uacfc\uc815\uc5d0\uc11c\uc758 \uc774\ud574\uac00 \uc870\uae08 \ud544\uc694\ud569\ub2c8\ub2e4.\\n\\nstate\uac00 \ubcc0\uacbd\ub41c parent \ucef4\ud3ec\ub10c\ud2b8\ub294 \ub9ac\ub80c\ub354\ub9c1\uc774 \uc77c\uc5b4\ub0a9\ub2c8\ub2e4. \\n\\n\uc774 \uacbd\uc6b0 js \ucef4\ud30c\uc77c\ub7ec\uc778 babel\uc774 \uc2e4\ud589\ub418\uba70 parent \ucef4\ud3ec\ub10c\ud2b8\uc758  \uc790\uc2dd\ub4e4\uc778 childA, childB \ucef4\ud3ec\ub10c\ud2b8\ub97c React.creatElement\ub97c \ud1b5\ud574 \uc0c8\ub85c\uc6b4 \uc694\uc18c\ub97c \uc0dd\uc131\ud558\uac8c \ub429\ub2c8\ub2e4.\\n\\n\uc774\ub7ec\ud55c \uc774\uc720\ub85c useCallback\uc744 \uc0ac\uc6a9\ud558\uc5ec childB\uc5d0 \uc804\ub2ec\ub418\ub294 prop\ub97c \uc774\uc804\uacfc \ub3d9\uc77c\ud558\uac8c \ud574\uc8fc\uc5b4\ub3c4 \ubd88\ud544\uc694\ud55c \ub9ac\ub80c\ub354\ub9c1\uc774 \uc77c\uc5b4\ub098\ub294 \uc774\uc720\uc785\ub2c8\ub2e4.\\n\\n+\uadf8\ub807\ub2e4\uba74 useCallback\uc744 \uc0ac\uc6a9\ud558\ub294 \uac83\uc740 \uae30\ub2a5\uc801\uc73c\ub85c \uc774\ub4dd\uc774 \uc5c6\ub098\uc694?\\n\\n- \uc544\ub2d9\ub2c8\ub2e4. \ub9ac\uc561\ud2b8 \ub80c\ub354\ub9c1 \uacfc\uc815\uc5d0\ub294 render phase, commit phase\uac00 \uc788\uc2b5\ub2c8\ub2e4. useCallback\uc744 \uc0ac\uc6a9\ud558\uac8c \ub41c\ub2e4\uba74 commit phase\uc758 \uacfc\uc815\uc774 \uc0dd\ub7b5\ub418\ub294 \uae30\ub2a5\uc774 \uc788\uc2b5\ub2c8\ub2e4. \uc704 \ub0b4\uc6a9\uc740 \uc124\uba85\uc774 \uae38\uc5b4\uc838 \uac04\ub2e8\ud558\uac8c \ub118\uc5b4\uac00\ub3c4\ub85d \ud558\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n\uadf8\ub807\ub2e4\uba74 \ub354\uc6b1 \ud655\uc2e4\ud558\uac8c childB\uc758 \ub9ac\ub80c\ub354\ub9c1\uc744 \ub9c9\uae30 \uc704\ud574 (render phase)\ub97c \ub9c9\uae30 \uc704\ud574\uc11c\ub294 \uc5b4\ub5bb\uac8c \ud560 \uc218 \uc788\uc744\uae4c\uc694?\\n\\n**React.memo**\\n\\n- \uc804\ub2ec\ubc1b\uc740 props\uac00 \uc774\uc804\uacfc \ube44\uad50\ud588\uc744 \ub54c, \uac19\uc73c\uba74 \ucef4\ud3ec\ub10c\ud2b8\uc758 \ub9ac\ub80c\ub354\ub9c1\uc744 \ub9c9\uc544\uc8fc\uace0, \ub80c\ub354\ub9c1 \ub41c \uacb0\uacfc\ub97c \uc7ac\uc0ac\uc6a9\\n- \uae30\ubcf8\uc801\uc73c\ub85c \uc595\uc740 \ube44\uad50\ub97c \ud1b5\ud574 props \ube44\uad50 \uc9c4\ud589 (\uc6d0\uc2dc \ud0c0\uc785 \ub370\uc774\ud130\ub294 \uac12 \ube44\uad50, \ucc38\uc870 \ud0c0\uc785 \ub370\uc774\ud130\ub294 \ucc38\uc870\uac12 \ube44\uad50)\\n\\n**\ub9cc\uc57d childB \ucef4\ud3ec\ub10c\ud2b8\uc5d0 props\ub85c \ud568\uc218\uac00 \uc544\ub2cc \ubcc0\ud558\uc9c0 \uc54a\ub294 parent\uc5d0 \uc815\uc758\ub41c test\ub77c\ub294 \uac1d\uccb4 \uac12\uc774 \ub2f4\uae34\ub2e4\uba74?**\\n\\n  (\uac1d\uccb4\ub97c porp\ub85c \ub118\uaca8\uc900\ub2e4\uba74)\\n\\n- parent \uac1d\uccb4\uac00 \ub9ac\ub80c\ub354\ub9c1 \ub429\ub2c8\ub2e4. \u21d2 item\uc774\ub77c\ub294 \uac1d\uccb4\uac00 \ub9e4\ubc88 \uc0c8\ub85c \uc0dd\uc131\ub429\ub2c8\ub2e4. (\ucc38\uc870\uac12\uc778 \uac1d\uccb4\ub294 \ub9e4\ubc88 \ub2e4\ub978 \ucc38\uc870 \uac12\uc744 \uac00\uc9c0\uac8c \ub429\ub2c8\ub2e4.)\\n- childB\uc5d0\uac8c \ub9e4\ubc88 \ub2e4\ub978 \ucc38\uc870\uac12\uc744 \uac00\uc9c0\ub294 \uac1d\uccb4\ub97c \uc804\ub2ec\\n- React.memo\uac00 \uc791\ub3d9 x (\uc774\uc804\uacfc \ube44\uad50\ud588\uc744 \ub54c \uac19\uc9c0 \uc54a\uae30 \ub54c\ubb38.)\\n\\n**useMemo**\\n\\n- \uac12\uc5d0 \ub300\ud55c \uba54\ubaa8\uc774\uc81c\uc774\uc158\uc744 \uc81c\uacf5\ud558\ub294 hook\\n- \uc758\uc874\uc131 \ubc30\uc5f4\uc5d0 \ub4e4\uc5b4\uc788\ub294 \uac12\uc774 \ubcc0\uacbd\ub418\uc9c0 \uc54a\ub294 \uc774\uc0c1 \uac19\uc740 \uac12 \ubc18\ud658\\n- `const memoizedTest = useMemo( ( ) \u21d2 test, [ ] );`\\n\\n\uc704\ucc98\ub7fc useMemo\ub97c \uc0ac\uc6a9\ud558\uac8c \ub41c\ub2e4\uba74 test\ub294 \ub3d9\uc77c\ud55c \ucc38\uc870\uac12\uc744 \uac00\uc9c0\uace0 \uc788\uc744 \uac83\uc774\uba70 \uc774\ub294 React.memo\ub97c \uc758\ub3c4\ud55c \ub300\ub85c \uc0ac\uc6a9\ud560 \uc218 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4.\\n\\n**\uc88b\uc740 \ucd5c\uc801\ud654\ub780?**\\n\\nuseMemo, useCallback, React.memo \uc774\ub294 \ub80c\ub354\ub9c1\uc744 \uc904\uc774\ub294 \uae30\ub2a5\uc744 \uac00\uc9c0\uace0 \uc788\uc9c0\ub9cc \uc774 \ub610\ud55c\ub3c4 \ud558\ub098\uc758 \ucf54\ub4dc\uc774\uba70 \ub3d9\uc791\uc785\ub2c8\ub2e4. \ucd5c\uc801\ud654\ub97c \uc704\ud574 \uc0ac\uc6a9\ud588\ub2e4 \uc624\ud788\ub824 \ubd80\ub2f4\uc774 \ub354 \uac00\ub294 \ucf54\ub4dc\ub97c \ub9cc\ub4e4 \uc218\ub3c4 \uc788\uc2b5\ub2c8\ub2e4. \\n\\n\ub530\ub77c\uc11c \ubb34\uc791\uc815 \uc0ac\uc6a9\ud558\ub294 \uac83\uc774 \uc544\ub2cc \uae30\ud68d\uc758\ub3c4\uc640 \uc5b4\ub5bb\uac8c \uc0ac\uc6a9\ud558\uc5ec\uc57c \uc88b\uc744\uc9c0 \uace0\ubbfc\ud558\uc5ec \uc801\uc808\ud55c \uc0ac\uc6a9\uc774 \uac00\uc7a5 \uc633\uc740 \ucd5c\uc801\ud654\ub77c\uace0 \ud560 \uc218 \uc788\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n\ub610\ud55c, \ucd5c\uc801\ud654 \ub3c4\uad6c\ub4e4\uc744 \uc0ac\uc6a9\ud558\uae30 \uc774\uc804, \uae30\ucd08\uc801\uc774\uace0 \uadfc\ubcf8\uc801\uc73c\ub85c \ucf54\ub4dc\ub97c \uc218\uc815\ud558\uace0 \uc798 \ub9cc\ub4dc\ub294 \uac83\uc5d0 \ucd08\uc810\uc744 \ub9de\ucd94\ub294 \uac83\uc774 \ub9e4\uc6b0 \uc911\uc694\ud558\uaca0\uc2b5\ub2c8\ub2e4. \\n\\n\ubd80\ubaa8 \ucef4\ud3ec\ub10c\ud2b8 \uc548\uc758 \uc790\uc2dd \ucef4\ud3ec\ub10c\ud2b8\ub85c \uc874\uc7ac\ud558\uace0 \uc788\ub294 \uad6c\uc870\ub97c children\uc744 \ud1b5\ud574 \uc8fc\uc785\uc2dc\ud0a8\ub2e4\uba74 \uc774\ub294 \ubd80\ubaa8 \ucef4\ud3ec\ub10c\ud2b8\uac00 \uc7ac\uc2e4\ud589 \ub418\uc5b4\ub3c4 \ub9ac\ub80c\ub354\ub9c1 \ub418\uc9c0 \uc54a\uc744 \uac83\uc785\ub2c8\ub2e4.\\n\\n### +\ucd5c\uc801\ud654\uac00 \ud544\uc694\ud574\uc694?\\n\\n\ub9ce\uc740 \ube14\ub85c\uadf8 \uc601\uc0c1\ub4e4\uc5d0\uc11c \uc774\ub978 \ucd5c\uc801\ud654 \ub9cc\ud07c\uc774\ub098 \ubd88\ud544\uc694\ud55c \uac83\uc774 \uc5c6\ub2e4\uace0 \uc774\uc57c\uae30\ud569\ub2c8\ub2e4.\\n\\n\uadf8\ub7ec\ub098 \ubaa8\ub974\uace0 \uc4f0\ub294 \uac83\uacfc \uc54c\uace0 \uc4f0\ub294 \uac83\uc740 \ub2e4\ub974\ub2e4\ub294 \ub9d0\uc5d0 \ub9e4\uc6b0 \uacf5\uac10\ub418\uc5c8\uc2b5\ub2c8\ub2e4. \\n\\n\ucd5c\uc801\ud654 \ub3c4\uad6c\ub4e4\uacfc \uadfc\ubcf8\uc801 \ucf54\ub4dc \uc218\uc815\ubc95 \ub4f1\uc744 \uc811\ud574\ubcf4\uace0 \uc774\ud6c4 \ud544\uc694\ud560 \ub54c\uc5d0 \uc801\uc808\ud55c \ubc29\ubc95\uc744 \ud1b5\ud574 \ub80c\ub354\ub9c1\uc744 \ucd5c\uc801\ud654\ud560 \uc218 \uc788\ub294 \ub2a5\ub825\uc744 \uae30\ub974\ub294 \uac83\uc740 \uaf64\ub098 \uc911\uc694\ud558\ub2e4\uace0 \ub290\uaf08\uc2b5\ub2c8\ub2e4. \uc774 \uc678\uc5d0\ub3c4 \ub2e4\uc591\ud55c \uae30\ubc95\uc744 \uc775\ud600\ubcf4\uba74 \uc88b\uc744 \uac83 \uac19\uc2b5\ub2c8\ub2e4.\\n\\n[React \ub80c\ub354\ub9c1 \uc774\ud574\ud558\uae30](https://medium.com/vingle-tech-blog/react-\ub80c\ub354\ub9c1-\uc774\ud574\ud558\uae30-f255d6569849)    \\n[https://www.youtube.com/watch?v=1YAWshEGU6g](https://www.youtube.com/watch?v=1YAWshEGU6g)\\n\\n<br />\\n## Web Vitals \ucd5c\uc801\ud654\ub97c \uc704\ud55c Tip.. - \uae40\ud558\ub098\\n\\n\uc6f9 \uc131\ub2a5 \ucd5c\uc801\ud654\ub294 \uc0ac\uc6a9\uc790 \uacbd\ud5d8\uc744 \ud5a5\uc0c1\uc2dc\ud0a4\ub294 \uc8fc\uc694 \uc694\uc18c\ub85c, \uc11c\ube44\uc2a4 \uad00\uc810\uc5d0\uc11c\ub3c4 \uc911\uc694\ud55c \uc5ed\ud560\uc744 \ud569\ub2c8\ub2e4. \ub85c\ub529 \uc18d\ub3c4\uac00 \ub290\ub9b4\uc218\ub85d \uc0ac\uc6a9\uc790\ub294 \uc6f9\uc0ac\uc774\ud2b8\ub97c \ub5a0\ub0a0 \uac00\ub2a5\uc131\uc774 \ub192\uc544\uc9c0\ub294\ub370, 0.1\ucd08\uc758 \uc131\ub2a5 \uac1c\uc120\ub3c4 conversion rate\ub97c \ub192\uc77c \uc218 \uc788\uc2b5\ub2c8\ub2e4. \\n\\n\uc8fc\ub85c LCP, FID, INP\uc640 \uac19\uc740 web vitals\ub85c \uce21\uc815\ub418\uba70, \uc774\ub7ec\ud55c \uc9c0\ud45c\ub294 \uc0ac\uc6a9\uc790\uc758 \uccab \ubc18\uc751\uc744 \uae30\uc900\uc73c\ub85c \ud569\ub2c8\ub2e4. (\ucd5c\uadfc\uc5d0\ub294 \uc774\ub97c \uac1c\uc120\ud558\uae30 \uc704\ud574 INP\uac00 \ub3c4\uc785\ub418\uc5c8\ub294\ub370, \uc774\ub294 \ubaa8\ub4e0 \uc785\ub825 \uc9c0\uc5f0 \uc2dc\uac04\uc758 \ud3c9\uade0\uc744 \uce21\uc815\ud558\ub294 \ub4f1 \ub354 \ub098\uc740 \uce21\uc815\uc774 \uac00\ub2a5\ud558\uac8c \ud569\ub2c8\ub2e4.)\\n\\n\uc774\ub7ec\ud55c web vitals \ub97c \uc5b4\ub5bb\uac8c \uac1c\uc120\ud560 \uc218 \uc788\ub294\uc9c0, \uc5ec\ub7ec\uac00\uc9c0 \ud301\ub4e4\uc744 \uc815\ub9ac\ud574\ubd24\uc2b5\ub2c8\ub2e4.\\n\\n### LCP \ucd5c\uc801\ud654\\n\\n1. LCP \uc790\uc6d0\uc774 HTML \ub0b4\uc5d0\uc11c \ube68\ub9ac \ucc3e\uc544\uc838\uc57c \ud569\ub2c8\ub2e4.\\n2. LCP \uc790\uc6d0\uc774 \uc6b0\uc120\uc2dc\ub418\uc5b4 \ub2e4\uc6b4\ub85c\ub4dc\ub420 \uc218 \uc788\ub3c4\ub85d \ud574\uc57c \ud569\ub2c8\ub2e4.\\n3. CDN\uc744 \uc0ac\uc6a9\ud558\uc5ec \ub3c8\uc744 \ud22c\uc790\ud569\ub2c8\ub2e4.\\n    - \uc0ac\uc6a9\uc790\uac00 \uac00\uc7a5 \uac00\uae4c\uc6b4 \uc11c\ubc84\uc5d0\uc11c \ub370\uc774\ud130\ub97c \uc804\ub2ec\ubc1b\uc744 \uc218 \uc788\ub3c4\ub85d \ud569\ub2c8\ub2e4.\\n    - \ubb3c\ub9ac\uc801\uc73c\ub85c \ucd5c\ub300\ud55c \uac00\uae4c\uc6b4 \uc11c\ubc84\ub97c \ud65c\uc6a9\ud569\ub2c8\ub2e4.\\n\\n**\uc2e4\uc81c \uc0ac\ub840:**\\n\\n- \uc774\ubbf8\uc9c0\ub294 **`<img>`** \uc5d8\ub9ac\uba3c\ud2b8\uc5d0 \ub123\uace0 `src`\ub098 `srcset` \uc18d\uc131\uc744 \uc774\uc6a9\ud558\uc5ec \uccab \ubc88\uc9f8 \ub80c\ub354\ub9c1 \uc2dc \ud544\uc694\ud55c \uc774\ubbf8\uc9c0\ub97c \uc54c\ub824\uc90d\ub2c8\ub2e4.\\n- SSR\uc744 \uc0ac\uc6a9\ud569\ub2c8\ub2e4.\\n- \ub0b4\ubd80\uc5d0\uc11c \ud638\uc2a4\ud305\ud558\uc9c0 \uc54a\ub294 \uc774\ubbf8\uc9c0\uc5d0\ub294 **`<link rel=\\"preload\\">`** \ud0dc\uadf8\ub97c \uc0ac\uc6a9\ud558\uc5ec \ube0c\ub77c\uc6b0\uc800\uc5d0\uac8c \ube68\ub9ac \ub85c\ub4dc\ud574\uc57c \ud558\ub294 \uc18c\uc2a4\uc784\uc744 \uc54c\ub824\uc90d\ub2c8\ub2e4.\\n- **`<img>`** \ud0dc\uadf8\uc5d0 **`fetchpriority=\\"high\\"`** \uc18d\uc131\uc744 \ucd94\uac00\ud558\uc5ec LCP \uc774\ubbf8\uc9c0\ub97c \uc6b0\uc120\uc801\uc73c\ub85c \ube0c\ub77c\uc6b0\uc800\uac00 \ub2e4\uc6b4\ub85c\ub4dc\ud558\uac8c \ud569\ub2c8\ub2e4.\\n- **`<img>`** \uc5d8\ub9ac\uba3c\ud2b8\uc5d0 **`loading=\\"lazy\\"`** \uc18d\uc131\uc744 \ucd94\uac00\ud558\uc5ec LCP \uac00 \uc544\ub2cc \uc774\ubbf8\uc9c0\ub97c \ub098\uc911\uc5d0 \ub85c\ub529\ud560 \uc218 \uc788\ub3c4\ub85d \ud569\ub2c8\ub2e4.\\n\\n### CLS \ucd5c\uc801\ud654\\n\\n- \ucee8\ud150\uce20\uc758 \uba85\ud655\ud55c \uc0ac\uc774\uc988\ub97c \uc124\uc815\ud569\ub2c8\ub2e4.\\n- \ud754\ub4e4\ub9ac\ub294 CSS \uc560\ub2c8\uba54\uc774\uc158 \ubc0f \uc804\ud658 \ud6a8\uacfc\ub97c \uc9c0\uc591\ud569\ub2c8\ub2e4.\\n- bfcache\ub97c \uc0ac\uc6a9\ud558\uc5ec \uce90\uc2f1\uc744 \ucd5c\uc801\ud654\ud569\ub2c8\ub2e4.\\n    - \ubaa8\ub4e0 \uc9c0\ud45c\ub97c \ud5a5\uc0c1\uc2dc\ud0ac \uc218 \uc788\ub294 \ub3c4\uad6c\uc785\ub2c8\ub2e4.\\n    - \uc774\ub97c \uc704\ud574 \uce90\uc2f1\uc744 \ub9c9\uc544\ub193\uc9c0 \uc54a\uc558\ub294\uc9c0 \ud655\uc778\ud569\ub2c8\ub2e4.\\n\\n**\uc2e4\uc81c \uc0ac\ub840:**\\n\\n- `width`\uc640 `height`\ub97c \uba85\uc2dc\uc801\uc73c\ub85c \uc9c0\uc815\ud569\ub2c8\ub2e4.\\n- `aspect-ratio`\ub97c \uc0ac\uc6a9\ud558\uc5ec `width`\ub9cc \uc9c0\uc815\ud558\uace0 `height`\ub97c \uc720\ub3d9\uc801\uc73c\ub85c \uc124\uc815\ud569\ub2c8\ub2e4.\\n- `min-height`\ub97c \uc9c0\uc815\ud558\uc5ec \uc694\uc18c\uac00 \ub35c \ubc00\ub9ac\ub3c4\ub85d \ubc29\uc9c0\ud569\ub2c8\ub2e4.\\n\\n### FID \ucd5c\uc801\ud654\\n\\n- \uae34 \uc791\uc5c5\uc744 \uc791\uac8c \ubd84\ud560\ud569\ub2c8\ub2e4.\\n- \ubd88\ud544\uc694\ud55c \uc790\ubc14\uc2a4\ud06c\ub9bd\ud2b8 \ucf54\ub4dc\ub97c \ucd5c\uc18c\ud654\ud569\ub2c8\ub2e4.\\n- \ud070 \ub80c\ub354\ub9c1 \uc5c5\ub370\uc774\ud2b8\ub97c \ud53c\ud569\ub2c8\ub2e4.\\n    - \ubd80\ubd84\uc801\uc73c\ub85c\ub9cc \uc5c5\ub370\uc774\ud2b8\ud569\ub2c8\ub2e4.\\n\\n**\uc2e4\uc81c \uc0ac\ub840:**\\n\\n- \uae34 \uc791\uc5c5\uc744 \uc791\uac8c \ubd84\ud560\ud569\ub2c8\ub2e4.\\n    - webpack\uacfc \uac19\uc740 \ub3c4\uad6c\ub97c \uc0ac\uc6a9\ud558\uc5ec chunking\uc774 \uac00\ub2a5\ud558\uac8c \ud569\ub2c8\ub2e4.\\n- \uba54\uc778 \uc4f0\ub808\ub4dc\uc5d0\uc11c \uc7a0\uc2dc \uc790\uc6d0\uc744 \uc591\ubcf4\ud569\ub2c8\ub2e4.\\n- coverage \ub3c4\uad6c\ub97c \ud65c\uc6a9\ud569\ub2c8\ub2e4.\\n- \ucf54\ub4dc\ub97c \ubd84\ud560\ud569\ub2c8\ub2e4.\\n- \ubd88\ud544\uc694\ud55c \ud2b8\ub798\ud0b9 \ud0dc\uadf8\ub97c \uc81c\uac70\ud569\ub2c8\ub2e4.\\n- **`requestAnimationFrame()`** \uc0ac\uc6a9\uc744 \uc9c0\uc591\ud558\uace0 DOM \ud06c\uae30\ub97c \ucd5c\uc18c\ud654\ud569\ub2c8\ub2e4.\\n\\n### reference\\n[https://web.dev/articles/vitals](https://web.dev/articles/vitals)   \\n[23\ub144 6\uc6d4 Tech \uc138\ubbf8\ub098 - \uc6f9 \ud504\ub860\ud2b8\uc5d4\ub4dc \uc131\ub2a5 \ucd5c\uc801\ud654 \ubc29\ubc95 \ubc0f \uc801\uc6a9 \uc0ac\ub840](https://www.youtube.com/watch?v=BEwv4to9OWY)"},{"id":"/hanagertrudeKim/infomate-5week","metadata":{"permalink":"/front-end/hanagertrudeKim/infomate-5week","source":"@site/@frontEnd/hanagertrudeKim/infomate-5week.mdx","title":"\uc778\ud3ec\uba54\uc774\ud2b8 5\uc8fc\ucc28 \uacf5\uc720(UX)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 5\uc8fc\ucc28 \uacf5\uc720(UX) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","date":"2024-04-16T00:00:00.000Z","tags":[{"label":"\uc778\ud3ec\uba54\uc774\ud2b8","permalink":"/front-end/tags/\uc778\ud3ec\uba54\uc774\ud2b8"},{"label":"UX","permalink":"/front-end/tags/ux"}],"readingTime":20.83,"hasTruncateMarker":true,"authors":[{"name":"hana Kim","url":"https://github.com/hanagertrudeKim","email":"rlagksk8428@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/101982606?v=4","key":"hanagertrudeKim"}],"frontMatter":{"date":"2024-04-16T00:00:00.000Z","authors":"hanagertrudeKim","title":"\uc778\ud3ec\uba54\uc774\ud2b8 5\uc8fc\ucc28 \uacf5\uc720(UX)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 5\uc8fc\ucc28 \uacf5\uc720(UX) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","keywords":["\uc778\ud3ec\uba54\uc774\ud2b8","UX"],"tags":["\uc778\ud3ec\uba54\uc774\ud2b8","UX"]},"unlisted":false,"prevItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 6\uc8fc\ucc28 \uacf5\uc720(\ucd5c\uc801\ud654)","permalink":"/front-end/GwakSeungJu/infomate-6week"},"nextItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 4\uc8fc\ucc28 \uacf5\uc720(\ud234)","permalink":"/front-end/GwakSeungJu/infomate-4week"}},"content":"\uc778\ud3ec\uba54\uc774\ud2b8 5\uc8fc\ucc28 \uacf5\uc720(UX) \ubaa8\uc74c\uc785\ub2c8\ub2e4.    \\n\\n\uc27d\uac8c \ub193\uce60 \uc218 \uc788\ub294 \ub354 \ub098\uc740 \ub85c\uadf8\uc778/\ud68c\uc6d0\uac00\uc785 UX \ud301 - \uacfd\uc2b9\uc8fc    \\n\uc0ac\uc6a9\uc790 \uce5c\ud654\uc801\uc778 \uc5d0\ub7ec \ucc98\ub9ac\ud558\uae30 - \uc724\ud574\uc9c4    \\n\ub85c\ub529 \uc2dc\uac04\uc5d0 \ub530\ub978 \ub2e4\ub978 \uc0ac\uc6a9\uc790 \uacbd\ud5d8 \ucc98\ub9ac - \uae40\ud558\ub098\\n\\n{/* truncate */}\\n\\nimport videoUrl from \\"../videos/scale-up.mp4\\";\\nimport ReactPlayer from \\"react-player\\";\\n\\n\\n# \uc27d\uac8c \ub193\uce60 \uc218 \uc788\ub294 \ub354 \ub098\uc740 \ub85c\uadf8\uc778/\ud68c\uc6d0\uac00\uc785 UX \ud301 - \uacfd\uc2b9\uc8fc\\n\\n## Intro\\n\\n\uc9c0\uae08\uae4c\uc9c0 \uc815\ub9d0 \ub9ce\uc740 \ub85c\uadf8\uc778, \ud68c\uc6d0\uac00\uc785\uc744 \ud574\uc624\uc168\uc744\ud150\ub370, \uadf8 \uacfc\uc815\uc5d0\uc11c \uc790\uc2e0\ub3c4 \ubaa8\ub974\uac8c \ubd88\ud3b8\ud588\ub358 \uacbd\ud5d8\uc774\ub098 \ud3b8\ud588\ub358 \uacbd\ud5d8\uc774 \uc788\uc73c\uc168\uc744 \uac83\uc785\ub2c8\ub2e4. \uc5c4\uccad \ud070 \ucc28\uc774\ub294 \uc5c6\uc5b4 \ub290\ub07c\uc9c0 \ubabb\ud558\uc168\uc744 \uc218\ub3c4 \uc788\uc9c0\ub9cc, \uc0ac\uc18c\ud55c \ucc28\uc774\ub97c \ud1b5\ud574 \uc0ac\uc6a9\uc790\uac00 \ub354 \ube60\ub974\uac8c \ud639\uc740 \ud3b8\ub9ac\ud558\uac8c \ub85c\uadf8\uc778, \ud68c\uc6d0\uac00\uc785\uc744 \ud560 \uc218 \uc788\uac8c \ub3c4\uc640\uc8fc\ub294 \ud301\uc744 \uc54c\ub824\ub4dc\ub9ac\ub824\uace0 \ud569\ub2c8\ub2e4.\\n\\n### 1. \uccab \ubc88\uc9f8 \ud544\ub4dc\uc5d0 autofocus\\n\\n\ub85c\uadf8\uc778 \ud398\uc774\uc9c0\ub098 \ud68c\uc6d0\uac00\uc785 \ud398\uc774\uc9c0\ub85c \uc774\ub3d9\ud558\uba74 \ubcf4\ud1b5\uc740 \uccab \uce78\uc744 \uc120\ud0dd\ud574 \uc785\ub825\ud558\uae30 \ub9c8\ub828\uc785\ub2c8\ub2e4. \uadf8\ub7ec\uae30 \uc704\ud574\uc11c\ub294 \uadf8 \uce78\uc744 \ud074\ub9ad\ud574\uc57c\ud558\ub294\ub370 \uadf8\ub7f0 \uc218\uace0\uc5c6\uc774 \uc790\ub3d9\uc73c\ub85c \uadf8 \uce78\uc744 \uc120\ud0dd\ud574\uc900\ub2e4\uba74 \ud3b8\ub9ac\ud558\uc9c0 \uc54a\uc744\uae4c\uc694? \uadf8 \ubc29\ubc95\uc73c\ub85c\ub294 `input` \ud0dc\uadf8\uc758 `autofocus` \uc18d\uc131\uc744 \uc0ac\uc6a9\ud558\uba74 \ub429\ub2c8\ub2e4.(\ub9ac\uc561\ud2b8\uc5d0\uc11c\ub294 `autoFocus` \uc0ac\uc6a9)\\n\\n```tsx\\n<input placeholder=\\"\uc544\uc774\ub514\ub97c \uc785\ub825\ud558\uc138\uc694\\" autoFocus />\\n```\\n\\n\u203b\ucc38\uace0: eslint\uc5d0\uc11c\ub294 \uc811\uadfc\uc131 \uad00\ub828 \uc6b0\ub824\ub85c autofocus \uc0ac\uc6a9\uc744 \uae08\uc9c0\ud569\ub2c8\ub2e4. `The autoFocus prop should not be used, as it can reduce usability and accessibility for users. eslint[(jsx-a11y/no-autofocus)](https://github.com/jsx-eslint/eslint-plugin-jsx-a11y/tree/HEAD/docs/rules/no-autofocus.md)`\\n\\n### 2. \ubaa8\ubc14\uc77c\uc6a9 \ud2b9\uc218 \ud0a4\ubcf4\ub4dc \uc124\uc815\ud558\uae30\\n\\n\ubaa8\ubc14\uc77c\uc758 \uacbd\uc6b0\uc5d0\uc11c \uc785\ub825 \uce78\uc744 \uc120\ud0dd \uc2dc\uc5d0 \ud0a4\ubcf4\ub4dc\uac00 \uc0dd\uc131\ub418\ub294\ub370 \uc785\ub825\ud560 \uac12\ub9cc \ub4e4\uc5b4\uc788\ub294 \ud0a4\ubcf4\ub4dc\uac00 \uc788\ub2e4\uba74 \uc815\ub9d0 \ud3b8\ub9ac\ud560 \uac83\uc785\ub2c8\ub2e4. \uc608\ub97c \ub4e4\uba74 \ud559\ubc88\uc774\ub098 \uc804\ud654\ubc88\ud638 \uac19\uc740 \uacbd\uc6b0 \uc22b\uc790\ub9cc \ud544\uc694\ud55c\ub370, \ubb38\uc790\ub3c4 \ud0a4\ubcf4\ub4dc\uc5d0 \ub4e4\uc5b4\uc788\uc5b4\uc11c \uc22b\uc790 \ud328\ub4dc\uac00 \uc791\uc544\uc9c0\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc22b\uc790\ub97c \ud130\uce58\ud558\uae30 \ubd88\ud3b8\ud560 \uac83\uc785\ub2c8\ub2e4. \uc774\ub97c \ud574\uacb0\ud558\uae30 \uc704\ud574, `input` \ud0dc\uadf8\uc758 `type` \uc18d\uc131\uc744 `num`, `tel`, `email`\ub85c \ud558\uc5ec \ud2b9\uc218 \ubaa8\ubc14\uc77c \ud0a4\ubcf4\ub4dc\uac00 \ub098\uc624\uac8c \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. `num`\uacfc `tel`\uc758 \uacbd\uc6b0\ub294 \uc22b\uc790\ub9cc \ub098\uc624\uac8c \ub418\uace0, `email`\uc758 \uacbd\uc6b0 \uae30\uc874 \ud0a4\ubcf4\ub4dc\uc5d0\ub294 \uc5c6\uc5c8\ub358 `@` \ub610\ub294 `.com`\uc774 \ub098\uc624\uac8c \ub429\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@frontEnd/infomate-5week/image01.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"20px\\" }} />\\n\\n### 3. \ube44\ubc00\ubc88\ud638 \uc694\uad6c\uc0ac\ud56d \ud45c\uc2dc\\n\\n\ud68c\uc6d0\uac00\uc785 \uc2dc \ubcf4\uc548\uc744 \uc704\ud574 \ube44\ubc00\ubc88\ud638\uc5d0 \ud2b9\uc218\ubb38\uc790 \ud558\ub098 \uc774\uc0c1, \uc22b\uc790 \ud558\ub098 \uc774\uc0c1, \uc804\uccb4 8\uae00\uc790 \uc774\uc0c1 \ub4f1\uc758 \uc694\uad6c\ub97c \ud560 \uac83\uc785\ub2c8\ub2e4. \ub530\ub77c\uc11c \uadf8 \uc694\uad6c\uc0ac\ud56d\uc744 \uc54c\ub824\uc8fc\uae30 \uc704\ud574 \ube44\ubc00\ubc88\ud638 \uc785\ub825\uce78 \uc544\ub798\uc5d0 \uc870\uac74\uc744 \ubcf4\uc5ec\uc918\uc57c \ud569\ub2c8\ub2e4. \ub9cc\uc57d \uadf8 \uc870\uac74\uc744 \ub9cc\uc871\ud588\ub2e4\uba74 \uc870\uac74\uc744 \ub9cc\uc871\ud588\ub2e4\ub294 \ud45c\uc2dc\ub97c \ud558\uac70\ub098, \uc870\uac74 \ud45c\uc2dc\ub97c \uc5c6\uc560\ub294 \uac83\uc740 \uc0ac\uc6a9\uc790\uac00 \uc798 \uc785\ub825\ud588\ub294\uc9c0 \ud655\uc778\ud560 \uc218 \uc788\ub294 \ubc29\ubc95\uc774 \ub429\ub2c8\ub2e4.\\n\\n### 4. \ube44\ubc00\ubc88\ud638 \ud655\uc778\\n\\n\ud68c\uc6d0\uac00\uc785 \uc2dc \uc0ac\uc6a9\uc790\uac00 \ube44\ubc00\ubc88\ud638\ub97c \uc62c\ubc14\ub974\uac8c \ucce4\ub294\uc9c0 \ud655\uc778\ud558\uae30 \uc704\ud574 \ube44\ubc00\ubc88\ud638\ub97c \ub450 \ubc88 \uc785\ub825\ud558\uac8c \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \uc0ac\uc6a9\uc790 \uc785\uc7a5\uc5d0\uc11c\ub294 \uc790\uc2e0\uc774 \uc785\ub825\ud55c \ube44\ubc00\ubc88\ud638\ub97c \ubcfc \uc218 \uc788\uac8c \ud558\ub294 \uac83\uc774 \ube44\ubc00\ubc88\ud638\ub97c \ub450 \ubc88 \uc785\ub825\ud558\ub294 \uac83\ubcf4\ub2e4 \ub35c \ubc88\uac70\ub85c\uc6b8 \uac83\uc785\ub2c8\ub2e4. \uadf8 \ubc29\ubc95\uc73c\ub85c\ub294 `input\uc758 type \uc18d\uc131`\uc774 `password`\ub85c \ub418\uc5b4\uc788\ub294 \uac83\uc744 `text`\ub85c\ub9cc \ubc14\uafb8\uba74 \ub429\ub2c8\ub2e4. \uadf8 \ubc29\ubc95\uc740 \uc544\ub798\uc640 \uac19\uc2b5\ub2c8\ub2e4.\\n\\n```tsx\\n  const [isShowPwChecked, setShowPwChecked] = useState(false);\\n\\n  const handleShowPwChecked = () => {\\n    const { password } = loginRef.current;\\n    if (password === null) return;\\n\\n    setShowPwChecked(!isShowPwChecked);\\n    if (!isShowPwChecked) {\\n      password.type = \'text\';\\n    } else {\\n      password.type = \'password\';\\n    }\\n  };\\n```\\n\\n\uadf8\ub9ac\uace0 \uc544\ub798 \uc694\uc18c\ub97c \ub123\uc5b4\uc8fc\uba74 \ub2e4\uc74c\uacfc \uac19\uc774 \ub098\ud0c0\ub0bc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n```tsx\\n<div className=\\"show_password_button\\">\\n   <label>\\n      <input type=\\"checkbox\\" onChange={handleShowPwChecked} />\\n      <span className=\\"show_password_title\\">\ube44\ubc00\ubc88\ud638 \ubcf4\uae30</span>\\n   </label>\\n</div>\\n```\\n\\n<img src=\\"/img/@frontEnd/infomate-5week/image02.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"20px\\" }} />\\n\\n### 5. Sign-in\uacfc Sign-up \uac19\uc774 \uc0ac\uc6a9\ud558\uc9c0 \ub9d0\uae30\\n\\n`Log in`\uacfc \uac19\uc740 \uc758\ubbf8\uc778 `Sign in`\uc744 \ud68c\uc6d0\uac00\uc785\uc744 \ub73b\ud558\ub294 `Sign up`\uacfc \uac19\uc774 \ubcf4\uc5ec\uc8fc\uac8c \ub418\uba74 \uc0ac\uc6a9\uc790 \uc785\uc7a5\uc5d0\uc11c\ub294 \ud5f7\uac08\ub9b4 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc601\ubb38\uc774 \uc775\uc219\uce58 \uc54a\uc740 \ud55c\uad6d\uc778\uc5d0\uac8c\ub294 \ub354\ub354\uc6b1 \ud5f7\uac08\ub9b4 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ub530\ub77c\uc11c \uc6b0\ub9ac\ub098\ub77c \ub9d0\ub85c\ub294 `\u2018\ub85c\uadf8\uc778 / \ud68c\uc6d0\uac00\uc785\u2019` \uc774\ub77c\ub294 \ub9d0\ub85c \ub300\uccb4\ud560 \uc218 \uc788\uace0, \ub9cc\uc57d \uc601\ubb38\uc73c\ub85c \ud45c\ud604\ud574\uc57c\ud55c\ub2e4\uba74 `Register / Sign in`, `Create account / Log in`, `Sign up / Log in` \ub4f1\uc73c\ub85c \ud45c\ud604\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### 6. \ub85c\uadf8\uc778 \ucc3d\uacfc \ud68c\uc6d0\uac00\uc785 \ucc3d \uac04 \uc26c\uc6b4 \uc774\ub3d9\\n\\n\ub9cc\uc57d \ub85c\uadf8\uc778 \ubc84\ud2bc\uc774\ub098 \ud68c\uc6d0\uac00\uc785 \ubc84\ud2bc\uc744 \uc798\ubabb \ub20c\ub7ec\uc11c \ud398\uc774\uc9c0 \uc774\ub3d9\uc774 \ub418\uc5c8\ub2e4\uba74 \uc0ac\uc6a9\uc790\ub294 \ub4a4\ub85c\uac00\uae30\ub97c \ud558\uace0 \ub2e4\uc2dc \uc6d0\ud558\ub294 \ubc84\ud2bc\uc744 \ud074\ub9ad\ud574\uc57c\ud560 \uac83\uc785\ub2c8\ub2e4. \uc774\ub7f0 \ubc88\uac70\ub85c\uc6c0\uc744 \ubc29\uc9c0\ud558\uae30 \uc704\ud574 \ub85c\uadf8\uc778 \ud398\uc774\uc9c0\uc5d0\uc11c\ub294 \ud68c\uc6d0\uac00\uc785 \ud398\uc774\uc9c0\ub85c \uc774\ub3d9\ud560 \uc218 \uc788\uac8c, \ud68c\uc6d0\uac00\uc785 \ud398\uc774\uc9c0\uc5d0\uc11c\ub294 \ub85c\uadf8\uc778 \ud398\uc774\uc9c0\ub85c \uc774\ub3d9\ud560 \uc218 \uc788\uac8c \ud558\uba74 \uc88b\uc744 \uac83\uc785\ub2c8\ub2e4. \uc608\ub97c \ub4e4\uc5b4, \ud68c\uc6d0\uac00\uc785 \ud398\uc774\uc9c0\uc5d0\uc11c\ub294 `\uc774\ubbf8 \uacc4\uc815\uc774 \uc788\uc73c\uc2e0\uac00\uc694? **Log in**` \uc774\ub77c \ud45c\uc2dc\ud560 \uc218 \uc788\uace0, \ub85c\uadf8\uc778 \ud398\uc774\uc9c0\uc5d0\uc11c\ub294 `\uacc4\uc815\uc774 \uc5c6\uc73c\uc2e0\uac00\uc694? **Sign up**`\uc774\ub77c \ud45c\uc2dc\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc544\ub2c8\uba74 \uac04\ub2e8\ud558\uac8c `\uc544\uc774\ub514 \ucc3e\uae30 | \ube44\ubc00\ubc88\ud638 \ucc3e\uae30 | \ud68c\uc6d0\uac00\uc785`\uc73c\ub85c \ub098\ud0c0\ub0bc \uc218\ub3c4 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n# \uc0ac\uc6a9\uc790 \uce5c\ud654\uc801\uc778 \uc5d0\ub7ec \ucc98\ub9ac\ud558\uae30 - \uc724\ud574\uc9c4\\n\\n## \ub4e4\uc5b4\uac00\ub294 \ub9d0\\n\\n\uc0ac\uc774\ud2b8\ub97c \uc774\uc6a9\uc744 \ud558\uba70 \uc5b4\ub5a0\ud55c \uc5d0\ub7ec\ub97c \uc9c1\uba74\ud558\ub294 \uc0c1\ud669\uc740 \ub9ce\uc774 \uacaa\uc5b4\ubcf4\uc168\uc744 \uac83\uc774\ub77c\uace0 \uc0dd\uac01\ud569\ub2c8\ub2e4.\\n\\n\uc5ec\uae30\uc11c \uc5d0\ub7ec\uac00 \ub0ac\uc744 \ub54c\uc758 \uc801\uc808\ud55c \uc0ac\uc774\ud2b8\uc758 \ub300\uc751\uc5d0 \ub530\ub77c \uc0ac\uc6a9\uc790 \uacbd\ud5d8\uc758 \ucc28\uc774\uac00 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4. \ub610\ud55c \uc774\uac83\uc740 \uc0ac\uc774\ud2b8\uc758 \uc644\uc131\ub3c4\uc5d0\ub3c4 \uc601\ud5a5\uc744 \ubbf8\uce60 \uac83\uc774\ub77c \uc0dd\uac01\ud569\ub2c8\ub2e4.\\n\\n\uc0ac\uc6a9\uc790\uac00 \ud574\uacb0\uc744 \ud560 \uc218 \uc788\uc74c\uacfc \uc5c6\uc74c, \uc758\ub3c4\uac00 \ub41c, \ub418\uc9c0 \uc54a\uc740 \uc5d0\ub7ec\uc758 \ucc28\uc774\uc810\uc5d0 \ub300\ud574 \uc774\uc57c\uae30\ud574 \ubcf4\uace0 BCSD\uc758 \uc11c\ube44\uc2a4\uc5d0\uc11c\ub294 \uc5b4\ub5a0\ud55c \ubc29\ud5a5\uc73c\ub85c \uc0ac\uc6a9\ud574 \ubcfc  \uc218 \uc788\uc744\uc9c0 \uc801\uc5b4\ubcf4\ub824 \ud569\ub2c8\ub2e4.\\n\\n## 1) \uc5b4\ub5a4 \uc5d0\ub7ec\uac00 \ubc1c\uc0dd\ud560 \uc218 \uc788\uc744\uae4c\uc694? :\\n\\n\ud06c\uac8c \ub098\ub204\uc5b4 **\ud658\uacbd, \uc0ac\uc6a9\uc790**\uc640\uc758 \uc5d0\ub7ec\ub85c \ub098\ub204\uace0 \uc138\ubd80\uc801\uc73c\ub85c\ub294 \ub450 \ud0c0\uc785\uc73c\ub85c \ub098\ub20c \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n**[\ud658\uacbd\uacfc \uc5d0\ub7ec]**\\n\\n1) \uc758\ub3c4\uac00 \ub41c \uc5d0\ub7ec(\uc608\uc0c1 \uac00\ub2a5\ud55c \uc5d0\ub7ec)\\n\\n2) \uc758\ub3c4\uac00 \ub418\uc9c0 \uc54a\uc740 \uc5d0\ub7ec(\uc608\uc0c1\ud558\uc9c0 \ubabb\ud55c \uc5d0\ub7ec)\\n\\n---\\n\\n**[\uc0ac\uc6a9\uc790\uc640 \uc5d0\ub7ec]**\\n\\n3) \uc0ac\uc6a9\uc790\uac00 \ud574\uacb0\ud560 \uc218 \uc788\ub294 \uc5d0\ub7ec\\n\\n4) \uc0ac\uc6a9\uc790\uac00 \ud574\uacb0\ud558\uc9c0 \ubabb\ud558\ub294 \uc5d0\ub7ec\\n\\n\uc608\uc2dc\ub97c \ub4e4\uc5b4 \uc704 \uc5d0\ub7ec\ub97c \uc124\uba85\ud574\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n- **\uc758\ub3c4\uac00 \ub41c \uc5d0\ub7ec(\uc608\uc0c1 \uac00\ub2a5\ud55c \uc5d0\ub7ec):**\\n    \\n    \ub85c\uadf8\uc778\uc744 \ud558\uc9c0 \uc54a\uc544 \uc778\uc99d\uc774 \ub418\uc9c0 \uc54a\uc740 \uacc4\uc815\uc73c\ub85c \ub85c\uadf8\uc778\uc774 \ud544\uc694\ud55c \ud398\uc774\uc9c0\uc5d0 \uc811\uadfc\uc744 \ud560 \ub54c\uc5d0\ub294 \uc11c\ubc84\uc5d0\uc11c 401 Error\ub97c \ub0b4\uace4 \ud569\ub2c8\ub2e4.\\n    \\n    \ub610\ud55c \uc798\ubabb\ub41c \uc811\uadfc\uc744 \uc2dc\ub3c4\ud588\uc744 \ub550 403 Error\ub97c \ub0b4\uace4 \ud569\ub2c8\ub2e4. \\n    \\n    \uadf8 \uc678\uc5d0\ub3c4 \ub3c4\uba54\uc778 \ud2b9\uc131\uc5d0 \ub530\ub77c \uc0ac\uc804\uc5d0 \uc870\uc728\uc774 \ub418\uc5b4\uc788\ub294 \uc5d0\ub7ec\uac00 \uc788\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n- **\uc758\ub3c4 \ub418\uc9c0 \uc54a\uc740 \uc5d0\ub7ec(\uc608\uc0c1\ud558\uc9c0 \ubabb\ud55c \uc5d0\ub7ec):**\\n    \\n    \uc11c\ubc84\uc5d0\uc11c \ub0b4\ub294 500\ub300\uc758 error\ub294 \uc758\ub3c4 \ub418\uc9c0 \uc54a\uc740 \uc5d0\ub7ec\ub77c \ud310\ub2e8\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n    \uc5b8\uc81c \uc5b4\ub514\uc11c \ub098\ud0c0\ub0a0\uc9c0\ub3c4 \ubaa8\ub974\uace0 \uc5b4\ub290 \ubd80\ubd84\uc5d0\uc11c \uc77c\uc9c0 \uc608\uce21 \ubd88\uac00\ub2a5\ud558\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4.\\n    \\n    \uadf8\ub9ac\uace0 \uc0ac\uc6a9\uc790\uc758 \ub124\ud2b8\uc6cc\ud06c \ud658\uacbd\uc5d0 \ub530\ub77c \ubc1c\uc0dd\ud560 \uc218 \uc788\ub294 \uc5d0\ub7ec, \uc0ac\uc6a9\uc790\uc758 \ube0c\ub77c\uc6b0\uc800 \ud658\uacbd\uc5d0\uc11c \ubc1c\uc0dd\ud560 \uc218 \uc788\ub294 \uc5d0\ub7ec\ub294 \uc608\uce21\ud558\uae30 \uc5b4\ub835\uae30 \ub54c\ubb38\uc5d0 \uc758\ub3c4 \ub418\uc9c0 \uc54a\uc740(\uc608\uce21\ud560 \uc218 \uc5c6\ub294 \uc5d0\ub7ec)\ub85c \ubd84\ub9ac\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n- **\uc0ac\uc6a9\uc790\uac00 \ud574\uacb0\ud560 \uc218 \uc788\ub294 \uc5d0\ub7ec:**\\n    \\n    \ub9cc\uc57d \ub85c\uadf8\uc778\uc774 \ud544\uc694\ud55c \ud398\uc774\uc9c0\uc5d0 \ub85c\uadf8\uc778\uc774 \ub418\uc9c0 \uc54a\uc740 \uc0c1\ud0dc\uc5d0\uc11c \uc811\uadfc\uc744 \ud558\uac8c \ub418\uc5c8\ub2e4\uba74 \uc0ac\uc6a9\uc790\ub294 401 \uacfc \uad00\ub828\ub41c \uc5d0\ub7ec\ub97c \ub9c8\uc8fc\ud560 \uac83\uc785\ub2c8\ub2e4. \uc774\ub54c\ub294 \ub85c\uadf8\uc778\uc744 \ud568\uc73c\ub85c \ud574\ub2f9 \uc5d0\ub7ec\ub97c \ucc98\ub9ac\ud560 \uc218 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4. \\n    \\n    \ub610\ud55c \ub124\ud2b8\uc6cc\ud06c\uac00 \uc88b\uc9c0 \uc54a\uc740 \uac83\uc5d0 \ub300\ud55c \uc774\uc288\ub77c\uba74 \ub124\ud2b8\uc6cc\ud06c \uc124\uc815\uc744 \ud655\uc778\ud55c\ub2e4 \ub4f1\uc73c\ub85c \uc0ac\uc6a9\uc790\uc758 \uc561\uc158\uc744 \ud1b5\ud574 \uc5d0\ub7ec\uac00 \ud574\uacb0 \uac00\ub2a5\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n- **\uc0ac\uc6a9\uc790\uac00 \ud574\uacb0\ud560 \uc218 \uc5c6\ub294 \uc5d0\ub7ec:**\\n    \\n    \uadf8\ub7ec\ub098 \uc0ac\uc6a9\uc790\uc5d0\uac8c \uc5b4\ub5a4\ud55c \uc5d0\ub7ec \uc0c1\ud669\uc778\uc9c0\ub97c \ub9d0\ud574\uc8fc\uc5b4\ub3c4 \uc561\uc158\uc744 \ucde8\ud560 \uc218  \uc5c6\ub294 \uacbd\uc6b0\uac00 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n    \uc0ac\uc6a9\uc790\uac00 \uc0ac\uc6a9\ud558\ub294 \uae30\uae30\uc5d0\uc11c\ub294 \uc9c0\uc6d0\ud558\uc9c0 \uc54a\ub294 \uc0c1\ud669 \ud639\uc740 \ub354 \uc774\uc0c1 \ud574\ub2f9 \uae30\ub2a5\uc744 \uc81c\uacf5\ud558\uc9c0 \uc54a\ub294 \uacbd\uc6b0 \ub4f1\uc774 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4.\\n    \\n\\n<img src=\\"/img/@frontEnd/infomate-5week/image03.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"20px\\" }} />\\n\\n\ucd9c\ucc98: [https://www.jbee.io/articles/react/\ud074\ub77c\uc774\uc5b8\ud2b8\uc758 \uc0ac\uc6a9\uc790 \uc911\uc2ec \uc608\uc678 \ucc98\ub9ac](https://www.jbee.io/articles/react/%ED%81%B4%EB%9D%BC%EC%9D%B4%EC%96%B8%ED%8A%B8%EC%9D%98%20%EC%82%AC%EC%9A%A9%EC%9E%90%20%EC%A4%91%EC%8B%AC%20%EC%98%88%EC%99%B8%20%EC%B2%98%EB%A6%AC)\\n\\n\uc704\uc758 \uc0ac\uc9c4\uc774 \uc55e\uc11c \uc124\uba85\ud55c \uc5d0\ub7ec\uc758 \uacbd\uc6b0\uc5d0 \ub300\ud574\uc11c \ubcf4\uae30 \uc88b\uac8c \ud45c\ud604\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n## 2) \uc5b4\ub5a4 \ubc29\uc2dd\uc73c\ub85c \uc0ac\uc6a9\uc790\uc5d0\uac8c \uce5c\uc808\ud55c \uc5d0\ub7ec\ub97c \ud45c\ud604\ud560 \uc218 \uc788\uc744\uae4c\uc694?\\n\\n- **\uc608\uc0c1\ud560 \uc218 \uc5c6\uace0, \ud574\uacb0 \ubc29\ubc95\uc774 \uc788\ub294 \uc5d0\ub7ec**\\n    \\n    \uc608\uc2dc\ub85c **\ub124\ud2b8\uc6cc\ud06c \uc5d0\ub7ec**\uc758 \uacbd\uc6b0\ub97c \ub4e4 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n    \uc774\uc758 \uacbd\uc6b0 \ub124\ud2b8\uc6cc\ud06c \ud658\uacbd\uc744 \ud655\uc778\ud558\ub77c\ub294 \uc548\ub0b4 \ubb38\uad6c\ub97c \uc81c\uc2dc\ud558\ub294 \ubc29\ud5a5\uc73c\ub85c \uc0ac\uc6a9\uc790\uc758 \uc5d0\ub7ec\uc5d0 \ub300\ud55c \uc6d0\uc778\uacfc \uc561\uc158\uc744 \uc81c\uc548\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n- **\uc608\uc0c1\ud560 \uc218 \uc5c6\uace0, \ud574\uacb0 \ubc29\ubc95\uc774 \uc5c6\ub294 \uc5d0\ub7ec**\\n    \\n    \uc774 \ubd80\ubd84\uc740 \uac1c\ubc1c \ub2e8\uacc4\uc5d0\uc11c \uaf3c\uaf3c\ud788 \uccb4\ud06c\ud558\uc5ec \uc0ac\uc6a9\uc790\uac00 \uc704\uc640 \uac19\uc740 \uc5d0\ub7ec\ub97c \uc9c1\uba74\ud558\uc9c0 \uc54a\uac8c \ud558\ub294 \uac83\uc774 \uc81c\uc77c \uc88b\uc740 \ub300\uc751\ubc95\uc77c \uac83\uc785\ub2c8\ub2e4.\\n    \\n    \uadf8\ub7fc\uc5d0\ub3c4 \ubd88\uad6c\ud558\uace0 \uc704\uc640 \uac19\uc740 \uc5d0\ub7ec\ub97c \uc0ac\uc6a9\uc790\uac00 \ubcf4\uc558\uc744 \uacbd\uc6b0\uc5d0\ub294 \uace0\uac1d \uc13c\ud130 \ubc0f \ubb38\uc758 \ucc44\ub110 \uc9c4\uc785\ub85c\ub97c \uc548\ub0b4\ud558\ub294 \uc561\uc158\uc744 \ucde8\ud560 \uc218 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4.\\n    \\n- **\uc608\uc0c1\ud560 \uc218 \uc788\uace0, \ud574\uacb0 \ubc29\ubc95\uc774 \uc788\ub294 \uc5d0\ub7ec**\\n    \\n    \uc774\ub294 \uae30\ud68d \ud30c\ud2b8\uc5d0\uc11c \uc124\uacc4\ub41c \ubd80\ubd84\uc77c \uac83\uc785\ub2c8\ub2e4.\\n    \\n    \uc704\uc758 \uacbd\uc6b0\uc5d0\ub294 \uc5d0\ub7ec\uc758 \uacbd\uc6b0\uc5d0 \ub9de\uac8c \uc124\uacc4\ub41c \ub85c\uc9c1\uc744 \ub530\ub974\uba74 \ub420 \uac83\uc785\ub2c8\ub2e4.\\n    \\n    -\ub85c\uadf8\uc778 \ud544\uc694\ud55c 401 \u21d2 \ub85c\uadf8\uc778 \ud398\uc774\uc9c0\ub85c \uc774\ub3d9\\n    \\n    -\uc798\ubabb\ub41c \ud398\uc774\uc9c0 \uc811\uadfc 404 \u21d2 \uba54\uc778 \ud639\uc740 \ub79c\ub529 \ud398\uc774\uc9c0\ub85c \uc774\ub3d9\\n    \\n- **\uc608\uc0c1\ud560 \uc218 \uc788\uace0, \ud574\uacb0 \ubc29\ubc95\uc774 \uc5c6\ub294 \uc5d0\ub7ec**\\n    \\n    \uc608\uc0c1\uc740 \ud560 \uc218 \uc788\uc9c0\ub9cc \ud574\uacb0\ud560 \ubc29\ubc95\uc774 \uc5c6\ub2e4\ub294 \uac83\uc740 \uae30\ud68d \uac1c\ubc1c\ub2e8\uc5d0\uc11c \ub193\uce5c \uc5d0\ub7ec\uac00 \uc788\ub2e4\ub294 \uac83\uc774\ub77c \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ud639\uc740 \uc0ac\uc6a9\uc790\uac00 \uace0\uc758\uc801\uc73c\ub85c \ube44\uc815\uc0c1\uc801\uc778 \uc811\uadfc\uc744 \ud55c \uacbd\uc6b0\ub85c\ub3c4 \ud30c\uc545\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ub530\ub77c\uc11c \ud574\ub2f9 \uc5d0\ub7ec\ub294 \ubcf4\uc548\uc0c1\uc758 \ud5c8\uc810 \ubc0f \uc5d0\ub7ec \uacbd\uc6b0\uc758 \uc218\ub97c \ubcf4\uc644\ud574\uc57c \ud560 \uac83\uc785\ub2c8\ub2e4.\\n    \\n\\n<img src=\\"/img/@frontEnd/infomate-5week/image04.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"20px\\" }} />\\n\\n\ucd9c\ucc98: [https://www.jbee.io/articles/react/\ud074\ub77c\uc774\uc5b8\ud2b8\uc758 \uc0ac\uc6a9\uc790 \uc911\uc2ec \uc608\uc678 \ucc98\ub9ac](https://www.jbee.io/articles/react/%ED%81%B4%EB%9D%BC%EC%9D%B4%EC%96%B8%ED%8A%B8%EC%9D%98%20%EC%82%AC%EC%9A%A9%EC%9E%90%20%EC%A4%91%EC%8B%AC%20%EC%98%88%EC%99%B8%20%EC%B2%98%EB%A6%AC)\\n\\n## 3) \uc6b0\ub9ac \uc11c\ube44\uc2a4\uc5d0 \uc5b4\ub5a4 \uc2dd\uc73c\ub85c \ub179\uc5ec\ubcfc \uc218 \uc788\uc744\uae4c\uc694?\\n\\n**Koin(\ucf54\uc778)**\uc73c\ub85c \uc608\uc2dc\ub97c \ub4e4\uc5b4\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n- **\ubc84\uc2a4/\uad50\ud1b5 PART**\\n    \\n    \ub9cc\uc57d \ubc84\uc2a4/\uad50\ud1b5 \ubd80\ubd84\uc5d0\uc11c API\uc758 500 ERROR\uac00 \uc624\uace0 \uc788\ub294 \uacbd\uc6b0\uc5d0 \uc5b4\ub5a4 \uc2dd\uc73c\ub85c \uc704 \ubc29\ubc95\uc744 \ud65c\uc6a9\ud560 \uc218 \uc788\uc744\uae4c\uc694?\\n    \\n    \uc81c \uc0dd\uac01\uc5d0\ub294 \uc774\ub294 \uc608\uc0c1\ud558\uc9c0 \ubabb\ud55c \uadf8\ub9ac\uace0 \uc0ac\uc6a9\uc790\uac00 \ud574\uacb0\ud558\uc9c0 \ubabb\ud558\ub294 \uc5d0\ub7ec\uc77c \uac83\uc785\ub2c8\ub2e4.\\n    \\n    \ub530\ub77c\uc11c \uc11c\ubc84 error\uac00 \uc624\ub294 API\ub97c \ud65c\uc6a9\ud558\ub294 \ubd80\ubd84\uc5d0 **Error Boundaries** \ub4f1\uc744 \ud65c\uc6a9\ud558\uc5ec \u201c\uc11c\ubc84\uc5d0 \uc5d0\ub7ec\uac00 \ubc1c\uc0dd\ud558\uc600\ub2e4 \ube60\ub974\uac8c \uc218\uc815\ud558\uaca0\ub2e4.\u201d\ub77c\ub294 \ub0b4\uc6a9\uc744 \ub2f4\uc740 \uc548\ub0b4 \ubb38\uad6c\ub97c \ub744\uc6b0\ub294 \ubc29\uc2dd\uc73c\ub85c \ubcf4\ub2e4 \uc0ac\uc6a9\uc790\uc5d0\uac8c \ud655\uc2e4\ud55c \uc804\ub2ec\uc744 \ud560 \uc218 \uc788\uc744 \uac83\uc774\ub77c\uace0 \ud310\ub2e8\ub429\ub2c8\ub2e4.\\n    \\n- **\uc2dc\uac04\ud45c PART**\\n    \\n    \ub9cc\uc57d \uc2dc\uac04\ud45c\uc5d0 \uc0c8\ub85c\uc6b4 \uae30\ub2a5\uc774 \ucd94\uac00\ub418\uc5c8\ub2e4\ub294 \uac00\uc815\uc744 \ud574\ubd05\uc2dc\ub2e4.\\n    \\n    \uadf8\ub7ec\ub098 \ud574\ub2f9 \uae30\ub2a5\uc5d0\uc11c\ub294 \ubb34\uc870\uac74 \uc801\uc778 \ud68c\uc6d0\ub9cc \uc811\uadfc \uac00\ub2a5\ud558\ub2e4\ub294 \uae30\ud68d\uc785\ub2c8\ub2e4.\\n    \\n    \uc774 \uacbd\uc6b0\uc5d0 \ub85c\uadf8\uc778\uc744 \ud558\uc9c0 \uc54a\uc740 \uc0ac\uc6a9\uc790\uac00 \ud574\ub2f9 \ud398\uc774\uc9c0 \ud639\uc740 \uae30\ub2a5\uc5d0 \uc811\uadfc\ud558\ub824\uace0 \ud558\uc600\ub2e4\uba74 \uc774\ub294 \uc608\uc0c1 \uac00\ub2a5\ud55c, \uc0ac\uc6a9\uc790\uac00 \ud574\uacb0 \uac00\ub2a5\ud55c \uc5d0\ub7ec\uc77c \uac83\uc785\ub2c8\ub2e4.\\n    \\n    \ub530\ub77c\uc11c \uc811\uadfc\uc744 \ud558\uc600\uc744 \ub54c \ub85c\uadf8\uc778\uc774 \ud544\uc694\ud55c \uae30\ub2a5\uc774\ub2e4. \ub85c\uadf8\uc778 \ud639\uc740 \ud68c\uc6d0\uac00\uc785\uc744 \ud574\ub77c. \uc640 \uac19\uc740 \ud50c\ub85c\uc6b0\ub85c \uc0ac\uc6a9\uc790\ub97c \uc720\ub3c4\ud558\ub294 \uc561\uc158\uc774 \ud544\uc694\ud560 \uac83\uc785\ub2c8\ub2e4.\\n    \\n\\n**\uc694\uc57d**\\n\\n- \uc5d0\ub7ec\ub97c \ud06c\uac8c \ubd84\ub958\ud558\uc790\uba74 \uc544\ub798\uc640 \uac19\ub2e4.\\n    \\n    1) \uc758\ub3c4\uac00 \ub41c \uc5d0\ub7ec(\uc608\uc0c1 \uac00\ub2a5\ud55c \uc5d0\ub7ec)\\n    \\n    2) \uc758\ub3c4\uac00 \ub418\uc9c0 \uc54a\uc740 \uc5d0\ub7ec(\uc608\uc0c1\ud558\uc9c0 \ubabb\ud55c \uc5d0\ub7ec)\\n    \\n    3) \uc0ac\uc6a9\uc790\uac00 \ud574\uacb0\ud560 \uc218 \uc788\ub294 \uc5d0\ub7ec\\n    \\n    4) \uc0ac\uc6a9\uc790\uac00 \ud574\uacb0\ud558\uc9c0 \ubabb\ud558\ub294 \uc5d0\ub7ec\\n    \\n- \uac01\uac01\uc758 \uc5d0\ub7ec \uc0c1\ud669\uc5d0 \ub9de\uac8c \uc801\uc808\ud55c \uc0ac\uc6a9\uc790\uc758 \uc561\uc158 \uc720\ub3c4\uac00 \ud544\uc694\ud558\ub2e4.\\n\\n\ucc38\uace0 \uae00\\n\\nhttps://toss.tech/article/how-to-write-error-message\\n\\n[https://www.jbee.io/articles/react/\ud074\ub77c\uc774\uc5b8\ud2b8\uc758 \uc0ac\uc6a9\uc790 \uc911\uc2ec \uc608\uc678 \ucc98\ub9ac](https://www.jbee.io/articles/react/%ED%81%B4%EB%9D%BC%EC%9D%B4%EC%96%B8%ED%8A%B8%EC%9D%98%20%EC%82%AC%EC%9A%A9%EC%9E%90%20%EC%A4%91%EC%8B%AC%20%EC%98%88%EC%99%B8%20%EC%B2%98%EB%A6%AC)\\n\\n\\n# \ub85c\ub529 \uc2dc\uac04\uc5d0 \ub530\ub978 \ub2e4\ub978 \uc0ac\uc6a9\uc790 \uacbd\ud5d8 \ucc98\ub9ac - \uae40\ud558\ub098\\n\\n\ud504\ub85c\uadf8\ub798\uc2a4 \ubc14\ub098 \ub85c\ub529 \uc2a4\ud53c\ub108\uc640 \uac19\uc740 UI \uc694\uc18c\ub294 \uc0ac\uc6a9\uc790\uac00 \ud604\uc7ac \uc791\uc5c5 \uc0c1\ud0dc\ub97c \ud30c\uc545\ud558\uace0 \ubd88\ud655\uc2e4\uc131\uc744 \uc904\uc5ec\uc8fc\uc5b4 \ud504\ub85c\uc138\uc2a4\ub97c \ub354 \uc27d\uac8c \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \ub3c4\uc640\uc90d\ub2c8\ub2e4. \uc774\ub85c\uc368 \uc0ac\uc6a9\uc790\ub294 \ub354\uc6b1 \ub9cc\uc871\uc2a4\ub7ec\uc6b4 \uacbd\ud5d8\uc744 \ud560 \uc218 \uc788\uac8c \ub429\ub2c8\ub2e4.\\n\\n\uc800\ud76c \uc11c\ube44\uc2a4\uc5d0\uc11c\ub3c4 \ub370\uc774\ud130 Fetching \uc2dc \uac78\ub9ac\ub294 \uc2dc\uac04\uc744 \ubcf4\uc5ec\uc8fc\uae30 \uc704\ud574 Suspense\ub97c \uc0ac\uc6a9\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \uc774\ub7ec\ud55c \ubc29\ubc95\uc774 \uc2e4\uc81c\ub85c \uc0ac\uc6a9\uc790 \uacbd\ud5d8\uc744 \ud5a5\uc0c1\uc2dc\ud0a4\uace0 \uc788\ub294\uc9c0 \uc758\ubb38\uc785\ub2c8\ub2e4.\\n\\n##Progress Indicator \uc5d0 \uad00\ud55c \ub9ac\uc11c\uce58\\n\\n\uc138\uacc4\uc801\uc778 UX \uc5f0\uad6c\uc790 \ub2d0\uc2a8 \ub180\uba3c\uc758 \uc9c0\uce68\uc744 \uc0b4\ud3b4\ubcf4\uba74 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.\\n\\n- **1\ucd08 \uc774\uc0c1 \uac78\ub9ac\ub294 \uc791\uc5c5\uc5d0\ub294 Progress Indicator\ub97c \uc0ac\uc6a9\ud569\ub2c8\ub2e4. \uc791\uc5c5\uc774 1\ucd08 \ubbf8\ub9cc\uc5d0 \uc644\ub8cc\ub418\ub294 \uacbd\uc6b0 \ubc18\ubcf5\ub418\ub294 \uc560\ub2c8\uba54\uc774\uc158\uc740 \uc0ac\uc6a9\ud558\uc9c0 \uc54a\ub294 \uac83\uc774 \uc88b\uc2b5\ub2c8\ub2e4.**\\n- \ub85c\ub529 \uc2a4\ud53c\ub108\uc640 \uac19\uc740 \uc694\uc18c\ub294 2~9\ucd08\uc758 \uc9c0\uc5f0 \uc2dc\uc5d0\ub9cc \uc0ac\uc6a9\ud569\ub2c8\ub2e4.\\n- \uc644\ub8cc\uc728 \uc560\ub2c8\uba54\uc774\uc158\uc740 10\ucd08 \uc774\uc0c1 \uc18c\uc694\ub418\ub294 \uc791\uc5c5\uc5d0 \uc0ac\uc6a9\ud569\ub2c8\ub2e4.\\n- \ube60\ub978 \uc751\ub2f5\uc774 \uac00\uc7a5 \uc774\uc0c1\uc801\uc774\uc9c0\ub9cc, \uc11c\ubc84 \uc5c5\uadf8\ub808\uc774\ub4dc\ub85c \uc778\ud574 \uc2dc\uc2a4\ud15c \uc18d\ub3c4\uac00 \ub290\ub824\uc9c8 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ub530\ub77c\uc11c \uc791\uc5c5\uc774 10\ucd08 \uc774\uc0c1 \uc18c\uc694\ub420 \uacbd\uc6b0 \uc0ac\uc6a9\uc790\uc5d0\uac8c \uc644\ub8cc \uc608\uc0c1 \uc2dc\uac04\uc744 \ud45c\uc2dc\ud574\uc57c \ud569\ub2c8\ub2e4.\\n- \uc815\uc801\uc778 \uc9c4\ud589\ub960 \ud45c\uc2dc\ub294 \ud53c\ud558\ub294 \uac83\uc774 \uc88b\uc2b5\ub2c8\ub2e4. (\uc608: \ud654\uba74\uc5d0 \ub2e8\uc21c\ud788 \\"...\ub85c\ub4dc \uc911\\" \ud14d\uc2a4\ud2b8\ub9cc \ud45c\uc2dc)\\n\\n\uc774\ub7ec\ud55c \uc9c0\uce68\uc744 \uace0\ub824\ud558\uba74 \ub85c\ub529 \uc2dc\uac04\uc5d0 \ub530\ub77c \ub2e4\ub978 \ub85c\ub529 \uacbd\ud5d8\uc744 \uc81c\uacf5\ud558\ub294 \uac83\uc774 \ubc14\ub78c\uc9c1\ud569\ub2c8\ub2e4.\\n\\n\ub610\ud55c, \ubaa8\ub4e0 \uacbd\uc6b0\uac00 \uc544\ub2cc 1\ucd08 \uc774\uc0c1 \uc9c0\uc5f0\ub420 \uacbd\uc6b0\uc5d0\ub9cc \ub85c\ub529 \uc2a4\ud53c\ub108\ub97c \uc0ac\uc6a9\ud558\ub294 \uac83\uc774 \uc88b\uc2b5\ub2c8\ub2e4.\\n\\n##React Suspense \ub97c \uc774\uc6a9\ud558\uc5ec \ub85c\ub529 \uacbd\ud5d8 \uac1c\uc120\\n\\n\ud604\uc7ac \uc800\ud76c\ub294 \ub300\ubd80\ubd84\uc758 \uacbd\uc6b0 Suspense\ub97c \uc774\uc6a9\ud558\uc5ec child component\ub97c \uac10\uc2f8 \ub85c\ub529 \uc2a4\ud53c\ub108\ub97c \ubcf4\uc5ec\uc8fc\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n```tsx\\n// example\\n<div className={styles.page__depart}>\\n  <React.Suspense fallback={<LoadingSpinner />}>\\n    <DeptListbox />\\n  </React.Suspense>\\n</div>\\n```\\n\\n\uc774\ub97c \ub85c\ub529 \uc2dc\uac04\uc5d0 \ub530\ub77c \ub2e4\ub978 UX\ub97c \uc81c\uacf5\ud560 \uc218 \uc788\ub3c4\ub85d \uc720\ud2f8\uc131 \ucef4\ud3ec\ub10c\ud2b8\ub97c \ud65c\uc6a9\ud574 \ubcc0\uacbd\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc608\ub97c \ub4e4\uc5b4, 1\ucd08\uae4c\uc9c0\ub294 \uc544\ubb34\ub7f0 UX\ub97c \uc81c\uacf5\ud558\uc9c0 \uc54a\ub2e4\uac00 1\ucd08 \uc774\uc0c1 \ub85c\ub529\uc774 \uc9c0\uc5f0\ub41c\ub2e4\uba74 \uadf8\ub54c \ub85c\ub529 \uc2a4\ud53c\ub108\ub97c \ubcf4\uc5ec\uc8fc\ub294 \ucef4\ud3ec\ub10c\ud2b8\ub97c \ub9cc\ub4e4 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc544\ub798\ub294 \uce74\uce74\uc624\uc5d0\uc11c \uc81c\uc2dc\ud55c \uc720\ud2f8 \ucef4\ud3ec\ub10c\ud2b8 \uc124\uacc4\uc785\ub2c8\ub2e4.\\n\\n```tsx\\nconst DeferredComponent = ({ children }: PropsWithChildren<{}>) => {\\n  const [isDeferred, setIsDeferred] = useState(false);\\n\\n  useEffect(() => {\\n    // 200ms \uc9c0\ub09c \ud6c4 children Render\\n    const timeoutId = setTimeout(() => {\\n      setIsDeferred(true);\\n    }, 200);\\n    return () => clearTimeout(timeoutId);\\n  }, []);\\n\\n  if (!isDeferred) {\\n    return null;\\n  }\\n\\n  return <>{children}</>;\\n};\\n```\\n\\n**`DeferredComponent`**\ub294 children\uc744 Props\ub85c \ubc1b\uace0, 200ms \uc774\uc804\uc5d0\ub294 children\uc744 \ub80c\ub354\ub9c1\ud558\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.\\n\\n\ub530\ub77c\uc11c \uae30\uc874\uc758 \ub85c\ub529 \uc2a4\ud53c\ub108\uc5d0 \uc774 **`DeferredComponent`**\ub97c \uc801\uc6a9\ud558\uba74 \ud2b9\uc815 \uc2dc\uc810\ubd80\ud130 \ub85c\ub529 \uc2a4\ud53c\ub108\uac00 \ubcf4\uc5ec\uc9c0\uac8c \ub429\ub2c8\ub2e4.\\n\\n```tsx\\n<div className={styles.page__depart}>\\n  <React.Suspense \\n\\t\\t fallback={\\n\\t\\t\\t\\t    <DeferredComponent>\\n\\t\\t\\t\\t\\t\\t  <LoadingSpinner />\\n\\t\\t\\t\\t\\t\\t</DeferredComponent>\\n\\t\\t\\t\\t\\t}>\\n    <DeptListbox />\\n  </React.Suspense>\\n</div>\\n```\\n\\n\uc6b0\ub9ac\ub294 \uc0ac\uc6a9\uc790 \uacbd\ud5d8\uc744 \ud5a5\uc0c1\uc2dc\ud0a4\uae30 \uc704\ud574 \ud56d\uc0c1 Progress Indicator(=Skeleton)\uc744 \uc0ac\uc6a9\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4. \uadf8\ub7ec\ub098 \ube60\ub978 \uc778\ud130\ub137 \ud658\uacbd\uc5d0\uc11c\ub294 \uc624\ud788\ub824 \uc120\ud0dd\uc801\uc73c\ub85c Progress Indicator\ub97c \uc81c\uacf5\ud558\ub294 \uac83\uc774 \ub354 \ub098\uc740 \uc0ac\uc6a9\uc790 \uacbd\ud5d8\uc744 \uc81c\uacf5\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\nresource\\n\\n- https://tech.kakaopay.com/post/skeleton-ui-idea/\\n- https://www.nngroup.com/articles/progress-indicators/"},{"id":"/GwakSeungJu/infomate-4week","metadata":{"permalink":"/front-end/GwakSeungJu/infomate-4week","source":"@site/@frontEnd/GwakSeungJu/infomate-4week.mdx","title":"\uc778\ud3ec\uba54\uc774\ud2b8 4\uc8fc\ucc28 \uacf5\uc720(\ud234)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 4\uc8fc\ucc28 \uacf5\uc720(\ud234) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","date":"2024-04-01T00:00:00.000Z","tags":[{"label":"\uc778\ud3ec\uba54\uc774\ud2b8","permalink":"/front-end/tags/\uc778\ud3ec\uba54\uc774\ud2b8"},{"label":"\ud234","permalink":"/front-end/tags/\ud234"}],"readingTime":16.545,"hasTruncateMarker":true,"authors":[{"name":"GwakSeungJu","url":"https://github.com/Gwak-Seungju","email":"gwak1016@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/74342515?v=4","key":"GwakSeungJu"}],"frontMatter":{"date":"2024-04-1","authors":"GwakSeungJu","title":"\uc778\ud3ec\uba54\uc774\ud2b8 4\uc8fc\ucc28 \uacf5\uc720(\ud234)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 4\uc8fc\ucc28 \uacf5\uc720(\ud234) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","keywords":["\uc778\ud3ec\uba54\uc774\ud2b8","\ud234"],"tags":["\uc778\ud3ec\uba54\uc774\ud2b8","\ud234"]},"unlisted":false,"prevItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 5\uc8fc\ucc28 \uacf5\uc720(UX)","permalink":"/front-end/hanagertrudeKim/infomate-5week"},"nextItem":{"title":"\ucf54\ub4dc \ucee8\ubca4\uc158\uc758 \uc911\uc694\uc131","permalink":"/front-end/posts/code-convention"}},"content":"\uc778\ud3ec\uba54\uc774\ud2b8 4\uc8fc\ucc28 \uacf5\uc720(\ud234) \ubaa8\uc74c\uc785\ub2c8\ub2e4.    \\n\\n\ud6a8\uc728\uc801\uc778 CSS \uc791\uc131, \uc5b4\ub835\uc9c0 \uc54a\uc544\uc694! - \uacfd\uc2b9\uc8fc    \\n\ucef4\ud3ec\ub10c\ud2b8\ub97c \ucc45\uc73c\ub85c? StoryBook - \uc724\ud574\uc9c4    \\nMocking tool\ub85c \uc0dd\uc0b0\uc131 \ucc59\uae30\uae30 - \uae40\ud558\ub098    \\n\\n{/* truncate */}\\n\\nimport videoUrl from \\"../videos/scale-up.mp4\\";\\nimport ReactPlayer from \\"react-player\\";\\n\\n\\n## \ud6a8\uc728\uc801\uc778 CSS \uc791\uc131, \uc5b4\ub835\uc9c0 \uc54a\uc544\uc694! - \uacfd\uc2b9\uc8fc\\n\\n## Intro\\n\\n`CSS`\ub294 \uc6f9 \ud398\uc774\uc9c0\ub97c \uac1c\ubc1c\ud560 \ub54c \ube60\uc9c8 \uc218 \uc5c6\ub294 \uc694\uc18c\uc774\uba70 \uc2e0\uacbd \uc368\uc57c \ud558\ub294 \ubd80\ubd84\uc785\ub2c8\ub2e4. \ud558\uc9c0\ub9cc, \uc790\uc2e0\uc774 \uc0dd\uac01\ud55c \ub300\ub85c \ud398\uc774\uc9c0\uc5d0 \uc801\uc6a9\uc774 \uc548 \ub418\uace0, \ub514\uc790\uc778\uc744 \uc5b4\ub5bb\uac8c \uad6c\ud604\ud574\uc57c \ud560\uc9c0 \ubaa8\ub974\uaca0\ub294 \uacbd\uc6b0\uac00 \uc885\uc885 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4. \uadf8\ub7f4 \ub54c \uc720\uc6a9\ud558\uac8c \uc0ac\uc6a9\ud560 \uc218 \uc788\ub294 `Tool`\ub4e4\uc744 \uc18c\uac1c\ud558\ub824\uace0 \ud569\ub2c8\ub2e4.\\n\\n## Tools\\n\\n### \uac1c\ubc1c\uc5d0 \uc55e\uc11c..\\n\\n- \ubb34\ud131\ub300\uace0 \ucc98\uc74c\ubd80\ud130 \ub514\uc790\uc778 \uad6c\ud604\uc744 \uc2dc\uc791\ud558\uba74 \ub098\uc911\uc5d0 \ud070\ucf54\ub2e4\uce58\uae30 \uc77c\uc464\uc785\ub2c8\ub2e4. \uadf8 \uc774\uc720\ub294 \ube0c\ub77c\uc6b0\uc800\ub9c8\ub2e4 \uae30\ubcf8\uc73c\ub85c \uc81c\uacf5\ud558\ub294 CSS \uc2a4\ud0c0\uc77c\uc774 \uc788\uc5b4 \ube0c\ub77c\uc6b0\uc800\ubcc4\ub85c \ubcf4\uc5ec\uc9c0\ub294 \ud654\uba74\uc774 \ub2ec\ub77c\uc9c8 \uc218 \uc788\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4. \ub530\ub77c\uc11c \ube0c\ub77c\uc6b0\uc800\uac00 \uac00\uc9c0\uace0 \uc788\ub294 \uae30\ubcf8 \uc2a4\ud0c0\uc77c\uc758 \ucc28\uc774\ub97c \uc5c6\uc560\uae30 \uc704\ud574 CSS\ub97c \ucd08\uae30\ud654\ud560 \ud544\uc694\uac00 \uc788\uc2b5\ub2c8\ub2e4. \uadf8 \ubc29\ubc95\uc73c\ub85c\ub294 CSS Reset\uc744 \uc0ac\uc6a9\ud558\ub294 \uac83\uc785\ub2c8\ub2e4. \uba3c\uc800, [\ub2e4\uc74c \ud398\uc774\uc9c0](https://piccalil.li/blog/a-more-modern-css-reset/)\uc5d0 \uc788\ub294 \ucf54\ub4dc \uc804\uccb4\ub97c \ubcf5\uc0ac\ud569\ub2c8\ub2e4. \uadf8\ub9ac\uace0`src`\ud3f4\ub354 \ud558\uc704 \uc704\uce58\uc5d0 `reset.css`\ub77c\ub294 \ud30c\uc77c\uc744 \uc0dd\uc131\ud558\uace0, \ubcf5\uc0ac\ud55c \ucf54\ub4dc\ub97c `reset.css`\uc5d0 \ubd99\uc5ec\ub123\uc2b5\ub2c8\ub2e4. \ub9c8\uc9c0\ub9c9\uc73c\ub85c \ucd5c\uc0c1\uc704 `css \ud30c\uc77c`\uc5d0 `import` \ud574\uc8fc\uba74 \uc2a4\ud0c0\uc77c\uc744 \ucd08\uae30\ud654\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### \uc560\ub2c8\uba54\uc774\uc158 \uad6c\ud604\\n\\n- ppt \uc790\ub8cc\uc5d0 \ud754\ud788 \uc0ac\uc6a9\ud558\ub294 \uc560\ub2c8\uba54\uc774\uc158 \ud6a8\uacfc\ub97c \uc6f9 \ud398\uc774\uc9c0\uc5d0\ub3c4 \ub123\uc744 \uc218 \uc788\ub2e4\uba74 \uc880 \ub354 \uc2a4\ud0c0\uc77c\ub9ac\uc26c\ud560 \uac83 \uac19\uc9c0 \uc54a\ub098\uc694? [\uc560\ub2c8\ubbf8\uc2a4\ud0c0(Animista)](https://animista.net/)\ub294 \uc815\ub9d0 \ub2e4\uc591\ud55c \uc560\ub2c8\uba54\uc774\uc158 \ud6a8\uacfc\ub97c \uc801\uc6a9\ud560 \uc218 \uc788\ub294 \uc2a4\ud0c0\uc77c \ucf54\ub4dc\ub97c \ubc14\ub85c \uc0dd\uc131\ud574 \uc90d\ub2c8\ub2e4.\\n    \\n    \uc608\uc2dc\ub85c, \ucf54\uc778\uc758 \uc8fc\ubcc0\uc0c1\uc810 \uce74\ud14c\uace0\ub9ac \uc774\ubbf8\uc9c0\uc5d0 \uc560\ub2c8\uba54\uc774\uc158 \ud6a8\uacfc\ub97c \uc27d\uac8c \ub123\uc5b4\uc904 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n    <ReactPlayer\\n      controls\\n      playing\\n      loop\\n      url={videoUrl}\\n      style={{ marginBottom: \\"20px\\" }}\\n    />\\n    \\n\\n### \uc2a4\ud0c0\uc77c\\n\\n- \uadf8\ub9bc\uc790 \uc0dd\uc131\\n    - `box-shadow` \uc18d\uc131\uc73c\ub85c \uac04\ub2e8\ud55c \uadf8\ub9bc\uc790\ub9cc \uad6c\ud604\uc744 \ud588\ub2e4\uba74, \uc774\uc81c\ubd80\ud130 [smooth shadow](https://shadows.brumm.af/)\ub97c \uc774\uc6a9\ud558\uc5ec \ubd80\ub4dc\ub7ec\uc6b4 \uadf8\ub9bc\uc790\ub97c \uc0dd\uc131\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc624\ub978\ucabd \uadf8\ub9bc\uc790 \uc2a4\ud0c0\uc77c \ub3c4\uad6c\ub97c \uc801\uc808\ud788 \uc870\uc808\ud558\uba74 \uc67c\ucabd \ubc15\uc2a4\uc5d0 \uadf8 \uc18d\uc131\uac12\uacfc \uc18d\uc131\uac12\uc774 \uc801\uc6a9\ub41c \uadf8\ub9bc\uc790\ub97c \ubcf4\uc5ec\uc90d\ub2c8\ub2e4.\\n      <img src=\\"/img/@frontEnd/infomate-4week/image04.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"20px\\" }} />\\n    \\n- Gradient\\n    - \ub2e8\uc0c9\ub9cc\uc73c\ub85c \uc6f9 \ud398\uc774\uc9c0\ub97c \uc2a4\ud0c0\uc77c\ub9c1\ud558\ub294 \uac83\uc774 \uc9c0\uaca8\uc6b8 \ub54c \uadf8\ub77c\ub370\uc774\uc158\uc774 \ub4e4\uc5b4\uac04 \uc0c9\uc744 \ub123\uc5b4 \ub2e4\ucc44\ub85c\uc6b4 \ud398\uc774\uc9c0\ub97c \ub9cc\ub4e4\uace0 \uc2f6\uc744 \ub54c\uac00 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4. \ub610\ud55c, \uadf8\ub77c\ub370\uc774\uc158\uc774 \ub4e4\uc5b4\uac04 \ub514\uc790\uc778\uc744 \uc694\uad6c\ubc1b\uc744 \uc2dc \uc815\ud655\ud558\uac8c \uc218\ud589\ud558\uae30 \uc5b4\ub824\uc6b4 \uacbd\uc6b0\uac00 \uc885\uc885 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4. \uc774\ub7ec\ud560 \ub54c, [CSS \uadf8\ub77c\ub514\uc5b8\ud2b8(CSS Gradient)](https://cssgradient.io/)\uac00 \ub3c4\uc6c0\uc774 \ub420 \uac83\uc785\ub2c8\ub2e4! CSS \uadf8\ub77c\ub514\uc5b8\ud2b8(CSS Gradient)\ub294 \uadf8\ub77c\ub370\uc774\uc158 \ubc30\uacbd\uc0c9\uc744 \ub9cc\ub4dc\ub294 CSS \ucf54\ub4dc\ub97c \uc0dd\uc131\ud574\uc90d\ub2c8\ub2e4.\\n      <img src=\\"/img/@frontEnd/infomate-4week/image05.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"20px\\" }} />\\n        \\n\\n### Layout \uad6c\uc131\\n\\n\ub9cc\uc57d \uc544\ub798\uc640 \uac19\uc774 \ubcf5\uc7a1\ud55c \ubc30\uce58 \uad6c\uc131\uc744 \uad6c\ud604\ud574\uc57c \ud560 \uacbd\uc6b0 \uc5b4\ub5bb\uac8c \uad6c\uc131\ud560\uc9c0 \uba38\ub9ac\uac00 \ub9e4\uc6b0 \uc544\ud50c \uac83\uc785\ub2c8\ub2e4.\\n<img src=\\"/img/@frontEnd/infomate-4week/image01.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"20px\\" }} />\\n\\n\ud558\uc9c0\ub9cc, [CSS Grid Generator](https://cssgrid-generator.netlify.app/)\ub97c \uc774\uc6a9\ud55c\ub2e4\uba74 \ube60\ub974\uace0 \uc27d\uac8c \uc774 \ubc30\uce58\ub97c \uad6c\ud604\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n<img src=\\"/img/@frontEnd/infomate-4week/image02.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"20px\\" }} />\\n\\n\ub2e8\uc21c \ub108\ube44 \ube44\uc728 \uc124\uc815\uacfc \ub4dc\ub798\uadf8\ub9cc\uc73c\ub85c \ubc30\uce58 \uad6c\uc131\uc744 \ub530\ub77c\ud560 \uc218 \uc788\uace0, \uc774\ub97c \ud1b5\ud574 \uc6b0\uce21\uc5d0 `Please may I have some code`\ub97c \ud074\ub9ad\ud558\uba74 \uc6b0\uce21 \uadf8\ub9bc\uacfc \uac19\uc740 \ucf54\ub4dc\ub97c \uc81c\uacf5\ud574\uc90d\ub2c8\ub2e4. \uac01 \uc120\ud0dd\uc790\uc5d0 `margin`\uc774\ub098 `background-color`\ub4f1 \uc790\uc2e0\uc774 \uc6d0\ud558\ub294 \uc18d\uc131\uc744 \ucd94\uac00\ud558\uba74 \ub429\ub2c8\ub2e4.\\n<img src=\\"/img/@frontEnd/infomate-4week/image03.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" />\\n\\n## \uacb0\ub860\\n\\nCSS \uac1c\ubc1c\uc744 \uc704\ud55c \ub2e4\uc591\ud55c \ud234\uc744 \uc18c\uac1c\ud588\uc2b5\ub2c8\ub2e4. CSS \uac1c\ubc1c\uc744 \uc704\ud55c \ud234\uacfc \ub77c\uc774\ube0c\ub7ec\ub9ac\ub294 \uad49\uc7a5\ud788 \ub2e4\uc591\ud558\uba70, \uc774 \uae00\uc5d0\uc11c \uc18c\uac1c\ud55c \ud234 \uc678\uc5d0 \ub354 \ub9ce\uc740 \uc120\ud0dd\uc9c0\uac00 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4. \uc774\ub7ec\ud55c \ub2e4\uc591\ud55c \ud234\ub4e4\uc744 \ud65c\uc6a9\ud558\uba74 CSS \ucf54\ub529\uc758 \uc0dd\uc0b0\uc131\uc744 \ud5a5\uc0c1\uc2dc\ud0ac \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uadf8\ub7ec\ub098 \uc774\ub7ec\ud55c \ub3c4\uad6c\ub4e4\uc744 \uc0ac\uc6a9\ud558\ub294 \ub3d9\uc2dc\uc5d0 \uae30\ubcf8\uc801\uc778 CSS \ubb38\ubc95\uc744 \uc798 \uc774\ud574\ud558\uace0 \ud65c\uc6a9\ud558\ub294 \uac83\uc774 \uc911\uc694\ud569\ub2c8\ub2e4. \ud234\uc740 \uac1c\ubc1c\uc790\uc758 \uc0dd\uc0b0\uc131\uc744 \ud5a5\uc0c1\uc2dc\ud0a4\ub294\ub370 \ub3c4\uc6c0\uc744 \uc8fc\uc9c0\ub9cc, \uadf8 \uae30\ubc18\uc5d0\ub294 \ud56d\uc0c1 \uae30\ubcf8\uc801\uc778 \uac1c\ub150\uacfc \uc774\ud574\uac00 \uc788\uc5b4\uc57c \ud569\ub2c8\ub2e4.\\n\\n## \ucc38\uace0\uc790\ub8cc\\n\\nhttps://hihiha2.tistory.com/154<br />\\nhttps://kofearticle.substack.com/p/korean-fe-article-css-reset<br />\\nhttps://blog.wishket.com/2023%eb%85%84-%ec%9c%a0%ec%9a%a9%ed%95%9c-css-%ec%83%9d%ec%84%b1-%eb%8f%84%ea%b5%ac-top-10/\\n\\n\\n## \ucef4\ud3ec\ub10c\ud2b8\ub97c \ucc45\uc73c\ub85c? StoryBook - \uc724\ud574\uc9c4\\n\\n### \ub4e4\uc5b4\uac00\uba70)\\n\\n\ucef4\ud3ec\ub10c\ud2b8 \uc8fc\ub3c4 \uac1c\ubc1c\uc744 \ud560 \ub54c \ubcf4\ud1b5 \uacb0\uacfc\ubb3c\uc744 \uc2e4\uc2dc\uac04\uc73c\ub85c \ud655\uc778\ud574\uac00\uba70 \ucef4\ud3ec\ub10c\ud2b8\ub97c \uad6c\ud604\ud569\ub2c8\ub2e4. \uc2e4\uc2dc\uac04\uc73c\ub85c \uacb0\uacfc\ubb3c\uc744 \ubcf4\uba70 \uc0c1\ud669\uc5d0 \ub530\ub978 \uc870\uac74\ub4e4\uacfc \ud574\ub2f9 \uacb0\uacfc\ub97c \ub9cc\ub4e4\uc5b4\uac00\ub294 \uac83\uc740 \uaf64\ub098 \ubc88\uac70\ub86d\uc2b5\ub2c8\ub2e4.\\n\\n- \ucd08\ub300 \ucf54\ub4dc\ub97c \ud1b5\ud574 \uc0c1\ub300\ub97c \ucd08\ub300\ud558\uace0 \ub728\ub294 \ubaa8\ub2ec\ucc3d\\n- \ud3ec\uc778\ud2b8 \uc0ac\uc6a9 \uc774\ub825 \ub4f1\\n\\n\uadf8\ub7ec\ub098 \uc774\ub7f0 \uc0c1\ud669\uc5d0\uc11c \ub3c5\ub9bd\uc801\uc778 \ud658\uacbd\uc5d0\uc11c UI\ub97c \uadf8\ub824\ubcfc \uc218 \uc788\ub2e4\uba74 \uac1c\ubc1c\uc5d0 \uc788\uc5b4 \uace0\ub824\ud560 \uac83\uc774 \ub9e4\uc6b0 \ucd95\uc18c\ub420 \uac83\uc785\ub2c8\ub2e4.\\n\\n\uc774\ub7f0 \uac1c\ubc1c\uc744 \ub3c4\uc640\uc8fc\ub294 \ucef4\ud3ec\ub10c\ud2b8 \ub2e8\uc704\uc758 UI\uac1c\ubc1c \ub3c4\uad6c\uc778 **storybook\uc758 \uc18c\uac1c\uae00**\ub4e4 \uc791\uc131\ud574\ubcf4\ub824\uace0 \ud569\ub2c8\ub2e4.\\n\\n## 1) CDD(\ucef4\ud3ec\ub10c\ud2b8 \uc8fc\ub3c4 \uac1c\ubc1c)\ub780 \ubb34\uc5c7\uc778\uac00\uc694?\\n\\nCDD(Component-Driven Development)\ub294 **\ucef4\ud3ec\ub10c\ud2b8 \ub2e8\uc704 \uc911\uc2ec\uc73c\ub85c \uac1c\ubc1c\ud558\ub294 \uac1c\ubc1c \ubc29\ubc95\ub860** \uc785\ub2c8\ub2e4.\\n\\n\ud654\uba74\uc744 \uad6c\uc131\ud560 \ub54c, \uc77c\uc77c\ud788 \ub2e4\ub978 UI\ub97c \uc0ac\uc6a9\ud558\ub294 \uac83\uc774 \uc544\ub2cc, \uc7ac\uc0ac\uc6a9\uac00\ub2a5\ud55c UI \ucef4\ud3ec\ub10c\ud2b8\ub97c \ubbf8\ub9ac \ub514\uc790\uc778 \ud558\uace0 \uac1c\ubc1c\uc5d0 \uc774\uc6a9\ud558\uba74 \ud6e8\uc52c \ube60\ub978 \uc9c4\ud589\uc774 \uac00\ub2a5\ud569\ub2c8\ub2e4.\\n\\n\uac04\ub2e8\ud558\uac8c \uc694\uc57d\ud558\uc790\uba74, `\ucef4\ud3ec\ub10c\ud2b8\ub97c \ub9c8\uce58 \ub808\uace0\uc758 \ud55c \ubd80\ud488`\ucc98\ub7fc \uc0ac\uc6a9\ud558\ub294 \ubc29\ubc95\ub860\uc785\ub2c8\ub2e4.\\n\\n## 2) \uc2a4\ud1a0\ub9ac\ubd81\uc774 \ubb54\uac00\uc694?\\n\\n\uc2a4\ud1a0\ub9ac\ubd81\uc774\ub780 \uc804\uccb4 UI\ub97c \ud55c\ub208\uc5d0 \ubcf4\uba74\uc11c \uac1c\ubc1c\uc744 \ud560 \uc218 \uc788\uc73c\uba70 CDD\ub97c \uc9c0\uc6d0\ud558\ub294 \ub3c4\uad6c \uc911 \ud558\ub098\uc785\ub2c8\ub2e4.\\n\\n\'**\uc2a4\ud1a0\ub9ac**\'\ub77c\ub294 \ucef4\ud3ec\ub10c\ud2b8 \ubbf8\ub9ac\ubcf4\uae30\ub97c \uc791\uc131\ud574\ub450\uc5b4 \uacb0\uacfc\ubb3c\uc744 \uc989\uc2dc \ud655\uc778 \uac00\ub2a5\ud569\ub2c8\ub2e4. \\n\\n\uc774\uac83\uc740 \uac1c\ubc1c\uc790 \ubfd0\ub9cc\uc774 \uc544\ub2cc \ucf54\ub4dc \ub9ac\ubdf0\ub97c \ud558\uac70\ub098 \ud574\ub2f9 \ud30c\ud2b8\ub97c \uc218\uc815\ud558\ub294 \ub2e4\ub978 \uac1c\ubc1c\uc790 \ub098\uc544\uac00 \ub514\uc790\uc774\ub108 \ub610\ud55c \uc27d\uac8c \ud655\uc778 \uac00\ub2a5\ud569\ub2c8\ub2e4.\\n<br />\\n[**\ubc84\ud2bc**]\uc744 \uac00\uc815\ud574\ubd05\uc2dc\ub2e4. \\n\\n\uadf8\ub807\ub2e4\uba74 \ub9c8\uc774\ud398\uc774\uc9c0 \uc548\uc5d0\uc11c\ub9cc \uc4f0\uc774\ub294 \ubc84\ud2bc\uc744 \ub9cc\ub4dc\ub294 \uac83\uc774 \uc544\ub2cc \uc5b4\ub514\uc11c\ub4e0 \uc4f0\uc77c \uc218 \uc788\ub294 \ubc84\ud2bc \uc989, \ubc84\ud2bc\uc774\ub77c\ub294 \ucef4\ud3ec\ub10c\ud2b8\ub97c \ub9cc\ub4e4\uac8c \ub420 \uac83\uc785\ub2c8\ub2e4.\\n\\n\uc7ac\ud65c\uc6a9\uc131\uc744 \ud655\ub300\ud558\uae30 \uc704\ud574 \ucef4\ud3ec\ub10c\ud2b8\ub97c \ubb38\uc11c\ud654\ud558\uace0, \uc790\ub3d9\uc73c\ub85c \ucef4\ud3ec\ub10c\ud2b8\ub97c \uc2dc\uac01\ud654\ud558\uc5ec \uc2dc\ubbac\ub808\uc774\uc158\uc774 \uac00\ub2a5\ud569\ub2c8\ub2e4. \\n\\n\ub530\ub77c\uc11c \ub2e4\uc591\ud55c \uc0c1\ud0dc\ud655\uc778\uc774 \uac00\ub2a5\ud569\ub2c8\ub2e4.\\n\\n## 3) \uc2a4\ud1a0\ub9ac \ubd81\uc744 \uc4f0\uba74 \ubb34\uc5c7\uc744 \uc5bb\uc744 \uc218 \uc788\uc8e0?\\n\\n- UI \ucef4\ud3ec\ub10c\ud2b8\ub4e4\uc744 \uce74\ud0c8\ub85c\uadf8\ud654\\n- \ucef4\ud3ec\ub10c\ud2b8 \ubcc0\ud654\ub97c Stories\ub85c \uc800\uc7a5\\n- \ud56b \ubaa8\ub4c8 \uc7ac \ub85c\ub529\uacfc \uac19\uc740 \uac1c\ubc1c \ud234 \uacbd\ud5d8 \uc81c\uacf5\\n- \ub9ac\uc561\ud2b8\ub97c \ud3ec\ud568\ud55c \ub2e4\uc591\ud55c \ubdf0 \ub808\uc774\uc5b4 \uc9c0\uc6d0\\n\\n\uc2a4\ud1a0\ub9ac \uc791\uc131\uc740 \uacb0\uacfc\ubb3c\uc744 \uc27d\uace0 \ube60\ub974\uac8c \ud655\uc778\ud560 \uc218 \uc788\ub2e4\ub294 \uc7a5\uc810 \ubfd0\ub9cc \uc544\ub2cc, **\uc880 \ub354 \ub098\uc740 \ucef4\ud3ec\ub10c\ud2b8 \uc124\uacc4\ub97c \uace0\ubbfc\ud558\uac8c \ub41c\ub2e4\ub294 \uc810**\uc785\ub2c8\ub2e4.\\n\\n\ud55c \ucef4\ud3ec\ub10c\ud2b8\ub97c \uc7ac\uc0ac\uc6a9\ud558\ub824 \ud560 \ub54c \ucd08\uae30\uc5d0 \uc9c4\ud589\ud588\ub358 \uc124\uacc4\uc5d0\uc11c \ubb38\uc81c\uc810\uc744 \ubc1c\uacac\ud574 \uc7ac\uc0ac\uc6a9\uc2dc \uc758\uc874\uc131 \uc81c\uac70 \ub4f1\uc744 \uc704\ud574 \uc218\uc815\uc744 \uac70\ucce4\ub358 \uae30\uc5b5\uc774 \uc788\uc2b5\ub2c8\ub2e4. \\n\\n\uadf8\ub7ec\ub098 \uc2a4\ud1a0\ub9ac\ubd81\uc744 \ud65c\uc6a9\ud558\uba70, \uc2a4\ud1a0\ub9ac\ub97c \uc791\uc131\ud558\ub294 \uacfc\uc815\uc5d0\uc11c \uc124\uacc4 \ubc0f \uad6c\uc870\uc758 \uacb0\ud568\uc744 \ub9ce\uc774 \ubc1c\uacac \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc774\ub294 \ud658\uacbd \ud639\uc740 \uc8fc\ubcc0\uc758 \ucef4\ud3ec\ub10c\ud2b8\uc640\uc758 \uc758\uc874\uc131\uc774 \ub0ae\uc544\uc57c \ub3c5\ub9bd\uc801\uc73c\ub85c \uadf8\ub9ac\ub294 \uac83\uc774 \uac00\ub2a5\ud558\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4. \\n\\n\ub610\ud55c \uc7ac\uc0ac\uc6a9\uc774 \uc27d\uac8c \uac1c\ubc1c\uc774 \uc9c4\ud589\ub418\uc5b4\uc57c\ud558\uae30\uc5d0 \uc2a4\ud1a0\ub9ac \uc791\uc131\uc774\ub77c\ub294 \uacfc\uc815\uc5d0\uc11c \uacc4\uc18d\ud574\uc11c \uad6c\uc870\uc5d0 \ub300\ud574 \uace0\ubbfc\ud558\ub294 \ub9ac\ud329\ud1a0\ub9c1 \ud6a8\uacfc\ub97c \ubd80\uc218\uc801\uc73c\ub85c \uc5bb\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n## \ud65c\uc6a9 \uc608\uc2dc)\\n<ul style={{ listStyle: \\"none\\", display: \\"flex\\", justifyContent: \\"space-between\\", padding:\\"0\\" }}>\\n  <li>\\n    <img src=\\"/img/@frontEnd/infomate-4week/Untitled.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ height: \\"404px\\" }}/>\\n  </li>\\n  <li>\\n    <img src=\\"/img/@frontEnd/infomate-4week/Untitled 1.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ height: \\"250px\\" }} />\\n  </li>\\n</ul>\\n\\n\uc2a4\ud1a0\ub9ac \uc791\uc131 \\n\\n<img src=\\"/img/@frontEnd/infomate-4week/Untitled 2.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" />\\n\\n\uc9c1\uc811 \ud655\uc778 \uac00\ub2a5\ud55c \ubaa8\uc2b5\\n\\n\\n## Mocking tool\ub85c \uc0dd\uc0b0\uc131 \ucc59\uae30\uae30 - \uae40\ud558\ub098    \\n\\n\ubaa8\ud0b9(Mocking)\uc774\ub780 \ub2e8\uc704 \ud14c\uc2a4\ud2b8 \uc791\uc131\ud560 \ub54c, \ud574\ub2f9 \ucf54\ub4dc\uac00 \uc758\uc874\ud558\ub294 \ubd80\ubd84\uc744 \uac00\uc9dc(mock)\ub85c \ub300\uccb4\ud558\ub294 \uae30\ubc95\uc785\ub2c8\ub2e4.\\n\\n\uac1c\ubc1c\uc744 \uc9c4\ud589\ud560\ub54c \ubc31\uc5d4\ub4dc\uc5d0\uc11c API\uac00 \uc644\uc131\ub418\uc9c0 \uc54a\uc544 \ub09c\ucc98\ud588\ub358 \uc801\uc774 \uc788\uc5c8\uc744 \uac83\uc785\ub2c8\ub2e4.<br />\\n\ud2b9\uc815 \uc0c1\ud669\uc758 \uac1c\ubc1c\ub418\uc9c0 \uc54a\uc740 \ubd80\ubd84\uc5d0 \uc758\uc874\ud558\uc5ec \uac1c\ubc1c\uc744 \uc9c4\ud589\ud558\uac8c \ub41c\ub2e4\uba74 \ub2e4\uc74c\uacfc \uac19\uc740 \ubb38\uc81c\ub97c \uc57c\uae30\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n1. \uac1c\ubc1c\ub418\uc9c0 \uc54a\uc740 \ubaa8\ub4c8\uc5d0 \uc758\uc874\ud558\uba74 \ud14c\uc2a4\ud305\uc774 \uc5b4\ub824\uc6c0\\n2. \ub2e4\ub978 \ubaa8\ub4c8\uc5d0 \uc758\ud574 \ud14c\uc2a4\ud2b8 \uacb0\uacfc\uac00 \ubc14\ub014\uc218\uc788\uace0, \ud14c\uc2a4\ud2b8 \uc2e4\ud589 \uc18d\ub3c4\uac00 \ub5a8\uc5b4\uc9d0\\n3. \ud504\ub85c\uc81d\ud2b8 \uaddc\ubaa8\uac00 \ucee4\uc838\uc11c \ud14c\uc2a4\ud2b8 \ucf00\uc774\ud06c\uac00 \ub9ce\uc544\uc9c8 \uacbd\uc6b0 \ud070 \uc774\uc288\uac00 \uc57c\uae30\ub420 \uc218 \uc788\uc74c\\n\\n\uc774\ub7ec\ud55c \uc0c1\ud669\uc5d0\uc11c \uc2e4\uc81c \ubaa8\ub4c8\uc744 \ubaa8\ubc29\ud55c \uac00\uc9dc \ubaa8\ub4c8\uc744 \uc0dd\uc131\ud558\ub294 mocking \uc774 \ud544\uc694\ud558\uac8c \ub418\uba70, \uc2e4\uc81c\ub85c \ud504\ub85c\uc81d\ud2b8\ub97c \uc9c4\ud589\ud558\uba74\uc11c\ub3c4 mocking \ud558\ub294 \ud589\uc704\uac00 \ube60\ub978 \uac1c\ubc1c\uacfc \uc548\uc815\uc131\uc5d0 \ub3c4\uc6c0\uc744 \uc904 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ud504\ub860\ud2b8\uc5d4\ub4dc\uc5d0\uc11c \ubc31\uc5d4\ub4dc \ubaa8\ud0b9\uc774 \ud544\uc694\ud55c \uc0c1\ud669\uc740 \ub2e4\uc591\ud569\ub2c8\ub2e4. <br />\\n\uc608\ub97c \ub4e4\uc5b4, \ubc31\uc5d4\ub4dc API\uac00 \uc544\uc9c1 \uac1c\ubc1c \uc911\uc774\uac70\ub098, \uc6d0\ud558\ub294 \ud615\ud0dc\uc758 \ub370\uc774\ud130\ub098 \uc751\ub2f5\uc744 \ud14c\uc2a4\ud2b8\ud574\uc57c \ud560 \ub54c, \ub610\ub294 \uc11c\ubc84 \uc5d0\ub7ec \uc0c1\ud669\uc744 \ud14c\uc2a4\ud2b8\ud558\uace0 \uc2f6\uc744 \ub54c \ub4f1\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc774 \uc0c1\ud669\uc5d0\uc11c\uc758 \uc194\ub8e8\uc158\uc740 \ub300\ud45c\uc801\uc73c\ub85c \uc138\uac00\uc9c0\ub85c \ub098\ub220\ubcfc \uc218 \uc788\ub294\ub370,\\n\\n1. \ubc31\uc5d4\ub4dc \uc791\uc5c5\uc774 \uc644\ub8cc\ub420\ub54c\uae4c\uc9c0 \uae30\ub2e4\ub9b0\ub2e4.\\n2. \uc560\ud50c\ub9ac\ucf00\uc774\uc158 \ub0b4\ubd80 \ub85c\uc9c1\uc5d0 \uc9c1\uc811 Mocking \ud55c\ub2e4. ([\ucc38\uace0](https://velog.io/@jsw4215/%EB%A6%AC%EC%95%A1%ED%8A%B8-Mock-API) : **public**\xa0**folder**\uc640\xa0**.json**\xa0\ud30c\uc77c \ub4f1\uc744 \uc774\uc6a9\ud558\uc5ec mocking )\\n3. \ud398\uc774\ud06c API\ub97c \uc81c\uacf5\ud558\ub294 \ub77c\uc774\ube0c\ub7ec\ub9ac\ub97c \uc0ac\uc6a9\ud55c\ub2e4.\\n\\n\ud604\uc2e4\uc801\uc73c\ub85c \uc2dc\uac04\uc774 \ub9ce\ub2e4\uba74 1\ubc88\uc744 \uc9c0\ud5a5\ud558\uaca0\uc9c0\ub9cc, \uc2dc\uac04\uc774 \ubd80\uc871\ud558\uac70\ub098 \ub9ac\uc18c\uc2a4\uac00 \ubd80\uc871\ud560 \uacbd\uc6b0\uc5d0\ub294 3\ubc88\uc744 \uc120\ud0dd\ud558\uac8c \ub429\ub2c8\ub2e4.\\n\\n\uc2e4\uc81c\ub85c \uca5d\uca5d\ubc15\uc0ac \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c\ub294 Google API \ud560\ub2f9\ub7c9 \ubd80\uc871\uc73c\ub85c \uc778\ud574 \uac1c\ubc1c \ud658\uacbd \ud14c\uc2a4\ud2b8\ub97c \uc704\ud574 3\ubc88 \ubc29\ubc95\uc744 \ucc44\ud0dd\ud588\uc2b5\ub2c8\ub2e4.\\n\\n\ub530\ub77c\uc11c \uc774\uc640 \uad00\ub828\ud558\uc5ec \uc8fc\ub85c \uc0ac\uc6a9\ub418\ub294 \ud234\ub4e4\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4.\\n\\n## Json Placeholder\\n\\n[JSONPlaceholder - Free Fake REST API](https://jsonplaceholder.typicode.com/)\\n\\nJson Placeholder\ub294 \ud504\ub85c\ud1a0\ud0c0\uc785 \ub610\ub294 \uac1c\ubc1c \ud14c\uc2a4\ud2b8\ub97c \uc704\ud55c \ud398\uc774\ud06c JSON API\ub97c \uc81c\uacf5\ud569\ub2c8\ub2e4.\\n\\n6\uac1c \uc720\ud615\uc758 \ub9ac\uc18c\uc2a4\ub97c \uc81c\uacf5\ud558\uba70, CRUD \ud14c\uc2a4\ud2b8\ub97c \uc704\ud55c \ubaa8\ub4e0 HTTP \uba54\uc11c\ub4dc\ub97c \uc9c0\uc6d0\ud569\ub2c8\ub2e4.\\n\\nGET, POST, PUT, PATCH, DELETE \uba54\uc18c\ub4dc\ub97c \ubaa8\ub450 \ud14c\uc2a4\ud2b8 \ud560 \uc218 \uc788\uc73c\uba70 \uac8c\uc2dc\ubb3c, \uc0ac\uc9c4 \ub4f1\uacfc \uac19\uc740 \ub370\uc774\ud130\ub4e4\ub3c4 \ub2e4\ub8f0\uc218 \uc788\uac8c \ub418\uc5b4\uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uac04\ub7b5\ud55c \uc0ac\uc6a9 \uc608\uc2dc\ub294 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.\\n\\n```jsx\\n// \uc694\uccad \uc608\uc2dc\\nfetch(\'https://jsonplaceholder.typicode.com/todos/1\')\\n  .then((response) => response.json())\\n  .then((json) => console.log(json));\\n```\\n\\nJson Placeholder\ub97c \uc774\uc6a9\ud558\uba74 \ube60\ub978 \uc18d\ub3c4\ub85c \ud14c\uc2a4\ud2b8\ud560 \uc218 \uc788\uc9c0\ub9cc, \uc751\ub2f5\uac12\uc744 \ucee4\uc2a4\ud140\ud558\ub294 \uac83\uc774 \uc5b4\ub824\uc6b4 \ub2e8\uc810\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n## **MSW(Mock Service Worker)**\\n\\n[Mock Service Worker](https://mswjs.io/)\\n\\nMSW(Mock Service Worker)\ub294 Service Worker\ub97c \uc774\uc6a9\ud574 \uc11c\ubc84\ub97c \ud5a5\ud55c \uc2e4\uc81c \ub124\ud2b8\uc6cc\ud06c \uc694\uccad\uc744 \uac00\ub85c\ucc44\uc11c(intercept) \ubaa8\uc758 \uc751\ub2f5(Mocked response)\ub97c \ubcf4\ub0b4\uc8fc\ub294 API Mocking \ub77c\uc774\ube0c\ub7ec\ub9ac\uc785\ub2c8\ub2e4. \uc2e4\uc81c API\ub97c \uc0ac\uc6a9\ud558\ub294 \uac83\uacfc \uc720\uc0ac\ud558\uac8c \ub124\ud2b8\uc6cc\ud06c \uc218\uc900\uc5d0\uc11c Mocking\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc0ac\uc6a9 \uc608\uc2dc\ub85c POST \uba54\uc11c\ub4dc\uc758 /login \uc694\uccad\uc744 \ub9cc\ub4e4\uc5b4\ubcf4\uba74 \ub2e4\uc74c\uacfc \uac19\uc774 API\ub97c \uc9c1\uc811 \uc815\uc758\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n```jsx\\n/ src/mocks.js\\nimport { setupWorker, rest } from \'msw\'\\n\\nconst worker = setupWorker(\\n  rest.post(\'/login\', (req, res, ctx) => {\\n    const isAuthenticated = sessionStorage.getItem(\'username\')\\n\\n    if (!isAuthenticated) {\\n      return res(\\n        ctx.status(403),\\n        ctx.json({\\n          errorMessage: \'Not authenticated\',\\n        }),\\n      )\\n    }\\n    return res(\\n      ctx.json({firstName: \'John\'}),\\n    )\\n  }),\\n)\\n\\n// Register the Service Worker and enable the mocking\\nworker.start()\\n```\\n\\n\uc774\ub7f0\uc2dd\uc73c\ub85c \uc0c1\ud0dc \ucf54\ub4dc\uc640 \uc5d0\ub7ec \uba54\uc2dc\uc9c0, \ubc18\ud658 \uac12\ub4e4\uc744 \ucee4\uc2a4\ud140 \ud560 \uc218 \uc788\uc73c\uba70 \uc5ec\ub7ec \uc635\uc158\ub4e4\uc744 \uc138\ubd80\uc801\uc73c\ub85c \uc801\uc6a9\ud560 \uc218 \uc788\ub2e4.\\n(\uc2e4\uc81c API \ucc98\ub7fc \uc815\ub9d0 \ub2e4\uc591\ud558\uac8c \ucee4\uc2a4\ud140 \ud560 \uc218 \uc788\ub2e4)\\n\\n\ud558\uc9c0\ub9cc \uc124\uc815 \ube44\uc6a9\uc774 \ube44\uad50\uc801 \ub9ce\uc774 \ub4e4\uace0, \uac04\ub2e8\ud55c \uc751\ub2f5 \ud14c\uc2a4\ud2b8\ub97c \uc704\ud574\uc11c\ub294 \ub2e4\uc18c \ubc88\uac70\ub85c\uc6b8 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### conclusion\\n\\n- FE \ud658\uacbd\uc758 \ube60\ub978 \uac1c\ubc1c\uc744 \uc704\ud55c\ub2e4\uba74 \ubc31\uc5d4\ub4dc \ubaa8\ud0b9\uc774 \ud544\uc694\ud558\ub2e4.\\n- Json Placeholder\ub294 \uac04\ub2e8\ud55c \uc751\ub2f5 \ud14c\uc2a4\ud2b8\uc5d0 \uc801\ud569\ud558\uba70, MSW\ub294 \ub354\uc6b1 \ubcf5\uc7a1\ud55c \uc0c1\ud669\uc5d0\uc11c \ucee4\uc2a4\ud130\ub9c8\uc774\uc9d5\uc774 \uac00\ub2a5\ud558\ub2e4.\\n\\nreference\\n\\nhttps://tech.kakao.com/2021/09/29/mocking-fe/ <br />\\nhttps://developer.mozilla.org/ko/docs/Web/API/Service_Worker_API <br />\\nhttps://www.daleseo.com/mock-service-worker/#google_vignette <br />"},{"id":"/posts/code-convention","metadata":{"permalink":"/front-end/posts/code-convention","source":"@site/@frontEnd/posts/code-convention.mdx","title":"\ucf54\ub4dc \ucee8\ubca4\uc158\uc758 \uc911\uc694\uc131","description":"\ub3d9\uc544\ub9ac\uc5d0\uc11c \uc57d 1\ub144 ~ 1\ub144 \ubc18\uc5d0 \uac78\uce5c \uae38\uace0 \uae38\uc5c8\ub358 \uca5d\uca5d\ubc15\uc0ac \ud504\ub85c\uc81d\ud2b8\uac00 \ub9c8\ubb34\ub9ac \ub418\uc5c8\uc2b5\ub2c8\ub2e4.","date":"2024-03-20T00:00:00.000Z","tags":[{"label":"\ud611\uc5c5","permalink":"/front-end/tags/\ud611\uc5c5"},{"label":"\ucf54\ub4dc \ucee8\ubca4\uc158","permalink":"/front-end/tags/\ucf54\ub4dc-\ucee8\ubca4\uc158"}],"readingTime":18.93,"hasTruncateMarker":true,"authors":[{"name":"Daeeui Kim","url":"https://github.com/kimeodml","email":"kimeodml@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/88065770?v=4","key":"kimeodml"}],"frontMatter":{"date":"2024-03-20T00:00:00.000Z","authors":"kimeodml","title":"\ucf54\ub4dc \ucee8\ubca4\uc158\uc758 \uc911\uc694\uc131","description":"\ub3d9\uc544\ub9ac\uc5d0\uc11c \uc57d 1\ub144 ~ 1\ub144 \ubc18\uc5d0 \uac78\uce5c \uae38\uace0 \uae38\uc5c8\ub358 \uca5d\uca5d\ubc15\uc0ac \ud504\ub85c\uc81d\ud2b8\uac00 \ub9c8\ubb34\ub9ac \ub418\uc5c8\uc2b5\ub2c8\ub2e4.","keywords":["\ud611\uc5c5","\ucf54\ub4dc \ucee8\ubca4\uc158"],"tags":["\ud611\uc5c5","\ucf54\ub4dc \ucee8\ubca4\uc158"]},"unlisted":false,"prevItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 4\uc8fc\ucc28 \uacf5\uc720(\ud234)","permalink":"/front-end/GwakSeungJu/infomate-4week"},"nextItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 3\uc8fc\ucc28 \uacf5\uc720(\ud611\uc5c5)","permalink":"/front-end/haejinyun/infomate-3week"}},"content":"\ub3d9\uc544\ub9ac\uc5d0\uc11c \uc57d 1\ub144 ~ 1\ub144 \ubc18\uc5d0 \uac78\uce5c \uae38\uace0 \uae38\uc5c8\ub358 \uca5d\uca5d\ubc15\uc0ac \ud504\ub85c\uc81d\ud2b8\uac00 \ub9c8\ubb34\ub9ac \ub418\uc5c8\uc2b5\ub2c8\ub2e4. \ud68c\uace0\ub97c \uc9c4\ud589\ud558\uba74\uc11c FE \ud300\uc6d0 \uacf5\ud1b5\uc801\uc73c\ub85c \uc598\uae30\ud588\ub358 \ucf54\ub4dc \ucee8\ubca4\uc158\uc5d0 \ub300\ud574 \uc774\uc57c\uae30\ud574\ubcf4\ub824 \ud569\ub2c8\ub2e4.\\n\\n{/* truncate */}\\n\\n\\n## \uc2dc\uc791\ud558\uae30 \uc804\u2026\\n\\n\ud611\uc5c5\uc744 \uc9c4\ud589\ud558\uba74\uc11c \ucf54\ub4dc \ucee8\ubca4\uc158\uc744 \uad6c\uccb4\uc801\uc73c\ub85c \uc815\ud558\uc9c0 \uc54a\uace0 \uc9c4\ud589\ud588\uc744 \ub54c \uacaa\uc5c8\ub358 \ubb38\uc81c\uc810 \ubc0f \ud574\uacb0\uacfc\uc815 \uadf8\ub9ac\uace0 \uc81c\uc548\ud560\uc810\uc5d0 \ub300\ud574 \uc4f4 \uae00\uc785\ub2c8\ub2e4.\\n\\n## \ucf54\ub4dc \ucee8\ubca4\uc158\uc774\ub780?\\n\\n:::note \ucf54\ub4dc \ucee8\ubca4\uc158\\n- \uc77d\uace0 \uad00\ub9ac\ud558\uae30 \uc26c\uc6b4 \ucf54\ub4dc\ub97c \uc791\uc131\ud558\uae30 \uc704\ud55c \uc77c\uc885\uc758 \ucf54\ub529 \uc2a4\ud0c0\uc77c \uaddc\uc57d(\ud558\ub098\uc758 \uc791\uc131 \ud45c\uc900)\uc774\ub2e4.\\n- \ud2b9\ud788, \ub2e4\ub978 \uc5b8\uc5b4\uc5d0 \ube44\ud574 \uc720\uc5f0\ud55c \ubb38\ubc95 \uad6c\uc870\ub97c \uac00\uc9c4 \uc5b8\uc5b4\uc77c\uc218\ub85d (ex. JavaScript) \uac1c\ubc1c\uc790 \uac04 \ud1b5\uc77c\ub41c \uaddc\uc57d\uc774 \uc5c6\ub2e4\uba74 \ucf54\ub4dc\uc758 \uc758\ub3c4\ub97c \ud30c\uc545\ud558\uac70\ub098 \uc624\ub958\ub97c \ucc3e\uae30 \uc5b4\ub824\uc6b0\uba70 \uc720\uc9c0\ubcf4\uc218 \ube44\uc6a9\uc774 \ub298\uc5b4\ub098\uae30 \ub54c\ubb38\uc5d0 \ucf54\ub4dc\uc758 \uac00\ub3c5\uc131\uc744 \ub192\uc774\uace0 \uc791\uc131\ud55c \ucf54\ub4dc\ub97c \ud6a8\uc728\uc801\uc73c\ub85c \uc720\uc9c0\ubcf4\uc218\ud558\uae30 \uc704\ud574\uc11c\ub294 \uacf5\ud1b5\uc758 \uaddc\uce59 (\ucf54\ub4dc \ucee8\ubca4\uc158)\uc744 \uaf2d \uc791\uc131\ud560 \ud544\uc694\uac00 \uc788\ub2e4.\\n:::\\n\\n\uc704\uc758 \uc124\uba85\uacfc \uac19\uc774 \ud1b5\uc77c\ub41c \uaddc\uc57d\uc774 \uc5c6\ub2e4\uba74 \ucf54\ub4dc\uc758 \uc758\ub3c4\ub098 \uc624\ub958\ub97c \ucc3e\uae30 \uc5b4\ub835\uae30 \ub54c\ubb38\uc5d0 \uaf2d \ud544\uc694\ud55c \ub2e8\uacc4\ub77c \uc815\uc758\ub418\uc5b4 \uc788\uc2b5\ub2c8\ub2e4. \ud2b9\ud788 \ud611\uc5c5\uc5d0\uc11c\ub294 \uaf2d \ud544\uc694\ud55c \ub2e8\uacc4\uc785\ub2c8\ub2e4. \\n\\n\ud558\uc9c0\ub9cc, \uadf8 \ub2f9\uc2dc\uc5d0 \ucc98\uc74c\uc73c\ub85c \uc9c4\ud589\ud574\ubcf4\ub294 \ud611\uc5c5 \ud504\ub85c\uc81d\ud2b8\uc600\uace0, \ucc98\uc74c \uc801\uc6a9\ud574 \ubcf4\ub294 \uae30\uc220 \uc2a4\ud0dd(Typescript, TanStack Query, Sass \ub4f1)\uc744 \ud559\uc2b5\ud558\uae30 \ubc85\ucc3c\uae30\uc5d0 \ucf54\ub4dc \ucee8\ubca4\uc158\uc5d0 \ub300\ud574 \uae4a\uac8c \uace0\ub824\ud558\uc9c0 \ubabb\ud588\uc5b4\uc694. ~~(\uc774\uac8c \ud070 \uc2a4\ub178\uc6b0\ubcfc\uc774 \ub420 \uc904\uc774\uc57c\u2026)~~\\n\\n## \uc5b8\uc81c \uae68\ub2ec\uc558\uc5b4?\\n\\n*\ucc98\uc74c\uc774 \ub450 \ubc88\uc774 \ub418\uace0, \uc138 \ubc88\uc774 \ub420 \ub54c\ucbe4\uc5d4\u2026\uc774\ubbf8 \ub2a6\uc5b4\ubc84\ub838\ub2e4.*\\n\\n### \ucc98\uc74c. \ud3f4\ub354 \uad6c\uc870\\n\\npr \uacfc\uc815\uc5d0\uc11c \ub2e4\uc591\ud55c \ud3f4\ub354 \uad6c\uc870\ub97c \ubcfc \uc218 \uc788\uc5c8\uc2b5\ub2c8\ub2e4. \uc544\ub798\ub294 \uae30\uc5b5\uc5d0 \ub0a8\ub294 \ud3f4\ub354 \uad6c\uc870\uc608\uc694.\\n\\n1. \ud568\uc218\uba85 \ud3f4\ub354 \uad6c\uc870\\n    \\n    \uc774 \ub2f9\uc2dc\uc5d0\ub294 \ubcf5\uc7a1\ud55c \ud3f4\ub354 \uad6c\uc870\ub97c \uac00\uc9c8 \uacbd\uc6b0\uc5d0\ub9cc *\ud568\uc218\uba85 \ud3f4\ub354\ub85c \ubd84\ub9ac\ud574 \ub193\ub294 \uac83*\uc744 \uad8c\uc7a5\ud588\uc5b4\uc694. \ub300\ubd80\ubd84\uc758 \ud3f4\ub354 \uad6c\uc870\uac00 *components \ud3f4\ub354 \ub0b4\uc5d0 \ud568\uc218\uba85 \ud3f4\ub354*\ub85c \uc774\ub8e8\uc5b4\uc84c\uae30\uc5d0 \uad8c\uc7a5\ud588\ub358 \ubc29\uc2dd\uc774\uc5c8\uc8e0.\\n    \\n    <img src=\\"/img/@frontEnd/code-convention/Untitled.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"20px\\" }}/>\\n\\n    <details markdown=\\"1\\">\\n      <summary>\ud3f4\ub354 \uad6c\uc870 Before/After</summary>\\n      <div>\\n        <ul style={{ listStyle: \\"none\\", display: \\"flex\\", justifyContent: \\"space-evenly\\", padding:\\"0\\" }}>\\n          <li>\\n            ```\\n            // Before\\n            \ud83d\udce6Inquiry\\n            \u2523 \ud83d\udcc2hooks\\n            \u2523 \ud83d\udcc2Inquire\\n            \u2503 \u2523 \ud83d\udcc2components\\n            \u2503 \u2503 \u2523 \ud83d\udcc2Explain\\n            \u2503 \u2503 \u2517 \ud83d\udcc2InquireForm\\n            \u2503 \u2503 \u2503 \u2523 \ud83d\udcc2components\\n            \u2503 \u2503 \u2503 \u2503 \u2517 \ud83d\udcc2RequiredLabel\\n            \u2517 \ud83d\udcc2Inquiry\\n            \u2503 \u2523 \ud83d\udcc2components\\n            \u2503 \u2503 \u2523 \ud83d\udcc2InquiryList\\n            \u2503 \u2503 \u2503 \u2523 \ud83d\udcc2components\\n            \u2503 \u2503 \u2503 \u2503 \u2517 \ud83d\udcc2InquiryBlock\\n            \u2503 \u2503 \u2503 \u2503 \u2503 \u2523 \ud83d\udcc2components\\n            \u2503 \u2503 \u2503 \u2503 \u2503 \u2503 \u2517 \ud83d\udcc2Answer\\n            \u2503 \u2503 \u2523 \ud83d\udcc2InquirySelectButton\\n            \u2503 \u2503 \u2517 \ud83d\udcc2SearchBar\\n            ```\\n          </li>\\n          <li>\\n            ```\\n            // After\\n            \ud83d\udce6Inquiry\\n            \u2523 \ud83d\udcc2hooks\\n            \u2523 \ud83d\udcc2Inquire\\n            \u2503 \u2523 \ud83d\udcc2components\\n            \u2503 \u2503 \u2523 \ud83d\udcc2Explain\\n            \u2503 \u2503 \u2517 \ud83d\udcc2InquireForm\\n            \u2503 \u2503 \u2503 \u2523 \ud83d\udcc2RequiredLabel\\n            \u2517 \ud83d\udcc2Inquiry\\n            \u2503 \u2523 \ud83d\udcc2components\\n            \u2503 \u2503 \u2523 \ud83d\udcc2InquiryList\\n            \u2503 \u2503 \u2503 \u2523 \ud83d\udcc2InquiryBlock\\n            \u2503 \u2503 \u2503 \u2503 \u2523 \ud83d\udcc2Answer\\n            \u2503 \u2503 \u2503 \u2503 \u2523 \ud83d\udcc2InquiryImages\\n            \u2503 \u2503 \u2523 \ud83d\udcc2InquirySelectButton\\n            \u2503 \u2503 \u2517 \ud83d\udcc2SearchBar\\n            \\n\\n            ```\\n          </li>\\n        </ul>\\n      </div>\\n    </details>\\n        \\n        \\n        \\n    \\n2. Mobile/PC \ubd84\ub9ac\\n    \\n    Mobile \ud658\uacbd\uacfc PC \ud658\uacbd\uc744 \ubd84\ub9ac\ud574\uc11c \uae30\ub2a5\uc744 \uad6c\ud604\ud55c \ud300\uc6d0\ub3c4 \uc788\uc5c8\uc5b4\uc694. \uac01\uac01\uc758 \ud658\uacbd\uc5d0\uc11c \ub514\uc790\uc778\uc774 \ub108\ubb34 \ub2ec\ub790\uae30\uc5d0 \uc11c\ub85c \ubd84\ub9ac\ud574\uc11c \uc9c4\ud589\ud55c \uacbd\uc6b0\uac00 \uc774\uc5d0 \ud574\ub2f9\ud574\uc694.\\n    \\n    ```\\n    \ud83d\udce6Setting\\n     \u2523 \ud83d\udcc2hooks\\n     \u2523 \ud83d\udcc2Mobile\\n     \u2523 \ud83d\udcc2PC\\n     \u2523 \ud83d\udcc2static\\n     \u2523 \ud83d\udcc2Withdrawal\\n     \u2517 \ud83d\udcdcindex.tsx\\n    ```\\n    \\n\\n\uc774 \uc678\uc5d0\ub3c4 \ub2e4\uc591\ud55c \ud3f4\ub354 \uad6c\uc870\uac00 \uc788\uc5c8\uc9c0\ub9cc \ud3f4\ub354 \uad6c\uc870\uc5d0 \ub300\ud55c \uc815\ub2f5\uc740 \uc5c6\uace0, \uadf8\uc800 \ubcf5\uc7a1\ud558\uc9c0 \uc54a\ub2e4\uba74 \uad1c\ucc2e\ub2e4\uace0 \uc0dd\uac01\ud588\uae30 \ub54c\ubb38\uc5d0 \ud06c\uac8c \ubd88\ud3b8\ud568\uc744 \ub290\ub07c\uc9c0 \uc54a\uc558\uc5b4\uc694. \ubb34\uc5c7\ubcf4\ub2e4 \uae30\ub2a5 \uad6c\ud604\uc774 \uac00\uc7a5 \ud070 \uc6b0\uc120\uc21c\uc704\uc5d0 \uc788\uae30\uc5d0 \ud3f4\ub354 \uad6c\uc870\uc5d0 \ub300\ud574\uc11c\ub294 \ud06c\uac8c \uace0\ub824\ud558\uc9c0 \uc54a\uc558\uc8e0.\\n\\n### \ub450\ubc88. \ud63c\uc6a9\ud558\ub294 \ub124\uc774\ubc0d\ub4e4\\n\\n\uc8fc\uac04 \uacf5\uc720 \uc2dc\uac04\uc5d0 \ub098\uc628 \ud63c\uc6a9\ud558\ub294 \ub124\uc774\ubc0d\ub4e4\uc5d0 \uad00\ud574\uc11c \uc815\ub9ac\ud574\uc57c\ud560 \uc0c1\ud669\uc774\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n1. scss\ub97c import\ud558\ub294 \uacfc\uc815\uc5d0\uc11c style\uc774\ub098 styles\ub85c \ud63c\uc6a9\ud574\uc11c \uc0ac\uc6a9\\n2. \uc0c1\uc810\uc744 store\uc774\ub098 shop\uc73c\ub85c \ud63c\uc6a9\ud574\uc11c \uc0ac\uc6a9\\n\\n\uc704\uc758 \ub450 \ubb38\uc81c \uc0ac\ud56d\uc5d0 \ub300\ud574 \ucc98\uc74c \ub4e0 \uc0dd\uac01\uc740 \u2018\uadf8\ub7fc \ub2e4\uc74c pr\ubd80\ud130 \uace0\uce58\uba74 \ub418\uaca0\ub2e4\u2019\uc600\uc5b4\uc694. \\n\\n\uac04\ub2e8\ud558\uac8c, styles\ub85c import\ud558\ub294 \ube44\uc728\uc774 \ub9ce\uae30 \ub54c\ubb38\uc5d0 **styles**\ub85c, \uc804\uc5ed\uc0c1\ud0dc\ub97c store \ud3f4\ub354\uc5d0 \uad00\ub9ac\ud558\uae30 \ub54c\ubb38\uc5d0 \uc0c1\uc810\uc740 **shop**\uc73c\ub85c \ud1b5\uc77c\ud558\ub294 \uac83\uc73c\ub85c \uacb0\uc815\ud588\uc8e0. \\n\\n\uc0ac\uc18c\ud55c \ub124\uc774\ubc0d \uc774\uc288\ub77c \uc0dd\uac01\ud588\uc9c0, \ucf54\ub4dc \ucee8\ubca4\uc158\uc744 \uc815\ud558\uc9c0 \uc54a\uc558\uae30\uc5d0 \ubc1c\uc0dd\ud55c \ubb38\uc81c\uc810\uc774\ub77c\uace0\ub294 \uc0dd\uac01\uc9c0\ub3c4 \ubabb\ud588\uac70\ub4e0\uc694. \\n\\n### \uc138\ubc88. QA\uc5d0\uc11c \ubc1c\uacac\ud55c \ub2e4\uc591\ud55c \ub124\uc774\ubc0d\\n\\n\ubc30\ud3ec \uc804 QA\ub97c \uc9c4\ud589\ud558\uba74\uc11c \ub2e4\uc591\ud55c \uc774\uc288\uac00 \ubc1c\uc0dd\ud588\uace0, \uc790\uc2e0\uc774 \uad6c\ud604\ud55c \ubd80\ubd84\uc5d0\uc11c\uc758 \uc774\uc288 \ud574\uacb0\ubfd0\ub9cc\uc774 \uc544\ub2c8\ub77c \ub2e4\ub978 \uc0ac\ub78c\uc774 \uad6c\ud604 \ubd80\ubd84\uc5d0\uc11c\ub3c4 \ud574\uacb0\uc774 \ud544\uc694\ud55c \uc0c1\ud669\uc774\uc5c8\uc5b4\uc694.\\n\\n\uadf8\ub807\ub2e4 \ubcf4\ub2c8 \ub2e4\ub978 \uc0ac\ub78c\uc774 \uc791\uc131\ud55c \ucf54\ub4dc \uc2a4\ud0c0\uc77c\uacfc \ub0b4\uac00 \uc791\uc131\ud55c \ucf54\ub4dc \uc2a4\ud0c0\uc77c\uc774 \uc815\ub9d0 \ub2e4\ub974\ub2e4\ub294 \uac83\uc744 \uae68\ub2eb\uac8c \ub418\uc5c8\uc2b5\ub2c8\ub2e4. \uadf8\uc81c\uc57c \ucf54\ub4dc \ucee8\ubca4\uc158\uc758 \uc911\uc694\uc131\uc744 \uae68\ub2ec\uc558\uc8e0. \uc704\uc5d0\uc11c \uc548\uc77c\ud558\uac8c \uc0dd\uac01\ud588\ub358 \ubb38\uc81c\uc810\ub4e4\uc758 \ucd1d\uc9d1\ud569\uc774\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n1. interface \uba85\\n    \\n    \uc544\ub798 \uc608\uc2dc\ub294 GET api\uc758 \uc751\ub2f5 \ub370\uc774\ud130\ub97c interface \ud0c0\uc785\uc73c\ub85c \ub098\ud0c0\ub0c8\uc744 \ub54c\uc758 \uc608\uc2dc\uc785\ub2c8\ub2e4. \uac01\uac01 \uc0c1\uc810/\ub9ac\ubdf0/\ud314\ub85c\uc6cc \uae30\ub2a5\uc744 \ub9e1\uc558\ub358 \uc0ac\ub78c\uc774 \ub2ec\ub790\uae30\uc5d0 \uc774\uc5d0 \ub530\ub978 interface \uba85\uba85 \uaddc\uce59\ub3c4 \uc11c\ub85c \ub2ec\ub790\uc5b4\uc694. \\n\\n    ```tsx\\n    // \ub2e8\uc77c \uc0c1\uc810 \uc870\ud68c : Fetch + \ud0c0\uc785\uba85 + Response\\n    export interface FetchShopResponse {\\n      // ...\\n    }\\n    \\n    // \uc791\uc131\ud55c \ub9ac\ubdf0\uac00 \uc788\ub294 \uc0c1\uc810 \ub9ac\uc2a4\ud2b8 \uc870\ud68c : \ud0c0\uc785\uba85 + Response\\n    export interface ReviewedShopsResponse {\\n      // ...\\n    }\\n    \\n    // \ud314\ub85c\uc6cc \ubaa9\ub85d \uc870\ud68c : Get + \ud0c0\uc785\uba85 + Response\\n    export interface GetFollowListResponse {\\n      // ...\\n    }\\n    ```\\n    \\n2. api \uc694\uccad\ud568\uc218\uba85\\n    \\n    \uc704\uc758 \uc751\ub2f5 \ub370\uc774\ud130\uc758 interface \uba85\uc774 \ub2e4\ub978 \uac83 \ucc98\ub7fc api \uc694\uccad\ud568\uc218\uba85 \ub610\ud55c \uc11c\ub85c \ub2ec\ub790\uc2b5\ub2c8\ub2e4. fetch\uc640 get\uc744 \uad6c\ubd84 \uc5c6\uc774 \uc0ac\uc6a9\ud558\ub294 \ud568\uc218\uba85\uc774 \ub9ce\uc558\uc5c8\uc8e0.\\n    \\n    ```tsx\\n    // fetch + \ud568\uc218\uba85\\n    export const fetchShop = async (placeId: string) => {\\n      const { data } = await shopApi.get<FetchShopResponse>(`/shops/${placeId}`);\\n      return data;\\n    };\\n    \\n    // get + \ud568\uc218\uba85\\n    export const getReviewedShops = async () => myPageApi.get<ReviewedShopsResponse>(\'/review/shops?size=10\');\\n    \\n    // \ud568\uc218\uba85\\n    export const followList = (pageParam: string) => followApi.get<GetFollowListResponse>(`/follow/followers?pageSize=10&${pageParam}`);\\n    ```\\n    \\n3. \ucef4\ud3ec\ub10c\ud2b8 props\uba85\\n    \\n    \ucef4\ud3ec\ub10c\ud2b8\uc758 Props \uc5ed\uc2dc `Props` \ub9cc\uc744 \uc0ac\uc6a9\ud558\uac70\ub098, `\ucef4\ud3ec\ub10c\ud2b8\uba85 + Props`\ub97c \ud63c\uc6a9\ud574\uc11c \uc0ac\uc6a9\ud558\uace0 \uc788\uc5c8\uc5b4\uc694.\\n    \\n    ```tsx\\n    // Type1 : Props\\n    interface Props {\\n      className: string;\\n      onClick: () => void;\\n      isActive: boolean;\\n    }\\n    \\n    // Type2 : \ucef4\ud3ec\ub10c\ud2b8\uba85 + Props\\n    interface SearchBarProps {\\n      className?: string;\\n      onChange: (text: string) => void;\\n      onSubmit: () => void;\\n    }\\n    ```\\n    \\n\\n\uc774 \uc678\uc5d0\ub3c4 \ud30c\uc77c\uba85, \ubcc0\uc218\uba85 \ub4f1 \ub2e4\uc591\ud55c \ubd80\ubd84\uc5d0\uc11c \ucf54\ub4dc\uc758 \uc77c\uad00\uc131\uc744 \ub290\ub084 \uc218\uac00 \uc5c6\uc5c8\uc5b4\uc694. \ub2e4\ub978 \uc0ac\ub78c\uc774 \uc791\uc131\ud55c \ucf54\ub4dc\ub97c \uc774\ud574\ud558\ub294 \uac83\ub3c4 \ubc85\ucc3c\ub294\ub370 \ucf54\ub4dc\uc758 \uc77c\uad00\uc131\uc774 \uc5c6\uc73c\ub2c8 \uc720\uc9c0\ubcf4\uc218 \ubc0f \uac00\ub3c5\uc131 \uce21\uba74\uc5d0\uc11c \ub5a8\uc5b4\uc9c0\ub294 \uac83\uc774 \ud655\uc5f0\ud788 \ub290\uaf08\uc8e0.\\n\\n## \uc81c\uc548\ud560 \uc810\\n\\n\uc704\uc640 \uac19\uc740 \ubb38\uc81c\uc810\uc744 \uacaa\uc5c8\uae30\uc5d0 \ud504\ub85c\uc81d\ud2b8 \uc9c4\ud589\uc804 \ucf54\ub4dc \ucee8\ubca4\uc158\uc744 \uc9c4\ud589\ud560 \ub54c \uba87 \uac00\uc9c0 \uc0ac\ud56d\uc744 \uc81c\uc548\ud569\ub2c8\ub2e4.\\n\\n### 1. \uad6c\uccb4\uc801\uc778 \ub124\uc774\ubc0d \uc815\ud558\uae30\\n\\n\uad6c\uae00\uc5d0 \uac80\uc0c9\uc744 \ud558\uba74 \ub2e4\uc591\ud55c \ucf54\ub4dc \ucee8\ubca4\uc158\uc758 \uc608\uc2dc\uac00 \uc788\uc2b5\ub2c8\ub2e4. \uc81c\uc548\ud55c \ub124\uc774\ubc0d\uc758 \uacbd\uc6b0 \uc774\ubc88 \ud504\ub85c\uc81d\ud2b8\ub97c \uc9c4\ud589\ud558\uba74 \ub193\ucce4\ub358 \ub124\uc774\ubc0d \ucee8\ubca4\uc158\uc774\uae30 \ub54c\ubb38\uc5d0 \uc544\ub798\uc758 \uc608\uc2dc\ub97c \ubb34\uc870\uac74 \ub530\ub974\uae30\ubcf4\ub2e8 \uac01 \uc0c1\ud669\uc5d0 \ub9de\uac8c \uc801\uc6a9\ud558\uba74 \ub420 \uac83 \uac19\uc544\uc694. \\n\\n1. interface \uba85/api \uc694\uccad\ud568\uc218\uba85\\n    \\n    \uca5d\uca5d\ubc15\uc0ac \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c **api \ud3f4\ub354** \ub0b4\uc758 interface \uba85\uc740 `api\uc758 \uc751\ub2f5 \ub370\uc774\ud130 \ud0c0\uc785`\uc744 \ub098\ud0c0\ub0b4\ub294 interface\uc640 api \uc694\uccad\uc5d0 \ud544\uc694\ud55c `\ub9e4\uac1c\ubcc0\uc218 \ud0c0\uc785`\uc744 \ud0c0\ub098\ub0b4\ub294 interface\ub85c \ub098\ub260 \uc218 \uc788\uc5b4\uc694.\\n    \\n    \uc774\ub54c, \uc751\ub2f5\uc758 \uacbd\uc6b0\ub294 `\ud0c0\uc785\uba85 + Response` \uc73c\ub85c, \ub9e4\uac1c\ubcc0\uc218\ub294 `\ud0c0\uc785\uba85 + Parmas` \ud615\uc2dd\uc73c\ub85c \uc9c4\ud589\ud588\uc744 \ub54c \ucf54\ub4dc\uac00 \ub354 \uc774\ud574\ud558\uae30 \ud3b8\ud588\uc5b4\uc694. \uc774 \uc678\uc5d0 Fetch\ub098 Get\uc744 \uc811\ub450\uc0ac\ub85c \ub193\ub294 \uacbd\uc6b0\uac00 \uc788\uc5c8\uc9c0\ub9cc, interface \uba85\uc774 \ub108\ubb34 \uae38\uba74 \uc624\ud788\ub824 \uac00\ub3c5\uc131\uc774 \ub5a8\uc5b4\uc9c4\ub2e4\ub294 \ub290\ub08c\uc774 \ub4e4\uc5c8\uc5b4\uc694.\\n    \\n    api \uc694\uccad\ud568\uc218\ub294 HTTP \uba54\uc11c\ub4dc \uc885\ub958\ub97c \uc811\ub450\uc0ac\ub85c \uc0ac\uc6a9\ud588\ub358 \uac8c \ub354 \uc9c1\uad00\uc801\uc774\uc5c8\uc5b4\uc694. \uc608\ub97c \ub4e4\uc5b4, GET \uc694\uccad \ud568\uc218\ub77c\uba74 `get + \ud568\uc218\uba85`\uc758 \ud615\uc2dd\uc73c\ub85c \uc791\uc131\ud558\ub294 \uac83\ucc98\ub7fc\uc694.\\n    \\n    \uc704\uc758 \uc0ac\ud56d\uc744 \ud1a0\ub300\ub85c \uae30\uc874\uc758 \ucf54\ub4dc\ub97c \ubcc0\uacbd\ud558\uba74 \uc544\ub798\uc640 \uac19\uc774 \ubcc0\uacbd\ud560 \uc218 \uc788\uc5b4\uc694.\\n    \\n    ```tsx\\n    // \ub2e8\uc77c \uc0c1\uc810 \uc870\ud68c : \ud0c0\uc785\uba85 + Response\\n    export interface ShopResponse {\\n      // ...\\n    }\\n    \\n    // get + \ud568\uc218\uba85\\n    export const getShop = async (placeId: string) => {\\n      const { data } = await shopApi.get<ShopResponse>(`/shops/${placeId}`);\\n    \\n      return data;\\n    };\\n    ```\\n    \\n2. \ucef4\ud3ec\ub10c\ud2b8 props\uba85\\n    \\n    \ucef4\ud3ec\ub10c\ud2b8\uc758 props\uc758 \uacbd\uc6b0 `\ucef4\ud3ec\ub10c\ud2b8+Props`\uc73c\ub85c \ub124\uc774\ubc0d \ud558\uc9c0 \uc54a\uc544\ub3c4 \uba85\ud655\ud558\uac8c \ucef4\ud3ec\ub10c\ud2b8\uc5d0\uc11c \uc120\uc5b8\ub418\uae30 \ub54c\ubb38\uc5d0 `Props`\ud0c0\uc785\uc73c\ub85c \uc9c0\uc815\ud574\ub3c4 \uad1c\ucc2e\uc544\uc694. \ud1b5\uc77c\uc131 \uc5c6\ub294 \ud0c0\uc785\ub4e4\uc744 \uc544\ub798\uc640 \uac19\uc774 \ubcc0\uacbd\ud560 \uc218 \uc788\uaca0\ub124\uc694.\\n    \\n    ```tsx\\n    // Props\ub85c \ud1b5\uc77c\\n    interface Props {\\n      className: string;\\n      onClick: () => void;\\n      isActive: boolean;\\n    }\\n    \\n    interface Props {\\n      className?: string;\\n      onChange: (text: string) => void;\\n      onSubmit: () => void;\\n    }\\n    ```\\n    \\n\\n### 2. \ud3f4\ub354 \uad6c\uc870 \ud1b5\uc77c\\n\\n\uac1c\uc778\uc801\uc778 \uc0dd\uac01\uc774\uc9c0\ub9cc \ud3f4\ub354 \uad6c\uc870\ub294 *\ud568\uc218\uba85 \ud3f4\ub354\ub85c \ubd84\ub9ac*\ud588\ub358 \uad6c\uc870\uac00 \ub354 \uae54\ub054\ud558\uace0 \ubcf4\uae30 \ud3b8\ud588\uc5b4\uc694. **components \ud3f4\ub354** \ub0b4\uc5d0 `\ud568\uc218\uba85 \ud3f4\ub354`\ub85c \uad6c\ubd84\ud574 \ub193\uc73c\ub2c8 \uad6c\ubd84 \uc5c6\uc774 components\uc5d0 \ub123\ub294 \uac83\uc5d0 \ube44\ud574\uc11c \uc5b4\ub5a4 \uc2dd\uc73c\ub85c \ucef4\ud3ec\ub10c\ud2b8\ub97c \ubd84\ub9ac\ud588\ub294\uc9c0 \ud655\uc5f0\ud788 \ub208\uc5d0 \ubcf4\uc774\ub354\ub77c\uace0\uc694.\\n\\n<ul style={{ listStyle: \\"none\\", display: \\"flex\\", justifyContent: \\"space-evenly\\", padding:\\"0\\" }}>\\n  <li>\\n    <img src=\\"/img/@frontEnd/code-convention/Untitled 1.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ height: \\"400px\\" }}/>\\n  </li>\\n  <li>\\n    <img src=\\"/img/@frontEnd/code-convention/Untitled 2.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ height: \\"200px\\" }}/>\\n  </li>\\n</ul>\\n<br/>\\n\ubb3c\ub860 Mobile/PC\ub85c \ubd84\ub9ac\ud574 \ub193\uc740 \ud300\uc6d0\ub3c4 \uc788\uc5c8\uc9c0\ub9cc, \uac01\uac01\uc758 \ucef4\ud3ec\ub10c\ud2b8\uac00 \uba85\ud655\ud558\uac8c \ubd84\ub9ac\ub418\uc9c0 \uc54a\ub294\ub2e4\ub294 \ubb38\uc81c\uc810\uc774 \uc788\uae30 \ub54c\ubb38\uc5d0 \uc800\ub294 \uc704\uc758 \ubc29\uc2dd\uc744 \uc790\uc8fc \uc0ac\uc6a9\ud588\uc5b4\uc694. \uc544\ub798\uc758 \uc608\uc2dc\ub294 \ubaa8\ud638\ud55c \ucef4\ud3ec\ub10c\ud2b8\uac00 \uc0dd\uacbc\uc744 \ub54c\uc758 \uc608\uc2dc\uc608\uc694.\\n\\n```tsx\\nimport PasswordSuccessModal from \'pages/Setting/PC/PasswordSuccessModal\';\\n// PC \ucef4\ud3ec\ub10c\ud2b8 import\\n\\nexport default function IdChange(): JSX.Element {\\n  // Mobile \ud3f4\ub354 \ub0b4\uc758 IdChange \ucef4\ud3ec\ub10c\ud2b8 \ucf54\ub4dc...\\n}\\n\\n```\\n\\n**Mobile \ud3f4\ub354**\uc758 `IdChange.tsx` \ucef4\ud3ec\ub10c\ud2b8\ub97c \ubcf4\uba74 **PC \ud3f4\ub354**\uc758 \ucef4\ud3ec\ub10c\ud2b8\ub97c import\ud55c\ub2e4\ub294 \uac83\uc744 \uc54c \uc218 \uc788\uc5b4\uc694. \uba85\ud655\ud558\uac8c \ubd84\ub9ac\ud558\uae30 \uc5b4\ub824\uc6b8 \ubfd0\ub9cc\uc774 \uc544\ub2c8\ub77c UI\uac00 \ubcc0\uacbd\ub420 \uacbd\uc6b0 \ub354 \ubaa8\ud638\ud574\uc9c0\ub294 \uc0c1\ud669\uc774 \ub420 \uc218 \uc788\uae30 \ub54c\ubb38\uc5d0 \uc88b\uc740 \ud3f4\ub354 \uad6c\uc870\uac00 \uc544\ub2c8\ub77c\ub294 \uc0dd\uac01\uc774 \ub4e4\uc5c8\uc8e0. \\n\\n\ud3f4\ub354 \uad6c\uc870\ub294 \uc815\ub9d0 \ub2e4\uc591\ud55c \ubc29\uc2dd\uc73c\ub85c \uad6c\uc131\ud560 \uc218 \uc788\uc9c0\ub9cc \ud611\uc5c5\uc744 \uc704\ud574\uc11c\ub77c\uba74 \ud1b5\uc77c\ud558\ub294 \uac83\ub3c4 \uace0\ub824\ud574 \ubcfc \uc0ac\ud56d\uc774\ub77c\uace0 \uc0dd\uac01\ud574\uc694. \\n\\n### 3. import/order \uaddc\uce59 \uc124\uc815\\n\\n<ul style={{ listStyle: \\"none\\", display: \\"flex\\", justifyContent: \\"space-evenly\\", padding:\\"0\\" }}>\\n  <li>\\n    <img src=\\"/img/@frontEnd/code-convention/Untitled 3.png\\" alt=\\"\uc774\ubbf8\uc9c0\\"/>\\n  </li>\\n  <li>\\n    <img src=\\"/img/@frontEnd/code-convention/Untitled 4.png\\" alt=\\"\uc774\ubbf8\uc9c0\\"/>\\n  </li>\\n</ul>\\n\\n\uc74c\uc2dd\uc810 \uac80\uc0c9/\uac8c\uc2dc\ubb3c \uac80\uc0c9 \ubd80\ubd84\uc744 \uc218\uc815\ud588\uc744 \ub54c \uc62c\ub77c\uc654\ub358 pr\uc774\uc5d0\uc694. \ud655\uc778 \uacb0\uacfc \uac01\uc790 \ub9e1\uc740 \ubd80\ubd84\uc5d0\uc11c import \uc21c\uc11c\uac00 \ub2e4\ub974\ub2e4\ub294 \uac83\uc744 \ubc1c\uacac\ud588\uace0,  [import/order](https://github.com/import-js/eslint-plugin-import/blob/main/docs/rules/order.md)\uacfc [sort-imports](https://eslint.org/docs/latest/rules/sort-imports)\uc744 \ud65c\uc6a9\ud574 import \uaddc\uce59\uc744 \uc815\ud588\uc5b4\uc694.\\n\\n<details markdown=\\"1\\">\\n  <summary>import/order \uaddc\uce59</summary>\\n  <div>\\n  ```tsx\\n    \\"import/order\\": [\\n          \\"error\\",{\\n            \\"groups\\": [\\"builtin\\", \\"external\\", \\"internal\\", [\\"sibling\\", \\"parent\\", \\"index\\"], \\"type\\", \\"unknown\\"],\\n            \\"pathGroups\\": [\\n              {\\n                \\"pattern\\": \\"react*\\",\\n                \\"group\\": \\"builtin\\",\\n                \\"position\\": \\"after\\"\\n              }\\n            ],\\n            \\"alphabetize\\": {\\n              \\"order\\": \\"asc\\",\\n              \\"caseInsensitive\\": true\\n            },\\n            \\"newlines-between\\":\\"always\\",\\n            \\"pathGroupsExcludedImportTypes\\": [\\"react*\\"]\\n          }\\n        ],\\n    ```\\n    \\n    - react\uac00 \ud3ec\ud568\ub41c import\uac00 \uac00\uc7a5 \ucd5c\uc0c1\ub2e8\uc5d0 \uc704\uce58\ud558\uac8c \ud569\ub2c8\ub2e4.\\n    - \uc54c\ud30c\ubcb3\uc744 \uae30\uc900\uc73c\ub85c \uc624\ub984\ucc28\uc21c\uc73c\ub85c \uc815\ub82c\ub429\ub2c8\ub2e4.\\n    - \uadf8\ub8f9\uc0ac\uc774\uc5d0 \ucd5c\uc18c \ud55c \uc904 \uc774\uc0c1\uc758 \uc904 \ubc14\uafc8\uc744 \uac15\uc81c\ud569\ub2c8\ub2e4. \\n  </div>\\n</details>\\n<details markdown=\\"1\\">\\n  <summary>sort-imports \uaddc\uce59</summary>\\n  <div>\\n  ```tsx\\n        \\"sort-imports\\": [\\n          \\"error\\",\\n          {\\n            \\"ignoreCase\\": true,\\n            \\"ignoreMemberSort\\": false,\\n            \\"ignoreDeclarationSort\\": true,\\n            \\"memberSyntaxSortOrder\\": [\\"none\\", \\"all\\", \\"multiple\\", \\"single\\"]\\n          }\\n        ],\\n    ```\\n    \\n    - \ubaa8\ub4c8\uc758 \ub300\uc18c\ubb38\uc790 \uad6c\ubd84\uc744 \ubb34\uc2dc\ud569\ub2c8\ub2e4.\\n    - \ubaa8\ub4c8 \ub0b4\uc758 \uc815\ub82c\uc744 \ubb34\uc2dc\ud569\ub2c8\ub2e4.\\n    - `import/order`\uc758 `groups` \uc635\uc158\uc758 \uc6b0\uc120\uc21c\uc704\ub97c \uc704\ud574 `ignoreDeclarationSort` \ub97c true\ub85c \ubcc0\uacbd\ud569\ub2c8\ub2e4. \uc774\ub294 `memberSyntaxSortOrder`\uc758 \uaddc\uce59\uc5d0\ub3c4 \uc601\ud5a5\uc744 \ubbf8\uce58\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.\\n  </div>\\n</details>\\n<br />\\n```tsx\\n// Before\\nimport { Link, useLocation } from \'react-router-dom\';\\nimport cn from \'utils/ts/classNames\';\\nimport { useAuth } from \'store/auth\';\\nimport styles from \'./BottomNavigation.module.scss\';\\nimport SpriteSvg from \'../SpriteSvg\';\\n\\n//After\\nimport { Link, useLocation } from \'react-router-dom\';\\n\\nimport SpriteSvg from \'components/common/SpriteSvg\';\\nimport { useAuth } from \'store/auth\';\\nimport cn from \'utils/ts/classNames\';\\n\\nimport styles from \'./BottomNavigation.module.scss\';\\n```\\n\\nstyles\ub97c \uc81c\uc678\ud55c \ubaa8\ub4e0 \uacbd\ub85c\ub294 \uc808\ub300\uacbd\ub85c\ub85c \uc218\uc815\ud588\uace0, \uadf8 \uacb0\uacfc \uc704\uc640 \uac19\uc774 \uc815\ub82c\ub41c \uac83\uc744 \ud655\uc778\ud560 \uc218 \uc774\uc5c8\uc5b4\uc694. \uc774\uc804\uc758 \ub4a4\uc8fd\ubc15\uc8fd\uc774\uc5c8\ub358 import \uad00\ub828 \ucf54\ub4dc\ub4e4\uacfc \ube44\uad50\ud574 \ubcf4\uc558\uc744 \ub54c \ud655\uc2e4\ud788 import\uc758 \ud750\ub984\uc774 \ub208\uc5d0 \ub354 \uc798 \ub4e4\uc5b4\uc624\uc9c0 \uc54a\ub098\uc694? \uc774 \ub54c\ubb38\uc5d0 \ud504\ub85c\uc81d\ud2b8 \uc2dc\uc791 \uc804 `import/order` \uaddc\uce59\uc744 \uc815\ud574\ubcf4\ub294 \uac83\uc744 \ucd94\ucc9c\ud574\uc694.\\n\\n### 4. \uacf5\uc6a9 \uc720\ud2f8\uc758 \uc8fc\uc11d\ucc98\ub9ac\ub97c \ud1b5\ud55c \uc811\uadfc\uc131 \uac1c\uc120\\n\\n\ud504\ub85c\uc81d\ud2b8 \uc9c4\ud589 \uc911\uac04\uc5d0 \uc0c8\ub85c\uc6b4 \ud300\uc6d0\ub4e4\uc774 \ub4e4\uc5b4\uc628 \uc801\uc774 \uc788\uc5c8\uc5b4\uc694. \uc57d 2\uc8fc\uac04\uc758 \uc628\ubcf4\ub529 \uae30\uac04\uc744 \uac70\uce5c \ud6c4\uc5d0 \ud504\ub85c\uc81d\ud2b8\uc5d0 \ucc38\uc5ec\ud558\uac8c \ub418\uc5c8\ub294\ub370 \uc9c0\uae08 \uc0dd\uac01\ud574 \ubcf4\uba74, \uc0c8\ub85c\uc6b4 \ud300\uc6d0\ub4e4\uc740 \ud604 \ud504\ub85c\uc81d\ud2b8\uc5d0 \uc0ac\uc6a9\ub418\ub294 \uae30\uc220 \uc2a4\ud0dd\uc744 \ud559\uc2b5\ud558\uae30\uc5d0 \ubc14\uc060 \ubfd0\ub9cc\uc774 \uc544\ub2c8\ub77c \uae30\uc874\uc5d0 \ub9cc\ub4e4\uc5b4\uc9c4 \ucf54\ub4dc\ub97c \ud574\uc11d\ud558\uae30\ub3c4 \ubc85\ucc30 \uac70\ub77c\ub294 \uc0dd\uac01\uc744 \ubabb \ud588\ub358 \uac83 \uac19\uc544\uc694.\\n\\n\ud2b9\ud788 \uc774\ubc88 \ud504\ub85c\uc81d\ud2b8\uc5d0\ub294 \uacf5\uc6a9 \uc720\ud2f8\uc774 \uaf64 \ub9ce\uc558\uc5c8\ub294\ub370 `\uc8fc\uc11d`\uc744 \ud1b5\ud574 \uc720\ud2f8\uc5d0 \ub300\ud55c \uc124\uba85\uc774 \uc788\uc5c8\ub354\ub77c\uba74 \uc6d0\ud560\ud55c \ud611\uc5c5\uc5d0 \ub3c4\uc6c0\uc774 \ub418\uc9c0 \uc54a\uc558\uc744\uae4c \uc2f6\ub124\uc694.\\n\\n\uac00\uc7a5 \uc790\uc8fc \uc0ac\uc6a9\ud588\ub358 useBooleanState\uc744 \uc608\ub85c \ub4e4\uba74 **\uc8fc\uc11d**\uc5d0 `\uac04\ub7b5\ud55c \uc124\uba85`, `params`, `return`\uc5d0 \uc815\ubcf4\ub97c \uae30\uc7ac\ud558\ub294 \uac83\uc774\uc5d0\uc694. \uad00\ub828 \uc720\ud2f8\uc758 \uc4f0\uc784\uc0c8\ub97c \uc54c \uc218 \uc788\uae30 \ub54c\ubb38\uc5d0 \ucf54\ub4dc\ub97c \uc774\ud574\ud558\ub294 \ub370 \ub3c4\uc6c0\uc774 \ub420 \uac83 \uac19\ub2e4\ub294 \uc0dd\uac01\uc774 \ub4e4\uc9c0 \uc54a\ub098\uc694? \ub2e4\uc74c \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c\ub294 \uc911\uac04\uc5d0 \ud22c\uc785\ub420 \uc0c8\ub85c\uc6b4 \ud300\uc6d0\uc744 \uc704\ud574 \uc8fc\uc11d\uc744 \ud1b5\ud574 \uc124\uba85\uc744 \uacc1\ub4e4\uc5ec\ubcf4\ub294 \uac83\uc744 \ucd94\ucc9c\ub4dc\ub824\uc694.\\n\\n```tsx\\nimport {\\n  Dispatch, SetStateAction, useCallback, useState,\\n} from \'react\';\\n\\ntype ReturnType = [boolean, () => void, () => void, () => void, Dispatch<SetStateAction<boolean>>];\\n\\n/**\\n * boolean \uc0c1\ud0dc\ub97c \ub2e4\ub8e8\ub294 \ucee4\uc2a4\ud140 \ud6c5\\n * @param {boolean} defaultValue \ucd08\uae30\uac12\\n * @return [value, setTrue, setFalse, toggle, setValue]\\n */\\nexport default function useBooleanState(defaultValue?: boolean): ReturnType {\\n  const [value, setValue] = useState(!!defaultValue);\\n\\n  const setTrue = useCallback(() => setValue(true), []);\\n  const setFalse = useCallback(() => setValue(false), []);\\n  const toggle = useCallback(() => setValue((x) => !x), []);\\n\\n  return [value, setTrue, setFalse, toggle, setValue];\\n}\\n\\n```\\n\\n<img src=\\"/img/@frontEnd/code-convention/Untitled 5.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" />\\n\\n## \ub9c8\ubb34\ub9ac\\n\\n\ucf54\ub4dc \ucee8\ubca4\uc158\uc744 \uad6c\uccb4\uc801\uc73c\ub85c \ud558\uc9c0 \uc54a\uc558\uc744 \ub54c\uc758 \ub2e4\uc591\ud55c \ubb38\uc81c\uc810\uc744 \uacaa\uc5c8\uc9c0\ub9cc, \uccab \ud504\ub85c\uc81d\ud2b8\uc600\ub358 \ub9cc\ud07c \uc644\uc131\ud588\ub2e4\ub294 \uac83\uc5d0 \uc758\uc758\ub97c \ub450\uace0 \uc2f6\ub124\uc694. \uc18c\ud1b5\uc774\ub098 \uae30\ub2a5 \uac1c\ubc1c\uc5d0 \uc6b0\uc120\uc21c\uc704\ub97c \ub480\uc9c0, \ucf54\ub4dc \ucee8\ubca4\uc158\uc5d0 \ub300\ud574\uc11c\ub294 \uae4a\uac8c \uace0\ubbfc\ud574 \ubcf8 \uc801\uc740 \uc5c6\uc5c8\ub294\ub370\u2026\uae00\ub85c \uc815\ub9ac\ud558\uba74\uc11c \uc0dd\uac01 \uc678\ub85c \ub193\uce5c \ubd80\ubd84\uc774 \ub9ce\uc558\ub2e4\ub294 \uac83\uc744 \ub290\uaf08\uc5b4\uc694. \uc5b4\uca4c\uba74 \uc5ec\uc804\ud788 \ub193\uce5c \ubd80\ubd84\uc774 \uc788\uc744 \uc218\ub3c4 \uc788\uace0\uc694. \uadf8\ub807\uae30 \ub54c\ubb38\uc5d0 \ub2e4\uc74c \ud504\ub85c\uc81d\ud2b8 \ub54c\uc5d0\ub294 \uc88b\uc740 \ucf54\ub4dc \ucee8\ubca4\uc158\uc73c\ub85c \uc6d0\ud65c\ud55c \ud611\uc5c5\uc744 \uc9c4\ud589\ud574 \ubd10\uc694! \ub9c8\uc9c0\ub9c9\uc73c\ub85c \uc774\ubc88 \uca5d\uca5d\ubc15\uc0ac \ud504\ub85c\uc81d\ud2b8\uc5d0 \ucc38\uc5ec\ud55c \ubaa8\ub4e0 \ubd84\ub4e4 \uc218\uace0 \ub9ce\uc73c\uc168\uc2b5\ub2c8\ub2e4!"},{"id":"/haejinyun/infomate-3week","metadata":{"permalink":"/front-end/haejinyun/infomate-3week","source":"@site/@frontEnd/haejinyun/infomate-3week.mdx","title":"\uc778\ud3ec\uba54\uc774\ud2b8 3\uc8fc\ucc28 \uacf5\uc720(\ud611\uc5c5)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 3\uc8fc\ucc28 \uacf5\uc720(\ud611\uc5c5) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","date":"2024-03-18T00:00:00.000Z","tags":[{"label":"\uc778\ud3ec\uba54\uc774\ud2b8","permalink":"/front-end/tags/\uc778\ud3ec\uba54\uc774\ud2b8"},{"label":"\ud611\uc5c5","permalink":"/front-end/tags/\ud611\uc5c5"}],"readingTime":13.28,"hasTruncateMarker":true,"authors":[{"name":"haejinyun","url":"https://github.com/haejinyun","email":"dbshaejin@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/86779590?v=4","key":"haejinyun"}],"frontMatter":{"date":"2024-03-18T00:00:00.000Z","authors":"haejinyun","title":"\uc778\ud3ec\uba54\uc774\ud2b8 3\uc8fc\ucc28 \uacf5\uc720(\ud611\uc5c5)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 3\uc8fc\ucc28 \uacf5\uc720(\ud611\uc5c5) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","keywords":["\uc778\ud3ec\uba54\uc774\ud2b8","\ud611\uc5c5"],"tags":["\uc778\ud3ec\uba54\uc774\ud2b8","\ud611\uc5c5"]},"unlisted":false,"prevItem":{"title":"\ucf54\ub4dc \ucee8\ubca4\uc158\uc758 \uc911\uc694\uc131","permalink":"/front-end/posts/code-convention"},"nextItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 2\uc8fc\ucc28 \uacf5\uc720(\ube0c\ub77c\uc6b0\uc800)","permalink":"/front-end/d0dam/infomate-2week"}},"content":"\uc778\ud3ec\uba54\uc774\ud2b8 3\uc8fc\ucc28 \uacf5\uc720(\ud611\uc5c5) \ubaa8\uc74c\uc785\ub2c8\ub2e4.     \\n\\n\uc544\ub2c8 Query Key\uac00 \ubb34\uc2a8 \ud638\ud06c\ub8e9\uc2a4\uc778\uac00\uc694? - \uc724\ud574\uc9c4     \\nCI/CD\uac00 \ud611\uc5c5\uc5d0 \ud544\uc694\ud55c \uc774\uc720 - \uae40\ud558\ub098\\n\\n{/* truncate */}\\n\\n\\n\\n# **[\uc778\ud3ec\uba54\uc774\ud2b8 3\ucc28\uc2dc \uacf5\uc720]**\\n\\n# \uc544\ub2c8 Query Key\uac00 \ubb34\uc2a8 \ud638\ud06c\ub8e9\uc2a4\uc778\uac00\uc694? - \uc724\ud574\uc9c4\\n\\n\\n\ud611\uc5c5\uc744 \ud558\uba74 \ubb34\uc5c7\uc774 \ub5a0\uc624\ub974\uc2dc\ub098\uc694?\\n\\n \ub2e4\uc591\ud55c \uac83\uc774 \uc788\uaca0\uc9c0\ub9cc \uc800\ub294 **\ucf54\ub4dc \ucee8\ubca4\uc158**\uacfc \uac19\uc740 \uac83\uc774 \uc6b0\uc120\uc801\uc73c\ub85c \uc0dd\uac01\uc774 \ub0ac\uc2b5\ub2c8\ub2e4.\\n\\n\uc0ac\ub78c\ub4e4\uc740 \uac01\uc790 \uac00\uc9c4 \ucf54\ub4dc\uc758 \uc2a4\ud0c0\uc77c\uc774 \uc788\uc2b5\ub2c8\ub2e4. (**\uac1c\ubc1c \ucabc**\ub77c\uace0 \ud560 \uc218\ub3c4 \uc788\uaca0\uc2b5\ub2c8\ub2e4.)\\n\\n\uadf8\ub7ec\ub098 \uc11c\ub85c \uac01\uae30 \ub2e4\ub978 \uc2a4\ud0c0\uc77c\uc774 \ud558\ub098\uc758 \uc11c\ube44\uc2a4\uc758 \uad6c\ud604\uc5d0\uc11c \ucda9\ub3cc\ud55c\ub2e4\uba74 \uc774\ud6c4 \uc791\uc5c5\uc790 \ud639\uc740 \uc2e0\uaddc \uc791\uc5c5\uc790\ub294 \ucf54\ub4dc\ub97c \uc77d\uc73c\uba70 \ud63c\ub3c8\uc5d0 \ube60\uc9c0\uace0 \ubd88\ud544\uc694\ud55c \uc2dc\uac04\uc744 \ub4e4\uc774\uac8c \ub420 \uac83\uc785\ub2c8\ub2e4. \\n\\n\ub530\ub77c\uc11c \uc800\ub294 \uc774\ubc88 `\ud611\uc5c5`\uc774\ub77c\ub294 \uc8fc\uc81c\uc5d0\uc11c `\ud6a8\uc728\uc131\uacfc \uc77c\uad00\uc131\uc744 \ub192\uc77c \uc218 \uc788\ub294 \uc804\ub7b5`\uc5d0 \ub300\ud574 \uacf5\uc720\ud574 \ubcf4\uace0\uc790 \ud558\ub294 \ud070 \ud2c0\uc744 \uc0dd\uac01\ud588\uc2b5\ub2c8\ub2e4.\\n\\n tanstack query (react query v5)\ub85c \ubc84\uc804\uc744 \uc62c\ub9ac\uace0 \uacf5\uc2dd \ubb38\uc11c\uc640 [TkDodo\'s blog](https://tkdodo.eu/blog)\ub97c \uc77d\uc73c\uba70 \uacf5\ubd80\ud558\ub358 \uc911 \uc774\uc804\ubd80\ud130 \ud544\uc694\ud558\ub2e4\uace0 \ub290\uaf08\ub358 react query key\uc758 \ud6a8\uc728\uc801\uc778 \uad00\ub9ac \ubc29\ubc95\uc744 \uc18c\uac1c\ud558\ub294 \uac83\uc744 \ubcf4\uc558\uc2b5\ub2c8\ub2e4. \\n\\n\uc801\uc808\ud55c query key \uad00\ub9ac \uc804\ub7b5\uc744 \ud1b5\ud574, \ud300\uc6d0 \uac04\uc758 \ucf54\ub4dc \uc774\ud574\ub3c4\ub97c \ub192\uc774\uace0, \uc804\uccb4 \ud504\ub85c\uc81d\ud2b8\uc758 \ud6a8\uc728\uc131\uacfc \uc720\uc9c0 \ubcf4\uc218\uc131\uc744 \ud5a5\uc0c1\uc5d0 \uc911\uc694\ud55c \uc5ed\ud560\uc744 \ud560 \uc218 \uc788\ub2e4 \uc0dd\uac01\ud558\uc5ec \uc138\ubd80\uc801\uc778 \uc8fc\uc81c\ub85c \uc120\ud0dd\ud574 \ubcf4\uc558\uc2b5\ub2c8\ub2e4.\\n\\n## React Query\uc5d0\uc11c Query key\uac00 \uc911\uc694\ud574\uc694?\\n\\n Query Key\uc758 \ub9e4\uc8fc \uc911\uc694\ud55c \ubd80\ubd84\uc740 `QueryCache(\ucffc\ub9ac \uce90\uc2dc)\uc640 \uc0c1\ud638\uc791\uc6a9`\ud558\uae30 \ub54c\ubb38\uc77c \uac83\uc785\ub2c8\ub2e4.\\n\\n\ub77c\uc774\ube0c\ub7ec\ub9ac \ub0b4\ubd80\uc801\uc73c\ub85c \uc62c\ubc14\ub978 \ub370\uc774\ud130 \uce90\uc2f1\uc744 \uac00\ub2a5\ud558\uac8c \ud569\ub2c8\ub2e4.\\n\\n\ub610\ud55c, \uc0c1\ud0dc\ub85c \uc874\uc7ac\ud558\ub294 query key \uac12\uc774 \ubc14\ub00c\uac8c \ub41c\ub2e4\uba74 \uc774\ub294 \ub9ac\ub80c\ub354\ub9c1\uc744 \ud1b5\ud574 React Query\uc758 query key\ub294 \ud56d\uc0c1 \ubcc0\ud560 \uac83\uc774\uba70 \ub370\uc774\ud130\ub97c \ub2e4\uc2dc \ubd88\ub7ec\uc624\uac8c \ub429\ub2c8\ub2e4. \u21d2 (\uc790\ub3d9\uc801\uc778 \uc0c1\ud638\uc791\uc6a9\uc774 \uc77c\uc5b4\ub098\uac8c \ub429\ub2c8\ub2e4.)\\n\\n\uadf8\ub7ec\ub098 \ub54c\ub54c\ub85c \uc6b0\ub9ac\ub294 **\uc218\ub3d9\uc801\uc778 \uc0c1\ud638\uc791\uc6a9\uc774 \ud544\uc694\ud55c \uacbd\uc6b0**\uac00 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4.\\n\\nquery key\uac00 \uac00\uc7a5 \uc911\uc694\ud55c \ubd80\ubd84\uc740 \ubc29\uae08 \uc5b8\uae09\ud55c \uce90\uc2dc\uc640 \uc218\ub3d9\uc801\uc73c\ub85c \uc0c1\ud638\uc791\uc6a9\ud558\ub294 \uacbd\uc6b0\uc785\ub2c8\ub2e4.\\n\\ninvalidate query\uc640 \uac19\uc774 \uac1c\ubc1c\uc790\uac00 \uc218\ub3d9\uc801\uc73c\ub85c \ucffc\ub9ac\ub97c \uc870\uc791\ud558\uace0\uc790 \ud560 \uacbd\uc6b0\uc5d0\ub3c4 query key\uac00 \uc0ac\uc6a9\ub429\ub2c8\ub2e4.\\n\\n## **\ud6a8\uc728\uc801\uc778 React Query key\uac00 \ud544\uc694\ud55c \uc774\uc720?**\\n\\n\uc55e\uc11c \uc774\uc57c\uae30\ud55c \ub300\ub85c react query\ub97c \uc774\uc6a9\ud560 \ub54c\ub294 query key\ub97c \uc791\uc131\ud574 \uc918\uc57c \ud569\ub2c8\ub2e4.\\n\\n\uadf8\ub7ec\ub098 query key\uc758 \uacbd\uc6b0 unique \ud55c \uac12\uc774\uc5b4\uc57c \ud569\ub2c8\ub2e4.\\n\\n\ub610\ud55c, \ub54c\ub54c\ub85c \uc6b0\ub9ac\ub294 mutation \uc774\ud6c4 \ud544\uc694\uc5d0 \ub530\ub77c query key\ub97c \ubb34\ud6a8\ud654 \uc2dc\ud0a4\uace0 \uc2f6\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uadf8\ub7ec\uae30 \uc704\ud574\uc120 \uace0\uc720\ud55c \ucffc\ub9ac\ud0a4\ub97c \ud544\uc694\uc5d0 \ub530\ub77c invalidate\ub85c \ubb34\ud6a8\ud654\ub97c \ud574\uc8fc\uc5b4\uc57c \ud569\ub2c8\ub2e4. \\n\\n\uc774\ub807\uac8c \uc6b0\ub9ac\ub294 key\ub97c \uc9c1\uc811\uc801\uc73c\ub85c \ub2e4\ub8e8\ub294 \uc77c\uc774 \uaf64\ub098 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc11c\ube44\uc2a4\uac00 \ubcf4\ub2e4 \ubcf5\uc7a1\ud574\uc9c4\ub2e4\uba74 query \ubb38\uacfc key\ub294 \ub354\ub354\uc6b1 \ub9ce\uc544\uc838 \ucd08\uc7a5\uc5d0 \uc798 \ub2e4\ub4ec\uc5b4 \ub193\uc9c0 \uc54a\uc73c\uba74 \ub9c8\uce58 \uc5c9\ud0a8 \uc2e4\ud0c0\ub798\ucc98\ub7fc \uaf2c\uc774\uace0 \ub9d0 \uac83\uc785\ub2c8\ub2e4. \\n\\n\uaddc\uce59 \uc5c6\uc774 \uc120\uc5b8\ub41c key\ub4e4\uc740 \uc5b4\ub514\uc5d0 \uc704\uce58\ud558\uace0 \uc788\ub294\uc9c0 \ucc3e\ub294 \uac83\uc5d0\ub3c4 \uc624\ub798 \uac78\ub9b4\ubfd0\ub354\ub7ec, invalidate\ub97c \ud1b5\ud574\uc11c \ubb34\ud6a8\ud654\ub97c \ud558\ub824 \ud574\ub3c4 \uc5b4\ub290 \uacf3\uc5d0\uc11c\ub294 \ub2e4\ub978 \uae30\uc900\uc73c\ub85c \uc120\uc5b8\ub41c key\ub4e4\ub85c \uc758\ub3c4\ud55c \ub300\ub85c \uc791\ub3d9\ud558\uc9c0 \uc54a\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ub610\ud55c unique \ud574\uc57c \ud558\ub294 key\uac00 \uacb9\uce5c \ucc44\ub85c \uc874\uc7ac\ud560 \uc218\ub3c4 \uc788\uc2b5\ub2c8\ub2e4. (\uc704 \uacbd\uc6b0\ub4e4\uc740 \uacbd\ud5d8\ub2f4\uc785\ub2c8\ub2e4..)\\n\\n\uc774\ub7ec\ud55c \uc774\uc720\ub85c \uc2dc\uac04\uc744 \ubc84\ub9ac\ub294 \uac83\uc774 \uc808\ub300 \uc88b\uc740 \uacbd\ud5d8\uc740 \uc544\ub2d0 \uac83\uc785\ub2c8\ub2e4. \\n\\n\ub530\ub77c\uc11c \uc800\ub294 \ud6a8\uc728\uc801\uc73c\ub85c key\ub97c \uad00\ub9ac\ud560 \uc218 \uc788\ub294 \ubc29\ubc95\uc5d0 \ub300\ud574\uc11c \uace0\ubbfc\ud558\uac8c \ub418\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n## \uadf8\ub807\ub2e4\uba74 \ud6a8\uc728\uc801\uc774\uae30 \uc704\ud574\uc11c \uc5b4\ub5a4 \ubc29\ubc95\uc744 \ud0dd\ud588\uc8e0? : Query Key Factory\\n\\nhttps://tkdodo.eu/blog/effective-react-query-keys\\n\\nReact Query \uacf5\ubd80\ub97c \ud558\ub358 \uc911 \ub9c8\uce68 query key \uad00\ub9ac\ubc95\uc774 \uc788\uc5b4 \uc77d\uc5b4\ubcf4\uac8c \ub418\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n\uc11c\ube44\uc2a4\uc758 \ud655\uc7a5\uc5d0 \ub530\ub978 \ud6a8\uacfc\uc801\uc778 keyFactory\ub97c \ud1b5\ud574 \ud0a4\ub97c \uad00\ub9ac \uc804\ub7b5\uc744 \uc18c\uac1c\ud558\uace0 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n\uac04\ub2e8\ud558\uac8c \uc694\uc57d\ud558\uc790\uba74, \uacf5\ud1b5\uc758 \ubd80\ubaa8 \ud3f4\ub354\uc5d0 **`\ud558\ub098\uc758 \uac1d\uccb4\ub85c \uc120\uc5b8`**\ud558\uac8c \ub41c\ub2e4\uba74 \uc720\uc9c0 \ubcf4\uc218 \ubc0f \ud574\ub2f9 query key \ud30c\uc545\uc774 \ubcf4\ub2e4 \ud6a8\uc728\uc801\uc77c \uac83\uc785\ub2c8\ub2e4.\\n\\n\uc544\ub798 \ucf54\ub4dc\uc640 \uac19\uc774 \uc5b4\ub5a0\ud55c \uae30\ub2a5\uacfc \uad00\ub828\ub41c query key\ub4e4\uc744 \ud558\ub098\uc758 \uac1d\uccb4\ub85c \ubaa8\uc544\ub450\uc5c8\uc2b5\ub2c8\ub2e4\\n\\n```tsx\\nexport const alarmKeys = {\\n  list: [\'alarm-list\'] as const,\\n  detail: (id: number) => [...alarmKeys.list, id] as const,\\n};\\n\\n```\\n\\n\uc774\ub807\uac8c \ub41c\ub2e4\uba74 \uc720\uc5f0\ud558\uace0 \ub3c5\ub9bd\uc801\uc73c\ub85c \ud0a4\uc5d0 \uc811\uadfc\uc774 \uac00\ub2a5\ud560\ubfd0\ub354\ub7ec \uc138\ubd80\uc801\uc778 key\ub97c \uc120\uc5b8\ud560 \ub54c \ucc38\uace0 \ubc0f \ubcc0\uacbd\uc774 \uc6a9\uc774\ud569\ub2c8\ub2e4.\\n\\n```tsx\\nimport { useMutation, useQueryClient } from \'@tanstack/react-query\';\\n\\nimport { postReadAlarm, postReadAllAlarm } from \'@/apis/alarm\';\\nimport { alarmKeys } from \'@/hooks/query/keyFactory/alarmKeys\';\\n\\nfunction useAlarmMutation() {\\n  const queryClient = useQueryClient();\\n\\n  const readAlarm = useMutation({\\n    mutationFn: postReadAlarm,\\n    onSuccess: () => {\\n      queryClient.invalidateQueries({ queryKey: alarmKeys.list });\\n    },\\n  });\\n\\n  const readAllAlarm = useMutation({\\n    mutationFn: postReadAllAlarm,\\n    onSuccess: () => {\\n      queryClient.invalidateQueries({ queryKey: alarmKeys.list });\\n    },\\n  });\\n\\n  return { readAlarm, readAllAlarm };\\n}\\n\\nexport default useAlarmMutation;\\n\\n```\\n\\n\uc704\uc640 \uac19\uc740 \ubc29\ubc95\uc73c\ub85c query\xa0key \uad00\ub9ac\uac00\xa0\uc774\ub8e8\uc5b4\uc9c0\ub2c8,\xa0key\ub97c \ucc3e\uae30 \uc704\ud574 \uc5ec\uae30\uc800\uae30 \ud30c\uc77c\uc744 \ub3cc\uc544\ub2e4\ub2d0 \ud544\uc694\ub3c4\xa0\uc5c6\uc5b4\uc84c\uc744\ubfd0\ub354\ub7ec,\xa0\uc0c8\ub85c\uc6b4 \ud0a4\ub97c\xa0\uc120\uc5b8\ud560 \ub54c\uc5d0\ub3c4\xa0\uace0\ubbfc\uc744 \ud558\uac70\ub098 \uae30\uc874 key\ub97c \ucc3e\ub294 \uc2dc\uac04\uc774 \ubd88\ud544\uc694\ud574\uc84c\uc2b5\ub2c8\ub2e4.\\n\\n## +P.S\\n\\n\ub2e4\ub978 \ubc29\ubc95 \ud639\uc740 \ucd94\ucc9c\ud574 \uc8fc\uc2e4 \ubc29\ubc95\uc774 \uc788\ub2e4\uba74 \ub313\uae00 \ub4f1\uc73c\ub85c \uacf5\uc720\ud574 \uc8fc\uc2dc\uba74 \uac10\uc0ac\ud558\uaca0\uc2b5\ub2c8\ub2e4!\\n\\n\uc77d\uc5b4\uc8fc\uc154\uc11c \uac10\uc0ac\ud569\ub2c8\ub2e4. \ud83d\ude01\\n\\n---\\n<br/>\\n\\n# CI/CD\uac00 \ud611\uc5c5\uc5d0 \ud544\uc694\ud55c \uc774\uc720 - \uae40\ud558\ub098\\n\\n\ud611\uc5c5 \uacbd\ud5d8\uc774 \ubd80\uc871\ud588\uc744 \ub54c\ub294 \uc791\uc5c5\ud55c \ub0b4\uc6a9\uc744 \ud55c \ubd84\uae30\uc5d0 \ud1b5\ud569\ud558\uace0 \ud574\ub2f9 \uc791\uc5c5\uc774 \ubc30\ud3ec\ub420 \ub54c\uae4c\uc9c0\uc758 \ud30c\uc774\ud504\ub77c\uc778\uc744 \uc218\ub3d9\uc73c\ub85c \uac80\uc99d\ud574\uc57c \ud588\ub358 \uae30\uc5b5\uc774 \uc788\uc2b5\ub2c8\ub2e4. \\n\\n\uadf8\ub7ec\ub098 Github Action\uc774\ub77c\ub294 CI/CD \ud234\uc744 \ud1b5\ud574 \ud611\uc5c5 \uacbd\ud5d8\uc744 \uac1c\uc120\ud558\uba74\uc11c, \ube0c\ub79c\uce58\ub97c \ubcd1\ud569\ud558\uae30 \uc804 CI\uc5d0\uc11c \ud14c\uc2a4\ud2b8\ub97c \uc218\ud589\ud558\uace0 \ubc30\ud3ec \uacfc\uc815(CD)\uc744 \uc790\ub3d9\ud654\ud560 \uc218 \uc788\uac8c \ub418\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n### CI/CD \uc124\uba85\\n\\nCI/CD\ub294 \ucf54\ub4dc \ubcc0\uacbd \uc0ac\ud56d\uc744 \ub354 \ube60\ub974\uace0 \uc548\uc815\uc801\uc73c\ub85c \uc81c\uacf5\ud558\uae30 \uc704\ud574 \ube4c\ub4dc, \ud14c\uc2a4\ud2b8 \ubc0f \ubc30\ud3ec\ub97c \uc790\ub3d9\ud654\ud558\ub294 \uac83\uc744 \uc758\ubbf8\ud569\ub2c8\ub2e4. \uc774\ub294 \uc9c0\uc18d\uc801\uc778 \ud1b5\ud569\uacfc \uc9c0\uc18d\uc801\uc778 \ubc30\ud3ec\ub85c \uc774\ub8e8\uc5b4\uc838 \uc788\uc73c\uba70, \uac01\uac01\uc758 \uc815\uc758\ub294 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.\\n\\n- CI - \uacf5\uc720 \uc800\uc7a5\uc18c\ub0b4\uc5d0\uc11c \ucf54\ub4dc \ubcc0\uacbd \uc0ac\ud56d\uc5d0 \ub300\ud55c \ube4c\ub4dc \ubc0f \ud14c\uc2a4\ud2b8\ub97c \ud1b5\ud569\ud55c\ub2e4.\\n- CD - \ubcc0\uacbd \uc0ac\ud56d\uc744 \ud504\ub85c\ub355\uc158 \ud658\uacbd\uc5d0 \uc804\ub2ec, \ucf54\ub4dc \ubcc0\uacbd \uc0ac\ud56d\uc744 \ubc30\ud3ec \uc790\ub3d9\ud654 \ud55c\ub2e4.\\n\\n\ub530\ub77c\uc11c CI/CD \ud30c\uc774\ud504\ub77c\uc778\uc740 \ubcf4\ud1b5 \ub450 \uac00\uc9c0 \uc139\uc158\uc73c\ub85c \ub098\ub258\uc5b4 \uc9c4\ud589\ub429\ub2c8\ub2e4.\\n\\n- build \u2192test \u2192 artifact / staging \u2192 production\\n\\nCI/CD \uc758 \uc790\uc138\ud55c \uc6cc\ud06c\ud50c\ub85c\uc6b0 \uc608\uc2dc\ub294 [\uc5ec\uae30](https://github.com/readme/guides/walking-the-walk-bringing-end-to-end-automation-and-testing-to-internal-teams)\ub97c \ucc38\uace0\ud558\uba74 \uc88b\uc744 \uac83 \uac19\uc2b5\ub2c8\ub2e4.\\n\\n###CI/CD\uc758 \uc774\uc810 \\n\\n[Google DevOps \ubcf4\uace0\uc11c](https://cloud.google.com/blog/products/devops-sre/the-2019-accelerate-state-of-devops-elite-performance-productivity-and-scaling?hl=en)\uc5d0 \ub530\ub974\uba74, CI/CD\ub97c \uc0ac\uc6a9\ud558\ub294 \uc870\uc9c1\uc740 \ub2e4\ub978 \uc870\uc9c1\ubcf4\ub2e4 \ubc30\ud3ec\ub97c 208\ubc30 \ub354 \uc790\uc8fc\ud558\uace0 \ub9ac\ub4dc \ud0c0\uc784\uc774 106\ubc30 \ub354 \ube60\ub974\ub2e4\uace0 \ud569\ub2c8\ub2e4. \uadf8 \uc678\uc758 \uc774\uc810\uc73c\ub85c\ub294 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.\\n\\n- \ucf54\ub4dc\ubca0\uc774\uc2a4\uac00 \uc5b8\uc81c\ub4e0\uc9c0 \uc548\uc815\uc801\uc778 \uc0c1\ud0dc \uc720\uc9c0\\n- \uc790\ub3d9\ud654\ub418\uace0 \uc9c0\uc18d\uc801\uc778 \ud14c\uc2a4\ud2b8 \uac00\ub2a5 (\ube44\uc6a9 \uc808\uac10 \ud6a8\uacfc)\\n- \ub9b4\ub9ac\uc2a4 \uc18d\ub3c4 \ub2e8\ucd95\\n- \uc624\ub958 \uaca9\ub9ac, \uc7a5\uc560 \uc9c0\uc810 \uac10\uc18c\\n- \uc624\ubc84\ud5e4\ub4dc \ube44\uc6a9 \uc808\uac10\\n\\n###\ud300\uc5d0 \ub3c4\uc785\ub418\uace0\uc788\ub294 cicd \ud604\ud669\\n\\n\uc800\ud76c \ud2b8\ub799\uc5d0\uc11c\ub294 Github Actions\ub97c \uc774\uc6a9\ud558\uc5ec CI/CD\ub97c \uc2e4\ud589\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\nGithub Actions\ub294 \ud2b9\uc815 \ub9ac\ud3ec\uc9c0\ud1a0\ub9ac\uc5d0\uc11c \ud2b8\ub9ac\uac70 \uc774\ubca4\ud2b8\uac00 \ubc1c\uc0dd\ud560 \ub54c GitHub Action Runner\uc5d0\uc11c \uc791\uc5c5\uc744 \uc2e4\ud589\ud558\ub294 \uad6c\uc870\uc785\ub2c8\ub2e4.\\n\\nRunner \uba38\uc2e0 \uad6c\ucd95 \uc774\ud6c4, \ub9ac\ud3ec\uc9c0\ud1a0\ub9ac\xa0`.github/workflows`\xa0\ub514\ub809\ud1a0\ub9ac\uc5d0 \uc6cc\ud06c\ud50c\ub85c\uc6b0 YAML \ud30c\uc77c\uc744 \uc791\uc131\ud558\uae30\ub9cc \ud558\uba74 \ubcc4\ub3c4\uc758 \uc124\uce58\ub098 \uc138\ud305 \uc5c6\uc774 \uc0ac\uc6a9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ud604\uc7ac\uae4c\uc9c0 \uc815\uc758\ub41c \uc6cc\ud06c\ud50c\ub85c\uc6b0\ub294 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.\\n\\n1. Lint Check\\n\\n\ucf54\ub4dc \ubca0\uc774\uc2a4\uc758 \uc548\uc815\uc131, \ubc30\ud3ec \uacfc\uc815\uc5d0\uc11c\uc758 \uc5d0\ub7ec\ub97c \ucd5c\uc18c\ud654\ud558\uae30 \uc704\ud574 \ub3c4\uc785\ub418\uc5c8\uc2b5\ub2c8\ub2e4. Pull Request\uac00 \ub4f1\ub85d\ub418\uba74 \uc790\ub3d9\uc73c\ub85c eslint \ud14c\uc2a4\ud2b8\ub97c \uc9c4\ud589\ud558\uace0 eslint\ub97c \ud1b5\uacfc\ud558\uc9c0 \ubabb\ud55c PR\uc740 merge \ud558\uc9c0 \ubabb\ud558\ub3c4\ub85d \uc81c\uc5b4\ub429\ub2c8\ub2e4.\\n\\n1. Type Check\\n\\n\ub9c8\ucc2c\uac00\uc9c0\ub85c \ucf54\ub4dc \ubca0\uc774\uc2a4\uc758 \uc548\uc815\uc131, \ubc30\ud3ec \uacfc\uc815\uc5d0\uc11c\uc758 \uc5d0\ub7ec\ub97c \ucd5c\uc18c\ud654\ud558\uae30 \uc704\ud574 \ub3c4\uc785\ub418\uc5c8\uc2b5\ub2c8\ub2e4. TypeScript \ud30c\uc77c\uc5d0 \ub300\ud574 \ud0c0\uc785 \uac80\uc0ac\ub97c \uc218\ud589\ud558\uace0, \ucf54\ub4dc\uc5d0 \uc624\ub958\uac00 \uc5c6\ub294\uc9c0 \ud655\uc778\ud569\ub2c8\ub2e4. \uc774\ub610\ud55c \ud14c\uc2a4\ud2b8\uc5d0\uc11c \uc624\ub958\uac00 \ubc1c\uc0dd\ud558\uba74 merge \ud560 \uc218 \uc5c6\uc2b5\ub2c8\ub2e4.\\n\\n1. Pick Reviewer\\n\\nPR \ub9ac\ubdf0\uc5b4\ub97c \ucee4\uc2a4\ud140\ud558\uae30 \uc704\ud574 \ub3c4\uc785\ub418\uc5c8\uc2b5\ub2c8\ub2e4. PR\uc774 \uc5f4\ub9ac\uba74 \uc815\ud574\uc9c4 \uad6c\uc131 \uc548\uc5d0\uc11c \ub79c\ub364\uc73c\ub85c \ub9ac\ubdf0\uc5b4\uac00 \ubc30\uc815\ub418\uba70, \uc774 \uacfc\uc815\uc740 \uc2ac\ub799\uc73c\ub85c \uc54c\ub9bc\uc774 \uc5f0\ub3d9\ub429\ub2c8\ub2e4. \\n\\n\ud604\uc7ac\ub294 \uac19\uc740 \ub3c4\uba54\uc778 \ud300 1\uba85\uacfc \ub2e4\ub978 \ub3c4\uba54\uc778 \ud300 1\uba85 \uad6c\uc131\uc73c\ub85c \uc124\uc815\ub418\uc5b4\uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ucd08\uae30\uc5d0\ub294 PR Lint test \uc2e4\ud589\uc744 \uc8fc\ubaa9\uc801\uc73c\ub85c \ub3c4\uc785\ub418\uc5c8\uc9c0\ub9cc, \uc774 \uacfc\uc815\uc5d0\uc11c Runner \uba38\uc2e0 \uad6c\ucd95 \ubfd0\ub9cc \uc544\ub2c8\ub77c PR\uc5d0 \ucee4\ubc0b\uc774 \ucd94\uac00\ub420 \ub54c\ub9c8\ub2e4 \uc911\ubcf5 \uc2e4\ud589\ub418\uac70\ub098, PR \ubcf8\ubb38\uc774 \ubcc0\uacbd\ub418\uc5b4\ub3c4 \ub9b0\ud2b8 \ud14c\uc2a4\ud2b8\uac00 \uc2e4\ud589\ub418\ub294 \ub4f1 \uac1c\uc120\uc774 \ud544\uc694\ud55c \ubd80\ubd84\uc774 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n\ub530\ub77c\uc11c Lint Test \uc774\uc678\uc758 \uac1c\ubc1c \ud6a8\uc728\uc131\uc744 \ub192\uc5ec\uc904 \ub9cc \ud55c \ub2e4\uc591\ud55c Action\ub4e4\uc744 \ucc3e\uc558\uace0, \uac80\ud1a0\ud574\ubcf4\uba74 \uc88b\uc744 \uac83\ub4e4\uc744 \ubaa8\uc544\ubd24\uc2b5\ub2c8\ub2e4.\\n\\n- develop \ube0c\ub79c\uce58\uc5d0 \ucf54\ub4dc \ubcc0\uacbd \uc0ac\ud56d\uc774 merge\ub418\ub294 \uc989\uc2dc \uc790\ub3d9\uc73c\ub85c \uc820\ud0a8\uc2a4 \ube4c\ub4dc \ud2b8\ub9ac\uac70\\n- \uce90\uc2f1 \ub370\uc774\ud130 \ud65c\uc6a9\ud558\uc5ec \uc6cc\ud06c\ud50c\ub85c\uc6b0 \ubd88\ud544\uc694\ud55c \uc791\uc5c5 \ucd5c\uc801\ud654\\n- \uc0ac\uc6a9\ud558\uc9c0 \uc54a\ub294 \ucf54\ub4dc \uc790\ub3d9 \ub808\uac70\uc2dc \uccb4\ud06c\\n\\n\uc694\uc57d\\n\\n- CI/CD \uc804\ub7b5\uc740 \uc18c\ud504\ud2b8\uc6e8\uc5b4 \uac1c\ubc1c \ub77c\uc774\ud504\uc0ac\uc774\ud074 \uc804\ubc18\uc5d0\uc11c \ud6a8\uc728\uc131\uacfc \uc548\uc815\uc131\uc744 \uc99d\ub300\uc2dc\ud0b5\ub2c8\ub2e4.\\n- \uc800\ud76c \ud300\uc5d0\uc11c\ub294 Lint Check\ub97c \uc704\uc8fc\ub85c \uc0ac\uc6a9\ud558\uace0\uc788\uc9c0\ub9cc, \ub354 \ud6a8\uc728\uc801\uc778 \ud504\ub85c\uc138\uc2a4\ub97c \ub3c4\uc785\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\nReferences\\n[CI/CD(CI CD, \uc9c0\uc18d\uc801 \ud1b5\ud569/\uc9c0\uc18d\uc801 \ubc30\ud3ec): \uac1c\ub150, \ud234, \uad6c\ucd95, \ucc28\uc774](https://www.redhat.com/ko/topics/devops/what-is-ci-cd)[CI/CD\ub780?](https://seongwon.dev/DevOps/20220713-CICD%EB%9E%80/)\\n\\nhttps://resources.github.com/ci-cd/ \\n\\nhttps://www.martinfowler.com/articles/originalContinuousIntegration.html\\n\\nhttps://it.donga.com/101955/\\n\\n[https://medium.com/naver-place-dev/github-actions\ub97c-\ud65c\uc6a9\ud55c-\uac1c\ubc1c-\ud6a8\uc728\ud654-7df7a14b8843](https://medium.com/naver-place-dev/github-actions%EB%A5%BC-%ED%99%9C%EC%9A%A9%ED%95%9C-%EA%B0%9C%EB%B0%9C-%ED%9A%A8%EC%9C%A8%ED%99%94-7df7a14b8843)"},{"id":"/d0dam/infomate-2week","metadata":{"permalink":"/front-end/d0dam/infomate-2week","source":"@site/@frontEnd/d0dam/infomate-2week.mdx","title":"\uc778\ud3ec\uba54\uc774\ud2b8 2\uc8fc\ucc28 \uacf5\uc720(\ube0c\ub77c\uc6b0\uc800)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 2\uc8fc\ucc28 \uacf5\uc720(\ube0c\ub77c\uc6b0\uc800) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","date":"2024-03-04T00:00:00.000Z","tags":[{"label":"\uc778\ud3ec\uba54\uc774\ud2b8","permalink":"/front-end/tags/\uc778\ud3ec\uba54\uc774\ud2b8"},{"label":"\ube0c\ub77c\uc6b0\uc800","permalink":"/front-end/tags/\ube0c\ub77c\uc6b0\uc800"}],"readingTime":20.695,"hasTruncateMarker":true,"authors":[{"name":"minjae Kim","url":"https://github.com/d0dam","email":"smallkdb@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/51052049?v=4","key":"d0dam"}],"frontMatter":{"date":"2024-03-04T00:00:00.000Z","authors":"d0dam","title":"\uc778\ud3ec\uba54\uc774\ud2b8 2\uc8fc\ucc28 \uacf5\uc720(\ube0c\ub77c\uc6b0\uc800)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 2\uc8fc\ucc28 \uacf5\uc720(\ube0c\ub77c\uc6b0\uc800) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","keywords":["\uc778\ud3ec\uba54\uc774\ud2b8","\ube0c\ub77c\uc6b0\uc800"],"tags":["\uc778\ud3ec\uba54\uc774\ud2b8","\ube0c\ub77c\uc6b0\uc800"]},"unlisted":false,"prevItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 3\uc8fc\ucc28 \uacf5\uc720(\ud611\uc5c5)","permalink":"/front-end/haejinyun/infomate-3week"},"nextItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 1\uc8fc\ucc28 \uacf5\uc720(JS)","permalink":"/front-end/hanagertrudeKim/infomate-1week"}},"content":"\uc778\ud3ec\uba54\uc774\ud2b8 2\uc8fc\ucc28 \uacf5\uc720(\ube0c\ub77c\uc6b0\uc800) \ubaa8\uc74c\uc785\ub2c8\ub2e4.  \\n\\n\uc544\ub2c8 \uc65c \ub85c\uceec\uc5d0\uc11c\ub294 \uc798 \ub418\ub294\ub370 \uc0ac\ud30c\ub9ac\ub294 \uc548\ub418\ub294\uac70\uc9c0? - \uc724\ud574\uc9c4  \\nCache-Control, Expires\ub97c \ube60\ub728\ub9ac\uba74 \ube0c\ub77c\uc6b0\uc800\uc5d0\uc11c \ubb34\uc2a8 \uc77c\uc774 \uc77c\uc5b4\ub0a0\uae4c? - \uae40\ud558\ub098  \\n\ube0c\ub77c\uc6b0\uc800\uac00 \uc228\uae30\ub294 \ub514\ubc84\uae45 \ube44\ubc00! \uc774\ub7f0 \ud2b8\ub9ad\ub4e4 \uc54c\uace0 \uacc4\uc168\ub098\uc694? - \uacfd\uc2b9\uc8fc\\n\\n{/* truncate */}\\n\\nimport ReactPlayer from \\"react-player\\";\\n\\n# **[\uc778\ud3ec\uba54\uc774\ud2b8 2\ucc28\uc2dc \uacf5\uc720]**\\n\\n# \uc544\ub2c8 \uc65c \ub85c\uceec\uc5d0\uc11c\ub294 \uc798 \ub418\ub294\ub370 \uc0ac\ud30c\ub9ac\ub294 \uc548\ub418\ub294\uac70\uc9c0? - \uc724\ud574\uc9c4\\n\\n**intro**\\n\\n\uac1c\ubc1c\uc744 \ud560 \ub54c \ubcf4\ud1b5 \ud06c\ub86c\uc744 \uc0ac\uc6a9\ud574 \uc791\uc5c5\uc744 \ud558\uac8c \ub429\ub2c8\ub2e4. \uadf8\ub54c\ub294 \uc544\ubb34 \ubb38\uc81c\uac00 \uc5c6\uc5c8\ub358 \uae30\ub2a5 \ud639 css\uac00 \uc0ac\ud30c\ub9ac\ub098 \ub2e4\ub978 \ube0c\ub77c\uc6b0\uc800\uc5d0\uc11c\ub294 \uae68\uc9c0\ub294 \uacbd\uc6b0\uac00 \uc0dd\uae30\uace4 \ud569\ub2c8\ub2e4. \ub530\ub77c\uc11c \ud574\ub2f9 \uac1c\ub150\uacfc \uc5f0\uad00 \uc9c0\uc5b4 \ud06c\ub85c\uc2a4 \ube0c\ub77c\uc6b0\uc9d5\uc5d0 \ub300\ud574 \uae00\uc744 \uc791\uc131\ud574 \ubcf4\uc558\uc2b5\ub2c8\ub2e4!\\n\\n**\ud06c\ub85c\uc2a4 \ube0c\ub77c\uc6b0\uc9d5\uc774\ub780?**\\n\\n- \ub2e4\uc591\ud55c \ube0c\ub77c\uc6b0\uc800 \uc18d\uc5d0\uc11c\ub3c4 \uc11c\ub85c \ud638\ud658\uc774 \uac00\ub2a5\ud55c \uc0c1\ud638 \ud638\ud658\uc131\uc744 \uc758\ubbf8\ud569\ub2c8\ub2e4.\\n\\n\uc5b4\ub290 \ud55c\ucabd\uc5d0 \ucd5c\uc801\ud654\ub418\uc9c0 \uc54a\uace0, \uacf5\ud1b5 \uc694\uc18c\ub97c \uc0ac\uc6a9\ud558\uc5ec \uc6f9 \ud398\uc774\uc9c0\ub97c \uc81c\uc791\ud558\ub294 \uae30\ubc95\uc73c\ub85c \ub3d9\ub4f1\ud55c \uc218\uc900\uc758 \uc815\ubcf4, \uae30\ub2a5 \uc811\uadfc\uc5d0 \ucd08\uc810\uc744 \ub9de\ucd94\ub294 \uac83\uc785\ub2c8\ub2e4.\\n\\n\uc608\ub97c \ub4e4\uc5b4 \uc81c\uac00 \ub9ce\uc774 \uacaa\uc5b4\ubcf4\uc558\ub358 \uac83\uc740 css\uc640 \uad00\ub828\ub418\uc5b4 chrome\uc5d0\uc11c\ub294 \uc815\uc0c1\uc801\uc778 \ud398\uc774\uc9c0\uac00 safari\uc5d0\uc11c\ub9cc width\uac00 \ub9de\ucdb0\uc9c0\uc9c0 \uc54a\uc544 \ud654\uba74 x\ucd95\uc73c\ub85c \uc2a4\ud06c\ub864\uc774 \ub418\ub358 \uacbd\ud5d8\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uadf8 \uc678\uc5d0\ub3c4\\n\\n- **\uc791\ub3d9\ud558\uc9c0 \uc54a\uc740 HTML5, Javascript \ucf54\ub4dc\uac00 \uc874\uc7ac**\\n- **\ud574\uc11d\ud558\uc9c0 \ubabb\ud558\ub294 CSS \ucf54\ub4dc \uc874\uc7ac**\\n- **\ube0c\ub77c\uc6b0\uc800 \ubc84\uadf8\ub4e4\uc774 \uc874\uc7ac**\\n- **\ube0c\ub77c\uc6b0\uc800 \uc790\uccb4\uc801\uc778 CSS \uc2a4\ud0c0\uc77c**\\n\\n\uc704 \uacbd\uc6b0\ucc98\ub7fc \uac19\uc740 \ucf54\ub4dc\uc5ec\ub3c4 \uc0ac\uc6a9\uc790\uac00 \uc811\uadfc\ud558\ub294 \ube0c\ub77c\uc6b0\uc800\ub9c8\ub2e4 \ub2e4\ub978 \uacb0\uacfc\ubb3c\uc744 \ubcf4\uc778\ub2e4\ub294 \uac83\uc740 \uc0ac\uc6a9\uc131\uc5d0 \uc788\uc5b4 \ub9e4\uc6b0 \uc88b\uc9c0 \uc54a\uc740 \uac83\uc774\ub77c\uace0 \ubaa8\ub450 \ub290\ub07c\uc2e4 \uac81\ub2c8\ub2e4.\\n\\n**\uc65c \uc77c\uc5b4\ub098\ub294 \uac83\uc77c\uae4c?**\\n\\n- \uc774\uc720\ub294 **OS**\uac00 \ub2e4\ub974\uace0, \ube0c\ub77c\uc6b0\uc800\ub9c8\ub2e4 \u2018**\ub80c\ub354\ub9c1 \uc5d4\uc9c4**\u2019\uc774 \ub2e4\ub974\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4.\\n\\n\uc774 \ub9d0\uc740 \uc989 \uacb0\uad6d \ub3d9\uc77c\ud558\uac8c \uc548 \ub9cc\ub4dc\ub294 \uac83\uc774 \uc544\ub2c8\ub77c \uc560\ucd08\ubd80\ud130 \ub3d9\uc77c\ud558\uac8c \ub9cc\ub4dc\ub294 \uac83\uc740 \u2018\ubd88\uac00\ub2a5\ud55c \uc77c\u2019\uc774\ub77c\uace0\ub3c4 \ud560 \uc218 \uc788\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n- _\ub80c\ub354\ub9c1 \uc5d4\uc9c4: \ud654\uba74\uc5d0 \ud14d\uc2a4\ud2b8\uc640 \uc774\ubbf8\uc9c0 \ub4f1\uc744 \uadf8\ub9ac\ub294 SW. HTML \uc744 \uc694\uccad\ud558\uba74 \uc694\uccad\uc5d0 \ub530\ub978 \uc801\uc808\ud55c \ud30c\uc2f1 \ud558\uc5ec \ud654\uba74\uc5d0 \ud45c\uc2dc\ud569\ub2c8\ub2e4._\\n\\n**\uadf8\ub807\ub2e4\uba74 \uc5b4\ub5bb\uac8c \ucc98\ub9ac\ud558\uc9c0?**\\n\\n- can i use (\uc6f9 \uc0ac\uc774\ud2b8)\\n  https://caniuse.com/?search=grid\\n  \uc704 \ud398\uc774\uc9c0\ub294 \ube0c\ub77c\uc6b0\uc800\ub9c8\ub2e4\uc758 css \uc0ac\uc6a9 \ubc0f \ud638\ud658 \uac00\ub2a5 \uc5ec\ubd80\ub97c \uc54c\ub824\uc8fc\ub294 \uace0\ub9c8\uc6b4 \ud398\uc774\uc9c0\uc785\ub2c8\ub2e4.\\n  \uc608\ub85c gird\ub77c\ub294 \uc18d\uc131\uc758 \uac01 \ube0c\ub77c\uc6b0\uc800\uc758 \ud638\ud658 \uac00\ub2a5 \uc5ec\ubd80\ub97c \uc54c\uc544\ubcf4\uace0 \uc2f6\uc744 \ub54c \ud574\ub2f9 \uc0ac\uc774\ud2b8\uc5d0 \uac80\uc0c9\uc744 \ud558\uba74 \ub2e4\uc591\ud55c \ube0c\ub77c\uc6b0\uc800\uc5d0\uc11c \ud574\ub2f9 \uc18d\uc131\uc774 \uc0ac\uc6a9 \uac00\ub2a5\ud55c\uc9c0 \ubcf4\uae30 \uc27d\uac8c \ub098\ud0c0\ub0c5\ub2c8\ub2e4.\\n- \ubaa8\uc9c8\ub77c MDN (\uc6f9 \uc0ac\uc774\ud2b8)\\n  https://developer.mozilla.org/ko/\\n  \uac1c\ubc1c\uc744 \ud558\uba70 \uc815\ub9d0 \ub9ce\uc774 \ub4e4\uc5b4\uac00 \ubcf4\ub294 \ud398\uc774\uc9c0 \uc911 \ud558\ub098\uc77c MDN\uc5d0\uc11c\ub3c4 \ube0c\ub77c\uc6b0\uc800 \ud638\ud658\uc131\uc744 \ud655\uc778\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n  \uac80\uc0c9\ud55c \ud0a4\uc6cc\ub4dc \ub0b4\uc6a9\uc758 \ucd5c\ud558\ub2e8\uc5d0 \ube0c\ub77c\uc6b0\uc800 \ubcc4 \ud638\ud658 \uad00\ub828 \uc815\ubcf4\uac00 \uc815\ub9ac\ub418\uc5b4 \uc788\uc5b4 \ucc3e\uace0\uc790 \ud558\ub294 \uc18d\uc131\uc744 \uac80\uc0c9 \ud6c4 \uc544\ub798\uc5d0\uc11c \ud2b9\uc774\ud558\uac8c \uc801\uc6a9\uc774 \uc548\ub418\ub294 \ube0c\ub77c\uc6b0\uc800\uac00 \uc788\ub294\uc9c0 \ud655\uc778\ud574 \ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- CSS \ucd08\uae30\ud654\\n  \u2018\uc6f9 \ube0c\ub77c\uc6b0\uc800\'\ub9c8\ub2e4 default \uac12\uc73c\ub85c \uc2a4\ud0c0\uc77c\uc774 \uc801\uc6a9\ub418\uc5b4 \uc788\uc2b5\ub2c8\ub2e4. \ub530\ub77c\uc11c \ube0c\ub77c\uc6b0\uc800\ub9c8\ub2e4\uc758 \uae30\ubcf8 \uc2a4\ud0c0\uc77c\uc744 \uc5c6\uc570\uc73c\ub85c \ucd08\uae43\uac12\uc744\uc744 \ub3d9\uc77c\ud558\uac8c \ud558\uc5ec \uc9c0\uba74\uc744 \ud3c9\ud3c9\ud558\uac8c \ub9cc\ub4dc\ub294 \uc791\uc5c5\uc744 \ud1b5\ud574 \uc774\ud6c4 \uac1c\ubc1c\uc5d0 \ucc28\uc9c8\uc774 \uc5c6\uac8c \ud558\ub294 \uac83\uc73c\ub85c \ud06c\ub85c\uc2a4 \ube0c\ub77c\uc6b0\uc9d5\uc744 \uc608\ubc29\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ud83d\udcbb\ube0c\ub77c\uc6b0\uc800 \ubcc4 \ubca4\ub354\ud504\ub9ac\ud53d\uc2a4 (\uc774\ub7f0\uac83\ub3c4 \uc788\uc5b4\uc694!)\\n\\n\uc6f9 \ube0c\ub77c\uc6b0\uc800 \uacf5\uae09\uc790\uac00 \uc0c8\ub85c\uc6b4 \uc2e4\ud5d8\uc801\uc778 \uae30\ub2a5\uc744 \uc81c\uacf5\ud560 \ub54c \uc774\uc804 \ubc84\uc804\uc758 \uc6f9 \ube0c\ub77c\uc6b0\uc800\uc5d0 \uadf8 \uc0ac\uc2e4\uc744 \uc54c\ub824\uc8fc\uae30 \uc704\ud574 \uc0ac\uc6a9\ud558\ub294 \uc811\ub450\uc0ac(prefix)\ub97c \uc758\ubbf8. \u21d2 CSS\uc5d0 \uc0c8\ub85c\uc6b4 \uc18d\uc131\uc744 \ucd94\uac00\ud558\uae30 \uc804 \uc784\uc2dc\uc801\uc73c\ub85c \uc811\ub450\uc5b4\ub97c \uc0ac\uc6a9\ud558\ub294 \uac83.\\n\\n- \ud06c\ub86c, \uc0ac\ud30c\ub9ac : -webkit-\\n- \ud30c\uc774\uc5b4\ud3ed\uc2a4 : moz- (mozila \ub77c\ub294 \ub2e8\uccb4\uac00 \ud30c\uc774\uc5b4\ud3ed\uc2a4\ub97c \ub9cc\ub4e4\uc5c8\uae30 \ub54c\ubb38\uc5d0)\\n- \uc624\ud398\ub77c : -o-\\n- \uc775\uc2a4\ud50c\ub85c\ub7ec : -ms-\\n\\n```\\nbackground: red;   \x3c!-- gradient \uc18d\uc131\uc744 \uc9c0\uc6d0\ud558\uc9c0 \uc54a\ub294 \ubaa8\ub4e0 \ube0c\ub77c\uc6b0\uc800\ub97c \uc704\ud55c \ucf54\ub4dc --\x3e\\nbackground: -webkit-linear-gradient(red, yellow);  \x3c!-- \ud06c\ub86c\uacfc \uc0ac\ud30c\ub9ac 4.0 \uc774\uc0c1\uc744 \uc704\ud55c \ucf54\ub4dc --\x3e\\nbackground: -moz-linear-gradient(red, yellow);     \x3c!-- \ud30c\uc774\uc5b4\ud3ed\uc2a4 3.6 \uc774\uc0c1\uc744 \uc704\ud55c \ucf54\ub4dc --\x3e\\nbackground: -ms-linear-gradient(red, yellow);      \x3c!-- \uc775\uc2a4\ud50c\ub85c\ub7ec 10.0 \uc774\uc0c1\uc744 \uc704\ud55c \ucf54\ub4dc --\x3e\\nbackground: -o-linear-gradient(red, yellow);       \x3c!-- \uc624\ud398\ub77c 10.0 \uc774\uc0c1\uc744 \uc704\ud55c \ucf54\ub4dc --\x3e\\nbackground: linear-gradient(red, yellow);          \x3c!-- CSS \ud45c\uc900 \ubb38\ubc95 \ucf54\ub4dc --\x3e\\n```\\n\\n# Cache-Control, Expires\ub97c \ube60\ub728\ub9ac\uba74 \ube0c\ub77c\uc6b0\uc800\uc5d0\uc11c \ubb34\uc2a8 \uc77c\uc774 \uc77c\uc5b4\ub0a0\uae4c? - \uae40\ud558\ub098\\n\\nhttp \uce90\uc2dc\ub97c \uc801\uadf9\uc801\uc73c\ub85c \uc124\uc815\ud558\uace0 \uc81c\uc5b4\ud568\uc73c\ub85c\uc368 \uc6f9 \uc131\ub2a5\uc744 \ub192\uc77c \uc218 \uc788\ub2e4\ub294 \uc0ac\uc2e4\uc744 \uc54c\uace0 \uacc4\uc2e0\uac00\uc694?\\n\\n\ud604\uc7ac \uc6b0\ub9ac \ud504\ub860\ud2b8\uc5d4\ub4dc \ud2b8\ub799\uc5d0\uc11c \uce90\uc2dc \uc124\uc815\uc744 \uc9c1\uc811 \ub2e4\ub8e8\uc9c0\ub294 \uc54a\uc2b5\ub2c8\ub2e4. \uadf8\ub807\uc9c0\ub9cc \uc55e\uc73c\ub85c\uc758 \uc6f9 \uc131\ub2a5\uacfc \uc774\ud574\ub97c \uc704\ud574 \ub2e4\uc591\ud55c \uc0dd\uba85 \uc8fc\uae30\ub97c \uac00\uc9c0\ub294 \uce90\uc2dc\ub97c \ub2e4\ub8e8\ub294 \ubc29\ubc95\uc5d0 \ub300\ud574 \uc544\ub294\uac83\uc740 \uaf2d \ud544\uc694\ud569\ub2c8\ub2e4.\\n\\n\uadf8\ub7f0\ub370 \ube0c\ub77c\uc6b0\uc800 \uce90\uc2dc \uad00\ub828 \ud5e4\ub354\uc778 `Cache-Control` , `Exprires` \ub97c \ube60\ub728\ub9ac\uba74 \ubb34\uc2a8 \uc77c\uc774 \uc77c\uc5b4\ub0a0\uae4c\uc694? \ub610\ud55c \ube0c\ub77c\uc6b0\uc800 \uce90\uc2dc \uc124\uc815\uc774 \uc65c \uc911\uc694\ud560\uae4c\uc694?\\n\\n## \uc6f9 \uce90\uc2dc\\n\\n- \uc2e4\uc81c \uc791\uc5c5\uc744 \ud558\uba70 \ube4c\ub4dc\ub41c \uc0ac\ud56d\uc774 \uc801\uc6a9\uc774 \uc548\ub420\ub54c `\uce90\uc2dc \uc0ad\uc81c\ud574\ub77c` `\uac15\ud55c \uc0c8\ub85c\uace0\uce68 \ud574\ub77c` \ub4f1\ub4f1\uc758 \ub9d0\uc744 \ub4e4\uc740 \uc801\uc774 \uc788\uc744 \uac81\ub2c8\ub2e4.(cc. \ucd5c\uc6d0\ube48\ub2d8) \uc774\uac83\ub4e4\ub3c4 \ube0c\ub77c\uc6b0\uc800 \uce90\uc2dc\uc640 \uad00\ub828\ub41c \uc0ac\ud56d\uc774\ub77c\uace0 \ubcfc \uc218 \uc788\uc8e0.\\n- \ud074\ub77c\uc774\uc5b8\ud2b8\ub294 \uc11c\ubc84\ub85c\ubd80\ud130 HTTP \uc694\uccad\uc744 \ud1b5\ud574 \ud544\uc694\ud55c \ub9ac\uc18c\uc2a4 (HTML, CSS, JS, \uc774\ubbf8\uc9c0 \ub4f1)\ub97c \ubd88\ub7ec\uc635\ub2c8\ub2e4. \ub124\ud2b8\uc6cc\ud06c\ub97c \ud1b5\ud574 \uc774 \uacfc\uc815\uc744 \uc218\ud589\ud558\ub294\uac74 \ub290\ub9ac\uace0 \ube44\uc6a9\uc774 \ub9ce\uc774 \ub4ed\ub2c8\ub2e4.\\n- \uc5ec\uae30\uc11c \ubc1c\uc0dd\ud560 \uc218 \uc788\ub294 \ubd88\ud544\uc694\ud55c \ub124\ud2b8\uc6cc\ud06c \uc7ac\uc694\uccad\uc744 \ubc29\uc9c0\ud558\uae30 \uc704\ud574 \uc6f9 \uce90\uc2f1\uc744 \uc0ac\uc6a9\ud569\ub2c8\ub2e4.\\n- `Cache-Control` `Expries` \ub4f1\uacfc \uac19\uc740 \uc6b0\ub9ac\uac00 \uc790\uc8fc \ubd10\uc628 \ud5e4\ub354\ub294 \uce90\uc2dc \ub3d9\uc791\uacfc \uad00\ub828\ub41c \ud5e4\ub354\ub85c, \uc11c\ubc84\uc758 \ube44\uc6a9\uc744 \uc904\uc774\uace0 \ud074\ub77c\uc774\uc5b8\ud2b8\uc758 \uc131\ub2a5\uc744 \ud5a5\uc0c1\uc2dc\ud0a4\ub294 \ub370 \uc720\uc6a9\ud558\uac8c \uc0ac\uc6a9\ub429\ub2c8\ub2e4.\\n\\n### Cache-Control, Expires \ud5e4\ub354\ub97c \uae30\uc785\ud558\uc9c0 \uc54a\uc740 \uacbd\uc6b0\\n\\n- \ub204\uad70\uac00 \uc758\ub3c4\ud588\ub4e0 \uc758\ub3c4\ud558\uc9c0 \uc54a\uc558\ub4e0 `Cache-Control` `Expires` \ud5e4\ub354 \ubaa8\ub450 \uae30\uc785\ud558\uc9c0 \uc54a\uc740 \uacbd\uc6b0, \ube0c\ub77c\uc6b0\uc800\ub294 \uc5b4\ub5bb\uac8c \ub3d9\uc791\ud560\uae4c\uc694?\\n- \ub300\ud45c\uc801\uc778 \ube0c\ub77c\uc6b0\uc800\uc778 \ud06c\ub86c\uc758 \uce90\uc2dc \ub3d9\uc791\uc744 \uc0b4\ud3b4\ubcf4\uae30 \uc704\ud574 Chromium\uc758 \ucf54\ub4dc\ub97c \ud655\uc778\ud574\ubcf4\uc558\uc2b5\ub2c8\ub2e4.\\n\\n```jsx\\nHttpResponseHeaders::GetFreshnessLifetimes(const Time& response_time) const {\\n  FreshnessLifetimes lifetimes;\\n  if (HasHeaderValue(\\"cache-control\\", \\"no-cache\\") ||\\n      HasHeaderValue(\\"cache-control\\", \\"no-store\\") ||\\n      HasHeaderValue(\\"pragma\\", \\"no-cache\\")) {\\n    return lifetimes;\\n  }\\n...\\nif ((response_code_ == net::HTTP_OK ||\\n       response_code_ == net::HTTP_NON_AUTHORITATIVE_INFORMATION ||\\n       response_code_ == net::HTTP_PARTIAL_CONTENT) &&\\n      !must_revalidate) {\\n    // TODO(darin): Implement a smarter heuristic.\\n    Time last_modified_value;\\n    if (GetLastModifiedValue(&last_modified_value)) {\\n      // The last-modified value can be a date in the future!\\n      if (last_modified_value <= date_value) {\\n        lifetimes.freshness = (date_value - last_modified_value) / 10; //\uc5ec\uae30!\\n        return lifetimes;\\n      }\\n    }\\n  }\\n```\\n\\n- Chromium\uc758 `http_response_headers.cc` \ub97c \uc0b4\ud3b4\ubcf4\ub2c8 freshness(\uc720\ud6a8\uc131)\uc774 `(date_value - last_modfied_value) / 10` \ub85c \ud560\ub2f9\ub418\ub294 \uac83 \uac19\uc2b5\ub2c8\ub2e4.\\n- \uc774\ub294 Date\uc640 LastModified\uc758 \ucc28\uc774\uac12\uc758 10\ubd84\uc758 1\ub85c \ucd94\uc815\ud558\uc5ec \uc720\ud6a8\uc131(freshness) \uacc4\uc0b0\uc744 \ud55c\ub2e4\ub294 \uac83\uc785\ub2c8\ub2e4. [MDN \ubb38\uc11c](https://developer.mozilla.org/ko/docs/Web/HTTP/Caching#%EC%9C%A0%ED%9A%A8%EC%84%B1_%EA%B2%80%EC%82%AC_%ED%9C%B4%EB%A6%AC%EC%8A%A4%ED%8B%B1)\ub97c \ubcf4\ub2c8 `heuristic` \uc774\ub77c\ub294 \ub3d9\uc791\uc73c\ub85c \uce90\uc2dc \ud5e4\ub354\ub97c \uc9c0\uc815\ud558\uc9c0 \uc54a\uc73c\uba74 **\uc6f9 \uc2a4\ud329\uc744 \uae30\ubc18\uc73c\ub85c \ub300\ub7b5\uc801\uc73c\ub85c \uce90\uc2dc \uc791\ub3d9\uc744 \ud569\ub2c8\ub2e4.**\\n\\n### \uadf8\ub7fc \uce90\uc2dc\ub3c4 \uc54c\uc544\uc11c \ub3d9\uc791\ud558\ub2c8 \ubb38\uc81c\uac00 \uc5c6\ub294\uac78\uae4c?\\n\\n\ud734\ub9ac\uc2a4\ud2f1 \uce90\uc2dc\ub294 \ubb38\uc81c\uac00 \ub9ce\uc774 \uc0dd\uaca8\ub0a0 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ucee8\ud150\uce20 \ubc30\ud3ec\ub97c \ud588\ub354\ub77c\ub3c4 \uc6f9 \ubc30\ud3ec\ud6c4 \ud2b9\uc815 \uae30\uae30\uc5d0\uc11c \uc774\uc804 \uce90\uc2dc \ub41c \ucf58\ud150\uce20\uac00 \ub178\ucd9c\ub420 \uc218 \uc788\uace0, \ubcc0\uacbd\uc0ac\ud56d\uc774 \uc2e4\uc81c\ub85c \uc801\uc6a9\ub418\ub294\ub370 \ub354 \ub9ce\uc740 \uc2dc\uac04\uc774 \uac78\ub9b4 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uac04\ub2e8\ud55c \ud574\uacb0\ucc45\uc73c\ub85c\ub294 \uc0ac\uc6a9\uc790\uac00 \uce90\uc2dc\ub97c \ube44\uc6cc \ub9ac\uc18c\uc2a4\ub97c \uc0c8\ub85c \uac00\uc838\uc624\ub3c4\ub85d \ud558\ub294 \uac83 \uc785\ub2c8\ub2e4.\\n\\n\uc2e4\uc81c \uac1c\ubc1c\uc790 \ucc3d\uc744 \uc5f4\uace0 \uc0c8\ub85c\uace0\uce68 \ubc84\ud2bc\uc744 \uc6b0\ud074\ub9ad\ud558\uba74 \u2018\uce90\uc2dc \ube44\uc6b0\uae30 \ubc0f \uac15\ub825 \uc0c8\ub85c\uace0\uce68\u2019 \uc744 \uc120\ud0dd\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uadf8\ub7ec\ub098 \uadfc\ubcf8\uc801\uc73c\ub85c \uce90\uc2f1\uc5d0 \uad00\ud55c \ubb38\uc81c\uac00 \ubc1c\uc0dd\ud558\uba74 \uba85\uc2dc\uc801\uc73c\ub85c \ud5e4\ub354\ub97c \uc124\uc815\ud558\uc5ec \uce90\uc2dc \ubb38\uc81c\ub97c \ud574\uacb0\ud574\uc8fc\ub294\uac8c \uc88b\ub2e4\uace0 \uc0dd\uac01\ud569\ub2c8\ub2e4. \uce90\uc2dc \uc720\ud6a8\uc2dc\uac04\uc744 \uc0ac\uc6a9\ud558\uc5ec \uc815\ud655\ud55c \uc2dc\uac04\uc5d0 \uc5c5\ub370\uc774\ud2b8\ub97c \ubcf4\uc7a5\ud558\ub294 \ubc29\ubc95\uc744 \uc368\ubcf4\uba74 \uc88b\uc744\uac83\uac19\uc2b5\ub2c8\ub2e4.\\n\\n\uc2e4\uc81c \ud1a0\uc2a4\uc5d0\uc11c\ub294 html\uc740 \ubc30\ud3ec \uc8fc\uae30\uc5d0 \uccb4\ud06c\ub418\uc5b4\uc57c \ud558\ub294 \ub9ac\uc18c\uc2a4\uc774\uae30 \ub54c\ubb38\uc5d0 `Cache-Control` \uac12\uc73c\ub85c `max-age=0, s-maxage=31536000` \uc744 \uc124\uc815\ud55c\ub2e4\uace0 \ud569\ub2c8\ub2e4. \uadf8\ub7ec\ub098 JavaScript \ub098 CSS \ud30c\uc77c\uc740 \ud504\ub860\ud2b8\uc5d4\ub4dc \uc6f9 \uc11c\ube44\uc2a4\ub97c \ube4c\ub4dc\ud560 \ub54c\ub9c8\ub2e4 \uc0c8\ub85c \ubcc0\uacbd\uc0ac\ud56d\uc774 \uc801\uc6a9\ub420 \uc218 \uc788\ub3c4\ub85d \uc784\uc758 \ubc84\uc804 \ubc88\ud638\ub97c \ubd80\uc5ec\ud574 \uc124\uc815\ud569\ub2c8\ub2e4.\\n\\n\u21d2 \ub9cc\uc57d \ud1a0\uc2a4\uc758 \uce90\uc2dc \uc124\uc815\uc5d0 \ub300\ud574 \ub354 \uc790\uc138\ud788 \uc54c\uace0\uc2f6\ub2e4\uba74 [\uc5ec\uae30\ub97c \ud074\ub9ad](https://toss.tech/article/smart-web-service-cache)\\n\\n## \uc694\uc57d\\n\\n1. \ube0c\ub77c\uc6b0\uc800 \uce90\uc2dc \uc124\uc815\uc744 \ub530\ub85c \ud558\uc9c0 \uc54a\uc744 \uacbd\uc6b0 \ud06c\ub86c, \uc0ac\ud30c\ub9ac \ub4f1\uc758 \ube0c\ub77c\uc6b0\uc800\ub294 \uc54c\uc544\uc11c \uce90\uc2dc \ub3d9\uc791\uc744 \ud574\uc90d\ub2c8\ub2e4.\\n2. \uc790\ub3d9\uc73c\ub85c \uce90\uc2dc \uc124\uc815\uc774 \ub41c\ub2e4\ub294\uac74 \ubb38\uc81c\uac00 \ubc1c\uc0dd\ud560 \uc218 \uc788\ub294 \uc9c0\uc810\uc774\uae30 \ub54c\ubb38\uc5d0 \uc774\ub97c \ud655\uc778\ud574\uc8fc\ub294\uac83\uc774 \uc911\uc694\ud569\ub2c8\ub2e4.\\n3. \uac01\uac01\uc758 \ud2b9\uc131\uc5d0 \ub530\ub77c \uce90\uc2dc\ub97c \uc12c\uc138\ud788 \uc81c\uc5b4\ud568\uc73c\ub85c \uc548\uc804\ud558\uace0 \ube60\ub974\uac8c HTTP \ub9ac\uc18c\uc2a4\ub97c \ub85c\ub4dc\ud560 \uc218 \uc788\uc73c\uba70, \ud2b8\ub798\ud53d \ube44\uc6a9\uc744 \uc808\uac10\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ucc38\uace0\uc790\ub8cc\\n\\n- https://web.dev/articles/http-cache\\n- https://developer.mozilla.org/ko/docs/Web/HTTP/Caching\\n\\n# \ube0c\ub77c\uc6b0\uc800\uac00 \uc228\uae30\ub294 \ub514\ubc84\uae45 \ube44\ubc00! \uc774\ub7f0 \ud2b8\ub9ad\ub4e4 \uc54c\uace0 \uacc4\uc168\ub098\uc694? - \uacfd\uc2b9\uc8fc\\n\\n# Intro\\n\\n\ube0c\ub77c\uc6b0\uc800\uc758 \ub514\ubc84\uac70\ub97c \ucd5c\ub300\ud55c \ud65c\uc6a9\ud558\uae30 \uc704\ud55c \uc720\uc6a9\ud558\uc9c0\ub9cc \ubed4\ud558\uc9c0 \uc54a\uc740 \ubc29\ubc95\ub4e4\uc785\ub2c8\ub2e4. \uac1c\ubc1c\uc790 \ub3c4\uad6c\uc5d0 \ub300\ud55c \uae30\ubcf8 \uc774\ud574\ub97c \uac00\uc9c0\uace0 \uc788\ub2e4\uace0 \uac00\uc815\ud569\ub2c8\ub2e4.\\n\\n## \uc870\uac74\ubd80 \uc911\ub2e8\uc810 \ud65c\uc6a9\\n\\n### \ub85c\uadf8 \uc9c0\uc810 / \ucd94\uc801 \uc9c0\uc810\\n\\n\uc870\uac74\ubd80 \uc911\ub2e8\uc810\uc5d0\uc11c `console.log`\ub97c \uc0ac\uc6a9\ud558\uac70\ub098 \ub85c\uadf8 \uc9c0\uc810\uc744 \uc0ac\uc6a9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ub85c\uadf8 \uc9c0\uc810\uc740 \uc2e4\ud589\uc744 \uc77c\uc2dc \uc911\uc9c0\ud558\uc9c0 \uc54a\uace0 \ucf58\uc194\uc5d0 \uae30\ub85d\ud558\ub294 \uc911\ub2e8\uc810\uc785\ub2c8\ub2e4.\\n\\n[\uc601\uc0c1 \ucc38\uace0](https://camo.githubusercontent.)\\n\\n**1. \uac10\uc2dc \ucc3d(Watch pane)**\\n\\n\uac10\uc2dc \ucc3d\uc5d0\uc11c `console.log`\ub97c \uc0ac\uc6a9\ud560 \uc218\ub3c4 \uc788\uc2b5\ub2c8\ub2e4. \uc608\ub97c \ub4e4\uc5b4, \ub514\ubc84\uac70\uc5d0\uc11c \uc571\uc774 \uc911\ub2e8\ub420 \ub54c\ub9c8\ub2e4 `localStorage`\uc758 \uc2a4\ub0c5\uc0f7\uc744 \ub364\ud504\ud558\uace0 \uc2f6\ub2e4\uba74 `console.table(loaclStorage)` \uac10\uc9c0\ub97c \uc0dd\uc131\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n<img\\n  src=\\"/img/@frontEnd/infomate-2week/watch-pane.png\\"\\n  alt=\\"\uc774\ubbf8\uc9c0\\"\\n  style={{ marginBottom: \\"20px\\" }}\\n/>\\n\\n**2. \ud638\ucd9c \uc2a4\ud0dd \ucd94\uc801**\\n\\n`console.trace`\ub97c \uc0ac\uc6a9\ud558\uc5ec \ucf54\ub4dc\ub97c \uc2e4\ud589\ud558\uba74 \ud638\ucd9c\ub418\ub294 \ub77c\uc778\uc744 \ud655\uc778\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n<img\\n  src=\\"/img/@frontEnd/infomate-2week/trace.png\\"\\n  alt=\\"\uc774\ubbf8\uc9c0\\"\\n  style={{ marginBottom: \\"20px\\" }}\\n/>\\n\\n### \ud504\ub85c\uadf8\ub7a8 \ub3d9\uc791 \ubcc0\uacbd\ud558\uae30\\n\\n\ud504\ub85c\uadf8\ub7a8 \ub3d9\uc791\uc5d0 \uc0ac\uc774\ub4dc \uc774\ud399\ud2b8\uac00 \uc788\ub294 \ud45c\ud604\uc2dd\uc744 \uc0ac\uc6a9\ud558\uba74 \ube0c\ub77c\uc6b0\uc800\uc5d0\uc11c \ubc14\ub85c \ud504\ub85c\uadf8\ub7a8 \ub3d9\uc791\uc744 \ubcc0\uacbd\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc608\ub97c \ub4e4\uc5b4 `getPerson` \ud568\uc218\uc758 \ub9e4\uac1c\ubcc0\uc218\ub97c \uc7ac\uc815\uc758\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc7ac\uc815\uc758 \uc2dc `id=1`\uc740 `true`\ub85c \ud3c9\uac00\ub418\ubbc0\ub85c \uc774 \uc870\uac74\ubd80 \uc911\ub2e8\uc810\uc740 \ub514\ubc84\uac70\ub97c \uc77c\uc2dc \uc911\uc9c0\ud569\ub2c8\ub2e4. \uc774\ub97c \ubc29\uc9c0\ud558\ub824\uba74 \ud45c\ud604\uc2dd\uc5d0 `false`\ub97c \ucd94\uac00\ud558\uba74 \ub429\ub2c8\ub2e4.\\n\\n[\uc601\uc0c1 \ucc38\uace0](https://camo.githubusercontent.)\\n\\n### \uc2dc\uac04 \uce21\uc815\\n\\n\ubb34\uc5b8\uac00\ub97c \uc2e4\ud589\ud558\ub294 \ub370 \uac78\ub9ac\ub294 \uc2dc\uac04\uc744 \ube60\ub974\uace0 \uac04\ub2e8\ud558\uac8c \uce21\uc815\ud558\uace0 \uc2f6\ub2e4\uba74 \uc870\uac74\ubd80 \uc911\ub2e8\uc810\uc5d0\uc11c \ucf58\uc194 \ud0c0\uc774\ubc0d API\ub97c \uc0ac\uc6a9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc2dc\uc791 \uc9c0\uc810\uc5d0 console.time(\u2019label\u2019) \uc870\uac74\uc73c\ub85c \uc911\ub2e8\uc810\uc744 \uc124\uc815\ud558\uace0 \uc885\ub8cc \uc9c0\uc810\uc5d0 console.timeEnd(\u2019label\u2019) \uc870\uac74\uc73c\ub85c \uc911\ub2e8\uc810\uc744 \uc124\uc815\ud558\uba74 \ub429\ub2c8\ub2e4.\\n\\n[\uc601\uc0c1 \ucc38\uace0](https://camo.githubusercontent.)\\n\\n### \ud568\uc218\uc758 \ud56d\uc218(Arity) \ud65c\uc6a9\\n\\n**1. \uc778\uc790 \uac1c\uc218\uc5d0 \ub530\ub978 \uc911\ub2e8**\\n\\n\uc608\ub97c \ub4e4\uc5b4, \ud604\uc7ac \ud568\uc218\uac00 3\uac1c\uc758 \uc778\uc218\ub85c \ud638\ucd9c\ub420 \ub54c\ub9cc \uc77c\uc2dc \uc911\uc9c0\ud560 \ub54c\uc785\ub2c8\ub2e4. `argument.callee.length===3`\\n\\n<img\\n  src=\\"/img/@frontEnd/infomate-2week/1.png\\"\\n  alt=\\"\uc774\ubbf8\uc9c0\\"\\n  style={{ marginBottom: \\"20px\\" }}\\n/>\\n\\n**2. \ud56d\uc218 \ubd88\uc77c\uce58 \uc2dc \uc911\ub2e8**\\n\\n\ud604\uc7ac \ud568\uc218\uac00 \uc798\ubabb\ub41c \uc778\uc218 \uac1c\uc218\ub85c \ud638\ucd9c\ub420 \ub54c\ub9cc \uc77c\uc2dc \uc911\uc9c0\ud569\ub2c8\ub2e4. `(arguments.callee.length) != arguments.length`\\n\\n<img\\n  src=\\"/img/@frontEnd/infomate-2week/2.png\\"\\n  alt=\\"\uc774\ubbf8\uc9c0\\"\\n  style={{ marginBottom: \\"20px\\" }}\\n/>\\n\\n\ud568\uc218 \ud638\ucd9c\ubd80\uc758 \ubc84\uadf8\ub97c \ucc3e\uc744 \ub54c \uc720\uc6a9\ud569\ub2c8\ub2e4.\\n\\n### \uc2dc\uac04 \ud65c\uc6a9\\n\\n**1. \ud398\uc774\uc9c0 \ub85c\ub4dc \uc2a4\ud0b5**\\n\\n\ud398\uc774\uc9c0 \ub85c\ub4dc \ud6c4 5\ucd08 \ub3d9\uc548 \uc5b4\ub5a0\ud55c \uc911\ub2e8\uc810\uc5d0\ub3c4 \uc77c\uc2dc \uc911\uc9c0\ud558\uc9c0 \uc54a\uae30 `performance.now() > 5000`\\n\\n\uc911\ub2e8\uc810\uc744 \uc124\uc815\ud558\uace0 \uc2f6\uc9c0\ub9cc \ucd08\uae30 \ud398\uc774\uc9c0 \ub85c\ub4dc \ud6c4 \uc2e4\ud589\uc744 \uc77c\uc2dc \uc911\uc9c0\ud558\ub294 \ub370\ub9cc \uad00\uc2ec\uc774 \uc788\ub294 \uacbd\uc6b0\uc5d0 \uc720\uc6a9\ud569\ub2c8\ub2e4.\\n\\n**2. N\ucd08 \uc2a4\ud0b5\ud558\uae30**\\n\\n\ub2e4\uc74c 5\ucd08 \uc774\ub0b4\uc5d0 \uc911\ub2e8\uc810\uc5d0 \ub3c4\ub2ec\ud558\uba74 \uc2e4\ud589\uc744 \uc77c\uc2dc \uc911\uc9c0\ud558\uc9c0 \uc54a\uace0, \uadf8 \uc774\ud6c4\uc5d0\ub294 \uc5b8\uc81c\ub4e0\uc9c0 \uc77c\uc2dc \uc911\uc9c0\ud569\ub2c8\ub2e4. `window.baseline = window.baseline || Date.now(), (Date.now() - window.baseline) > 5000`\\n\\n\uc6d0\ud558\ub294 \uacbd\uc6b0 \uc5b8\uc81c\ub4e0\uc9c0 \ucf58\uc194\uc5d0\uc11c \uce74\uc6b4\ud130\ub97c \uc7ac\uc124\uc815\ud569\ub2c8\ub2e4. `window.baseline=Date.now()`\\n\\n### CSS \uc0ac\uc6a9\\n\\n\uacc4\uc0b0\ub41c CSS \uac12\uc5d0 \ub530\ub77c \uc77c\uc2dc \uc911\uc9c0\ud558\uae30(\uc608: document.body\uc758 \ubc30\uacbd\uc0c9\uc774 \ube68\uac04\uc0c9\uc77c \ub54c\ub9cc \uc77c\uc2dc \uc911\uc9c0): `window.getComputedStyle(document.body).backgroundColor === \u201crgb(255,0,0)\u201d`\\n\\n### \uc9dd\uc218 \ud638\ucd9c\ub9cc\\n\\n\uc904\uc774 \uc9dd\uc218 \ubc88 \uc2e4\ud589\ub420 \ub54c\ub9c8\ub2e4 \uc77c\uc2dc \uc911\uc9c0: `window.counter = window.counter || 0, window.counter % 2 === 0`\\n\\n### \uc808\ub300 \uc911\ub2e8\uc2dc\ud0a4\uc9c0 \uc54a\uae30\\n\\n*\ud06c\ub86c*\uc5d0\uc11c \u201cNever Pause Here\u201d\uc744 \uc120\ud0dd\ud558\uba74 false\uc778 \uc870\uac74\ubd80 \uc911\ub2e8\uc810\uc744 \uc0dd\uc131\ud569\ub2c8\ub2e4. \uc774\ub97c \ud1b5\ud574 \ub514\ubc84\uac70\ub294 \uc774 \ub77c\uc778\uc5d0\uc11c \uc808\ub300 \uc77c\uc2dc \uc911\uc9c0\ub418\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.\\n\\nXHR \uc911\ub2e8\uc810\uc5d0\uc11c \ud55c \uc904\uc744 \uc81c\uc678\ud558\uac70\ub098, \uc608\uc678\uac00 \ubc1c\uc0dd\ud588\uc744 \ub54c \uc774\ub97c \ubb34\uc2dc\ud558\uace0 \uc2f6\uc744 \ub54c \uc720\uc6a9\ud569\ub2c8\ub2e4.\\n\\n## \ud504\ub85c\ud37c\ud2f0 \uc77d\uae30 \ub514\ubc84\uae45\\n\\n\uac1d\uccb4\uac00 \uc788\uace0 \uadf8 \uac1d\uccb4\uc5d0\uc11c \ud504\ub85c\ud37c\ud2f0\ub97c \uc77d\uc744 \ub54c\ub9c8\ub2e4 \uc54c\uace0 \uc2f6\ub2e4\uba74 `debugger` \ud638\ucd9c\uacfc \ud568\uaed8 \uac1d\uccb4 getter\ub97c \uc0ac\uc6a9\ud558\uc138\uc694. \uc5b4\ub5a4 \uc124\uc815 \uc635\uc158\uc744 \uc804\ub2ec\ud560 \ub54c \uadf8 \uc635\uc158\uc774 \uc5b4\ub5bb\uac8c \uc0ac\uc6a9\ub418\ub294\uc9c0 \ubcf4\uace0 \uc2f6\uc744 \ub54c \uc720\uc6a9\ud569\ub2c8\ub2e4.\\n\\n**copy() \ud65c\uc6a9**\\n\\n`copy()` \ucf58\uc194 API\ub97c \uc0ac\uc6a9\ud558\uba74 \ubb38\uc790\uc5f4\uc744 \uc798\ub77c\ub0b4\uc9c0 \uc54a\uace0\ub3c4 \ube0c\ub77c\uc6b0\uc800\uc5d0\uc11c \uad00\uc2ec\uc774 \uc788\ub294 \uc815\ubcf4\ub97c \ud074\ub9bd\ubcf4\ub4dc\ub85c \ubc14\ub85c \ubcf5\uc0ac\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n- \ud604\uc7ac DOM \uc2a4\ub0c5\uc0f7: `copy(document.documentElement.outerHTML)`\\n- localStorage \ub364\ud504: `copy(localStorage)`\\n\\n## HTML / CSS \ub514\ubc84\uae45\\n\\n### JS \ube44\ud65c\uc131\ud654 \uc0c1\ud0dc\uc5d0\uc11c DOM \uac80\uc0ac\ud558\uae30\\n\\nDOM \uc778\uc2a4\ud399\ud130\uc5d0\uc11c `crtl+\\\\`\ub97c \ub204\ub974\uba74 JS \uc2e4\ud589\uc744 \uc5b8\uc81c\ub4e0 \uba48\ucda5\ub2c8\ub2e4. \uc774\ub97c \ud1b5\ud574 JS\uac00 DOM\uc744 \ubcc0\ud615\ud558\uac70\ub098 \uc774\ubca4\ud2b8(\uc608: \ub9c8\uc6b0\uc2a4 \uc624\ubc84)\ub85c \uc778\ud574 DOM\uc774 \ubcc0\uacbd\ub420 \uc5fc\ub824 \uc5c6\uc774 DOM\uc758 \uc2a4\ub0c5\uc0f7\uc744 \uac80\uc0ac\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### \ucc3e\uae30 \uc5b4\ub824\uc6b4 \uc694\uc18c \uac80\uc0ac\\n\\n\uc870\uac74\ubd80\ub85c\ub9cc \ud45c\uc2dc\ub418\ub294 DOM \uc694\uc18c\ub97c \uac80\uc0ac\ud558\uace0 \uc2f6\ub2e4\uace0 \uac00\uc815\ud574 \ubcf4\uaca0\uc2b5\ub2c8\ub2e4. \ud574\ub2f9 \uc694\uc18c\ub97c \uac80\uc0ac\ud558\ub824\uba74 \ub9c8\uc6b0\uc2a4\ub97c \ud574\ub2f9 \uc694\uc18c\ub85c \uc774\ub3d9\ud574\uc57c \ud558\ub294\ub370, \ub9c8\uc6b0\uc2a4\ub97c \uc774\ub3d9\ud558\ub824\uace0 \ud558\uba74 \ud574\ub2f9 \uc694\uc18c\uac00 \uc0ac\ub77c\uc9d1\ub2c8\ub2e4.\\n\\n[\uc601\uc0c1 \ucc38\uace0](https://camo.githubusercontent.com/b0a344f9fde72e401cfd9521fe80f89255d90bb294fde4cb6c09fedb178faa2b/68747470733a2f2f616c616e2e6e6f7262617565722e636f6d2f5f6e6578742f696d6167653f75726c3d2532465f6e6578742532467374617469632532466d65646961253246656c75736976652d656c656d656e742e34393562303934352e67696626773d3139323026713d3735)\\n\\n`setTimeout(function() {debugger; }, 5000);` \uc774\ub807\uac8c \ud558\uba74 5\ucd08 \ub3d9\uc548 UI\ub97c \ud2b8\ub9ac\uac70\ud560 \uc218 \uc788\uc73c\uba70, 5\ucd08 \ud0c0\uc774\uba38\uac00 \ub05d\ub098\uba74 JS \uc2e4\ud589\uc774 \uc77c\uc2dc \uc911\uc9c0\ub418\uace0 \uc694\uc18c\uac00 \uc0ac\ub77c\uc9c0\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.\\n\\n[\uc601\uc0c1 \ucc38\uace0](https://camo.githubusercontent.)\\n\\n## \ud604\uc7ac \uc120\ud0dd\ub41c \uc694\uc18c \ucc38\uc870\\n\\n\ucf58\uc194\uc5d0\uc11c `$0`\uc740 \uc694\uc18c \uc778\uc2a4\ud399\ud130\uc5d0\uc11c \ud604\uc7ac \uc120\ud0dd\ub41c \uc694\uc18c\ub97c \uc790\ub3d9\uc73c\ub85c \ucc38\uc870\ud569\ub2c8\ub2e4.\\n\\n### \uc774\uc804 \uc694\uc18c\\n\\n*\ud06c\ub86c*\uacfc *\uc5e3\uc9c0*\uc5d0\uc11c\ub294 `$1`\ub85c \ub9c8\uc9c0\ub9c9\uc73c\ub85c \uac80\uc0ac\ud55c \uc694\uc18c, `$2`\ub85c \uadf8 \uc774\uc804 \uc694\uc18c \ub4f1\uc5d0 \uc811\uadfc\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### \uc774\ubca4\ud2b8 \ub9ac\uc2a4\ub108 \uac00\uc838\uc624\uae30\\n\\n*\ud06c\ub86c*\uc5d0\uc11c\ub294 \ud604\uc7ac \uc120\ud0dd\ub41c \uc694\uc18c\uc758 \ubaa8\ub4e0 \uc774\ubca4\ud2b8 \ub9ac\uc2a4\ub108\ub97c \uc870\uc0ac\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4: `getEventListener($0)`\\n\\n## \uc694\uc57d\\n\\n\ube0c\ub77c\uc6b0\uc800(\uc8fc\ub85c \ud06c\ub86c)\uc5d0\ub294 \uc815\ub9d0 \ubb34\uc218\ud788 \ud65c\uc6a9 \uac00\ub2a5\ud55c \ub514\ubc84\uae45 \ud2b8\ub9ad\ub4e4\uc774 \uc788\uc2b5\ub2c8\ub2e4. \uae30\ubcf8\uc801\uc778 \uc911\ub2e8\uc810 \uc0ac\uc6a9 \uc678\uc5d0 \ub2e4\uc591\ud55c \uc911\ub2e8 \uc870\uac74\uc744 \uac78\uc5b4 \uc911\ub2e8 \uc5ec\ubd80\ub97c \uacb0\uc815\ud560 \uc218 \uc788\ub294 \ubc29\ubc95\uc774\ub098 \uc911\ub2e8\uc810\uc744 \uc0ac\uc6a9\ud558\uc5ec \uc694\uc18c \uac12\uc744 \uc54c\uc544\ub0b4\uae30 \uc5b4\ub824\uc6b4 \uacbd\uc6b0 \ub4f1\uc5d0\uc11c \ub514\ubc84\uae45\ud558\ub294 \ubc29\ubc95\uacfc \uac19\uc774 \ub514\ubc84\uac70\ub97c \ucd5c\ub300\ud55c \ud65c\uc6a9\ud574 \ub514\ubc84\uae45\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ub098\uc911\uc5d0 \u201c\uc774\ub7f4 \ub550 \uc5b4\ub5bb\uac8c \ub514\ubc84\uae45\ud558\uc9c0\u201d\ub77c\ub294 \uc0dd\uac01\uc774 \ub4dc\uc2e4 \ub54c \ud55c \ubc88\uc529 \ud655\uc778\ud574 \ubcf4\uba74 \uc88b\uc744 \uac83 \uac19\uc2b5\ub2c8\ub2e4."},{"id":"/hanagertrudeKim/infomate-1week","metadata":{"permalink":"/front-end/hanagertrudeKim/infomate-1week","source":"@site/@frontEnd/hanagertrudeKim/infomate-1week.mdx","title":"\uc778\ud3ec\uba54\uc774\ud2b8 1\uc8fc\ucc28 \uacf5\uc720(JS)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 1\uc8fc\ucc28 \uacf5\uc720(JS) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","date":"2024-02-24T00:00:00.000Z","tags":[{"label":"\uc778\ud3ec\uba54\uc774\ud2b8","permalink":"/front-end/tags/\uc778\ud3ec\uba54\uc774\ud2b8"},{"label":"JS","permalink":"/front-end/tags/js"},{"label":"TS","permalink":"/front-end/tags/ts"}],"readingTime":24.08,"hasTruncateMarker":true,"authors":[{"name":"hana Kim","url":"https://github.com/hanagertrudeKim","email":"rlagksk8428@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/101982606?v=4","key":"hanagertrudeKim"}],"frontMatter":{"date":"2024-02-24T00:00:00.000Z","authors":"hanagertrudeKim","title":"\uc778\ud3ec\uba54\uc774\ud2b8 1\uc8fc\ucc28 \uacf5\uc720(JS)","description":"\uc778\ud3ec\uba54\uc774\ud2b8 1\uc8fc\ucc28 \uacf5\uc720(JS) \ubaa8\uc74c\uc785\ub2c8\ub2e4.","keywords":["\uc778\ud3ec\uba54\uc774\ud2b8","JS","TS"],"tags":["\uc778\ud3ec\uba54\uc774\ud2b8","JS","TS"]},"unlisted":false,"prevItem":{"title":"\uc778\ud3ec\uba54\uc774\ud2b8 2\uc8fc\ucc28 \uacf5\uc720(\ube0c\ub77c\uc6b0\uc800)","permalink":"/front-end/d0dam/infomate-2week"}},"content":"\uc778\ud3ec\uba54\uc774\ud2b8 1\uc8fc\ucc28 \uacf5\uc720(JS) \ubaa8\uc74c\uc785\ub2c8\ub2e4.\\n\\nimport\ub85c \uc778\ud55c \uc21c\ud658 \ucc38\uc870 \ubb38\uc81c\ub97c \ud574\uacb0\ud558\ub294 \ubc29\ubc95 - \uae40\ud558\ub098  \\njs\uc758 Currying \uc774\ub780? - \uc724\ud574\uc9c4    \\nJS\uc758 \uc8fc\uc11d\uc740 //\uacfc /* */\ubfd0\ub9cc\uc774 \uc544\ub2c8\ub2e4 - \uacfd\uc2b9\uc8fc  \\n\uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\uac00 \ubb34\uc5c7\uc778\uac00\uc694? - \uc774\ud574\ub8e8 \\n\\n{/* truncate */}\\n\\nimport videoUrl from \\"../videos/scale-up.mp4\\";\\nimport ReactPlayer from \\"react-player\\";\\n\\n\\n# import\ub85c \uc778\ud55c \uc21c\ud658 \ucc38\uc870 \ubb38\uc81c\ub97c \ud574\uacb0\ud558\ub294 \ubc29\ubc95 - \uae40\ud558\ub098\\n\\n### Intro\\n\\n\ud504\ub85c\uc81d\ud2b8 \uaddc\ubaa8\uac00 \uc810\ucc28 \ucee4\uc9c8\uc218\ub85d \ubd84\ub9ac\ub418\ub294 \ud30c\uc77c\ub4e4\ub3c4 \ub298\uc5b4\ub098\uace0 `import` `export` \uad00\uacc4\uac00 \ubcf5\uc7a1\ud574\uc9c8 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc774\ub7f0 \uacbd\uc6b0 \uc5b4\ub5a4 \ud55c \ud30c\uc77c\uc5d0 \ub2e4\ub978 \ud30c\uc77c\uc774 \uc11c\ub85c \ucc38\uc870\ud558\ub294 \ubb38\uc81c\uac00 \ubc1c\uc0dd\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc2e4\uc81c\ub85c \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c\ub3c4 \uc800\ub294 \uc815\ub9d0 \uac00\ub054\uc529 `import` \ub418\ub294 \ubaa8\ub4c8 \ud30c\uc77c\uc744 \uc778\uc2dd\ud558\uc9c0 \ubabb\ud574 \uc54c \uc218 \uc5c6\ub294 \ube68\uac04\uc904 \uc5d0\ub7ec\uac00 \ub72c \uc801\uc774 \uc788\ub294\ub370, \u2018\uc21c\ud658 \ucc38\uc870 (circular dependency) \ubb38\uc81c\u2019 \uc640 \uc5f0\uad00\uc774 \uc788\uc744\uc218\ub3c4 \uc788\uaca0\ub2e4\ub294 \uc0dd\uac01\uc774 \ub4e4\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n\ub530\ub77c\uc11c \uc21c\ud658 \ucc38\uc870\uac00 \ubb34\uc5c7\uc778\uc9c0 \uc778\uc2dd\ud558\uace0 \uc21c\ud658 \ucc38\uc870\ub97c \ud574\uacb0/\uc608\ubc29\ud558\uae30 \uc704\ud55c \uac04\ub2e8\ud55c \ud328\ud134\ub4e4\uc744 \uc18c\uac1c\ud574\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n### \uc21c\ud658 \ucc38\uc870\ub780?\\n\\n\uc790\ubc14\uc2a4\ud06c\ub9bd\ud2b8 \ubaa8\ub4c8 \uc2dc\uc2a4\ud15c\uc5d0\uc11c\ub294 \uae30\ubcf8\uc801\uc73c\ub85c \uc21c\ud658 \ucc38\uc870\ub97c \ud5c8\uc6a9\ud569\ub2c8\ub2e4. \uc21c\ud658 \ucc38\uc870\ub780 \uc11c\ub85c\uac00 \uc11c\ub85c\ub97c \ucc38\uc870\ud558\ub294 \uc0c1\ud0dc\ub97c \uc774\uc57c\uae30\ud569\ub2c8\ub2e4. JS \uc5d0\uc11c\ub294 \uc774\ub97c \uc2dc\uc2a4\ud15c\uc5d0\uc11c \uac78\ub7ec\ub0b4\uc9c0 \uc54a\uace0, \ud55c\ucabd\uc758 `export` \ub97c \ube48 \uac1d\uccb4\ub85c \ub9cc\ub4e4\uc5b4 \ubc84\ub9bd\ub2c8\ub2e4.\\n\\n\uc544\ub798 \uc608\uc2dc\ub294 \uc21c\ud658 \ucc38\uc870\uc758 \ub300\ud45c\uc801 \uc608\uc2dc\uc785\ub2c8\ub2e4.\\n\\n```jsx\\n// index.js\\nimport \'./a.js\';\\n\\n// a.js\\nimport { sayHello } from \'./b.js\';\\n\\nexport const NAME = \'mike\';\\n\\nconsole.log(\'module_a\');\\nsayHello();\\n\\n// b.js\\nimport { NAME } from \'./a.js\';\\n\\nconsole.log(\'module_b\');\\n\\nexport const sayHello = () => {\\n  console.log(\'hello~!\', NAME);\\n};\\n```\\n\\n\uc5ec\uae30\uc11c `b.js` \uc5d0\uc11c `sayHello()` \ud568\uc218\ub97c \uc77d\ub294 \ud615\ud0dc\ub294 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.\\n\\n```jsx\\nexport const sayHello = () => {\\n\\tconsole.log(\'hello~!\', aModuleObject.Name);\\n};\\n```\\n\\nNAME \uc744 a \ubaa8\ub4c8\uc758 \uac1d\uccb4\ub77c\uace0 \uc77d\uc744 \uc218 \uc788\ub294 \uc774\uc720\ub294 `a.js` \uc5d0\uc11c NAME \ubcc0\uc218\ub97c \ub0b4\ubcf4\ub0b4\ub294 \uc2dc\uc810\uc774 `sayHello()` \ud638\ucd9c\ubd80 \uc774\uc804 \uc774\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4. \\n\\n\ub9cc\uc57d NAME \ubcc0\uc218 \ub0b4\ubcf4\ub0b4\ub294 \uc2dc\uc810\uc744 `sayHello()` \ud638\ucd9c\ubd80 \uc774\ud6c4\ub85c \ubcf4\ub0b4\uba74 \uc5d0\ub7ec\uac00 \ubc1c\uc0dd\ud558\uac8c \ub429\ub2c8\ub2e4. \uc774\ub7ec\ud55c \ubb38\uc81c\ub4e4\uc774 \uacb9\uce58\uac8c \ub418\uba74, \uc21c\ud658 \ucc38\uc870 \ubb38\uc81c\uac00 \uc0dd\uae30\uac8c \ub41c\ub2e4\uace0 \uc124\uba85\ud569\ub2c8\ub2e4.\\n\\n### \uc21c\ud658 \ucc38\uc870\uc5d0\uc11c \ubb38\uc81c\uac00 \ub0ac\uc744\ub54c \uc54c\uc544\ucc28\ub9ac\uae30 \ud798\ub4e0 \uc774\uc720\\n\\n- ESM \uc5d0\uc11c\ub294 \ubaa8\ub4c8\uc5d0\uc11c \uc5c6\ub294 \uc18d\uc131\uc744 \uac00\uc838\uc62c\ub54c \uc5d0\ub7ec\uac00 \ubc1c\uc0dd\ud569\ub2c8\ub2e4.\\n\u21d2 \uba85\uc2dc\uc801\uc73c\ub85c \uc5d0\ub7ec\uac00 \ubc1c\uc0dd\ud558\uae30 \ub54c\ubb38\uc5d0 \uc21c\ud658 \ucc38\uc870 \uc624\ub958\ub97c \ube60\ub974\uac8c \uc778\uc2dd\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- commonJS \uc5d0\uc11c\ub294 \ubaa8\ub4c8\uc5d0\uc11c \uc5c6\ub294 \uc18d\uc131\uc744 \uac00\uc838\uc624\uba74 \uc77c\ubc18\uc801\uc778 \uac1d\uccb4\ucc98\ub7fc `undefined`\uac00 \ubc18\ud658\ub418\uace0 \uc5d0\ub7ec\ub97c \ubc1c\uc0dd\uc2dc\ud0a4\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4. \\n\u21d2 \uc21c\ud658 \ucc38\uc870 \ubb38\uc81c\ub97c \uc27d\uac8c \uc54c\uc544\ucc28\ub9ac\uc9c0 \ubabb\ud569\ub2c8\ub2e4. (commonJS\uc744 \uc0ac\uc6a9\ud558\ub294 \uc6f9\ud329\uc758 \uacbd\uc6b0 \uc21c\ud658 \ucc38\uc870 \ubb38\uc81c\ub97c \ubc1c\uacac\ud558\uae30 \ud798\ub4ed\ub2c8\ub2e4.)\\n\\n### \uac00\uc7a5 \uba85\uc2dc\uc801\uc778 \ud574\uacb0 \ubc29\ubc95 - \ub0b4\ubd80 \ubaa8\ub4c8 \ud328\ud134(Internal module pattern)\\n\\n\uac00\uc7a5 \uba85\uc2dc\uc801\uc778 \ud574\uacb0 \ubc29\ubc95\uc740 \ubaa8\ub4c8\uc758 \ud3c9\uac00 \uc21c\uc11c\ub97c \ub0b4\ubd80\uc801\uc73c\ub85c \uc815\uc758\ud558\ub294 \ud30c\uc77c\uc744 \ub9cc\ub4dc\ub294 \uac83 \uc785\ub2c8\ub2e4.\\n\\n\ub530\ub77c\uc11c, \ubaa8\ub4c8\uc744 \uac00\uc838\uc62c\ub54c \ud56d\uc0c1 \uadf8 \ud30c\uc77c\ub85c\ubd80\ud130 \uac00\uc838\uc624\ub294 \ud615\ud0dc\ub97c \uac16\ucd94\uac8c \ub429\ub2c8\ub2e4.\\n\\n\ud575\uc2ec\uc740 \ub2e4\ub978 \ubaa8\ub4c8\ub4e4\uc744 \uc9c1\uc811\uc801\uc73c\ub85c \ubd88\ub7ec\uc624\uc9c0 \uc54a\ub3c4\ub85d \ud558\ub294 \uac83 \uc785\ub2c8\ub2e4.\\n\\n\uc704\uc758 \uc608\uc2dc\uc758 \ubaa8\ub4c8\uc744\uc758 \uc21c\uc11c\ub97c \ub2e4\uc74c\uacfc \uac19\uc774 `modules.js` \ud30c\uc77c\uc5d0 \uc815\uc758\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n```jsx\\n// modules.js\\nexport * from \'./b.js\';\\nexport * from \'./a.js\';\\n```\\n\\n\ubaa8\ub4c8 \ud638\ucd9c\ubd80\ub294 \ub2e4\uc74c\uacfc \uac19\uc774 \ub2ec\ub77c\uc9c8 \uac83\uc785\ub2c8\ub2e4.\\n\\n```jsx\\n//index.js\\nimport { NAME,   sayHello ) from \'./modules.js\';\\n//a.js\\nimport { sayHello } from \'./modules.js\';\\n//b.js\\nimport { NAME } from \'./modules.js\';\\n```\\n\\n### \uc694\uc57d\\n\\n- \uc21c\ud658 \ucc38\uc870\ub294 \uc11c\ub85c\uac00 \uc11c\ub85c\ub97c \ucc38\uc870\ud558\ub294 \ud615\ud0dc\uc785\ub2c8\ub2e4.  (a\ubaa8\ub4c8 \u2194 b\ubaa8\ub4c8)\\n- \uc21c\ud658 \ucc38\uc870\ub294 CommonJS \ud658\uacbd\uc5d0\uc11c \uc27d\uac8c \ubc1c\uacac\ud558\uc9c0 \ubabb\ud569\ub2c8\ub2e4.\\n- \ub0b4\ubd80\uc801\uc73c\ub85c \ubaa8\ub4c8 \ud3c9\uac00 \uc21c\uc11c\ub97c \uc815\uc758\ud558\ub294 \ud30c\uc77c\uc744 \ub530\ub85c \ub9cc\ub4e4\uc5b4 \uc21c\ud658 \ucc38\uc870 \ubb38\uc81c\ub97c \ud574\uacb0\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n[How to fix nasty circular dependency issues once and for all in JavaScript & TypeScript](https://medium.com/visual-development/how-to-fix-nasty-circular-dependency-issues-once-and-for-all-in-javascript-typescript-a04c987cf0de)\\n\\n[JS \ubaa8\ub4c8 \uc2dc\uc2a4\ud15c\uacfc \uc21c\ud658 \ucc38\uc870 \ubb38\uc81c](https://ljs0705.medium.com/js-\ubaa8\ub4c8-\uc2dc\uc2a4\ud15c\uacfc-\uc21c\ud658-\ucc38\uc870-\ubb38\uc81c-a9e0c90c07e5)\\n\\n# js\uc758 Currying \uc774\ub780? - \uc724\ud574\uc9c4    \\n\\n### Intro\\n\\n\ucf54\ub4dc \ub9ac\ubdf0\ub85c \ub2e4\ub978 \ub3d9\ub8cc\ubd84\uaed8 \ucee4\ub9c1\uc744 \uc0ac\uc6a9\ud558\ub294 \uac83\ub3c4 \uc88b\uc544 \ubcf4\uc774\ub124\uc694!\ub77c\ub294 \uc774\uc57c\uae30\ub97c \ub4e4\uc5c8\uc2b5\ub2c8\ub2e4. \\n\\n\ubd80\ub044\ub7fd\uc9c0\ub9cc \uadf8\ub54c\ub294 \ucee4\ub9c1\uc774 \ubb34\uc5c7\uc778\uc9c0 \ubab0\ub790\uc5c8\uc2b5\ub2c8\ub2e4. \ucee4\ub9c1\uc5d0 \ub300\ud574 \ucc3e\uc544\ubcf4\ub2c8 \ud568\uc218\ud615 \ud504\ub85c\uadf8\ub798\ubc0d\uc5d0 \uc788\uc5b4 \ubcf4\ub2e4 \ud568\uc218\uc758 \uc7ac\uc0ac\uc6a9\uc131\uc744 \ub192\uc77c \uc218 \uc788\ub294 \ubc29\ubc95\uc774\ub77c\ub294 \uac83\uc744 \uc54c\uac8c \ub418\uc5b4 \uc774\ubc88 \uae30\ud68c\ub85c \uacf5\uc720\ub97c \ud574\ubcf4\ub824 \ud569\ub2c8\ub2e4. \ud83d\ude03\\n\\n### Currying(\ucffc\ub9c1)\uc774 \ubb34\uc5c7\uc778\uac00?\\n\\n- \uc5ec\ub7ec \uac1c\uc758 \uc778\uc218\ub97c \ud568\uc218\uac00 \uc911\ucca9\ub418\ub294 \uc21c\uc11c\ub300\ub85c \ubcf4\ub0b4\ub294 \ud558\ub098\uc758 \uacfc\uc815\\n\\nCurrying\uc740 \ubaa8\ub4e0 \uc778\uc218\ub4e4\uc774 \uc0ac\uc6a9\ub420 \ub54c\uae4c\uc9c0 \uacc4\uc18d \uc0c8\ub85c\uc6b4 \ud568\uc218\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.\\n\\n```jsx\\n//\ubaa8\ub4e0 \uc778\uc218\ub97c \uac00\uc9c0\uace0 \ud568\uc218\ub97c \ud638\ucd9c\\n\\nfunction multiply (a, b, c) {\\n    return a * b * c;\\n}\\n\\nmultiply(1, 2, 3); \\n\\n```\\n\\n\u21d2\\n\\n```jsx\\n//curried\ub41c \ud568\uc218\uc758 \ud638\ucd9c\\n\\nfunction multiply (a) {\\n    return (b) => {\\n        return (c) => {\\n            return a * b * c;\\n        };\\n    };\\n}\\n\\nmultiply(1)(2)(3);  \\n\\n```\\n\\n\ud558\ub098\uc758 \ud568\uc218\uac00 \uc5ec\ub7ec \ud568\uc218\uc758 \uc870\ud569\uc73c\ub85c \ubd84\ud574\uac00 \ub41c \uac83\uc744 \ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n**\uc989, Currying\uc740 \uc5ec\ub7ec \uac1c\uc758 \uc778\uc218\ub97c \uac00\uc9c4 \ud568\uc218\ub97c `\uac01\uac01\uc774 \ud558\ub098\uc758 \uc778\uc218\ub97c \uac16\ub294 \uc77c\ub828\uc758 \ud568\uc218`\ub4e4\ub85c \ubcc0\ud658\ud569\ub2c8\ub2e4.**\\n\\n\uadf8\ub7ec\ub098, **\uc774\ubbf8 \ubc18\ud658\ub41c \uc678\ubd80 \ud568\uc218\uc758 return \uac12\uc5d0 \uc5b4\ub5bb\uac8c \uc811\uadfc\uc744 \ud558\ub294 \uac83\uc77c\uae4c\uc694?** \ud83e\udd14\\n\\n\u21d2 \uc774 \ubd80\ubd84\uc740 JavaScript\uc5d0\uc11c\ub294 **\ud074\ub85c\uc800(Closure)**\ub77c\ub294 \uac1c\ub150\uc744 \ud1b5\ud574 **\uc774\ubbf8 \ubc18\ud658\ub41c \uc678\ubd80 \ud568\uc218\uc758 \uc9c0\uc5ed \ubcc0\uc218\uc5d0 \uc811\uadfc\ud560 \uc218 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.**\\n\\n\uc774\ub294 \ud568\uc218\uac00 \uc2e4\ud589\ub420 \ub54c \uc790\uc2e0\uc774 \uc0dd\uc131\ub420 \ub2f9\uc2dc\uc758 \ud658\uacbd\uc5d0 \uc788\ub294 \ubcc0\uc218\ub4e4\uc5d0 \uc811\uadfc\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ub530\ub77c\uc11c \uc704 \uc608\uc2dc\uc5d0\uc11c\ub294 \\n\\n- **multiply(1)**\uc740 **a** \uac00 **1**\ub85c \uace0\uc815\ub41c \uc0c8\ub85c\uc6b4 \ud568\uc218\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.\\n- **(2)**(\uc774\uc804 \ub2e8\uacc4\uc5d0\uc11c \ubc18\ud658\ub41c \ud568\uc218\uc5d0 \ub300\ud55c \ud638\ucd9c)\ub294 **b** \uac00 **2**\ub85c \uace0\uc815\ub418\uace0, **c** \ub97c \ubc1b\ub294 \ub610 \ub2e4\ub978 \uc0c8\ub85c\uc6b4 \ud568\uc218\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.\\n- **(3)**(\ub450 \ubc88\uc9f8 \ub2e8\uacc4\uc5d0\uc11c \ubc18\ud658\ub41c \ud568\uc218\uc5d0 \ub300\ud55c \ud638\ucd9c)\uc740 **c** \uac00 **3**\uc73c\ub85c \uace0\uc815\ub418\uace0, \uc774\uc81c \ubaa8\ub4e0 \uc778\uc790\uac00 \uc900\ube44\ub418\uc5c8\uc73c\ubbc0\ub85c **a * b * c \uacc4\uc0b0\uc744 \uc218\ud589\ud558\uace0 \uadf8 \uacb0\uacfc\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.**\\n\\n\uc774 \uacfc\uc815\uc5d0\uc11c **a**\uc640 **b**\ub294 \uac01\uac01\uc758 \ud074\ub85c\uc800 \ub0b4\uc5d0\uc11c \\"\uc0b4\uc544\uc788\ub294\\" \uc0c1\ud0dc\ub85c \uc720\uc9c0\ub418\uba70, \ub9c8\uc9c0\ub9c9 \ud568\uc218\uc5d0\uc11c **a**, **b**, \uadf8\ub9ac\uace0 **c**\uc758 \uac12\uc744 \uc0ac\uc6a9\ud558\uc5ec \uacc4\uc0b0\uc744 \uc218\ud589\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n### Currying(\ucffc\ub9c1)\uc740 \uc720\uc6a9\ud55c\uac00?\\n\\n1. \uc7ac\uc0ac\uc6a9 \uac00\ub2a5\ud558\uace0 \uc27d\uac8c \uad6c\uc131\ud560 \uc218 \uc788\ub294 \uc791\uc740 \ucf54\ub4dc \ubaa8\ub4c8 \uc791\uc131\ud569\ub2c8\ub2e4.\\n    - \ub9cc\uc57d, \ub9e4\ubc88 \uace0\uac1d\uc5d0\uac8c 10%\uc758 \ud560\uc778\uc744 \uc801\uc6a9\ud574 \uc8fc\uace0\uc790 \ud569\ub2c8\ub2e4.\\n    \\n    ```jsx\\n    function discountedPrice(price, discountRate) {\\n        return price * (1 - discountRate);\\n    }\\n    ```\\n    \\n    \uc704\uc640 \uac19\uc740 \ucf54\ub4dc\ub85c \ud560\uc778 \uac00\uaca9\uc744 \uc0b0\ucd9c\ud574 \ub0bc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n    \uadf8\ub7ec\ub098, \uc774\ub294 \uc7a5\uae30\uc801\uc73c\ub85c \ub9e4\ubc88 10%\uc758 \ud560\uc778\uc744 \uacc4\uc0b0\ud558\uac8c \ub429\ub2c8\ub2e4.\\n    \\n    ```jsx\\n    const price = discountedPrice(1500000, 0.1);  //=> 1,350,000\\n    const price = discountedPrice(50000, 0.1);    //=> 45,000\\n    const price = discountedPrice(300000, 0.1);   //=> 270,000\\n    ```\\n    \\n    \uc774\ub54c, **discountedPrice \ud568\uc218**\ub97c curry\ub85c \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uadf8\ub7ec\uba74 \ub9e4\ubc88 0.1 \ud560\uc778\uc728\uc744 \ucd94\uac00\ud558\uc9c0 \uc54a\uc544\ub3c4 \ub429\ub2c8\ub2e4!\\n    \\n    ```jsx\\n    function discountedPrice(discountRate) {\\n        return (price) => {\\n            return price * (1 - discountRate);\\n        };\\n    }\\n    \\n    const tenPercentDiscount = discountedPrice(0.1);\\n    \\n    tenPercentDiscount(500000);  //=> 450000\\n    ```\\n    \\n\\ncurry\ub97c \uc774\uc6a9\ud568\uc73c\ub85c \uace0\uac1d\uc774 \uc0ac\ub294 \ubb3c\uac74\uc758 \uac00\uaca9\ub9cc \uac00\uc9c0\uace0 \uacc4\uc0b0\uc744 \ud560 \uc218 \uc788\uac8c \ub418\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n\ub610\ud55c, \ub354\uc6b1 \uc2a4\ud398\uc15c\ud55c \uace0\uac1d\uc5d0\uac8c\ub294 `const twentyPercentDiscount = discountedPrice(0.2);`\ub85c \ud65c\uc6a9\ud560 \uc218\ub3c4 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n1. \uac19\uc740 \uc778\uc218\ub97c \uac00\uc9c0\uace0 \uc790\uc8fc \ud568\uc218\ub97c \ud638\ucd9c\ud558\ub294 \uac83\uc744 \ud53c\ud560 \uc218 \uc788\ub2e4.\\n    - \uc608\uc2dc\ub85c \uc2e4\ub9b0\ub354\uc758 \ubd80\ud53c\ub97c \uacc4\uc0b0\ud558\ub294 \ud568\uc218\uac00 \uc788\uc2b5\ub2c8\ub2e4\\n    \\n    ```jsx\\n    function volume(length, width, height) {\\n        return length * width * height;\\n    }\\n    ```\\n    \\n    \uc5ec\uae30\uc11c \uc5b4\ub5a4 \uc2e4\ub9b0\ub354\uc758 height\uac00 \ubaa8\ub450 100\uc774\ub77c\uace0 \ud55c\ub2e4\uba74, \uc0ac\uc6a9\uc790\ub294 \ubc18\ubcf5\ud574\uc11c\xa0height\xa0\uc778\uc218\uc5d0\xa0100\uc744 \ub123\uc5b4\uc11c \ud638\ucd9c\ud574\uc57c \ud569\ub2c8\ub2e4.\\n    \\n    \uc774\ub97c \ud574\uacb0\ud558\uae30 \uc704\ud574,\xa0volumn\xa0\ud568\uc218\ub97c curried \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n    ```jsx\\n    function volumn (height) {\\n        return (width) => {\\n            return (length) => {\\n                return length * width * height;\\n            };\\n        };\\n    }\\n    ```\\n    \\n    \ud2b9\uc815\ud55c \ub192\uc774\uc5d0 \ub300\ud574\uc11c \ud568\uc218\ub97c \uc815\uc758\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n    ```jsx\\n    const hundredCylinderHeight = volumn(100);\\n    \\n    hundredCylinderHeight(200)(30);\\n    ```\\n    \\n\\n### \uc694\uc57d\\n\\n- \ucffc\ub9c1\uc774\ub780 \uc5ec\ub7ec \uac1c\uc758 \uc778\uc218\ub97c \uac00\uc9c4 \ud568\uc218\ub97c \uac01\uac01\uc774 \ud558\ub098\uc758 \uc778\uc218\ub97c \uac16\ub294 \uc77c\ub828\uc758 \ud568\uc218\ub4e4\ub85c \ubcc0\ud658\ud558\ub294 \uac83.\\n- \ucffc\ub9c1\uc744 \uc0ac\uc6a9\ud560 \ub54c \ud074\ub85c\uc800\ub77c\ub294 js\uc758 \uac1c\ub150\uc73c\ub85c \uc790\uc2e0\uc774 \uc0dd\uc131\ub420 \ub2f9\uc2dc\uc758 \ud658\uacbd\uc5d0 \uc788\ub294 \ubcc0\uc218\ub4e4\uc5d0 \uc811\uadfc \uac00\ub2a5.\\n- \ucffc\ub9c1\uc758 \uc7a5\uc810\uc73c\ub85c\ub294 \uc7ac\uc0ac\uc6a9 \uac00\ub2a5\ud558\uace0 \uc27d\uac8c \uad6c\uc131\ud560 \uc218 \uc788\ub294 \uc791\uc740 \ucf54\ub4dc \ubaa8\ub4c8 \uc791\uc131 \uac00\ub2a5, \uac19\uc740 \uc778\uc218\ub97c \uac00\uc9c0\uace0 \uc790\uc8fc \ud568\uc218\ub97c \ud638\ucd9c\ud558\ub294 \uac83 \ud68c\ud53c \uac00\ub2a5.\\n\\nhttps://blog.bitsrc.io/understanding-currying-in-javascript-ceb2188c339\\n\\n\\n[Everything about Currying in JavaScript](https://blog.bitsrc.io/understanding-currying-in-javascript-ceb2188c339)\\n\\n# JS\uc758 \uc8fc\uc11d\uc740 //\uacfc /* */\ubfd0\ub9cc\uc774 \uc544\ub2c8\ub2e4 - \uacfd\uc2b9\uc8fc\\n\\n## **Intro**\\n\\nJavaScript\uc5d0\uc11c `//`\uc640 `/* */`\ub85c \uac01\uac01 \ud55c \uc904 \uc8fc\uc11d\uacfc \uc5ec\ub7ec \uc904 \uc8fc\uc11d\uc744 \ub9cc\ub4e4 \uc218 \uc788\ub2e4\ub294 \uac83\uc740 \ub2e4\ub4e4 \uc54c\uace0 \uc788\uc744 \uac83\uc785\ub2c8\ub2e4. \ud558\uc9c0\ub9cc JavaScript \uba85\uc138\uc5d0\ub294 `#!`\ub85c \uc2dc\uc791\ud558\ub294 Hashbang Comments\uc640 HTML \uc8fc\uc11d \ud615\uc2dd\uc778 `\x3c!--`\uc640 `--\x3e` \ub85c \uac10\uc2f8\ub294 HTML-like Comments \ub4f1 \ub2e4\ub978 \uac83\ub3c4 \uc815\uc758\ub418\uc5b4 \uc788\uc2b5\ub2c8\ub2e4.  \uc5ec\uae30\uc5d0\uc11c\ub294 `#!`\uc640 `\x3c!--` `--\x3e`\uc758 \uac04\ub2e8\ud55c \ubb38\ubc95\uacfc \uc0ac\uc6a9 \ubaa9\uc801\uc744 \uc18c\uac1c\ud558\ub824\uace0 \ud569\ub2c8\ub2e4.\\n\\n## 1. Hashbang Comments\\n\\n### 1.1. \ubb38\ubc95\\n\\n\uc774\ub294 hashbang \ud639\uc740 shebang\uc774\ub77c\uace0 \ubd80\ub974\ub294 `#!`\ub85c \uc2dc\uc791\ud558\ub294 \ud55c \uc904 \uc8fc\uc11d\uc785\ub2c8\ub2e4. \uadf8\ub9ac\uace0 `#!` \uc774\uc804\uc5d0 \uacf5\ubc31\uc774 \uc788\uc73c\uba74 \uc548\ub429\ub2c8\ub2e4. \ud55c \uc904 \uc8fc\uc11d\uc774\ubbc0\ub85c \uc8fc\uc11d\uc744 \ub05d\ub0b4\ub294 `LineTerminator`\ub97c \uc81c\uc678\ud55c \ubaa8\ub4e0 \uae00\uc790\ub97c \uc4f8 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc774 \uc8fc\uc11d\uc740 \uadf8 \ud2b9\uc131\uc0c1 \uc2a4\ud06c\ub9bd\ud2b8 \ud639\uc740 \ubaa8\ub4c8\uc758 \uccab \uc2dc\uc791 \ubd80\ubd84\uc5d0\uc11c\ub9cc \uc720\ud6a8\ud569\ub2c8\ub2e4. \uc5b4\ub5a4 \ud2b9\uc131\uc778\uc9c0\ub294 \ub2e4\uc74c \uc139\uc158\uc5d0\uc11c \uc54c\uc544\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n### 1.2. Hashbang Comments\uc758 \ubaa9\uc801\\n\\n\uc774\ub294 \uc6d0\ub798 Unix \uacc4\uc5f4\uc758 \uc6b4\uc601\uccb4\uc81c\uc5d0\uc11c \uc0ac\uc6a9\ub418\ub358 \uac83\uc785\ub2c8\ub2e4. `#!`\ub85c \uc2dc\uc791\ud558\ub294 \ubb38\uc790\uc5f4\uc774 \uccab \uc904\uc5d0 \uc788\ub294 \ud30c\uc77c\uc740 \ud574\ub2f9 \ud30c\uc77c\uc744 \uc2e4\ud589\ud560 \ub54c `#!` \uc774\ud6c4\uc758 \ubb38\uc790\uc5f4\uc744 \uc778\ud130\ud504\ub9ac\ud130\ub85c \uc0ac\uc6a9\ud569\ub2c8\ub2e4.\\n\\nJavaScript\uc5d0\uc11c\ub3c4 \ube44\uc2b7\ud55c \ubaa9\uc801\uc73c\ub85c \ud574\ub2f9 \uc8fc\uc11d \ud615\uc2dd\uc774 \ub3c4\uc785\ub418\uc5c8\uc2b5\ub2c8\ub2e4. \uc774\ub294 \uc2a4\ud06c\ub9bd\ud2b8\ub098 \ubaa8\ub4c8 \ud30c\uc77c\uc5d0 \ucc98\uc74c\uc5d0 \uc120\uc5b8\ub418\uc5b4\uc11c \ud574\ub2f9 \ucf54\ub4dc\ub97c \uc2e4\ud589\ud560 \ub54c \uc5b4\ub5a4 JavaScript \uc778\ud130\ud504\ub9ac\ud130\ub97c \uc0ac\uc6a9\ud560\uc9c0 \uba85\uc2dc\ud558\ub294 \uc5ed\ud560\uc744 \ud569\ub2c8\ub2e4.\\n\\n\ud558\uc9c0\ub9cc, \uc2a4\ud06c\ub9bd\ud2b8\uac00 \uc258\uc5d0\uc11c \ub3cc\uc544\uac00\uc9c0 \uc54a\ub294 \uc774\uc0c1 \uc774 \uc8fc\uc11d\uc740 \uc77c\ubc18\uc801\uc778 \ud55c \uc904 \uc8fc\uc11d(`//`)\uacfc \uc644\uc804\ud788 \uac19\uc740 \uc758\ubbf8\ub97c \uac16\uac8c \ub429\ub2c8\ub2e4.\\n\\n```jsx\\n#! /usr/bin/env node\\n\\nconsole.log(\\"Hello, World\\");\\n```\\n\\n\ub530\ub77c\uc11c \uc774\ub294 \uc11c\ubc84\uc0ac\uc774\ub4dc JavaScript\uc5d0\uc11c \uc720\uc6a9\ud569\ub2c8\ub2e4. \uc11c\ubc84\uc5d0\ub294 \uc5ec\ub7ec JavaScript \uc778\ud130\ud504\ub9ac\ud130\uac00 \uc788\uc744 \uc218 \uc788\ub294\ub370 \uc774 \uc8fc\uc11d\uc744 \ud1b5\ud574\uc11c \uc5b4\ub5a4 \uc778\ud130\ud504\ub9ac\ud130\ub97c \uc0ac\uc6a9\ud560\uc9c0 \uba85\uc2dc\ud560 \uc218 \uc788\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4.\\n\\n## 2. HTML-like Comments\\n\\n### 2.1. \ubb38\ubc95\\n\\n`\x3c!--`\uc740 `SingleLineHTMLOpenComment`\ub85c \uc815\uc758\ub418\uc5b4 \uc788\uc2b5\ub2c8\ub2e4. \ud55c \uc904 \uc8fc\uc11d\uacfc \ub611\uac19\uc774 \uc791\ub3d9\ud558\uc5ec `LineTerminator`\ub97c \uc81c\uc678\ud55c \ubaa8\ub4e0 \uae00\uc790\ub97c \ud3ec\ud568\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc774\ub7f0 \uc2dd\uc73c\ub85c \uc4f0\uc77c \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n```jsx\\nconsole.log(1); \x3c!-- \ud55c\uc904\uc8fc\uc11d\\n```\\n\\n`--\x3e`\uc740 `SingleLineHTMLCloseComment`\ub85c \uc815\uc758\ub418\uc5b4 \uc788\uc2b5\ub2c8\ub2e4. \uc8fc\uc11d \ub0b4\uc6a9 \uc790\uccb4\ub294 \ud55c \uc904 \uc8fc\uc11d\uacfc \ub611\uac19\uc774 \uc791\ub3d9\ud558\uc5ec `--\x3e` \ub2e4\uc74c\uc5d0 \uc624\ub294 \uac19\uc740 \uc904\uc758 \uae00\uc790\ub4e4\uc744 \uc8fc\uc11d \ucc98\ub9ac\ud569\ub2c8\ub2e4. \ub2e8, `--\x3e` \uc774\uc804\uc5d0\ub294 \uacf5\ubc31, \uc904\ubc14\uafc8 \ud639\uc740 \ud55c \uc904\ub85c \uc81c\ud55c\ub41c \uc8fc\uc11d\ub9cc \uc788\uc5b4\uc57c \ud558\uace0 \ub2e4\ub978 \uae00\uc790\uac00 \uc788\uc73c\uba74 \uc548\ub429\ub2c8\ub2e4.\\n\\n\uc774\ub7f0 \uc2dd\uc73c\ub85c \uc4f0\uc77c \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n```jsx\\n*/ --\x3e \uc8fc\uc11d\ub0b4\uc6a9\\n--\x3e \ud55c\uc904 \uc8fc\uc11d\\nconsole.log(1); --\x3e \ud55c\uc904\uc8fc\uc11d // \uc774\uac74 --\x3e \uc774\uc804\uc5d0 \uc8fc\uc11d \uc678\uc758 \ub2e4\ub978 \uae00\uc790\uac00 \uc640\uc11c \uc548\ub429\ub2c8\ub2e4.\\n```\\n\\n### 2.2. \ubaa9\uc801\\n\\nJavaScript\uc758 \ucd08\uae30\uc5d0\ub294 JavaScript\ub97c \uc9c0\uc6d0\ud558\uc9c0 \uc54a\ub294 \uad6c\uc2dd \ube0c\ub77c\uc6b0\uc800\ub4e4\uc774 \ub9ce\uc558\uc2b5\ub2c8\ub2e4. JavaScript\ub97c \ud3ec\ud568\ud558\ub294 `<script>`\ud0dc\uadf8\ub97c \uc81c\ub300\ub85c \ucc98\ub9ac\ud560 \uc218\ub3c4 \uc5c6\uc5c8\uc2b5\ub2c8\ub2e4. \ub530\ub77c\uc11c JavaScript\ub97c HTML \ubb38\uc11c\uc758 `<script>`\ud0dc\uadf8\uc5d0 \ud3ec\ud568\ud55c \uacbd\uc6b0 \uad6c\uc2dd \ube0c\ub77c\uc6b0\uc800\uc5d0\uc11c\uc758 \ud638\ud658\uc131 \ubb38\uc81c\uac00 \uc788\uc5b4 `<script>` \uc694\uc18c\uc758 \ubcf8\ubb38\uc744 \uc6f9 \ud398\uc774\uc9c0\uc5d0 \uc77c\ubc18 \ud14d\uc2a4\ud2b8\ub85c \ud45c\uc2dc\ud574\ubc84\ub9ac\ub294 \ubb38\uc81c\uac00 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n\uc774 \ubb38\uc81c\ub294 HTML \uc8fc\uc11d\uc73c\ub85c \uc2a4\ud06c\ub9bd\ud2b8 \ubcf8\ubb38\uc744 \uac10\uc2f8\ub294 \uac83\uc73c\ub85c \ubc29\uc9c0\ud560 \uc218 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n```html\\n<script>\\n  \x3c!-- This is an HTML comment surrounding a script body\\n  alert(\\"this is a message from JavaScript\\"); // not visible to old browsers\\n  // the following line ends the HTML comment\\n  --\x3e\\n<\/script>\\n```\\n\\n\uc774\ub7f0 \ucf54\ub529 \ud328\ud134\uc744 \uc0ac\uc6a9\ud558\uba74 \uad6c\uc2dd \ube0c\ub77c\uc6b0\uc800\ub294 \uc804\uccb4 \uc2a4\ud06c\ub9bd\ud2b8 \ubcf8\ubb38\uc744 HTML \uc8fc\uc11d\uc73c\ub85c \uc778\uc2dd\ud558\uace0 \ud398\uc774\uc9c0\uc5d0 \ud45c\uc2dc\ud558\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4. \ud558\uc9c0\ub9cc, \uc774\ub7f0 \ud328\ud134\uc744 \uc0ac\uc6a9 \uc2dc HTML\uc758 \uc8fc\uc11d \uad6c\ubd84\uc790 `\x3c!--`\uc774 JavaScript \ucf54\ub4dc\uc5d0\uc11c \ubb38\ubc95\uc801\uc73c\ub85c \uc720\ud6a8\ud558\uc9c0 \uc54a\uc558\uae30 \ub54c\ubb38\uc5d0 JavaScript\ub97c \uc9c0\uc6d0\ud558\ub294 \ube0c\ub77c\uc6b0\uc800\uac00 \uc2a4\ud06c\ub9bd\ud2b8 \ubcf8\ubb38\uc744 \uc81c\ub300\ub85c \ud30c\uc2f1\ud558\uace0 \uc2e4\ud589\ud558\uc9c0 \ubabb\ud588\uc2b5\ub2c8\ub2e4.\\n\\n\uc774 \ubb38\uc81c\ub97c \ud53c\ud558\uae30 \uc704\ud574 `\x3c!--`\uac00 \ud55c \uc904 \uc8fc\uc11d\uc758 \uc2dc\uc791\uc73c\ub85c \uc778\uc2dd\ub418\ub3c4\ub85d \ud558\uace0 `--\x3e`\uc758 \uc55e\uc5d0 `//`\ub97c \ub450\ub294 \uac83\uc73c\ub85c \uc544\ub798\uc640 \uac19\uc774 \ud558\uc5ec \ud558\uc704 \ud638\ud658\uc131\uc744 \uc9c0\ud0ac \uc218 \uc788\uac8c \ud588\uc2b5\ub2c8\ub2e4.\\n\\n```html\\n<script>\\n\\t\x3c!-- This is an HTML comment in old browsers and a JS single line comment\\n  alert(\\"this is a message from JavaScript\\"); // not visible to old browsers\\n  // the following line ends the HTML comment and is a JS single line comment\\n  // --\x3e\\n<\/script>\\n```\\n\\n\uc774\ub7f0 \ubc29\ubc95\uc774 \uc624\ub798\ub3c4\ub85d \ub9ce\uc740 \uc6f9 \uac1c\ubc1c\uc790\ub4e4\uc5d0\uac8c \uc0ac\uc6a9\ub41c \uacb0\uacfc, \ud45c\uc900\ud654\ub41c \uac83\uc774 \uc704\uc758 \ubb38\ubc95\uc785\ub2c8\ub2e4.\\n\\n## \uacb0\ub860\\n\\nHashbang Comments\uc640 HTML-like Comments\ub97c \uc54c\uc544\ubcf4\uc558\ub294\ub370 \uc774\ub4e4\uc740 \ud2b9\ubcc4\ud55c \ubaa9\uc801\uc744 \uc704\ud574 \ub3c4\uc785\ub41c \uac83\uc785\ub2c8\ub2e4. \ub530\ub77c\uc11c \uacb0\uad6d\uc740 `//`\uc744 \ud55c \uc904 \uc8fc\uc11d\uc73c\ub85c, `/* */`\ub97c \uc5ec\ub7ec \uc904 \uc8fc\uc11d\uc73c\ub85c \uc0ac\uc6a9\ud558\ub294 \uac8c \uac00\uc7a5 \uc88b\uc2b5\ub2c8\ub2e4. \\n\\n\ud558\uc9c0\ub9cc \uc774\ub7f0 \uc8fc\uc11d \ud615\uc2dd\ub4e4\uc774 \uc65c \ub3c4\uc785\ub418\uc5c8\ub294\uc9c0, \uc5b4\ub5a4 \ubaa9\uc801\uc744 \uc704\ud574 \ub3c4\uc785\ub418\uc5c8\ub294\uc9c0 \uc54c\uc544\ubcf4\ub294 \uac83\uc740 \ub9ce\uc740 \ud1a0\ub9c9\uc9c0\uc2dd\ub4e4\uc744 \uc804\ud574 \uc8fc\uc5c8\uc2b5\ub2c8\ub2e4. Hashbang Comments\uc640 HTML-like Comments \ub4f1\uc740 JavaScript\uac00 \uac78\uc5b4\uc628 \uae38\ub4e4\uc758 \ub2e8\uba74\uc744 \ubcf4\uc5ec \uc90d\ub2c8\ub2e4.\\n\\n[JS \ud0d0\uad6c\uc0dd\ud65c - JS\uc758 \uc8fc\uc11d\uc740 //\uacfc /* */\ubfd0\ub9cc\uc774 \uc544\ub2c8\ub2e4](https://witch.work/posts/javascript-various-comments)\\n\\n# \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\uac00 \ubb34\uc5c7\uc778\uac00\uc694? - \uc774\ud574\ub8e8 \\n\\n# \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8(Excution Context)\uac00 \ubb34\uc5c7\uc778\uac00\uc694?\\n\\nJavaScript\ub97c \uacf5\ubd80\ud558\ub2e4\ubcf4\uba74 \ub9c8\uc8fc\uce58\uac8c \ub418\ub294 \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\uc758 \uac1c\ub150\uc5d0 \ub300\ud574 \uac04\ub2e8\ud558\uac8c \uc54c\uc544\ubd05\uc2dc\ub2e4.\\n\\n**\uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8(Excution Context)**\ub780 **\ucf54\ub4dc\ub97c \uc2e4\ud589\ud568\uc5d0 \uc788\uc5b4\uc11c \uc2e4\ud589\ud560 \ucf54\ub4dc\uc5d0 \uc81c\uacf5\ud560 \ud658\uacbd \uc815\ubcf4\ub4e4\uc744 \ubaa8\uc544\ub193\uc740 \uac1d\uccb4**\uc785\ub2c8\ub2e4.\\n\\n\uc790\ubc14\uc2a4\ud06c\ub9bd\ud2b8\ub294 \ucf54\ub4dc\ub97c \uc2e4\ud589\ud560 \ub54c, \ud544\uc694\ud55c \ud658\uacbd\uc815\ubcf4\ub4e4\uc744 \ubaa8\uc544 \ucee8\ud14d\uc2a4\ud2b8\ub97c \uad6c\uc131\ud558\uace0, \uc774\ub97c \ucf5c\uc2a4\ud0dd\uc5d0 \uc313\uc544\ub461\ub2c8\ub2e4. \uc774\ud6c4 \uac00\uc7a5 \uc704\uc5d0 \uc313\uc5ec\uc788\ub294 \ucee8\ud14d\uc2a4\ud2b8\uc640 \uad00\ub828\ub41c \ucf54\ub4dc\ubd80\ud130 \uc21c\uc11c\ub300\ub85c \uc2e4\ud589\ud558\uba74\uc11c \uc21c\uc11c\ub97c \ubcf4\uc7a5\ud569\ub2c8\ub2e4.\\n\\n\uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\uc758 \uc885\ub958\ub294 3\uac00\uc9c0\uac00 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n- **\uc804\uc5ed \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8(Global Execution Context)**\\n    - \uc790\ubc14\uc2a4\ud06c\ub9bd\ud2b8\uac00 \uc2e4\ud589\ub418\ub294 \uc21c\uac04 \uc0dd\uc131\ub418\ub294 \uac00\uc7a5 \uae30\ubcf8\uc801\uc778 \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\uc785\ub2c8\ub2e4.\\n- **\ud568\uc218 \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8(Functional Execution Context)**\\n    - \ud568\uc218\uac00 \uc2e4\ud589 \ub418\uc5c8\uc744 \ub54c \uc0dd\uc131\ub418\ub294 \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\uc785\ub2c8\ub2e4.\\n- **Eval \ud568\uc218 \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8(Eval Function Execution Context)**\\n    - Eval \ud568\uc218\uac00 \uc2e4\ud589\ub418\uc5c8\uc744 \ub54c, \ub0b4\ubd80\uc758 \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\uc785\ub2c8\ub2e4.\\n\\n\uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\ub294 \uc0dd\uc131 \ud398\uc774\uc988(Creation Phase)\uc640 \uc2e4\ud589 \ud398\uc774\uc988(Execution Phase) \ub450 \ub2e8\uacc4\ub97c \uac70\uce69\ub2c8\ub2e4.\\n\\n### Creation Phase\\n\\nCreation phase\uc5d0\uc11c\ub294 \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\uac00 \uc0dd\uc131\ub429\ub2c8\ub2e4. \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\ub294 \ub2e4\uc74c\uacfc \uac19\uc740 \uad6c\uc870\ub97c \uac00\uc9d1\ub2c8\ub2e4.\\n\\n- LexicalEnvironment\\n    - environmentRecord\\n    - outer-EnvironmentReference\\n- VariableEnvironment\\n    - environmentRecord(snapshot)\\n    - outer-EnvironmentReference(snapshot)\\n- This binding\\n\\n\uac01 \ubd80\ubd84\uc744 \uc54c\uc544\ubd05\uc2dc\ub2e4.\\n\\nLexicalEnvironment(\ub809\uc2dc\uceec \ud658\uacbd)\ub294 \ucee8\ud14d\uc2a4\ud2b8 \ub0b4\ubd80\uc758 \uc2dd\ubcc4\uc790 \uc815\ubcf4\uac00 \ud3ec\ud568\ub418\uc5b4\uc788\ub294 environmentRecord\uc640 \uc0c1\uc704 \uc2a4\ucf54\ud504\uc758 environmentRecord\ub97c \ucc38\uc870\ud558\ub294 outer-EnvironmentReference\ub85c \uad6c\uc131\ub429\ub2c8\ub2e4. \uc774\uac83\uc740 \uc790\ubc14\uc2a4\ud06c\ub9bd\ud2b8\uac00 \ubcc0\uc218\uc5d0 \ub300\ud55c \ucc38\uc870\ub97c \ucc3e\uc744 \ub54c, \ud604\uc7ac \ub809\uc2dc\uceec \ud658\uacbd\uc5d0\uc11c \ucc3e\uc744 \uc218 \uc5c6\ub2e4\uba74, \uc0c1\uc704\uc758 \ucee8\ud14d\uc2a4\ud2b8\ub85c \ubcc0\uc218\uc5d0 \ub300\ud55c \uc815\ubcf4\ub97c \uacc4\uc18d\ud574\uc11c \ucc3e\uc544 \ub098\uac08 \uc218 \uc788\ub2e4\ub294 \uac83\uc744 \uc758\ubbf8\ud569\ub2c8\ub2e4.\\n\\nVariableEnvironment\ub294 LexicalEnvironment\uc640 \uac19\uc740 \uc815\ubcf4\ub97c \ub2f4\uace0 \uc788\uc9c0\ub9cc, \uc0dd\uc131 \uc2dc\uc810\uc758 snapshot\uc774\uae30 \ub54c\ubb38\uc5d0 \uac12\uc774 \ubcc0\ud558\uc9c0 \uc54a\ub294\ub2e4\ub294 \ud2b9\uc9d5\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\nES6\uc5d0\uc11c LexicalEnvironment\uc740 \ud568\uc218 \uc120\uc5b8 \ubc0f `let`\uacfc `const`\ubcc0\uc218\uc758 \ubc14\uc778\ub529\uc5d0 \uc0ac\uc6a9\ub418\uc9c0\ub9cc VariableEnvironment\ub294 `var` \ubc14\uc778\ub529\ub9cc \uac00\ub2a5\ud558\ub2e4\ub294 \ucc28\uc774\uc810\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\nThisBinding\uc740 \uc2dd\ubcc4\uc790\uac00 \ubc14\ub77c\ubcf4\uc544\uc57c \ud560 this\uc758 \uac12\uc785\ub2c8\ub2e4.\\n\\n### **Execution Phase**\\n\\nExecution phase\uc5d0\uc11c\ub294 \ubaa8\ub4e0 \ubcc0\uc218\uc5d0 \ub300\ud55c \ud560\ub2f9\uc774 \uc218\ud589\ub418\uace0, \ucd5c\uc885\uc801\uc73c\ub85c \ucf54\ub4dc\uac00 \uc2e4\ud589\ub429\ub2c8\ub2e4.\\n\\n\uac04\ub2e8\ud55c \uc608\uc2dc\ub97c \ud1b5\ud574 \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\uc758 \ub3d9\uc791\uc744 \uc54c\uc544\ubd05\uc2dc\ub2e4.\\n\\n```jsx\\nlet a = 20;\\nconst b = 30;\\nvar c;\\nfunction multiply(e, f) {\\n var g = 20;\\n return e * f * g;\\n}\\nc = multiply(20, 30);\\n```\\n\\n\ucf54\ub4dc\uac00 \uc2e4\ud589\ub418\uba74, \uc790\ubc14\uc2a4\ud06c\ub9bd\ud2b8 \uc5d4\uc9c4\uc740 \uc804\uc5ed \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8(Global execution context)\ub97c \uc0dd\uc131\ud569\ub2c8\ub2e4. \uc804\uc5ed \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\ub294 \uc544\ub798\uc640 \uac19\uc744 \uac83\uc785\ub2c8\ub2e4.\\n\\nCreation Phase\\n\\n```jsx\\nGlobalExectionContext = {\\n  LexicalEnvironment: {\\n    EnvironmentRecord: {\\n      Type: \\"Object\\",\\n      a: < uninitialized >,\\n      b: < uninitialized >,\\n      multiply: < func >\\n    }\\n    outer: <null>,\\n    ThisBinding: <Global Object>\\n  },\\n  VariableEnvironment: {\\n    EnvironmentRecord: {\\n      Type: \\"Object\\",\\n      c: undefined,\\n    }\\n    outer: <null>,\\n    ThisBinding: <Global Object>\\n  }\\n}\\n```\\n\\nExecution Phase\\n\\n```jsx\\nGlobalExectionContext = {\\nLexicalEnvironment: {\\n    EnvironmentRecord: {\\n      Type: \\"Object\\",\\n      a: 20,\\n      b: 30,\\n      multiply: < func >\\n    }\\n    outer: <null>,\\n    ThisBinding: <Global Object>\\n  },\\nVariableEnvironment: {\\n    EnvironmentRecord: {\\n      Type: \\"Object\\",\\n      c: undefined,\\n    }\\n    outer: <null>,\\n    ThisBinding: <Global Object>\\n  }\\n}\\n```\\n\\n\uc774\ud6c4, `multiply(20, 30);`  \uac00 \uc2e4\ud589\ub418\uba74, `multiply`\uc758 \ud568\uc218 \uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\uac00 \uc0dd\uc131\ub429\ub2c8\ub2e4.\\n\\nCreation Phase\\n\\n```jsx\\nFunctionExectionContext = {\\nLexicalEnvironment: {\\n    EnvironmentRecord: {\\n      Type: \\"Declarative\\",\\n      Arguments: {0: 20, 1: 30, length: 2},\\n    },\\n    outer: <GlobalLexicalEnvironment>,\\n    ThisBinding: <Global Object or undefined>,\\n  },\\nVariableEnvironment: {\\n    EnvironmentRecord: {\\n      Type: \\"Declarative\\",\\n      g: undefined\\n    },\\n    outer: <GlobalLexicalEnvironment>,\\n    ThisBinding: <Global Object or undefined>\\n  }\\n}\\n```\\n\\nExecution Phase\\n\\n```jsx\\nFunctionExectionContext = {\\nLexicalEnvironment: {\\n    EnvironmentRecord: {\\n      Type: \\"Declarative\\",\\n      Arguments: {0: 20, 1: 30, length: 2},\\n    },\\n    outer: <GlobalLexicalEnvironment>,\\n    ThisBinding: <Global Object or undefined>,\\n  },\\nVariableEnvironment: {\\n    EnvironmentRecord: {\\n      Type: \\"Declarative\\",\\n      g: 20\\n    },\\n    outer: <GlobalLexicalEnvironment>,\\n    ThisBinding: <Global Object or undefined>\\n  }\\n}\\n```\\n\\n`multiply` \uac00 \uc2e4\ud589\ub418\uace0, \ubc18\ud658\ub41c \uac12\uc774 \uae00\ub85c\ubc8c \ucee8\ud14d\uc2a4\ud2b8\uc758 `c` \uc5d0 \uc800\uc7a5\ub418\uace0, LexicalEnvironment\uac00 \uc5c5\ub370\uc774\ud2b8 \ub429\ub2c8\ub2e4. \ud504\ub85c\uadf8\ub7a8\uc774 \uc885\ub8cc\ub429\ub2c8\ub2e4.\\n\\n### \ucd94\uac00\ub85c\\n\\n\ucf54\ub4dc\ub97c \ubcf4\uba74 `let`\uacfc `const`\ub97c \uc0ac\uc6a9\ud55c \ubcc0\uc218\ub294 creation phase\uc5d0\uc11c \uc544\ubb34 \uac12\uc744 \uac00\uc9c0\uc9c0 \uc54a\uc9c0\ub9cc(uninitialized), `var` \uc758 \uacbd\uc6b0\ub294 `undefined`\ub77c\ub294 \uac12\uc744 \uac16\uc2b5\ub2c8\ub2e4.\\n\\n\uc774\uac83\uc774 \uac12\uc774 \ucd08\uae30\ud654 \ub418\uae30 \uc804\uc5d0 `var` \ub85c \uc120\uc5b8\ub41c \ubcc0\uc218\ub294 \uc811\uadfc\ud560 \uc218 \uc788\uace0, `let`\uacfc `const` \ub85c \uc120\uc5b8\ud55c \ubcc0\uc218\ub294 \uc811\uadfc\ud560 \uc218 \uc5c6\ub294 \uc774\uc720\uc785\ub2c8\ub2e4.\\n\\n\uc2e4\ud589 \ucee8\ud14d\uc2a4\ud2b8\ub77c\ub294 \uac1c\ub150\uc740 \ud074\ub85c\uc800\ub098, \ud638\uc774\uc2a4\ud305\uc744 \uacf5\ubd80\ud558\ub2e4 \ubcf4\uba74 \uacc4\uc18d\ud574\uc11c \ub9c8\uc8fc\uce58\uac8c \ub418\ub294 \uac1c\ub150\uc785\ub2c8\ub2e4. \uac1c\ub150\uc744 \ud655\uc2e4\ud558\uac8c \uc54c\uc544\ub454\ub2e4\uba74 \uc774\ud6c4\uc5d0 \ub2e4\ub978 \uac1c\ub150\uc758 \uc774\ud574\uc5d0 \ub9ce\uc740 \ub3c4\uc6c0\uc774 \ub420 \uac83\uc774\ub77c \uc0dd\uac01\ud569\ub2c8\ub2e4.\\n\\n[Understanding Execution Context and Execution Stack in Javascript](https://blog.bitsrc.io/understanding-execution-context-and-execution-stack-in-javascript-1c9ea8642dd0)"}]}')}}]);